if os.name == "nt":
    from ctypes import wintypes

    _user32 = ctypes.WinDLL("user32", use_last_error=True)
    _kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)
    _WNDENUMPROC = ctypes.WINFUNCTYPE(wintypes.BOOL, wintypes.HWND, wintypes.LPARAM)
    _GWL_STYLE = -16
    _GW_OWNER = 4
    _GW_CHILD = 5
    _RDW_INVALIDATE = 0x0001
    _RDW_ERASE = 0x0004
    _RDW_ALLCHILDREN = 0x0080
    _RDW_UPDATENOW = 0x0100
    _SW_HIDE = 0
    _SW_SHOW = 5
    _SWP_NOSIZE = 0x0001
    _SWP_NOMOVE = 0x0002
    _SWP_NOZORDER = 0x0004
    _SWP_NOACTIVATE = 0x0010
    _SWP_FRAMECHANGED = 0x0020
    _WM_CHAR = 0x0102
    _WM_KEYDOWN = 0x0100
    _WM_KEYUP = 0x0101
    _VK_RETURN = 0x0D
    _WS_CHILD = 0x40000000
    _WS_POPUP = 0x80000000
    _WS_CAPTION = 0x00C00000
    _WS_THICKFRAME = 0x00040000
    _WS_MINIMIZEBOX = 0x00020000
    _WS_MAXIMIZEBOX = 0x00010000
    _WS_SYSMENU = 0x00080000
    _ERROR_ALREADY_EXISTS = 183
    _SINGLE_INSTANCE_MUTEX_NAME = "Local\\CodAI_PenelopeStudioV9_SingleInstance"
    _single_instance_mutex_handle = None

    def _find_visible_window_for_pid(pid):
        pid = int(pid or 0)
        if pid <= 0:
            return 0
        matches = []

        @_WNDENUMPROC
        def _enum_cb(hwnd, _lparam):
            proc_id = wintypes.DWORD()
            _user32.GetWindowThreadProcessId(hwnd, ctypes.byref(proc_id))
            if proc_id.value != pid:
                return True
            if not _user32.IsWindowVisible(hwnd):
                return True
            if _user32.GetWindow(hwnd, _GW_OWNER):
                return True
            title_len = int(_user32.GetWindowTextLengthW(hwnd))
            title_buf = ctypes.create_unicode_buffer(max(title_len + 1, 1))
            _user32.GetWindowTextW(hwnd, title_buf, len(title_buf))
            title = title_buf.value or ""
            matches.append((int(hwnd), title, title_len))
            return True

        _user32.EnumWindows(_enum_cb, 0)
        if not matches:
            return 0
        matches.sort(key=lambda item: (0 if item[2] > 0 else 1, -item[2], item[0]))
        return int(matches[0][0])

    def _send_text_to_window(hwnd, text):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        payload = str(text or "")
        try:
            _user32.SetFocus(wintypes.HWND(hwnd))
        except Exception:
            pass
        for ch in payload:
            try:
                _user32.PostMessageW(wintypes.HWND(hwnd), _WM_CHAR, ord(ch), 1)
            except Exception:
                return False
        try:
            _user32.PostMessageW(wintypes.HWND(hwnd), _WM_KEYDOWN, _VK_RETURN, 0)
            _user32.PostMessageW(wintypes.HWND(hwnd), _WM_CHAR, ord("\r"), 1)
            _user32.PostMessageW(wintypes.HWND(hwnd), _WM_KEYUP, _VK_RETURN, 0)
        except Exception:
            return False
        return True

    def _focus_target_window(hwnd):
        current = int(hwnd or 0)
        if current <= 0:
            return 0
        while True:
            try:
                child = int(_user32.GetWindow(wintypes.HWND(current), _GW_CHILD) or 0)
            except Exception:
                child = 0
            if child <= 0 or child == current:
                break
            current = child
        return current

    def _activate_window(hwnd):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        target = _focus_target_window(hwnd)
        ok = False
        for candidate in (hwnd, target):
            candidate = int(candidate or 0)
            if candidate <= 0:
                continue
            try:
                _user32.SetForegroundWindow(wintypes.HWND(candidate))
            except Exception:
                pass
            try:
                _user32.SetActiveWindow(wintypes.HWND(candidate))
            except Exception:
                pass
            try:
                _user32.SetFocus(wintypes.HWND(candidate))
                ok = True
            except Exception:
                pass
        return ok

    def _resize_window(hwnd, width, height):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        w = max(1, int(width or 1))
        h = max(1, int(height or 1))
        target = _focus_target_window(hwnd)
        ok = False
        for candidate in (hwnd, target):
            candidate = int(candidate or 0)
            if candidate <= 0:
                continue
            try:
                _user32.MoveWindow(wintypes.HWND(candidate), 0, 0, w, h, True)
                ok = True
            except Exception:
                pass
            try:
                _user32.RedrawWindow(
                    wintypes.HWND(candidate),
                    None,
                    None,
                    _RDW_INVALIDATE | _RDW_ERASE | _RDW_ALLCHILDREN | _RDW_UPDATENOW,
                )
            except Exception:
                pass
        return ok

    def _strip_window_chrome(hwnd, drop_menu=False):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        targets = []
        seen = set()
        for candidate in (hwnd, _focus_target_window(hwnd)):
            candidate = int(candidate or 0)
            if candidate > 0 and candidate not in seen:
                seen.add(candidate)
                targets.append(candidate)
        ok = False
        for candidate in targets:
            try:
                style = int(_user32.GetWindowLongW(wintypes.HWND(candidate), _GWL_STYLE) or 0)
            except Exception:
                style = 0
            style &= ~(
                _WS_CAPTION
                | _WS_THICKFRAME
                | _WS_MINIMIZEBOX
                | _WS_MAXIMIZEBOX
                | _WS_SYSMENU
                | _WS_POPUP
            )
            try:
                _user32.SetWindowLongW(wintypes.HWND(candidate), _GWL_STYLE, style)
                ok = True
            except Exception:
                pass
            try:
                _user32.SetWindowPos(
                    wintypes.HWND(candidate),
                    None,
                    0,
                    0,
                    0,
                    0,
                    _SWP_NOMOVE | _SWP_NOSIZE | _SWP_NOZORDER | _SWP_NOACTIVATE | _SWP_FRAMECHANGED,
                )
            except Exception:
                pass
        if drop_menu:
            try:
                _user32.SetMenu(wintypes.HWND(hwnd), None)
                ok = True
            except Exception:
                pass
            try:
                _user32.DrawMenuBar(wintypes.HWND(hwnd))
            except Exception:
                pass
        try:
            _user32.ShowWindow(wintypes.HWND(hwnd), _SW_SHOW)
            ok = True
        except Exception:
            pass
        return ok

    def _reparent_window(hwnd, parent_hwnd):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        _ = int(parent_hwnd or 0)
        return _strip_window_chrome(hwnd, drop_menu=True)

    def _place_window(hwnd, x, y, width, height):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        x = int(x or 0)
        y = int(y or 0)
        w = max(1, int(width or 1))
        h = max(1, int(height or 1))
        try:
            _user32.SetWindowPos(
                wintypes.HWND(hwnd),
                None,
                x,
                y,
                w,
                h,
                _SWP_NOZORDER | _SWP_NOACTIVATE | _SWP_FRAMECHANGED,
            )
        except Exception:
            return False
        try:
            _user32.RedrawWindow(
                wintypes.HWND(hwnd),
                None,
                None,
                _RDW_INVALIDATE | _RDW_ERASE | _RDW_ALLCHILDREN | _RDW_UPDATENOW,
            )
        except Exception:
            pass
        child = _focus_target_window(hwnd)
        if child and child != hwnd:
            try:
                _user32.MoveWindow(wintypes.HWND(child), 0, 0, w, h, True)
            except Exception:
                pass
            try:
                _user32.RedrawWindow(
                    wintypes.HWND(child),
                    None,
                    None,
                    _RDW_INVALIDATE | _RDW_ERASE | _RDW_ALLCHILDREN | _RDW_UPDATENOW,
                )
            except Exception:
                pass
        return True

    def _show_window(hwnd, visible):
        hwnd = int(hwnd or 0)
        if hwnd <= 0:
            return False
        try:
            _user32.ShowWindow(wintypes.HWND(hwnd), _SW_SHOW if visible else _SW_HIDE)
            return True
        except Exception:
            return False

    def _acquire_single_instance_guard():
        global _single_instance_mutex_handle
        if _single_instance_mutex_handle:
            return True
        try:
            handle = _kernel32.CreateMutexW(None, False, _SINGLE_INSTANCE_MUTEX_NAME)
        except Exception:
            return True
        if not handle:
            return True
        if ctypes.get_last_error() == _ERROR_ALREADY_EXISTS:
            try:
                _kernel32.CloseHandle(handle)
            except Exception:
                pass
            return False
        _single_instance_mutex_handle = handle
        return True

    def _release_single_instance_guard():
        global _single_instance_mutex_handle
        if not _single_instance_mutex_handle:
            return
        try:
            _kernel32.CloseHandle(_single_instance_mutex_handle)
        except Exception:
            pass
        _single_instance_mutex_handle = None
else:
    def _find_visible_window_for_pid(pid):
        return 0

    def _send_text_to_window(hwnd, text):
        return False

    def _activate_window(hwnd):
        return False

    def _resize_window(hwnd, width, height):
        return False

    def _reparent_window(hwnd, parent_hwnd):
        return False

    def _strip_window_chrome(hwnd, drop_menu=False):
        return False

    def _place_window(hwnd, x, y, width, height):
        return False

    def _show_window(hwnd, visible):
        return False

    _single_instance_lock = None

    def _single_instance_lock_path():
        base = QStandardPaths.writableLocation(QStandardPaths.StandardLocation.AppLocalDataLocation)
        root = Path(base) if base else (Path(tempfile.gettempdir()) / "PenelopeStudioV9")
        return root / "penelope_studio_v9.lock"

    def _acquire_single_instance_guard():
        global _single_instance_lock
        if _single_instance_lock is not None:
            return True
        try:
            lock_path = _single_instance_lock_path()
            lock_path.parent.mkdir(parents=True, exist_ok=True)
            lock = QLockFile(str(lock_path))
            lock.setStaleLockTime(30000)
            if not lock.tryLock(0):
                return False
            _single_instance_lock = lock
            return True
        except Exception:
            return True

    def _release_single_instance_guard():
        global _single_instance_lock
        if _single_instance_lock is None:
            return
        try:
            _single_instance_lock.unlock()
        except Exception:
            pass
        _single_instance_lock = None

