# PENELOPE/RANECU seed limits used by penmain input RSEED.
PENELOPE_ISEED1_MAX = 2147483562
PENELOPE_ISEED2_MAX = 2147483398


def _normalize_penelope_seed(value, maximum):
    """Return a valid positive PENELOPE/RANECU-style seed in 1..maximum."""
    try:
        raw = int(float(str(value).strip()))
    except Exception:
        raw = 1
    return ((raw - 1) % int(maximum)) + 1


def generate_penelope_seed_pairs(count, base1=12345, base2=67890):
    """
    Generate deterministic, simple unique PENELOPE RSEED pairs.

    This is intentionally labelled and used as a simple unique seed mode.
    It is not a rigorous RANECU skip-ahead/substream implementation.
    """
    try:
        count = int(count)
    except Exception:
        count = 0
    if count <= 0:
        return []
    s1 = _normalize_penelope_seed(base1, PENELOPE_ISEED1_MAX)
    s2 = _normalize_penelope_seed(base2, PENELOPE_ISEED2_MAX)
    pairs = []
    seen = set()
    salt = 0
    # Multipliers are common small LCG-like constants for deterministic mixing;
    # ranges are enforced explicitly below.
    while len(pairs) < count:
        i = len(pairs) + 1 + salt
        s1 = (40014 * s1 + 104729 * i + 12345) % PENELOPE_ISEED1_MAX
        s2 = (40692 * s2 + 130363 * i + 67890) % PENELOPE_ISEED2_MAX
        seed1 = _normalize_penelope_seed(s1, PENELOPE_ISEED1_MAX)
        seed2 = _normalize_penelope_seed(s2, PENELOPE_ISEED2_MAX)
        pair = (seed1, seed2)
        if pair not in seen:
            seen.add(pair)
            pairs.append(pair)
        else:
            salt += 1
            if salt > count * 10 + 1000:
                raise RuntimeError("Could not generate unique PENELOPE seed pairs.")
    return pairs


def _format_penelope_count_value(value):
    """Format shower counts compactly for NSIMSH while preserving integer counts exactly where possible."""
    try:
        number = float(str(value).replace("D", "E").replace("d", "e"))
    except Exception:
        return str(value).strip()
    if math.isfinite(number) and abs(number - round(number)) <= max(1.0, abs(number)) * 1e-12:
        return str(int(round(number)))
    return f"{number:.12g}"


ZERO_DEFAULT_GEO_PARAMS = {
    "X-SCALE", "Y-SCALE", "Z-SCALE",
    "X-SHIFT", "Y-SHIFT", "Z-SHIFT",
    "OMEGA", "THETA", "PHI",
}


def _decode_text_bytes(raw):
    for enc in ("utf-8-sig", "utf-8", "cp1252", "latin-1"):
        try:
            return raw.decode(enc)
        except UnicodeDecodeError:
            continue
    return raw.decode("latin-1", errors="replace")


def _coerce_bool_setting(value, default=False):
    if value is None:
        return bool(default)
    if isinstance(value, bool):
        return value
    text = str(value).strip().lower()
    if text in {"1", "true", "yes", "on"}:
        return True
    if text in {"0", "false", "no", "off"}:
        return False
    return bool(default)


def _coerce_int_list_setting(value):
    if value is None:
        return []
    if isinstance(value, (list, tuple)):
        raw_parts = list(value)
    else:
        raw_parts = re.findall(r"-?\d+", str(value))
    result = []
    for part in raw_parts:
        try:
            result.append(int(part))
        except (TypeError, ValueError):
            continue
    return result


def _encode_text_bytes(text):
    normalized = (text.replace("\r\n", "\n").replace("\r", "\n")
                      .replace("\n", "\r\n"))
    for enc in ("cp1252", "utf-8"):
        try:
            return normalized.encode(enc)
        except UnicodeEncodeError:
            continue
    return normalized.encode("utf-8", errors="replace")


def _ascii_safe_geo_text(text):
    src = (text or "").replace("\r\n", "\n").replace("\r", "\n")
    safe_lines = []
    for line in src.split("\n"):
        if re.match(r"^\s*(SURFACE|BODY|MODULE)\s*\(", line, re.IGNORECASE):
            match = re.match(r"^(\s*(?:SURFACE|BODY|MODULE)\s*\(\s*\d+\s*\)\s*)(.*)$", line, re.IGNORECASE)
            if match:
                prefix = match.group(1)
                label = match.group(2) or ""
                normalized = unicodedata.normalize("NFKD", label)
                ascii_label = normalized.encode("ascii", errors="ignore").decode("ascii")
                ascii_label = re.sub(r"[^\x20-\x7E]", "", ascii_label)
                line = prefix + ascii_label
        safe_lines.append(line)
    return "\n".join(safe_lines)


def _is_zero_default_param_line(line):
    match = re.match(
        r"^\s*([A-Z][A-Z0-9]*(?:-[A-Z][A-Z0-9]*)?)\s*=\s*\(\s*"
        r"([+-]?(?:\d+(?:\.\d*)?|\.\d+)(?:[Ee][+-]?\d+)?)\s*,",
        line or "",
        re.IGNORECASE,
    )
    if not match:
        return False
    key = match.group(1).upper()
    if key not in ZERO_DEFAULT_GEO_PARAMS:
        return False
    try:
        return abs(float(match.group(2))) < 1e-15
    except ValueError:
        return False


def _is_transform_sep_line(line):
    return bool(re.match(r"^\s*1{10,}\s*$", line or ""))


def _strip_zero_default_geo_params(text):
    src = (text or "").replace("\r\n", "\n").replace("\r", "\n")
    return "\n".join(
        line for line in src.split("\n")
        if not _is_zero_default_param_line(line)
    )


def _geo_axis_bounds(surfaces):
    bounds = {
        "X": {"low": None, "high": None},
        "Y": {"low": None, "high": None},
        "Z": {"low": None, "high": None},
    }
    for surf in surfaces.values():
        params = surf.get("params", {})
        for axis in ("X", "Y", "Z"):
            scale = abs(params.get(f"{axis}-SCALE", 0.0) or 0.0)
            shift = params.get(f"{axis}-SHIFT", 0.0) or 0.0
            if scale == 0.0 and f"{axis}-SHIFT" not in params and f"{axis}-SCALE" not in params:
                continue
            low = shift - scale
            high = shift + scale
            cur = bounds[axis]
            cur["low"] = low if cur["low"] is None else min(cur["low"], low)
            cur["high"] = high if cur["high"] is None else max(cur["high"], high)
    return bounds


def _geo_axis_markers(surfaces):
    markers = {"X": [], "Y": [], "Z": []}
    for surf in surfaces.values():
        params = surf.get("params", {})
        for axis in ("X", "Y", "Z"):
            shift_key = f"{axis}-SHIFT"
            if shift_key in params:
                markers[axis].append(float(params[shift_key]))

        ax = float(params.get("AX", 0.0) or 0.0)
        ay = float(params.get("AY", 0.0) or 0.0)
        az = float(params.get("AZ", 0.0) or 0.0)
        a0 = float(params.get("A0", 0.0) or 0.0)
        coeffs = [("X", ax), ("Y", ay), ("Z", az)]
        non_zero = [(name, val) for name, val in coeffs if abs(val) > 1e-12]
        if len(non_zero) == 1:
            axis, coeff = non_zero[0]
            markers[axis].append(-a0 / coeff)
    return markers


def _geo_body_axis_bounds(body, surfaces):
    """Best-effort axis-aligned bounds for one BODY from raw .geo data."""
    if not body or not surfaces:
        return None
    axis_planes = {"X": [], "Y": [], "Z": []}
    shape_bounds = {"X": [], "Y": [], "Z": []}
    for sid, _side in body.get("surfaces", []):
        surf = surfaces.get(sid)
        if not surf:
            continue
        p = surf.get("params", {})
        coeffs = [("X", p.get("AX", 0.0)), ("Y", p.get("AY", 0.0)), ("Z", p.get("AZ", 0.0))]
        nonzero = [(axis, coeff) for axis, coeff in coeffs if abs(coeff or 0.0) > 1e-12]
        if len(nonzero) == 1 and "A0" in p:
            axis, coeff = nonzero[0]
            axis_planes[axis].append(-p["A0"] / coeff)
        for axis in ("X", "Y", "Z"):
            scale_key = f"{axis}-SCALE"
            shift_key = f"{axis}-SHIFT"
            if scale_key in p:
                scale = abs(p.get(scale_key, 0.0) or 0.0)
                shift = p.get(shift_key, 0.0) or 0.0
                if scale > 0:
                    shape_bounds[axis].append((shift - scale, shift + scale))
    global_markers = _geo_axis_markers(surfaces)
    global_bounds = _geo_axis_bounds(surfaces)
    bounds = {}
    for axis in ("X", "Y", "Z"):
        if len(axis_planes[axis]) >= 2:
            bounds[axis] = (min(axis_planes[axis]), max(axis_planes[axis]))
        elif shape_bounds[axis]:
            lows = [lo for lo, _hi in shape_bounds[axis]]
            highs = [hi for _lo, hi in shape_bounds[axis]]
            bounds[axis] = (min(lows), max(highs))
        elif len(global_markers[axis]) >= 2:
            bounds[axis] = (min(global_markers[axis]), max(global_markers[axis]))
        else:
            gb = global_bounds[axis]
            if gb["low"] is not None and gb["high"] is not None:
                bounds[axis] = (gb["low"], gb["high"])
            else:
                return None
        if abs(bounds[axis][1] - bounds[axis][0]) < 1e-12:
            return None
    return bounds


def _linked_rep_candidates_for_geo(geo_path):
    try:
        geo = Path(geo_path)
    except Exception:
        return []
    if not str(geo):
        return []
    candidates = []
    seen = set()
    for candidate in (geo.parent / "geometry.rep", geo.with_suffix(".rep")):
        key = str(candidate).lower()
        if key in seen:
            continue
        seen.add(key)
        candidates.append(candidate)
    return candidates


def _rep_file_is_valid(path):
    try:
        rep = Path(path)
    except Exception:
        return False
    try:
        if (not rep.exists()) or (not rep.is_file()) or rep.stat().st_size < 64:
            return False
    except Exception:
        return False
    try:
        text = _decode_text_bytes(rep.read_bytes())
    except Exception:
        return False
    src = (text or "").replace("\r\n", "\n").replace("\r", "\n")
    if not src.strip():
        return False
    structural_markers = ("KSURF", "KFLAG", "KBODY", "*** BODY", "*** MODULE", "KMOTH")
    return any(marker in src for marker in structural_markers)

