def apply_global_tooltip_style():
    css = tooltip_css()
    app = QApplication.instance()
    if app is not None and css not in app.styleSheet():
        current = app.styleSheet() or ""
        app.setStyleSheet((current + "\n" + css).strip())
    pal = QToolTip.palette()
    pal.setColor(QPalette.ColorRole.ToolTipBase, QColor("#FFF8C5"))
    pal.setColor(QPalette.ColorRole.ToolTipText, QColor("#000000"))
    QToolTip.setPalette(pal)


def show_uniform_tooltip(global_pos, text, anchor=None):
    apply_global_tooltip_style()
    QToolTip.showText(global_pos, text, anchor)


def hide_uniform_tooltip():
    QToolTip.hideText()

_GLOBAL_TOOLTIP_FILTER = None

class UnifiedTooltipEventFilter(QObject):
    def eventFilter(self, obj, event):
        if event.type() != QEvent.Type.ToolTip:
            return False
        apply_global_tooltip_style()
        text = ""
        anchor = obj if isinstance(obj, QWidget) else None
        local_pos = event.pos() if hasattr(event, "pos") else None
        global_pos = event.globalPos() if hasattr(event, "globalPos") else QCursor.pos()
        view = None
        probe = obj
        while probe is not None:
            if isinstance(probe, QAbstractItemView):
                view = probe
                break
            probe = probe.parent() if hasattr(probe, "parent") else None
        if view is not None and local_pos is not None:
            try:
                view_pos = local_pos if obj is view.viewport() else view.viewport().mapFromGlobal(global_pos)
                index = view.indexAt(view_pos)
            except Exception:
                index = QModelIndex()
            if index.isValid():
                data = index.data(Qt.ItemDataRole.ToolTipRole)
                if data not in (None, ""):
                    text = str(data)
                    anchor = view.viewport()
        if not text and isinstance(obj, QWidget):
            tip = obj.toolTip()
            if tip:
                text = str(tip)
                anchor = obj
        if text:
            show_uniform_tooltip(global_pos, text, anchor)
            return True
        hide_uniform_tooltip()
        return False

def install_global_tooltip_filter():
    global _GLOBAL_TOOLTIP_FILTER
    app = QApplication.instance()
    if app is None:
        return
    if _GLOBAL_TOOLTIP_FILTER is None:
        _GLOBAL_TOOLTIP_FILTER = UnifiedTooltipEventFilter(app)
        app.installEventFilter(_GLOBAL_TOOLTIP_FILTER)


def make_help_label(text, hint="", style=None, return_label=False):
    label = QLabel(text)
    if style:
        label.setStyleSheet(style)
    hint = str(hint or "").strip()
    if not hint:
        return (label, label) if return_label else label
    info = QLabel("?")
    info.setStyleSheet(label_css(P["fg2"], bold=True, size=8))
    info.setFixedWidth(12)
    box = QWidget()
    lay = QHBoxLayout(box)
    lay.setContentsMargins(0, 0, 0, 0)
    lay.setSpacing(4)
    lay.addWidget(label)
    lay.addWidget(info)
    lay.addStretch(1)
    for widget in (box, label, info):
        widget.setToolTip(hint)
    return (box, label) if return_label else box


def _preferred_app_screen():
    screen = None
    try:
        screen = QGuiApplication.screenAt(QCursor.pos())
    except Exception:
        screen = None
    if screen is None:
        try:
            screen = QGuiApplication.primaryScreen()
        except Exception:
            screen = None
    return screen


def _clear_all_override_cursors():
    """Drain any stacked Qt override cursors."""
    app = QApplication.instance()
    if app is None:
        return
    try:
        while QApplication.overrideCursor() is not None:
            QApplication.restoreOverrideCursor()
    except Exception:
        try:
            QApplication.restoreOverrideCursor()
        except Exception:
            pass


class StartupSplashWindow(QWidget):
    def __init__(self, total_steps=1, parent=None):
        flags = (
            Qt.WindowType.SplashScreen
            | Qt.WindowType.FramelessWindowHint
            | Qt.WindowType.WindowStaysOnTopHint
        )
        super().__init__(parent, flags)
        self._total_steps = max(1, int(total_steps or 1))
        self._current_step = 0
        self.setAttribute(Qt.WidgetAttribute.WA_DeleteOnClose, False)
        self.setAttribute(Qt.WidgetAttribute.WA_StyledBackground, True)
        self.setFixedSize(560, 320)
        self.setStyleSheet(f"QWidget {{ background:{P['bg']}; color:{P['fg']}; }}")

        shell = QFrame(self)
        shell.setStyleSheet(
            f"QFrame {{ background:{P['bg2']}; border:1px solid {P['border']}; border-radius:12px; }}"
        )
        shell_layout = QVBoxLayout(shell)
        shell_layout.setContentsMargins(18, 18, 18, 18)
        shell_layout.setSpacing(10)

        title = QLabel(f"PENELOPE Simulation Studio {APP_VERSION}")
        title.setStyleSheet(label_css(P["accent"], bold=True, size=14))
        shell_layout.addWidget(title)

        self.lbl_stage = QLabel("Launching workspace")
        self.lbl_stage.setStyleSheet(label_css(P["fg"], bold=True, size=11))
        shell_layout.addWidget(self.lbl_stage)

        self.lbl_detail = QLabel("Preparing application runtime...")
        self.lbl_detail.setStyleSheet(label_css(P["fg2"], size=9))
        self.lbl_detail.setWordWrap(True)
        shell_layout.addWidget(self.lbl_detail)

        self.progress = QProgressBar()
        self.progress.setRange(0, self._total_steps)
        self.progress.setValue(0)
        self.progress.setTextVisible(True)
        self.progress.setFormat(f"Step 0 of {self._total_steps}")
        self.progress.setStyleSheet(
            f"QProgressBar {{ background:{P['bg']}; color:{P['fg']}; border:1px solid {P['border']};"
            f" border-radius:6px; text-align:center; height:22px; }}"
            f"QProgressBar::chunk {{ background:{P['accent']}; border-radius:5px; }}"
        )
        shell_layout.addWidget(self.progress)

        self.log = QPlainTextEdit()
        self.log.setReadOnly(True)
        self.log.setMaximumBlockCount(50)
        self.log.setStyleSheet(
            f"QPlainTextEdit {{ background:{P['bg']}; color:{P['fg2']}; border:1px solid {P['border']};"
            f" border-radius:8px; font-family:'Consolas'; font-size:10pt; padding:6px; }}"
        )
        shell_layout.addWidget(self.log, stretch=1)

        footer = QLabel("Loading modules, restoring settings, building tabs, and reopening context.")
        footer.setStyleSheet(label_css(P["fg2"], size=8))
        footer.setWordWrap(True)
        shell_layout.addWidget(footer)

        root = QVBoxLayout(self)
        root.setContentsMargins(0, 0, 0, 0)
        root.addWidget(shell)

    def show_on_preferred_screen(self):
        screen = _preferred_app_screen()
        if screen is not None:
            geo = screen.availableGeometry()
            self.move(
                geo.x() + (geo.width() - self.width()) // 2,
                geo.y() + (geo.height() - self.height()) // 2,
            )
        self.show()
        self.raise_()
        self.activateWindow()
        QApplication.processEvents()

    def advance(self, title, detail=""):
        self._current_step = min(self._total_steps, self._current_step + 1)
        self.lbl_stage.setText(str(title or "Launching workspace"))
        self.lbl_detail.setText(str(detail or ""))
        self.progress.setValue(self._current_step)
        self.progress.setFormat(f"Step {self._current_step} of {self._total_steps}")
        stamp = datetime.now().strftime("%H:%M:%S")
        entry = f"[{stamp}] {title}"
        if detail:
            entry += f" - {detail}"
        self.log.appendPlainText(entry)
        self.log.verticalScrollBar().setValue(self.log.verticalScrollBar().maximum())
        QApplication.processEvents()

    def finish(self, title, detail=""):
        self._current_step = self._total_steps
        self.lbl_stage.setText(str(title or "Ready"))
        self.lbl_detail.setText(str(detail or ""))
        self.progress.setValue(self._current_step)
        self.progress.setFormat(f"Step {self._current_step} of {self._total_steps}")
        stamp = datetime.now().strftime("%H:%M:%S")
        entry = f"[{stamp}] {title}"
        if detail:
            entry += f" - {detail}"
        self.log.appendPlainText(entry)
        self.log.verticalScrollBar().setValue(self.log.verticalScrollBar().maximum())
        QApplication.processEvents()

def show_help_dialog(parent, title, html, width=760, height=560):
    dlg = QDialog(parent)
    dlg.setWindowTitle(title)
    dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; color:{P['fg']}; }}")
    lay = QVBoxLayout(dlg)
    lay.setContentsMargins(10, 10, 10, 10)
    lay.setSpacing(8)
    viewer = QTextEdit()
    viewer.setReadOnly(True)
    viewer.setStyleSheet(
        f"QTextEdit {{ background:{P['bg2']}; color:{P['fg']};"
        f" border:1px solid {P['border']}; border-radius:6px;"
        f" padding:10px; font-size:10pt; }}"
    )
    viewer.setHtml(html)
    lay.addWidget(viewer)
    close = QPushButton("Close")
    close.setStyleSheet(btn_css(width=90))
    close.clicked.connect(dlg.accept)
    lay.addWidget(close, alignment=Qt.AlignmentFlag.AlignRight)
    dlg.resize(width, height)
    dlg.exec()

class WrappingButtonRow(QWidget):
    def __init__(self, widgets, spacing=4, parent=None):
        super().__init__(parent)
        self._widgets = list(widgets)
        self._spacing = spacing
        self._grid = QGridLayout(self)
        self._grid.setContentsMargins(0, 0, 0, 0)
        self._grid.setHorizontalSpacing(spacing)
        self._grid.setVerticalSpacing(spacing)
        self._last_width = -1
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Preferred)
        self._relayout()

    def resizeEvent(self, event):
        super().resizeEvent(event)
        if abs(self.width() - self._last_width) >= 8:
            self._relayout()

    def _clear_grid(self):
        while self._grid.count():
            item = self._grid.takeAt(0)
            if item.widget():
                item.widget().setParent(None)

    def _relayout(self):
        self._last_width = self.width()
        self._clear_grid()
        available = max(1, self.width())
        row = 0
        col = 0
        row_width = 0
        for widget in self._widgets:
            hint = widget.sizeHint().width()
            needed = hint if col == 0 else hint + self._spacing
            if col > 0 and row_width + needed > available:
                row += 1
                col = 0
                row_width = 0
                needed = hint
            self._grid.addWidget(widget, row, col)
            row_width += needed
            col += 1
        self._grid.setColumnStretch(col, 1)
        self._grid.invalidate()
        self.updateGeometry()


class CornerToast(QFrame):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setObjectName("cornerToast")
        self.setAttribute(Qt.WidgetAttribute.WA_ShowWithoutActivating, True)
        self.setWindowFlags(Qt.WindowType.SubWindow | Qt.WindowType.FramelessWindowHint)
        self.setStyleSheet(
            f"QFrame#cornerToast {{"
            f" background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:10px; }}"
        )
        self.setMinimumWidth(280)
        outer = QVBoxLayout(self)
        outer.setContentsMargins(12, 10, 12, 10)
        outer.setSpacing(4)
        self.lbl_title = QLabel("")
        self.lbl_title.setStyleSheet(label_css(P["accent"], bold=True, size=10))
        self.lbl_body = QLabel("")
        self.lbl_body.setStyleSheet(label_css(P["fg"], size=9))
        self.lbl_body.setWordWrap(True)
        outer.addWidget(self.lbl_title)
        outer.addWidget(self.lbl_body)
        self._timer = QTimer(self)
        self._timer.setSingleShot(True)
        self._timer.timeout.connect(self.hide)
        self.hide()

    def show_toast(self, title, body="", timeout_ms=5000):
        self.lbl_title.setText(str(title or "Notice"))
        self.lbl_body.setText(str(body or ""))
        self.adjustSize()
        self._reposition()
        self.raise_()
        self.show()
        self._timer.start(max(1200, int(timeout_ms or 5000)))

    def _reposition(self):
        parent = self.parentWidget()
        if parent is None:
            return
        self.adjustSize()
        margin = 18
        width = max(self.minimumWidth(), self.sizeHint().width())
        height = self.sizeHint().height()
        x = max(margin, parent.width() - width - margin)
        y = max(margin, parent.height() - height - margin)
        self.setGeometry(x, y, width, height)


def _inline_widget_group(*widgets, spacing=6, stretch_last=False):
    row = QWidget()
    lay = QHBoxLayout(row)
    lay.setContentsMargins(0, 0, 0, 0)
    lay.setSpacing(spacing)
    usable = [widget for widget in widgets if widget is not None]
    last_idx = len(usable) - 1
    for idx, widget in enumerate(usable):
        lay.addWidget(widget, 1 if (stretch_last and idx == last_idx) else 0)
    row.setSizePolicy(QSizePolicy.Policy.Maximum, QSizePolicy.Policy.Preferred)
    return row


# 
#  GEO SYNTAX HIGHLIGHTER
# 

def _fmt(color, bold=False, italic=False):
    f = QTextCharFormat()
    f.setForeground(QColor(color))
    if bold:   f.setFontWeight(QFont.Weight.Bold)
    if italic: f.setFontItalic(True)
    return f


class GeoHighlighter(QSyntaxHighlighter):
    def __init__(self, doc):
        super().__init__(doc)
        self._sep_re  = QRegularExpression(r"^0{10,}\s*$")
        self._xfrm_sep_re = QRegularExpression(r"^1{10,}\s*$")
        self._end_re  = QRegularExpression(r"^END\b.*")
        self._cmt_re  = QRegularExpression(r"^\s*(C\s|C$|//)")

        self._sep_fmt = _fmt(P["g_sep"], bold=True)
        self._end_fmt = _fmt(P["g_end"], bold=True)
        self._cmt_fmt = _fmt(P["g_comment"], italic=True)

        self._rules = [
            (QRegularExpression(
                r"\bsurface_[A-Za-z0-9_]+\b",
                QRegularExpression.PatternOption.CaseInsensitiveOption),
             _fmt(P["g_auto_kw"], bold=True)),
            (QRegularExpression(r"\bSURFACE\b"),
             _fmt(P["g_surface"], bold=True)),
            (QRegularExpression(r"\b(BODY|MODULE)\b"),
             _fmt(P["g_body"], bold=True)),
            (QRegularExpression(r"\bMATERIAL\b"),
             _fmt(P["g_material"], bold=True)),
            (QRegularExpression(r"\bINDICES\b"),
             _fmt(P["g_kw"], bold=True)),
            (QRegularExpression(
                r"\b(X-SCALE|Y-SCALE|Z-SCALE|X-SHIFT|Y-SHIFT|Z-SHIFT"
                r"|OMEGA|THETA|PHI|AXX|AXY|AXZ|AYY|AYZ|AZZ|AX|AY|AZ|A0)\b"),
             _fmt(P["g_param"])),
            (QRegularExpression(r"SIDE POINTER"),
             _fmt(P["g_param"])),
            (QRegularExpression(r"\(\s*[+\-]?\s*\d[\d\.E+\-]*,\s*\d+\s*\)"),
             _fmt(P["g_value"])),
            (QRegularExpression(r"(?<=\))\s+\S.*$"),
             _fmt(P["g_label"])),
        ]

    def highlightBlock(self, text):
        if self._sep_re.match(text).hasMatch() or self._xfrm_sep_re.match(text).hasMatch():
            self.setFormat(0, len(text), self._sep_fmt); return
        if self._end_re.match(text).hasMatch():
            self.setFormat(0, len(text), self._end_fmt); return
        if self._cmt_re.match(text).hasMatch():
            self.setFormat(0, len(text), self._cmt_fmt); return
        for regex, fmt in self._rules:
            it = regex.globalMatch(text)
            while it.hasNext():
                m = it.next()
                self.setFormat(m.capturedStart(), m.capturedLength(), fmt)


# 
#  .IN SYNTAX HIGHLIGHTER
# 

class InHighlighter(QSyntaxHighlighter):
    IN_KEYWORDS = [
        "TITLE","SKPAR","SENERG","SPECTR","SPOSIT","SCONE","SRADI","SPOLAR",
        "MFNAME","MSIMPA","GEOMFN","DSMAX","EABSB","IFORCE","NBE","NBANGL","ENDETC",
        "IMPDET","IDBODY","RESUME","DUMPTO","DUMPP","RSEED","NSIMSH","TIME","END",
    ]

    def __init__(self, doc):
        super().__init__(doc)
        kw_pat = r"\b(" + "|".join(self.IN_KEYWORDS) + r")\b"
        self._kw_re  = QRegularExpression(kw_pat)
        self._cmt_re = QRegularExpression(r"\[.*\]")
        self._sec_re = QRegularExpression(r">>>>+.*$")
        self._num_re = QRegularExpression(r"\b\d[\d\.e+\-]*\b")

        self._kw_fmt  = _fmt(P["i_cmd"],     bold=True)
        self._cmt_fmt = _fmt(P["i_comment"], italic=True)
        self._sec_fmt = _fmt(P["i_section"])
        self._num_fmt = _fmt(P["i_value"])

    def highlightBlock(self, text):
        for regex, fmt in [
            (self._sec_re,  self._sec_fmt),
            (self._cmt_re,  self._cmt_fmt),
            (self._kw_re,   self._kw_fmt),
            (self._num_re,  self._num_fmt),
        ]:
            it = regex.globalMatch(text)
            while it.hasNext():
                m = it.next()
                self.setFormat(m.capturedStart(), m.capturedLength(), fmt)


