class Gutter(QWidget):
    def __init__(self, editor):
        super().__init__(editor)
        self._e = editor

    def sizeHint(self):
        return QSize(self._e.gutter_width(), 0)

    def paintEvent(self, ev):
        self._e.paint_gutter(ev)


