    def _prime_workspace_splitter_tracking(self):
        splitter = getattr(self, "_workspace_splitter", None)
        if splitter is None:
            return
        sizes = splitter.sizes()
        self._workspace_last_left_width = sizes[0] if sizes else None

    def _on_workspace_splitter_moved(self, pos, index):
        splitter = getattr(self, "_workspace_splitter", None)
        if splitter is None or self._workspace_splitter_adjusting:
            return
        sizes = splitter.sizes()
        if len(sizes) < 2:
            return
        left_width = int(sizes[0] or 0)
        previous = self._workspace_last_left_width
        self._workspace_last_left_width = left_width
        if previous is None:
            return
        delta = left_width - int(previous)
        if delta > 0:
            self.sidebar_reclaim_requested.emit(delta)
        self._update_geometry_responsive_layout()

    def resizeEvent(self, event):
        super().resizeEvent(event)
        self._update_geometry_responsive_layout()

    def _update_geometry_responsive_layout(self):
        controls_row = getattr(self, "_geo_controls_row", None)
        if controls_row is None:
            return
        if controls_row.direction() != QBoxLayout.Direction.LeftToRight:
            self._geo_controls_stacked = False
            controls_row.setDirection(QBoxLayout.Direction.LeftToRight)
            controls_row.invalidate()

    def _geometry_block_group_style(self, compact=False):
        title_size = 9 if compact else 10
        padding = 4 if compact else 6
        margin = 5 if compact else 6
        return (
            f"QGroupBox {{ color:{P['accent']}; border:1px solid {P['border']};"
            f" border-radius:4px; margin-top:{margin}px; padding:{padding}px; }}"
            f"QGroupBox::title {{ subcontrol-origin:margin; left:8px; font-size:{title_size}px; }}"
        )

    def _apply_block_action_button_style(self, button, width, compact=False, tool=False):
        height = 24 if compact else 30
        font = button.font()
        font.setPointSize(10 if compact else 11)
        button.setFont(font)
        if tool:
            padding = "2px 8px" if compact else "4px 12px"
            button.setStyleSheet(
                f"QToolButton {{ background:{P['bg2']}; color:{P['fg']};"
                f" border:1px solid {P['border']}; border-radius:4px; padding:{padding}; font-size:{10 if compact else 11}px; min-width:{width}px; }}"
                f"QToolButton:hover {{ background:{P['bg3']}; border-color:{P['accent']}; }}"
            )
            button.setFixedWidth(width)
            button.setFixedHeight(height)
        else:
            padding = "2px 8px" if compact else "4px 14px"
            button.setStyleSheet(
                f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
                f" border:1px solid {P['border']}; border-radius:4px; padding:{padding}; font-size:{10 if compact else 11}px; min-width:{width}px; }}"
                f"QPushButton:hover   {{ background:{P['bg3']}; border-color:{P['accent']}; }}"
                f"QPushButton:pressed {{ background:{P['sel']}; }}"
                f"QPushButton:disabled {{ color:{P['fg2']}; }}"
            )
            button.setFixedHeight(height)

    def _rebuild_block_actions_layout(self, layout, buttons, single_column=False):
        if layout is None:
            return
        self._clear_layout_items(layout)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setHorizontalSpacing(4)
        layout.setVerticalSpacing(4)
        if single_column:
            for row, button in enumerate(buttons or []):
                layout.addWidget(button, row, 0)
        else:
            if len(buttons) >= 7:
                layout.addWidget(buttons[0], 0, 0)
                layout.addWidget(buttons[1], 0, 1)
                layout.addWidget(buttons[2], 1, 0)
                layout.addWidget(buttons[3], 1, 1)
                layout.addWidget(buttons[4], 2, 0, 1, 2)
                layout.addWidget(buttons[5], 3, 0)
                layout.addWidget(buttons[6], 3, 1)
            else:
                for row, button in enumerate(buttons or []):
                    layout.addWidget(button, row, 0)

    def _set_block_actions_layout_mode(self, edit_mode=False):
        edit_mode = bool(edit_mode)
        body_buttons = list(getattr(self, "_body_block_action_buttons", []) or [])
        geo_buttons = list(getattr(self, "_geometry_block_action_buttons", []) or [])
        if hasattr(self, "body_blocks_actions_layout"):
            self._rebuild_block_actions_layout(
                self.body_blocks_actions_layout,
                body_buttons,
                single_column=edit_mode,
            )
        if hasattr(self, "blocks_actions_layout"):
            self._rebuild_block_actions_layout(
                self.blocks_actions_layout,
                geo_buttons,
                single_column=edit_mode,
            )
        if hasattr(self, "body_blocks_actions_widget"):
            self.body_blocks_actions_widget.setMinimumWidth(100 if edit_mode else 150)
            self.body_blocks_actions_widget.setMaximumWidth(16777215)
        if hasattr(self, "blocks_actions_widget"):
            self.blocks_actions_widget.setMinimumWidth(100 if edit_mode else 150)
            self.blocks_actions_widget.setMaximumWidth(16777215)

    def _target_list_height_for_rows(self, list_widget, rows=6):
        row_height = 0
        try:
            row_height = int(list_widget.sizeHintForRow(0) or 0)
        except Exception:
            row_height = 0
        if row_height <= 0:
            row_height = 19
        frame = max(2, int(list_widget.frameWidth() or 1) * 2)
        return int(row_height * max(1, rows) + frame + 8)

    def _apply_render_mode_block_compaction(self):
        compact = self.geometry_layout_mode() == "render"
        if hasattr(self, "grp_body_blocks"):
            self.grp_body_blocks.setStyleSheet(self._geometry_block_group_style(compact))
        if hasattr(self, "grp_blocks"):
            self.grp_blocks.setStyleSheet(self._geometry_block_group_style(compact))
        if hasattr(self, "lst_body_blocks"):
            body_height = self._target_list_height_for_rows(self.lst_body_blocks, 6) if compact else 84
            self.lst_body_blocks.setMinimumHeight(body_height)
            self.lst_body_blocks.setMaximumHeight(body_height if compact else 16777215)
            self.lst_body_blocks.setStyleSheet(
                f"QListWidget {{ background:{P['bg']}; color:{P['fg']};"
                f" border:1px solid {P['border']}; border-radius:4px;"
                f" padding:2px; font-family:'Courier New'; font-size:{10 if compact else 11}px; }}"
                f"QListWidget::item:selected {{ background:{P['sel']}; color:{P['fg']}; }}"
            )
        if hasattr(self, "lst_blocks"):
            blocks_height = self._target_list_height_for_rows(self.lst_blocks, 6) if compact else 120
            self.lst_blocks.setMinimumHeight(blocks_height)
            self.lst_blocks.setMaximumHeight(blocks_height if compact else 16777215)
            self.lst_blocks.setStyleSheet(
                f"QListWidget {{ background:{P['bg']}; color:{P['fg']};"
                f" border:1px solid {P['border']}; border-radius:4px;"
                f" padding:2px; font-family:'Courier New'; font-size:{10 if compact else 11}px; }}"
                f"QListWidget::item:selected {{ background:{P['sel']}; color:{P['fg']}; }}"
            )
        if hasattr(self, "console"):
            self.console.setMaximumHeight(96 if compact else 130)
        for button, regular_width, compact_width in getattr(self, "_body_block_action_specs", []):
            self._apply_block_action_button_style(button, compact_width if compact else regular_width, compact=compact, tool=isinstance(button, QToolButton))
        for button, regular_width, compact_width in getattr(self, "_geometry_block_action_specs", []):
            self._apply_block_action_button_style(button, compact_width if compact else regular_width, compact=compact, tool=isinstance(button, QToolButton))
        self._set_block_actions_layout_mode(edit_mode=not compact)

    def _clear_layout_items(self, layout):
        if layout is None:
            return
        while layout.count():
            item = layout.takeAt(0)
            child_layout = item.layout()
            if child_layout is not None:
                self._clear_layout_items(child_layout)

    def _populate_render_mode_layout(self):
        self._clear_layout_items(self._render_mode_layout)
        self._render_mode_layout.addWidget(self.body_module_panel)
        self._render_mode_layout.addWidget(self.blocks_panel)
        self._render_mode_layout.addWidget(self.editor, stretch=1)
        self._render_mode_layout.addWidget(self.console)

    def _populate_edit_mode_layout(self):
        self._clear_layout_items(self._edit_mode_left_layout)
        self._clear_layout_items(self._edit_mode_right_layout)
        self._edit_mode_left_layout.addWidget(self.body_module_panel)
        self._edit_mode_left_layout.addWidget(self.blocks_panel)
        self._edit_mode_left_layout.addWidget(self.console)
        self._edit_mode_right_layout.addWidget(self.editor, stretch=1)

    def geometry_layout_mode(self):
        return "edit" if str(getattr(self, "_geometry_layout_mode", "render")).strip().lower().startswith("edit") else "render"

    def render_panel_visible(self):
        return self.geometry_layout_mode() == "render"

    def _normalized_render_workspace_sizes(self, sizes):
        values = list(sizes or [])
        if len(values) < 2:
            values = [700, 1100]
        left = max(0, int(values[0] or 0))
        right = max(0, int(values[1] or 0))
        total = left + right
        if total <= 0:
            return [700, 1100]
        min_left = 320
        min_right = 720
        max_left = max(min_left, total - min_right)
        if right < min_right or left < min_left or left > max_left:
            target_left = int(total * 0.38)
            left = min(max_left, max(min_left, target_left))
            right = max(min_right, total - left)
        return [int(left), int(right)]

    def _normalized_editor_workspace_sizes(self, sizes):
        values = list(sizes or [])
        if len(values) < 2:
            values = [540, 460]
        left = max(0, int(values[0] or 0))
        right = max(0, int(values[1] or 0))
        total = left + right
        if total <= 0:
            return [540, 460]
        min_left = 420
        min_right = 300
        max_left = max(min_left, total - min_right)
        if right < min_right or left < min_left or left > max_left:
            target_left = int(total * 0.54)
            left = min(max_left, max(min_left, target_left))
            right = max(min_right, total - left)
        return [int(left), int(right)]

    def _prioritize_native_render_workspace(self):
        splitter = getattr(self, "_workspace_splitter", None)
        if splitter is None:
            return
        sizes = splitter.sizes()
        total = sum(max(0, int(v or 0)) for v in sizes[:2]) or max(1, self.width())
        desired_left = max(300, min(420, total - 900))
        desired_right = max(900, total - desired_left)
        if desired_left + desired_right > total:
            desired_left = max(300, total - desired_right)
        if desired_left <= 0 or desired_right <= 0:
            return
        self._saved_render_mode_workspace_sizes = self._normalized_render_workspace_sizes([desired_left, desired_right])
        self._workspace_splitter_adjusting = True
        try:
            splitter.setSizes(self._saved_render_mode_workspace_sizes)
        finally:
            QTimer.singleShot(0, lambda: setattr(self, "_workspace_splitter_adjusting", False))

    def _native_render_panel_active(self):
        current = getattr(self, "render_stack", None)
        if current is None:
            return False
        widget = current.currentWidget()
        return widget in (getattr(self, "native_gview2d_panel", None), getattr(self, "native_gview3d_panel", None))

    def _update_native_render_focus_state(self):
        native_active = self._native_render_panel_active() and self.geometry_layout_mode() == "render"
        controls_container = getattr(self, "_geo_controls_container", None)
        if controls_container is not None:
            controls_container.setVisible(not native_active)
        status_label = getattr(self, "lbl_render_status", None)
        if status_label is not None:
            status_label.setVisible(not native_active)
        layout = getattr(self, "_geo_right_layout", None)
        if layout is not None:
            if native_active:
                layout.setContentsMargins(4, 4, 4, 4)
                layout.setSpacing(4)
            else:
                layout.setContentsMargins(8, 8, 8, 8)
                layout.setSpacing(6)
        if native_active:
            self._prioritize_native_render_workspace()

    def _on_render_stack_changed(self, _index):
        self._update_native_render_focus_state()

    def _close_native_render_if_active(self):
        if self._native_render_panel_active():
            self._return_from_native_interface()

    def _update_geometry_mode_buttons(self):
        btn_toggle = getattr(self, "btn_geo_mode_toggle", None)
        mode = self.geometry_layout_mode()
        if btn_toggle is not None:
            if mode == "render":
                btn_toggle.setText("Edit Mode")
                btn_toggle.setToolTip("Switch the Geometry tab to Edit Mode.")
            else:
                btn_toggle.setText("Render Mode")
                btn_toggle.setToolTip("Switch the Geometry tab to Render Mode.")

    def _apply_render_workspace_visibility(self, visible):
        visible = bool(visible)
        right = getattr(self, "_geo_right_panel", None)
        splitter = getattr(self, "_workspace_splitter", None)
        current = splitter.sizes() if splitter is not None else []
        if visible:
            restore = self._normalized_render_workspace_sizes(
                self._saved_render_mode_workspace_sizes or current or [700, 1100]
            )
            if splitter is not None:
                self._workspace_splitter_adjusting = True
            try:
                if right is not None:
                    right.setVisible(True)
                if splitter is not None:
                    splitter.setSizes([max(420, int(restore[0] or 0)), max(620, int(restore[1] or 0))])
            finally:
                if splitter is not None:
                    QTimer.singleShot(0, lambda: setattr(self, "_workspace_splitter_adjusting", False))
        else:
            if len(current) >= 2 and int(current[1] or 0) > 0:
                self._saved_render_mode_workspace_sizes = self._normalized_render_workspace_sizes(current[:2])
            if splitter is not None:
                self._workspace_splitter_adjusting = True
            try:
                if right is not None:
                    right.setVisible(False)
                if splitter is not None:
                    total = sum(max(0, int(v or 0)) for v in current[:2]) or max(1, self.width())
                    splitter.setSizes([max(1, total), 0])
            finally:
                if splitter is not None:
                    QTimer.singleShot(0, lambda: setattr(self, "_workspace_splitter_adjusting", False))

    def _toggle_geometry_layout_mode(self):
        self.set_geometry_layout_mode("edit" if self.geometry_layout_mode() == "render" else "render")

    def set_geometry_layout_mode(self, mode):
        self._apply_geometry_layout_mode(mode, preserve=True)

    def _apply_geometry_layout_mode(self, mode, preserve=True):
        requested = "edit" if str(mode or "").strip().lower().startswith("edit") else "render"
        previous = self.geometry_layout_mode()
        if preserve and previous == "render":
            splitter = getattr(self, "_workspace_splitter", None)
            if splitter is not None:
                sizes = splitter.sizes()
                if len(sizes) >= 2 and int(sizes[1] or 0) > 0:
                    self._saved_render_mode_workspace_sizes = self._normalized_render_workspace_sizes(sizes[:2])
        elif preserve and previous == "edit":
            splitter = getattr(self, "_editor_workspace_splitter", None)
            if splitter is not None:
                self._saved_geo_editor_splitter_sizes = self._normalized_editor_workspace_sizes(splitter.sizes()[:2])

        if requested == "edit":
            self._populate_edit_mode_layout()
            self._geo_mode_stack.setCurrentWidget(self._edit_mode_page)
            self._apply_render_workspace_visibility(False)
            self._geometry_layout_mode = "edit"
            editor_splitter = getattr(self, "_editor_workspace_splitter", None)
            sizes = self._normalized_editor_workspace_sizes(
                getattr(self, "_saved_geo_editor_splitter_sizes", None) or [540, 460]
            )
            if editor_splitter is not None:
                editor_splitter.setSizes(sizes)
        else:
            self._populate_render_mode_layout()
            self._geo_mode_stack.setCurrentWidget(self._render_mode_page)
            self._apply_render_workspace_visibility(True)
            self._geometry_layout_mode = "render"

        self._update_geometry_mode_buttons()
        self._apply_render_mode_block_compaction()
        self._update_native_render_focus_state()

    def restore_workspace_layout_state(self, editor_sizes=None, layout_mode="render"):
        editor_splitter = getattr(self, "_editor_workspace_splitter", None)
        sizes = list(editor_sizes or [])
        if len(sizes) >= 2 and sum(max(0, int(v)) for v in sizes[:2]) > 0:
            self._saved_geo_editor_splitter_sizes = self._normalized_editor_workspace_sizes(sizes[:2])
            if editor_splitter is not None:
                editor_splitter.setSizes(self._saved_geo_editor_splitter_sizes)
        workspace_splitter = getattr(self, "_workspace_splitter", None)
        if workspace_splitter is not None:
            current = workspace_splitter.sizes()
            if len(current) >= 2 and int(current[1] or 0) > 0:
                self._saved_render_mode_workspace_sizes = self._normalized_render_workspace_sizes(current[:2])
        requested = "edit" if str(layout_mode or "").strip().lower().startswith("edit") else "render"
        if requested == self.geometry_layout_mode():
            if requested == "render":
                self._apply_render_workspace_visibility(True)
            else:
                self._apply_render_workspace_visibility(False)
                if editor_splitter is not None and self._saved_geo_editor_splitter_sizes:
                    editor_splitter.setSizes(self._saved_geo_editor_splitter_sizes)
            self._update_geometry_mode_buttons()
            self._apply_render_mode_block_compaction()
            self._update_native_render_focus_state()
            return
        self._apply_geometry_layout_mode(requested, preserve=False)

    def _refresh_geo_path_label(self):
        if not hasattr(self, "lbl_geo_path"):
            return
        label = ""
        if self._geo_path:
            label = os.path.basename(self._geo_path)
            if hasattr(self, "editor") and self.has_unsaved_changes():
                label = f"{label} *"
        elif hasattr(self, "editor") and self.has_unsaved_changes():
            label = "Unsaved *"
        self.lbl_geo_path.setText(label)
        self.lbl_geo_path.setVisible(bool(label))

