    def _default_geo_material_link(self):
        return {
            "source_kind": "",
            "source_path": "",
            "material_paths": [],
            "material_names": [],
            "source_label": "",
        }

    def _geo_material_link_sidecar_path(self, geo_path=None):
        target = Path(geo_path) if geo_path else (Path(self._geo_path) if self._geo_path else None)
        if target is None:
            return None
        return target.with_suffix(target.suffix + ".material_link.json")

    def _geo_material_link_display_name(self, raw_name):
        text = str(raw_name or "").strip().strip('"')
        if not text:
            return ""
        path = Path(text)
        return path.name or text

    def _geo_material_store_path(self, raw_path, base_dir):
        text = str(raw_path or "").strip()
        if not text:
            return ""
        candidate = Path(text)
        if not candidate.is_absolute():
            candidate = Path(base_dir) / candidate
        try:
            resolved = candidate.resolve()
        except Exception:
            resolved = candidate
        try:
            return str(resolved.relative_to(Path(base_dir).resolve()))
        except Exception:
            return str(resolved)

    def _geo_material_resolve_path(self, raw_path, base_dir):
        text = str(raw_path or "").strip()
        if not text:
            return ""
        candidate = Path(text)
        if not candidate.is_absolute():
            candidate = Path(base_dir) / candidate
        try:
            return str(candidate.resolve())
        except Exception:
            return str(candidate)

    def _mfname_material_labels_from_text(self, text):
        names = []
        for line in (text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n"):
            match = re.match(r"^\s*MFNAME\s+([^\[]+)", line, re.IGNORECASE)
            if not match:
                continue
            raw = match.group(1).strip()
            if not raw:
                continue
            name = raw if (".mat" in raw.lower() and " " in raw.strip()) else raw.split()[0]
            display_name = self._geo_material_link_display_name(name)
            if display_name:
                names.append(display_name)
        return names

    def _parse_geo_header_material_line(self, line):
        match = re.match(r"^\s*(\d+)\s*-\s*(.+?)\s*$", line or "")
        if not match:
            return None
        try:
            material_id = int(match.group(1))
        except ValueError:
            return None
        name = match.group(2).strip()
        if not name:
            return None
        return material_id, name

    def _header_material_entries(self, header_lines=None):
        lines = header_lines if header_lines is not None else self._geo_header_lines
        entries = []
        for line in list(lines or [])[1:]:
            parsed = self._parse_geo_header_material_line(line)
            if parsed:
                entries.append(parsed)
        return entries

    def _linked_material_source_label(self):
        link = getattr(self, "_geo_material_link", {}) or {}
        label = str(link.get("source_label", "") or "").strip()
        if label:
            return label
        kind = str(link.get("source_kind", "") or "").strip().lower()
        if kind == "current_sim":
            return "current .in"
        if kind == "in":
            path = str(link.get("source_path", "") or "").strip()
            return Path(path).name if path else ".in file"
        if kind == "manual":
            return label or "saved material list"
        if kind == "materials":
            material_paths = [str(p).strip() for p in link.get("material_paths", []) if str(p).strip()]
            if material_paths:
                if len(material_paths) == 1:
                    return Path(material_paths[0]).name
                return f"{len(material_paths)} material files"
            return "selected material files"
        return ""

    def _resolve_geo_linked_material_names(self):
        link = getattr(self, "_geo_material_link", {}) or {}
        kind = str(link.get("source_kind", "") or "").strip().lower()
        if not kind:
            return [self._geo_material_link_display_name(name) for name in link.get("material_names", []) if str(name).strip()]

        if kind == "current_sim" and self._sim_tab is not None and not getattr(self._sim_tab, "_in_path", None):
            try:
                names = self._mfname_material_labels_from_text(self._sim_tab._get_text())
                if names:
                    return names
            except Exception:
                pass

        if kind == "in":
            source_path = str(link.get("source_path", "") or "").strip()
            if source_path:
                try:
                    source_obj = Path(source_path)
                    if self._sim_tab is not None and getattr(self._sim_tab, "_in_path", None):
                        active_in = Path(self._sim_tab._in_path)
                        try:
                            same_file = source_obj.resolve() == active_in.resolve()
                        except Exception:
                            same_file = str(source_obj) == str(active_in)
                        if same_file:
                            names = self._mfname_material_labels_from_text(self._sim_tab._get_text())
                        else:
                            names = self._mfname_material_labels_from_text(_decode_text_bytes(source_obj.read_bytes()))
                    else:
                        names = self._mfname_material_labels_from_text(_decode_text_bytes(source_obj.read_bytes()))
                    if names:
                        return names
                except Exception:
                    pass

        if kind == "materials":
            names = []
            for path_text in link.get("material_paths", []):
                name = self._geo_material_link_display_name(path_text)
                if name:
                    names.append(name)
            if names:
                return names

        return [self._geo_material_link_display_name(name) for name in link.get("material_names", []) if str(name).strip()]

    def _current_geo_material_entries(self, live=False):
        if live:
            names = self._resolve_geo_linked_material_names()
            if names:
                if self._geo_material_link.get("source_kind"):
                    self._geo_material_link["material_names"] = list(names)
                return [(idx, name) for idx, name in enumerate(names, start=1)]
        header_entries = self._header_material_entries(self._geo_header_lines)
        if header_entries:
            return header_entries
        names = [self._geo_material_link_display_name(name) for name in self._geo_material_link.get("material_names", []) if str(name).strip()]
        if names:
            return [(idx, name) for idx, name in enumerate(names, start=1)]
        return []

    def _geo_material_link_summary(self):
        entries = self._current_geo_material_entries(live=False)
        if self._geo_material_link.get("source_kind"):
            source = self._linked_material_source_label() or "linked source"
            return f"Linked materials: {len(entries)} item(s) from {source}." if entries else f"Linked materials source: {source}."
        if entries:
            return f"Header materials: {len(entries)} item(s) listed above the first separator."
        return "No linked materials. Use Tools > Linked Materials to sync MFNAME labels into this .geo."

    def _update_geo_material_link_ui(self):
        summary = self._geo_material_link_summary()
        if hasattr(self, "_geo_tools_btn"):
            self._geo_tools_btn.setToolTip(
                "Geometry help, material creation, and linked material labels.\n\n" + summary
            )
        if hasattr(self, "lbl_geo_path"):
            path_label = self._geo_path if self._geo_path else "Unsaved geometry"
            self.lbl_geo_path.setToolTip(f"{path_label}\n{summary}")
        self._refresh_geo_path_label()

    def _apply_geo_material_names_to_header(self, material_names):
        names = [self._geo_material_link_display_name(name) for name in (material_names or []) if self._geo_material_link_display_name(name)]
        header = list(self._geo_header_lines or ["Title"])
        if not header:
            header = ["Title"]
        title = header[0] if header else "Title"
        extras = [line for line in header[1:] if self._parse_geo_header_material_line(line) is None]
        new_header = [title]
        new_header.extend(f"{idx}- {name}" for idx, name in enumerate(names, start=1))
        new_header.extend(extras)
        if new_header == list(self._geo_header_lines or []):
            return False
        self._geo_header_lines = new_header
        self._write_model_to_editor()
        return True

    def _save_geo_material_link(self, geo_path):
        sidecar = self._geo_material_link_sidecar_path(geo_path)
        if sidecar is None:
            return
        link = getattr(self, "_geo_material_link", {}) or {}
        kind = str(link.get("source_kind", "") or "").strip().lower()
        if not kind:
            try:
                if sidecar.exists():
                    sidecar.unlink()
            except Exception:
                pass
            return
        base_dir = Path(geo_path).parent
        saved_kind = "manual" if kind == "current_sim" else kind
        payload = {
            "source_kind": saved_kind,
            "source_label": str(link.get("source_label", "") or "").strip(),
            "material_names": [self._geo_material_link_display_name(name) for name in link.get("material_names", []) if str(name).strip()],
            "saved_at": datetime.now().isoformat(timespec="seconds"),
        }
        source_path = str(link.get("source_path", "") or "").strip()
        if kind == "in" and source_path:
            payload["source_path"] = self._geo_material_store_path(source_path, base_dir)
        material_paths = [str(path_text).strip() for path_text in link.get("material_paths", []) if str(path_text).strip()]
        if kind == "materials" and material_paths:
            payload["material_paths"] = [self._geo_material_store_path(path_text, base_dir) for path_text in material_paths]
        sidecar.write_text(json.dumps(payload, indent=2), encoding="utf-8")

    def _load_geo_material_link(self, geo_path):
        self._geo_material_link = self._default_geo_material_link()
        sidecar = self._geo_material_link_sidecar_path(geo_path)
        if sidecar is None or not sidecar.exists():
            self._update_geo_material_link_ui()
            return
        try:
            data = json.loads(sidecar.read_text(encoding="utf-8"))
            base_dir = Path(geo_path).parent
            link = self._default_geo_material_link()
            link["source_kind"] = str(data.get("source_kind", "") or "").strip().lower()
            link["source_label"] = str(data.get("source_label", "") or "").strip()
            link["material_names"] = [
                self._geo_material_link_display_name(name)
                for name in data.get("material_names", [])
                if str(name).strip()
            ]
            source_path = str(data.get("source_path", "") or "").strip()
            if source_path:
                link["source_path"] = self._geo_material_resolve_path(source_path, base_dir)
            material_paths = []
            for raw_path in data.get("material_paths", []):
                resolved = self._geo_material_resolve_path(raw_path, base_dir)
                if resolved:
                    material_paths.append(resolved)
            link["material_paths"] = material_paths
            self._geo_material_link = link
        except Exception as exc:
            self.console.log(f"[GEO] Failed to load linked materials: {exc}\n", "warn")
            self._geo_material_link = self._default_geo_material_link()
        self._update_geo_material_link_ui()

    def _geo_material_selector_hint(self, text, entries):
        match = re.match(r"^\s*(-?\d+)", str(text or ""))
        if not match:
            if entries:
                return "Pick a linked material label or type an integer material id."
            return "Type an integer material id. Positive ids follow MFNAME order when linked."
        material_id = int(match.group(1))
        if material_id <= 0:
            return "Vacuum / void region."
        entry_map = {mid: name for mid, name in entries}
        if material_id in entry_map:
            return f"MFNAME #{material_id}: {entry_map[material_id]}"
        if entries:
            return f"Material #{material_id} is outside the linked MFNAME list."
        return f"Material #{material_id}."

    def _build_geo_material_selector(self, initial_material=1):
        entries = self._current_geo_material_entries(live=True)
        widget = QWidget()
        row = QHBoxLayout(widget)
        row.setContentsMargins(0, 0, 0, 0)
        row.setSpacing(8)

        combo = QComboBox()
        combo.setEditable(True)
        combo.setInsertPolicy(QComboBox.InsertPolicy.NoInsert)
        combo.setStyleSheet(combo_css())
        combo.setMinimumWidth(180)
        combo.setToolTip(
            "Material id for this BODY or MODULE. Positive ids follow the linked MFNAME order when available; "
            "0 or negative means vacuum."
        )
        for material_id, name in entries:
            combo.addItem(f"{material_id}- {name}", material_id)
        matching_text = next((f"{mid}- {name}" for mid, name in entries if int(mid) == int(initial_material)), None)
        combo.setCurrentText(matching_text or str(initial_material))
        if combo.lineEdit() is not None:
            combo.lineEdit().setPlaceholderText("1")

        hint = QLabel()
        hint.setWordWrap(True)
        hint.setMinimumWidth(180)
        hint.setStyleSheet(label_css(P["fg2"]))

        def refresh_hint(_text=""):
            hint.setText(self._geo_material_selector_hint(combo.currentText(), entries))

        combo.currentTextChanged.connect(refresh_hint)
        refresh_hint()

        row.addWidget(combo)
        row.addWidget(hint, 1)
        return widget, combo

    def _geo_material_selector_value(self, combo):
        text = combo.currentText() if hasattr(combo, "currentText") else combo.text()
        match = re.match(r"^\s*(-?\d+)", str(text or ""))
        if not match:
            raise ValueError("Material must be an integer.")
        return int(match.group(1))

    def _set_geo_material_link(self, link_data, refresh_header=True):
        link = self._default_geo_material_link()
        for key in link:
            if key == "material_paths":
                link[key] = [str(path_text).strip() for path_text in link_data.get(key, []) if str(path_text).strip()]
            elif key == "material_names":
                link[key] = [self._geo_material_link_display_name(name) for name in link_data.get(key, []) if str(name).strip()]
            else:
                link[key] = str(link_data.get(key, "") or "").strip() if isinstance(link[key], str) else link[key]
        self._geo_material_link = link
        self._update_geo_material_link_ui()
        if refresh_header:
            self._refresh_geo_material_link()

    def _refresh_geo_material_link(self, quiet=False):
        link = getattr(self, "_geo_material_link", {}) or {}
        kind = str(link.get("source_kind", "") or "").strip().lower()
        if not kind:
            if not quiet:
                QMessageBox.information(self, "Linked Materials", "No material link is set for this geometry.")
            return False
        names = self._resolve_geo_linked_material_names()
        if not names:
            if not quiet:
                QMessageBox.warning(
                    self,
                    "Linked Materials",
                    "No materials could be resolved from the linked source.\n\n"
                    "Check the linked .in/.mat files or relink the geometry.",
                )
            return False
        self._geo_material_link["material_names"] = list(names)
        changed = self._apply_geo_material_names_to_header(names)
        self._update_geo_material_link_ui()
        source = self._linked_material_source_label() or "linked source"
        if not quiet or changed:
            message = f"[GEO] Linked materials refreshed from {source}: {len(names)} item(s).\n"
            self.console.log(message, "info" if changed else "ok")
        if not quiet:
            self.status_message.emit(f"Linked materials: {len(names)} from {source}")
        return True

    def _clear_geo_material_link(self):
        self._sync_model_from_editor()
        header = list(self._geo_header_lines or ["Title"])
        if not header:
            header = ["Title"]
        title = header[0]
        extras = [line for line in header[1:] if self._parse_geo_header_material_line(line) is None]
        self._geo_header_lines = [title] + extras
        self._geo_material_link = self._default_geo_material_link()
        self._write_model_to_editor()
        self._update_geo_material_link_ui()
        self.console.log("[GEO] Material link cleared.\n", "info")
        self.status_message.emit("Linked materials cleared")

    def _link_geo_materials_from_current_input(self):
        if self._sim_tab is None:
            QMessageBox.warning(self, "Linked Materials", "The Simulation tab is not available in this session.")
            return
        names = self._mfname_material_labels_from_text(self._sim_tab._get_text())
        if not names:
            QMessageBox.warning(self, "Linked Materials", "The current .in file has no MFNAME material entries.")
            return
        source_kind = "in" if getattr(self._sim_tab, "_in_path", None) else "current_sim"
        source_path = str(getattr(self._sim_tab, "_in_path", "") or "").strip()
        source_label = Path(source_path).name if source_path else "current .in (unsaved)"
        self._set_geo_material_link({
            "source_kind": source_kind,
            "source_path": source_path,
            "material_paths": [],
            "material_names": names,
            "source_label": source_label,
        })

    def _link_geo_materials_from_input_file(self):
        start_folder = str(Path(getattr(self._sim_tab, "_in_path", "")).parent) if self._sim_tab is not None and getattr(self._sim_tab, "_in_path", None) else str(Path(self._geo_path).parent) if self._geo_path else str(Path.cwd())
        path, _ = QFileDialog.getOpenFileName(
            self,
            "Choose linked .in file",
            start_folder,
            "PENELOPE input (*.in);;All files (*.*)",
        )
        if not path:
            return
        try:
            text = _decode_text_bytes(Path(path).read_bytes())
        except Exception as exc:
            QMessageBox.critical(self, "Linked Materials", f"Could not read input file:\n{exc}")
            return
        names = self._mfname_material_labels_from_text(text)
        if not names:
            QMessageBox.warning(self, "Linked Materials", "The selected .in file has no MFNAME material entries.")
            return
        self._set_geo_material_link({
            "source_kind": "in",
            "source_path": str(Path(path)),
            "material_paths": [],
            "material_names": names,
            "source_label": Path(path).name,
        })

    def _link_geo_materials_from_files(self):
        if self._sim_tab is not None:
            start_folder = str(self._sim_tab._material_list_folder())
        elif self._geo_path:
            start_folder = str(Path(self._geo_path).parent)
        else:
            start_folder = str(Path.cwd())
        paths, _ = QFileDialog.getOpenFileNames(
            self,
            "Choose material files",
            start_folder,
            "PENELOPE material (*.mat);;All files (*.*)",
        )
        if not paths:
            return
        names = [self._geo_material_link_display_name(path) for path in paths if self._geo_material_link_display_name(path)]
        self._set_geo_material_link({
            "source_kind": "materials",
            "source_path": "",
            "material_paths": list(paths),
            "material_names": names,
            "source_label": f"{len(names)} material file(s)",
        })

    def _show_help(self):
        show_help_dialog(
            self,
            "Geometry Viewer Help",
            f"""
            <h2 style="color:{P['accent']};">Geometry Viewer</h2>
            <p>This tab edits and previews PENELOPE <b>.geo</b> files. The left side keeps the raw geometry code visible; the block lists above it give a safer way to navigate, edit, duplicate, and renumber geometry pieces.</p>
            <h3>Core Workflow</h3>
            <ul>
              <li><b>New/Open/Save/Save As</b> manage the active geometry file using PENELOPE-compatible text encoding and formatting.</li>
              <li><b>ADD</b> inserts structured SURFACE, BODY, and MODULE blocks.</li>
              <li><b>Tools &gt; Linked Materials</b> can pull MFNAME order from a current/chosen <code>.in</code> file or a chosen group of <code>.mat</code> files and stamp them into the header rows before the first separator.</li>
              <li><b>Body/Module Blocks</b> show only BODY/MODULE definitions, including material IDs and labels for quick selection.</li>
              <li><b>Surface Blocks</b> show only SURFACE definitions. Click to jump the code editor near that block; double-click to edit through forms.</li>
            </ul>
            <h3>Editing Tools</h3>
            <ul>
              <li><b>Duplicate</b> copies a selected block. BODY/MODULE duplication can also duplicate linked surfaces so arrays of rods or repeated objects can be made safely.</li>
              <li><b>Tools &gt; Auto ID</b> renumbers SURFACE and BODY/MODULE IDs in file order and updates references.</li>
              <li><b>Tools &gt; Label Manager</b> opens a bulk label manager for SURFACE/BODY/MODULE blocks.</li>
              <li><b>Up/Down</b> rearrange selected SURFACE or BODY/MODULE blocks within their file order.</li>
              <li><b>Group</b> creates visual groups for SURFACE blocks or BODY/MODULE blocks without changing the underlying <code>.geo</code> code.</li>
              <li>BODY and MODULE IDs share the same numbering sequence.</li>
            </ul>
            <h3>PENELOPE Geometry Rules (manual-based)</h3>
            <ul>
              <li><b>SURFACE parameters are flexible:</b> parameter lines are optional, can appear in any order, and missing values use defaults.</li>
              <li><b>Scale constraints:</b> <code>X-SCALE</code>, <code>Y-SCALE</code>, <code>Z-SCALE</code> should be positive.</li>
              <li><b>Linear plane form:</b> use <code>INDICES=(0,0,0,0,0)</code> with <code>AX</code>, <code>AY</code>, <code>AZ</code>, <code>A0</code> to define general planes.</li>
              <li><b>Avoid double planes when possible:</b> replacing them with two single planes is usually clearer and less ambiguous.</li>
              <li><b><code>SURFACE*</code> behavior:</b> starred surfaces are fixed and do not move with module transformations or clones.</li>
              <li><b>BODY/MODULE limits must be explicit:</b> include all limiting surfaces/bodies/modules needed to close the intended volume.</li>
              <li><b>Vacuum definition:</b> <code>MATERIAL=0</code> (or negative) represents vacuum for void regions.</li>
              <li><b>Module topology:</b> descendants must stay contained, sister regions should not overlap, and connected limiting volumes are expected.</li>
              <li><b>Root enclosure quality:</b> a single convex enclosure module is the safest setup for stable tracking.</li>
              <li><b>Side pointer reminder:</b> in common quadric usage, <code>SIDE POINTER=(-1)</code> corresponds to the inside side.</li>
              <li><b>Clone use:</b> <code>CLONE</code> is for repeating modules; avoid overlap between original and clones.</li>
            </ul>
            <h3>Reduced vs Implicit Quadrics</h3>
            <ul>
              <li><b>Reduced form (simple INDICES mode):</b> reduced quadrics use <code>INDICES=(I1,I2,I3,I4,I5)</code> for the canonical equation <code>I1*x^2 + I2*y^2 + I3*z^2 + I4*z + I5 = 0</code>.</li>
              <li><b>What INDICES do:</b> they choose the quadric family and, in the canonical frame, the sign/opening. Example: <code>INDICES=(1,1,0,-1,0)</code> means <code>x^2 + y^2 - z = 0</code>, a paraboloid opening in <code>+Z</code>. Changing it to <code>(1,1,0,1,0)</code> flips the opening to <code>-Z</code>.</li>
              <li><b>Why Z is special in reduced form:</b> the reduced equation has a linear <code>z</code> term, but no linear <code>x</code> or <code>y</code> term. That is why paraboloids, parabolic cylinders, hyperbolic paraboloids, and angular planes are naturally defined as canonical <code>Z</code>-axis shapes.</li>
              <li><b>When indices alone are enough:</b> shapes with only quadratic axis terms can sometimes change principal axis by permuting the first three indices. Example: a cylinder along <code>Z</code> is <code>(1,1,0,0,-1)</code>, while a cylinder along <code>X</code> is <code>(0,1,1,0,-1)</code>.</li>
              <li><b>When angles are required:</b> if the desired surface would need a linear <code>x</code> or <code>y</code> term, reduced indices alone are not enough. A paraboloid along <code>+X</code> would be <code>y^2 + z^2 - x = 0</code>, so it must be built by keeping the canonical reduced form and applying <code>OMEGA/THETA/PHI</code>, or by switching to the full implicit coefficients.</li>
              <li><b>Implicit form (complex/general quadric):</b> use <code>INDICES=(0,0,0,0,0)</code> with <code>AXX</code>, <code>AXY</code>, <code>AXZ</code>, <code>AYY</code>, <code>AYZ</code>, <code>AZZ</code>, <code>AX</code>, <code>AY</code>, <code>AZ</code>, and <code>A0</code> to define the full quadric equation directly. This is the most flexible option when the reduced preset is not enough.</li>
              <li><b>Transform reminder:</b> conceptually PENELOPE applies scale, then rotation, then translation. The order of parameter lines in the file is mainly for readability; the geometry meaning comes from the values themselves.</li>
              <li><b>Practical rule:</b> use reduced presets plus orientation angles for most standard shapes, and fall back to the implicit form when you need a general tilted quadric or a surface that is awkward to express in canonical reduced form.</li>
            </ul>
            <h3>Rendering</h3>
            <ul>
              <li><b>2D Cross-section</b> renders a selected plane with center/span controls and keyboard pan/zoom after the image is focused. <b>Native 2D</b> opens an in-tab bridge to PENELOPE's own <code>gview2d.exe</code> with the current editor geometry staged automatically.</li>
              <li><b>3D View</b> renders within explicit min/max axis limits. Color mode can be by material or by body. Use <b>Static voxels</b> for the current high-quality image or <b>Lite boundary cloud</b> for a faster approximate sampled preview. <b>Native 3D</b> opens the same kind of in-tab bridge for <code>gview3d.exe</code>.</li>
              <li><b>Reset</b> recomputes view limits from geometry shifts/planes after objects are added or moved.</li>
            </ul>
            <h3>Debugging with gview2d (expanded)</h3>
            <ul>
              <li><b>1) Start coarse, then refine:</b> render at low resolution first, then increase only after geometry looks correct.</li>
              <li><b>2) Sweep the cut plane:</b> move the fixed coordinate through the model to verify continuity and detect missing/extra limits.</li>
              <li><b>3) Read symptoms fast:</b> empty slices often mean wrong SIDE POINTER signs, wrong axis/index choices, or ranges not covering your geometry.</li>
              <li><b>4) Validate limits directly:</b> for planes, check <code>AX/AY/AZ/A0</code>; for shifted quadrics, check <code>X/Y/Z-SHIFT</code> and scales.</li>
              <li><b>5) Use geometry.rep as ground truth:</b> after rendering/parsing, inspect <code>geometry.rep</code> for processed geometry and diagnostic messages. The native bridge watches the session folder and re-imports the newest <code>.rep</code> back into Studio when it appears.</li>
              <li><b>6) Iterate with small edits:</b> fix one issue at a time (sign, axis, one surface id), re-render, and confirm before batch changes.</li>
            </ul>
            <h3>Gotchas</h3>
            <ul>
              <li>Zero-thickness or duplicated planes can be valid, but can confuse visual interpretation.</li>
              <li>For current shielding cases, the source should usually travel along the same axis used by the wall and phantom geometry.</li>
              <li>After changing geometry used by a simulation, old <code>.dat</code>/<code>.dmp</code> results should not be reused.</li>
            </ul>
            """,
        )

    def _open_material_builder(self):
        exe = (self._material_exe or "").strip() or _default_material_exe_path()
        output_dir = self._default_material_builder_output_dir(exe)
        if exe:
            self._material_exe = exe
        dlg = MaterialCreatorDialog(exe, output_dir, self)
        self._material_dialogs.append(dlg)

        def cleanup(_obj=None, dialog=dlg):
            if dialog in self._material_dialogs:
                self._material_dialogs.remove(dialog)

        dlg.destroyed.connect(cleanup)
        dlg.show()

    def _default_material_builder_output_dir(self, exe_path=""):
        sim_tab = getattr(self, "_sim_tab", None)
        project_root = str(getattr(sim_tab, "_project_root", "") or "").strip() if sim_tab is not None else ""
        if project_root:
            try:
                root = Path(project_root)
                meta = dict(getattr(sim_tab, "_project_meta", {}) or {})
                folders = dict(meta.get("folders") or {})
                return str(root / folders.get("materials", PROJECT_DIR_MATERIALS))
            except Exception:
                pass
        resolved_exe = str(exe_path or "").strip()
        if resolved_exe:
            try:
                exe_folder = Path(resolved_exe).expanduser().resolve().parent
                return str(exe_folder)
            except Exception:
                try:
                    return str(Path(resolved_exe).expanduser().parent)
                except Exception:
                    pass
        return str(Path.cwd())

    def _open_gview2d_interface(self):
        self._open_gview_interface("2d")

    def _open_gview3d_interface(self):
        self._open_gview_interface("3d")

    def _return_from_native_interface(self):
        target = self._last_non_native_render_stack_index if self._last_non_native_render_stack_index in (0, 1) else 0
        self.render_stack.setCurrentIndex(target)
        if target == 1:
            self.lbl_render_status.setText("Lite preview")
        elif self.img_label.pixmap() is not None:
            self.lbl_render_status.setText("Done")
        else:
            self.lbl_render_status.setText("Ready")

    def _new_gview_session_dir(self, mode_key):
        mode_key = "2d" if str(mode_key).strip().lower().startswith("2") else "3d"
        if self._geo_path:
            try:
                root = Path(self._geo_path).resolve().parent / "_studio_gview"
            except Exception:
                root = Path(tempfile.gettempdir()) / "penelope_studio_v9" / "gview"
        else:
            root = Path(tempfile.gettempdir()) / "penelope_studio_v9" / "gview"
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
        session_dir = root / f"{mode_key}_{stamp}"
        session_dir.mkdir(parents=True, exist_ok=True)
        return session_dir

    def _stage_current_geometry_for_gview(self, target_dir, geo_name="geometry.geo"):
        target_dir = Path(target_dir)
        target_dir.mkdir(parents=True, exist_ok=True)
        geo_name = Path(str(geo_name or "geometry.geo")).name or "geometry.geo"
        staged = target_dir / geo_name
        export_text = self._prepared_geo_export_text(update_editor=False)
        export_bytes = _encode_text_bytes(_ascii_safe_geo_text(export_text))
        staged.write_bytes(export_bytes)
        alias_name = ""
        try:
            alias_name = Path(str(self._geo_path or "")).name
        except Exception:
            alias_name = ""
        alias_name = Path(str(alias_name or "")).name if alias_name else ""
        if alias_name and alias_name.lower() != geo_name.lower():
            try:
                (target_dir / alias_name).write_bytes(export_bytes)
            except Exception:
                pass
        return str(staged)

    def _open_gview_interface(self, mode):
        mode_key = "2d" if str(mode).strip().lower().startswith("2") else "3d"
        panel = self.native_gview2d_panel if mode_key == "2d" else self.native_gview3d_panel
        exe = (self._gview2d_exe if mode_key == "2d" else self._gview3d_exe) or (f"gview{mode_key}.exe")
        if self.geometry_layout_mode() != "render":
            self.set_geometry_layout_mode("render")
        if self.render_stack.currentWidget() not in (self.native_gview2d_panel, self.native_gview3d_panel):
            self._last_non_native_render_stack_index = self.render_stack.currentIndex()
        if not panel.is_running():
            panel.reset_session(exe_path=exe, work_dir=str(self._new_gview_session_dir(mode_key)))
        else:
            panel.set_executable_path(exe)
        panel.stage_current_geometry()
        self.render_stack.setCurrentWidget(panel)
        self._prioritize_native_render_workspace()
        self.lbl_render_status.setText(f"Native {panel._mode_label}")
        self.console.log(
            f"[GEO] Showing native {panel._mode_label} bridge inside the Geometry tab.\n",
            "info",
        )

    def _make_blocks_panel(self):
        grp = QGroupBox("Surface Blocks")
        grp.setStyleSheet(self._geometry_block_group_style(False))
        lay = QVBoxLayout(grp)
        lay.setContentsMargins(6, 6, 6, 6)
        lay.setSpacing(4)
        self.grp_blocks = grp

        self.lst_blocks = ReorderableBlockList()
        self.lst_blocks.setMinimumHeight(120)
        self.lst_blocks.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)
        self.lst_blocks.setStyleSheet(
            f"QListWidget {{ background:{P['bg']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:4px;"
            f" padding:2px; font-family:'Courier New'; font-size:11px; }}"
            f"QListWidget::item:selected {{ background:{P['sel']}; color:{P['fg']}; }}"
        )
        self.lst_blocks.itemDoubleClicked.connect(lambda _item: self._edit_selected_block())
        self.lst_blocks.currentRowChanged.connect(lambda _row: self._update_block_actions())
        self.lst_blocks.itemClicked.connect(lambda _item: self._jump_to_block(self.lst_blocks.row(_item)))
        self.lst_blocks.itemActivated.connect(lambda _item: self._jump_to_block(self.lst_blocks.row(_item)))
        self.lst_blocks.blocksReordered.connect(self._apply_block_list_reorder)

        self.btn_blocks_refresh = QPushButton("Refresh")
        self.btn_blocks_edit = QPushButton("Edit")
        self.btn_blocks_delete = QPushButton("Delete")
        self.btn_blocks_up = QPushButton("Up")
        self.btn_blocks_down = QPushButton("Down")
        block_btn_font_css = "QPushButton { font-size:10.5pt; }"
        for b, width in (
            (self.btn_blocks_refresh, 62),
            (self.btn_blocks_edit, 52),
            (self.btn_blocks_delete, 60),
            (self.btn_blocks_up, 46),
            (self.btn_blocks_down, 58),
        ):
            b.setStyleSheet(btn_css(P["bg2"], width) + block_btn_font_css)
            b.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)

        self.btn_blocks_clone_menu = QToolButton()
        self.btn_blocks_clone_menu.setText("Clone")
        self.btn_blocks_clone_menu.setToolTip("Duplicate or mirror the selected block")
        self.btn_blocks_clone_menu.setStyleSheet(
            f"QToolButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:4px; padding:4px 12px; font-size:10.5pt; }}"
            f"QToolButton:hover {{ background:{P['bg3']}; border-color:{P['accent']}; }}"
        )
        self.btn_blocks_clone_menu.setPopupMode(QToolButton.ToolButtonPopupMode.InstantPopup)
        clone_menu = QMenu(self.btn_blocks_clone_menu)
        clone_menu.setStyleSheet(
            f"QMenu {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; }}"
            f"QMenu::item:selected {{ background:{P['sel']}; }}"
        )
        clone_menu.addAction("Duplicate", self._duplicate_selected_block)
        clone_menu.addAction("Mirror", self._mirror_selected_block)
        self.btn_blocks_clone_menu.setMenu(clone_menu)

        self.btn_blocks_group_menu = QToolButton()
        self.btn_blocks_group_menu.setText("Group")
        self.btn_blocks_group_menu.setToolTip("Group or ungroup selected SURFACE blocks")
        self.btn_blocks_group_menu.setStyleSheet(
            f"QToolButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:4px; padding:4px 12px; font-size:10.5pt; }}"
            f"QToolButton:hover {{ background:{P['bg3']}; border-color:{P['accent']}; }}"
        )
        self.btn_blocks_group_menu.setPopupMode(QToolButton.ToolButtonPopupMode.InstantPopup)
        group_menu = QMenu(self.btn_blocks_group_menu)
        group_menu.setStyleSheet(
            f"QMenu {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; }}"
            f"QMenu::item:selected {{ background:{P['sel']}; }}"
        )
        group_menu.addAction("Group selected", self._group_selected_surfaces)
        group_menu.addAction("Ungroup selected", self._ungroup_selected_surfaces)
        self.btn_blocks_group_menu.setMenu(group_menu)
        self._geometry_block_action_specs = [
            (self.btn_blocks_refresh, 62, 54),
            (self.btn_blocks_edit, 52, 46),
            (self.btn_blocks_delete, 60, 52),
            (self.btn_blocks_clone_menu, 68, 56),
            (self.btn_blocks_group_menu, 66, 56),
            (self.btn_blocks_up, 46, 40),
            (self.btn_blocks_down, 58, 50),
        ]
        self._geometry_block_action_buttons = [
            self.btn_blocks_refresh,
            self.btn_blocks_edit,
            self.btn_blocks_delete,
            self.btn_blocks_clone_menu,
            self.btn_blocks_group_menu,
            self.btn_blocks_up,
            self.btn_blocks_down,
        ]
        content_row = QHBoxLayout()
        content_row.setContentsMargins(0, 0, 0, 0)
        content_row.setSpacing(6)
        actions_widget = QWidget()
        actions_widget.setSizePolicy(QSizePolicy.Policy.Preferred, QSizePolicy.Policy.Minimum)
        actions_lay = QGridLayout(actions_widget)
        actions_lay.setContentsMargins(0, 0, 0, 0)
        actions_lay.setHorizontalSpacing(4)
        actions_lay.setVerticalSpacing(4)
        actions_lay.addWidget(self.btn_blocks_refresh, 0, 0)
        actions_lay.addWidget(self.btn_blocks_edit, 0, 1)
        actions_lay.addWidget(self.btn_blocks_delete, 1, 0)
        actions_lay.addWidget(self.btn_blocks_clone_menu, 1, 1)
        actions_lay.addWidget(self.btn_blocks_group_menu, 2, 0, 1, 2)
        actions_lay.addWidget(self.btn_blocks_up, 3, 0)
        actions_lay.addWidget(self.btn_blocks_down, 3, 1)
        self.blocks_actions_layout = actions_lay
        self.blocks_actions_widget = actions_widget
        content_row.addWidget(actions_widget, 0, Qt.AlignmentFlag.AlignTop)
        content_row.addWidget(self.lst_blocks, 1)
        lay.addLayout(content_row)

        self.btn_blocks_refresh.clicked.connect(self._refresh_from_editor_and_labels)
        self.btn_blocks_edit.clicked.connect(self._edit_selected_block)
        self.btn_blocks_delete.clicked.connect(self._delete_selected_block)
        self.btn_blocks_up.clicked.connect(lambda: self._move_selected_block(-1))
        self.btn_blocks_down.clicked.connect(lambda: self._move_selected_block(1))
        self._update_block_actions()
        return grp

    def _make_body_module_panel(self):
        grp = QGroupBox("Body/Module Blocks")
        grp.setStyleSheet(self._geometry_block_group_style(False))
        lay = QVBoxLayout(grp)
        lay.setContentsMargins(6, 6, 6, 6)
        lay.setSpacing(4)
        self.grp_body_blocks = grp

        self.lst_body_blocks = QListWidget()
        self.lst_body_blocks.setMinimumHeight(84)
        self.lst_body_blocks.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)
        self.lst_body_blocks.setStyleSheet(
            f"QListWidget {{ background:{P['bg']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:4px;"
            f" padding:2px; font-family:'Courier New'; font-size:11px; }}"
            f"QListWidget::item:selected {{ background:{P['sel']}; color:{P['fg']}; }}"
        )
