    def _set_editor_text(self, text):
        self._updating_from_model = True
        try:
            self.editor.setPlainText(text)
        finally:
            self._updating_from_model = False

    def _geo_recovery_path(self, geo_path=None):
        target = str(geo_path or self._geo_path or "").strip()
        if target:
            try:
                path_obj = Path(target)
                return path_obj.with_suffix(path_obj.suffix + ".studio-recovery")
            except Exception:
                pass
        root = Path(__file__).resolve().parent / "logs" / "geometry_recovery"
        return root / "untitled_geometry.studio-recovery.geo"

    def _geo_settings_store(self):
        return QSettings(APP_SETTINGS_ORG, APP_SETTINGS_NAME)

    def _load_geo_autosave_interval_minutes(self):
        settings = self._geo_settings_store()
        try:
            minutes = int(settings.value("geo/autosave_interval_minutes", DEFAULT_GEO_AUTOSAVE_INTERVAL_MINUTES))
        except Exception:
            minutes = DEFAULT_GEO_AUTOSAVE_INTERVAL_MINUTES
        return max(0, minutes)

    def _save_geo_autosave_interval_minutes(self, minutes):
        self._geo_autosave_interval_minutes = max(0, int(minutes))
        settings = self._geo_settings_store()
        settings.setValue("geo/autosave_interval_minutes", int(self._geo_autosave_interval_minutes))

    def _toggle_render_gpu(self, _state):
        global _RENDER_GPU_ENABLED
        _RENDER_GPU_ENABLED = self.chk_render_gpu.isChecked()
        QSettings("CodAI", "PenelopeStudio").setValue("render/gpu_enabled", _RENDER_GPU_ENABLED)

    def _apply_geo_autosave_timer(self):
        if not hasattr(self, "_geo_autosave_timer"):
            return
        minutes = max(0, int(getattr(self, "_geo_autosave_interval_minutes", DEFAULT_GEO_AUTOSAVE_INTERVAL_MINUTES)))
        if minutes <= 0:
            self._geo_autosave_timer.stop()
            return
        self._geo_autosave_timer.setInterval(minutes * 60 * 1000)
        self._geo_autosave_timer.start()

    def _geo_autosave_root(self):
        if self._geo_path:
            try:
                return Path(self._geo_path).resolve().parent / "_studio_autosave"
            except Exception:
                pass
        project_geometry = self._project_geometry_folder()
        if project_geometry is not None:
            try:
                return Path(project_geometry).resolve() / "_studio_autosave"
            except Exception:
                pass
        return Path(__file__).resolve().parent / "logs" / "geometry_autosave"

    def _geo_autosave_stem(self):
        target = str(self._geo_path or "").strip()
        if target:
            try:
                return Path(target).stem or "geometry"
            except Exception:
                pass
        return "untitled_geometry"

    def _geo_autosave_signature(self, text):
        text = str(text or "")
        return hashlib.sha1(text.encode("utf-8", "ignore")).hexdigest()

    def _write_geo_autosave_snapshot(self, reason="autosave", text=None, force=False):
        try:
            current_text = self.editor.toPlainText() if text is None else str(text)
        except Exception:
            return None
        if not current_text.strip():
            return None
        save_text = _ascii_safe_geo_text(current_text.replace("\r\n", "\n").replace("\r", "\n"))
        signature = self._geo_autosave_signature(save_text)
        if not force and signature == getattr(self, "_last_geo_autosave_signature", ""):
            return None
        try:
            root = self._geo_autosave_root()
            root.mkdir(parents=True, exist_ok=True)
            stem = self._geo_autosave_stem()
            stamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
            safe_reason = re.sub(r"[^a-z0-9_]+", "_", str(reason or "autosave").strip().lower()) or "autosave"
            path = root / f"{stem}__{safe_reason}_{stamp}.geo"
            path.write_bytes(_encode_text_bytes(save_text))
            autosaves = sorted(root.glob(f"{stem}__*.geo"), key=lambda p: p.stat().st_mtime, reverse=True)
            for old_path in autosaves[MAX_GEO_AUTOSAVE_FILES:]:
                try:
                    old_path.unlink()
                except Exception:
                    pass
            self._last_geo_autosave_signature = signature
            return path
        except Exception as exc:
            self.console.log(f"[GEO] Autosave failed: {exc}\n", "warn")
            return None

    def _maybe_write_periodic_geo_autosave(self):
        if not getattr(self, "_geo_autosave_pending", False):
            return
        if not self.has_unsaved_changes():
            self._geo_autosave_pending = False
            return
        path = self._write_geo_autosave_snapshot("autosave")
        if path is not None:
            self._geo_autosave_pending = False
            self.console.log(f"[GEO] Autosave: {path}\n", "muted")

    def _edit_geo_autosave_interval(self):
        current = int(getattr(self, "_geo_autosave_interval_minutes", DEFAULT_GEO_AUTOSAVE_INTERVAL_MINUTES))
        minutes, ok = QInputDialog.getInt(
            self,
            "Geometry Autosave Interval",
            "Minutes between rotating autosaves (0 disables):",
            current,
            0,
            240,
            1,
        )
        if not ok:
            return
        self._save_geo_autosave_interval_minutes(minutes)
        self._apply_geo_autosave_timer()
        if minutes <= 0:
            msg = "Geometry autosave disabled."
        else:
            msg = f"Geometry autosave interval set to {minutes} minute(s)."
        self.status_message.emit(msg)
        self.console.log(f"[GEO] {msg}\n", "info")

    def _project_geometry_folder(self):
        project_root = str(getattr(self, "_project_root", "") or "").strip()
        if not project_root:
            return None
        meta = dict(getattr(self, "_project_meta", {}) or {})
        folders = dict(meta.get("folders") or {})
        rel = folders.get("geometry", PROJECT_DIR_GEOMETRY)
        try:
            return Path(project_root) / rel
        except Exception:
            return None

    def _geo_open_start_folder(self):
        if self._geo_path:
            try:
                return str(Path(self._geo_path).parent)
            except Exception:
                pass
        project_geom = self._project_geometry_folder()
        if project_geom is not None:
            try:
                project_geom.mkdir(parents=True, exist_ok=True)
            except Exception:
                pass
            return str(project_geom)
        # No project → Documents, then cwd.
        try:
            docs = Path.home() / "Documents"
            if docs.is_dir():
                return str(docs)
        except Exception:
            pass
        return str(Path.cwd())

    def _geo_save_start_path(self):
        if self._geo_path:
            return str(self._geo_path)
        project_geom = self._project_geometry_folder()
        if project_geom is not None:
            try:
                project_geom.mkdir(parents=True, exist_ok=True)
            except Exception:
                pass
            return str(project_geom / "geometry.geo")
        # No project → Documents, then cwd.
        try:
            docs = Path.home() / "Documents"
            if docs.is_dir():
                return str(docs / "geometry.geo")
        except Exception:
            pass
        return str(Path.cwd() / "geometry.geo")

    def _flush_geo_recovery_snapshot(self):
        try:
            text = self.editor.toPlainText()
        except Exception:
            return
        if not str(text).strip():
            return
        try:
            recovery_path = self._geo_recovery_path()
            recovery_path.parent.mkdir(parents=True, exist_ok=True)
            recovery_path.write_bytes(_encode_text_bytes(_ascii_safe_geo_text(text)))
        except Exception as exc:
            self.console.log(f"[GEO] Recovery snapshot failed: {exc}\n", "warn")

    def _clear_geo_recovery_snapshot(self, geo_path=None):
        try:
            recovery_path = self._geo_recovery_path(geo_path)
        except Exception:
            return
        try:
            if recovery_path.exists():
                recovery_path.unlink()
        except Exception:
            pass

    def _mark_geo_modified(self):
        try:
            self.editor.document().setModified(True)
        except Exception:
            pass
        self._refresh_geo_path_label()
        if hasattr(self, "_geo_recovery_timer"):
            self._geo_recovery_timer.start(900)

    def _confirm_replace_geo_document(self, action_label):
        if not self.has_unsaved_changes():
            return True
        name = os.path.basename(self._geo_path) if self._geo_path else "Untitled"
        box = QMessageBox(self)
        box.setIcon(QMessageBox.Icon.Warning)
        box.setWindowTitle("Unsaved Geometry Changes")
        box.setText("Geometry (.geo) has unsaved changes.")
        box.setInformativeText(f"Do you want to save changes to {name} before {action_label}?")
        save_btn = box.addButton("Save", QMessageBox.ButtonRole.AcceptRole)
        save_as_btn = box.addButton("Save As...", QMessageBox.ButtonRole.ActionRole)
        discard_btn = box.addButton("Discard", QMessageBox.ButtonRole.DestructiveRole)
        cancel_btn = box.addButton("Cancel", QMessageBox.ButtonRole.RejectRole)
        box.setDefaultButton(save_btn)
        box.exec()
        clicked = box.clickedButton()
        if clicked is save_btn:
            return bool(self._save_geo()) and not self.has_unsaved_changes()
        if clicked is save_as_btn:
            return bool(self._save_geo_as()) and not self.has_unsaved_changes()
        if clicked is discard_btn:
            return True
        if clicked is cancel_btn:
            return False
        return False

    def _maybe_offer_geo_recovery(self, path, file_text):
        recovery_path = self._geo_recovery_path(path)
        try:
            if not recovery_path.exists():
                return file_text, False
            recovery_text = _decode_text_bytes(recovery_path.read_bytes()).replace("\r\n", "\n").replace("\r", "\n")
        except Exception:
            return file_text, False
        if recovery_text == file_text:
            self._clear_geo_recovery_snapshot(path)
            return file_text, False
        file_stamp = ""
        recovery_stamp = ""
        try:
            file_stamp = datetime.fromtimestamp(Path(path).stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
        except Exception:
            pass
        try:
            recovery_stamp = datetime.fromtimestamp(recovery_path.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
        except Exception:
            pass
        choice = QMessageBox.question(
            self,
            "Recovery Copy Found",
            "Studio found a local recovery copy for this geometry file.\n\n"
            f"File: {path}\n"
            f"File time: {file_stamp or 'unknown'}\n"
            f"Recovery time: {recovery_stamp or 'unknown'}\n\n"
            "Open the recovery copy instead of the file on disk?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.Yes,
        )
        if choice == QMessageBox.StandardButton.Yes:
            return recovery_text, True
        return file_text, False

    def _parse_geo_model(self, text):
        src = (text or "").replace("\r\n", "\n").replace("\r", "\n")
        lines = src.split("\n")
        end_idx = None
        for i, ln in enumerate(lines):
            if self._is_end_line(ln):
                end_idx = i
        end_line = END_GEO
        if end_idx is not None:
            end_line = lines[end_idx].strip() or END_GEO
            work = lines[:end_idx]
        else:
            work = lines[:]

        while work and work[-1].strip() == "":
            work.pop()

        sep_idx = [i for i, ln in enumerate(work) if self._is_sep_line(ln)]
        blocks = []
        meta = []
        if sep_idx:
            header = work[:sep_idx[0]]
            boundaries = sep_idx + [len(work)]
            for a, b in zip(boundaries, boundaries[1:]):
                start_line = a + 1
                block_end_line = b - 1
                while start_line <= block_end_line and work[start_line].strip() == "":
                    start_line += 1
                while block_end_line >= start_line and work[block_end_line].strip() == "":
                    block_end_line -= 1
                if start_line <= block_end_line:
                    chunk = work[start_line:block_end_line + 1]
                    blocks.append("\n".join(chunk))
                    meta.append({
                        "sep_before_line": a,
                        "start_line": start_line,
                        "end_line": block_end_line,
                        "sep_after_line": b if b < len(work) else None,
                    })
        else:
            header = []
            first_non_empty = next((i for i, ln in enumerate(work) if ln.strip()), None)
            if first_non_empty is not None:
                header = [work[first_non_empty]]
                start_line = first_non_empty + 1
                block_end_line = len(work) - 1
                while start_line <= block_end_line and work[start_line].strip() == "":
                    start_line += 1
                while block_end_line >= start_line and work[block_end_line].strip() == "":
                    block_end_line -= 1
                if start_line <= block_end_line:
                    chunk = work[start_line:block_end_line + 1]
                    blocks.append("\n".join(chunk))
                    meta.append({
                        "sep_before_line": None,
                        "start_line": start_line,
                        "end_line": block_end_line,
                        "sep_after_line": None,
                    })

        if not header:
            header = ["Title"]
        return header, blocks, end_line, meta

    def _render_geo_text_from_model(self):
        header = list(self._geo_header_lines or ["Title"])
        while header and header[-1].strip() == "":
            header.pop()
        if not header:
            header = ["Title"]

        lines = header + [SEP]
        for block in self._geo_blocks:
            raw = (block or "").replace("\r\n", "\n").replace("\r", "\n").strip("\n")
            raw = _strip_zero_default_geo_params(raw).strip("\n")
            if not raw.strip():
                continue
            lines.extend(raw.split("\n"))
            lines.append(SEP)
        lines.append((self._geo_end_line or END_GEO).strip() or END_GEO)
        return "\n".join(lines) + "\n"

    def _block_summary(self, idx, block_text):
        lines = [(ln or "").strip() for ln in (block_text or "").splitlines() if (ln or "").strip()]
        if not lines:
            return f"{idx:02d}. (empty block)"
        first = lines[0]
        m = re.match(r"^\s*(SURFACE|BODY|MODULE)\s*\(\s*(\d+)\s*\)\s*(.*)$", first, re.IGNORECASE)
        if m:
            kind = m.group(1).upper()
            ident = m.group(2)
            label = m.group(3).strip()
            base = f"{idx:02d}. {kind}({ident})"
            return f"{base} {label}" if label else base
        preview = re.sub(r"\s+", " ", first).strip()
        if len(preview) > 46:
            preview = preview[:43] + "..."
        return f"{idx:02d}. {preview}"

    def _focus_surface_list_block_row(self, block_row):
        if not hasattr(self, "lst_blocks"):
            return False
        for row in range(self.lst_blocks.count()):
            item = self.lst_blocks.item(row)
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if not payload or payload.get("type") != "block":
                continue
            if int(payload.get("block_row", -1)) == int(block_row):
                self.lst_blocks.setCurrentRow(row)
                return True
        return False

    def _refresh_block_list(self, selected_row=None, preserve_view=False):
        if not hasattr(self, "lst_blocks"):
            return
        prev_block_row = None
        if selected_row is not None:
            prev_block_row = int(selected_row)
        elif self.lst_blocks.currentRow() >= 0:
            item = self.lst_blocks.currentItem()
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if payload and payload.get("type") == "block":
                prev_block_row = int(payload.get("block_row", -1))
        vscroll = self.lst_blocks.verticalScrollBar().value() if preserve_view else None
        hscroll = self.lst_blocks.horizontalScrollBar().value() if preserve_view else None
        self.lst_blocks.clear()
        self._prune_surface_groups()
        surface_entries = []
        for block_row, block in enumerate(self._geo_blocks):
            stripped = (block or "").lstrip().upper()
            if not stripped.startswith("SURFACE"):
                continue
            ident = self._block_identity(block)
            group_name = self._surface_block_group_name(ident) if ident else ""
            surface_entries.append((block_row, block, group_name))

        grouped = {}
        ungrouped = []
        for entry in surface_entries:
            if entry[2]:
                grouped.setdefault(entry[2], []).append(entry)
            else:
                ungrouped.append(entry)

        display_idx = 1

        def add_surface_item(block_row, block_text, group_name=""):
            nonlocal display_idx
            prefix = "  " if group_name else ""
            item = QListWidgetItem(prefix + self._block_summary(display_idx, block_text))
            item.setToolTip(block_text)
            payload = {
                "type": "block",
                "block_row": block_row,
                "meta": self._geo_block_meta[block_row] if block_row < len(self._geo_block_meta) else None,
                "group": group_name,
            }
            item.setData(Qt.ItemDataRole.UserRole, payload)
            item.setData(Qt.ItemDataRole.UserRole + 1, int(block_row))
            self.lst_blocks.addItem(item)
            display_idx += 1

        for group_name in sorted(grouped, key=str.lower):
            entries = grouped[group_name]
            collapsed = group_name in self._surface_group_collapsed
            marker = "[+]" if collapsed else "[-]"
            header = QListWidgetItem(f"{marker} {group_name}  ({len(entries)} linked surface(s))")
            header.setToolTip("Click to expand/collapse this visual surface group. Grouping does not change .geo code.")
            header.setData(Qt.ItemDataRole.UserRole, {"type": "group", "name": group_name})
            header.setForeground(QColor(P["accent"]))
            font = header.font()
            font.setBold(True)
            header.setFont(font)
            self.lst_blocks.addItem(header)
            if not collapsed:
                for block_row, block_text, _group in entries:
                    add_surface_item(block_row, block_text, group_name)

        for block_row, block_text, _group in ungrouped:
            add_surface_item(block_row, block_text, "")

        if self.lst_blocks.count() > 0:
            if prev_block_row is not None and self._focus_surface_list_block_row(prev_block_row):
                pass
            else:
                for row in range(self.lst_blocks.count() - 1, -1, -1):
                    item = self.lst_blocks.item(row)
                    payload = item.data(Qt.ItemDataRole.UserRole) if item else None
                    if payload and payload.get("type") == "block":
                        self.lst_blocks.setCurrentRow(row)
                        break
        if preserve_view:
            if vscroll is not None:
                self.lst_blocks.verticalScrollBar().setValue(
                    max(0, min(vscroll, self.lst_blocks.verticalScrollBar().maximum()))
                )
            if hscroll is not None:
                self.lst_blocks.horizontalScrollBar().setValue(
                    max(0, min(hscroll, self.lst_blocks.horizontalScrollBar().maximum()))
                )
        self._update_block_actions()

    def _body_block_summary(self, idx, data):
        kind = data.get("kind", "BODY")
        body_id = data.get("body_id", "?")
        material = data.get("material", "?")
        label = (data.get("label", "") or "").strip()
        base = f"{idx:02d}. {kind}({body_id}) MAT({material})"
        return f"{base} {label}" if label else base

    def _block_identity(self, block_text):
        first = next((ln for ln in (block_text or "").splitlines() if ln.strip()), "")
        match = re.match(r"^\s*(SURFACE|BODY|MODULE)\s*\(\s*(\d+)\s*\)\s*(.*)$", first, re.IGNORECASE)
        if not match:
            return None
        return (match.group(1).upper(), int(match.group(2)), (match.group(3) or "").strip())

    def _body_block_group_name(self, kind, body_id, label):
        for group_name, identities in self._geo_groups.items():
            for ident in identities:
                if len(ident) >= 2 and ident[0] == kind and int(ident[1]) == int(body_id):
                    if len(ident) < 3 or not ident[2] or ident[2] == label:
                        return group_name
        return ""

    def _surface_block_group_name(self, ident):
        if not ident:
            return ""
        for group_name, identities in self._surface_groups.items():
            for entry in identities:
                if len(entry) >= 2 and entry[0] == ident[0] and int(entry[1]) == int(ident[1]):
                    if len(entry) < 3 or not entry[2] or entry[2] == ident[2]:
                        return group_name
        return ""

    def _prune_geo_groups(self):
        available = set()
        for block in self._geo_blocks:
            ident = self._block_identity(block)
            if ident:
                available.add(ident)
                available.add((ident[0], ident[1], ""))
        for group_name in list(self._geo_groups):
            kept = []
            for ident in self._geo_groups[group_name]:
                key = tuple(ident)
                loose = (key[0], key[1], "")
                if key in available or loose in available:
                    kept.append(key)
            if kept:
                self._geo_groups[group_name] = kept
            else:
                self._geo_groups.pop(group_name, None)
                self._geo_group_collapsed.discard(group_name)

    def _prune_surface_groups(self):
        available = set()
        for block in self._geo_blocks:
            ident = self._block_identity(block)
            if ident and ident[0] == "SURFACE":
                available.add(ident)
                available.add((ident[0], ident[1], ""))
        for group_name in list(self._surface_groups):
            kept = []
            for ident in self._surface_groups[group_name]:
                key = tuple(ident)
                loose = (key[0], key[1], "")
                if key in available or loose in available:
                    kept.append(key)
            if kept:
                self._surface_groups[group_name] = kept
            else:
                self._surface_groups.pop(group_name, None)
                self._surface_group_collapsed.discard(group_name)

    # ── Body-block list hover tooltip (ID-section only) ─────────────────────

    def eventFilter(self, obj, event):
        """Show the geometry block tooltip only while the cursor is over the
        ID portion of a body-block item  (e.g. "01. BODY(4) MAT(2)").
        Hovering over the label part or trailing whitespace hides the tooltip.
        """
        vp = getattr(self, "lst_body_blocks", None)
        if vp is not None and obj is vp.viewport():
            etype = event.type()
            if etype == QEvent.Type.MouseMove:
                self._handle_body_block_hover(event.position().toPoint())
                return False          # let the list widget process the event too
            if etype in (QEvent.Type.Leave, QEvent.Type.HoverLeave):
                hide_uniform_tooltip()
        return super().eventFilter(obj, event)

    def _handle_body_block_hover(self, pos):
        """Show tooltip text when *pos* (viewport coordinates) is within the
        fixed "ID" column of a body-block row; hide it everywhere else.

        The ID column is defined as the rendered width of the base summary
        text  "NN. KIND(id) MAT(mat)"  — everything before the optional label.
        """
        item = self.lst_body_blocks.itemAt(pos)
        if item is None:
            hide_uniform_tooltip()
            return
        payload = item.data(Qt.ItemDataRole.UserRole)
        if not payload or payload.get("type") != "block":
            hide_uniform_tooltip()
            return
        block_row = payload.get("block_row", -1)
        if not (0 <= block_row < len(self._geo_blocks)):
            hide_uniform_tooltip()
            return
        block_text = (self._geo_blocks[block_row] or "").strip()
        if not block_text:
            hide_uniform_tooltip()
            return

        # Measure the pixel width of the ID part of the item text.
        # Format from _body_block_summary: "NN. KIND(id) MAT(mat)" [+ " label"]
        item_text = item.text().lstrip()          # strip indent prefix for grouped items
        m = re.match(r"(\d+\.\s+\w+\(\d+\)\s+MAT\(\d+\))", item_text)
        id_text = m.group(1) if m else item_text
        fm = QFontMetrics(self.lst_body_blocks.font())
        # Account for the leading indent ("  ") that grouped items have
        indent_px = fm.horizontalAdvance(item.text()[: len(item.text()) - len(item.text().lstrip())])
        id_end_px = indent_px + fm.horizontalAdvance(id_text)

        item_rect = self.lst_body_blocks.visualItemRect(item)
        x_in_item = pos.x() - item_rect.left()

        if x_in_item <= id_end_px:
            global_pos = self.lst_body_blocks.viewport().mapToGlobal(pos)
            show_uniform_tooltip(global_pos, block_text, self.lst_body_blocks.viewport())
        else:
            hide_uniform_tooltip()

    # ─────────────────────────────────────────────────────────────────────────

    def _refresh_body_block_list(self):
        if not hasattr(self, "lst_body_blocks"):
            return
        prev_block_row = self._selected_body_module_block_row()
        self.lst_body_blocks.clear()
        self._body_module_rows = []
        self._prune_geo_groups()

        body_entries = []
        for block_row, block in enumerate(self._geo_blocks):
            stripped = (block or "").lstrip().upper()
            if not (stripped.startswith("BODY") or stripped.startswith("MODULE")):
                continue
            data = self._parse_body_block_data(block)
            if not data:
                continue
            group_name = self._body_block_group_name(data.get("kind"), data.get("body_id"), data.get("label", ""))
            body_entries.append((block_row, block, data, group_name))

        grouped = {}
        ungrouped = []
        for entry in body_entries:
            if entry[3]:
                grouped.setdefault(entry[3], []).append(entry)
            else:
                ungrouped.append(entry)

        def add_body_item(block_row, block, data, group_name=""):
            idx = len(self._body_module_rows) + 1
            prefix = "  " if group_name else ""
            item = QListWidgetItem(prefix + self._body_block_summary(idx, data))
            # Tooltip is NOT set on the item — the viewport event filter shows it only
            # when the cursor is over the ID portion (handled by eventFilter below).
            payload = {
                "type": "block",
                "block_row": block_row,
                "meta": self._geo_block_meta[block_row] if block_row < len(self._geo_block_meta) else None,
                "kind": data.get("kind"),
                "body_id": data.get("body_id"),
                "group": group_name,
            }
            item.setData(Qt.ItemDataRole.UserRole, payload)
            self.lst_body_blocks.addItem(item)
            self._body_module_rows.append(block_row)

        for group_name in sorted(grouped, key=str.lower):
            entries = grouped[group_name]
            collapsed = group_name in self._geo_group_collapsed
            marker = "[+]" if collapsed else "[-]"
            header = QListWidgetItem(f"{marker} {group_name}  ({len(entries)} linked block(s))")
            header.setToolTip("Click to expand/collapse this visual group. Grouping does not duplicate or change .geo code.")
            header.setData(Qt.ItemDataRole.UserRole, {"type": "group", "name": group_name})
            header.setForeground(QColor(P["accent"]))
            font = header.font()
            font.setBold(True)
            header.setFont(font)
            self.lst_body_blocks.addItem(header)
            if not collapsed:
                for block_row, block, data, _group in entries:
                    add_body_item(block_row, block, data, group_name)

        for block_row, block, data, _group in ungrouped:
            add_body_item(block_row, block, data, "")

        if self.lst_body_blocks.count() > 0:
            if prev_block_row is not None and prev_block_row >= 0 and self._focus_body_module_list_block_row(prev_block_row):
                pass
            else:
                for row in range(self.lst_body_blocks.count()):
                    item = self.lst_body_blocks.item(row)
                    payload = item.data(Qt.ItemDataRole.UserRole) if item else None
                    if payload and payload.get("type") == "block":
                        self.lst_body_blocks.setCurrentRow(row)
                        break
        self._update_body_block_actions()

    def _sync_model_from_editor(self):
        if getattr(self, "_updating_from_model", False):
            return
        text = self.editor.toPlainText()
        self._geo_header_lines, self._geo_blocks, self._geo_end_line, self._geo_block_meta = self._parse_geo_model(text)
        self._surface_id_snapshot = self._merged_surface_id_snapshot(self._geo_blocks)
        self._refresh_block_list()
        self._refresh_body_block_list()
        self._apply_render_mode_block_compaction()
        self._update_geo_material_link_ui()

    def _refresh_surface_block_label(self, block_text):
        data = self._parse_surface_block_data(block_text)
        if not data:
            return block_text, False

        if data.get("key") != "surface_plane":
            sid = int(data.get("surface_id", 0) or 0)
            current_label = self._sanitize_label(data.get("label", ""))
            refreshed_label = self._surface_label_text(data.get("key", ""), current_label, surface_id=sid)
            if refreshed_label == current_label:
                return block_text, False
            return self._set_surface_header_id_label(block_text, sid, refreshed_label), True

        sid = int(data.get("surface_id", 0) or 0)
        label = self._sanitize_label(data.get("label", ""))
        params = dict(data.get("params", {}))
        indices = list(data.get("indices", []))
        label_meta = self._parse_plane_label_metadata(label)
        hint = self._surface_builder_hint(sid)
        builder_state = dict(hint.get("builder_state") or {})
        has_explicit_angles = any(name in params for name in ("OMEGA", "THETA", "PHI"))

        coeff_params = dict(params)
        if indices == [0, 0, 0, 1, 0]:
            coeff_params = self._legacy_angular_plane_coeffs(params)
        simple_axis_plane = self._single_axis_plane_info_from_surface(
            {"indices": [0, 0, 0, 0, 0], "params": coeff_params}
        )

        axis_name = ""
        if str(builder_state.get("kind", "") or "").strip().lower() == "plane":
            axis_name = str(builder_state.get("axis", "") or "").strip().upper()
        if not axis_name and label_meta.get("axis"):
            axis_name = str(label_meta.get("axis") or "").strip().upper()

        coord_value = None
        if axis_name in ("X", "Y", "Z"):
            coeff = float(coeff_params.get(f"A{axis_name}", 0.0) or 0.0)
            if abs(coeff) > 1.0e-12 and "A0" in coeff_params:
                coord_value = -float(coeff_params.get("A0", 0.0) or 0.0) / coeff

        plane_info = None
        if coord_value is None or not axis_name:
            plane_info = simple_axis_plane
            if plane_info:
                if not axis_name:
                    axis_name = str(plane_info.get("axis", "") or "").strip().upper()
                if coord_value is None:
                    coord_value = float(plane_info.get("coord", 0.0) or 0.0)

        refreshable_label = False
        if str(builder_state.get("kind", "") or "").strip().lower() == "plane":
            refreshable_label = True
        elif label_meta.get("axis") is not None:
            refreshable_label = True
        elif any(label_meta.get(name) is not None for name in ("omega", "theta", "phi")):
            refreshable_label = True
        elif label.strip().lower() in ("", "limiting plane"):
            refreshable_label = True
        elif plane_info and not label.strip():
            refreshable_label = True

        if not refreshable_label or axis_name not in ("X", "Y", "Z") or coord_value is None:
            return block_text, False

        if str(builder_state.get("kind", "") or "").strip().lower() == "plane":
            label_only = self._sanitize_label(builder_state.get("label_only", label_meta.get("label_only", "")), GEO_LABEL_MAX_LEN)
        else:
            label_only = self._sanitize_label(label_meta.get("label_only", label or ""), GEO_LABEL_MAX_LEN)

        if indices == [0, 0, 0, 0, 0] and simple_axis_plane is not None and not has_explicit_angles:
            omega = 0.0
            theta = 0.0
            phi = 0.0
        else:
            omega = float(params.get("OMEGA", builder_state.get("omega", label_meta.get("omega", 0.0) or 0.0)) or 0.0)
            theta = float(params.get("THETA", builder_state.get("theta", label_meta.get("theta", 0.0) or 0.0)) or 0.0)
            phi = float(params.get("PHI", builder_state.get("phi", label_meta.get("phi", 0.0) or 0.0)) or 0.0)

        refreshed_label = self._plane_label_text(
            axis_name,
            coord_value,
            omega=omega,
            theta=theta,
            phi=phi,
            label_only=label_only,
        )
        if refreshed_label == label:
            return block_text, False
        return self._set_surface_header_id_label(block_text, sid, refreshed_label), True

    def _refresh_surface_labels_from_model(self):
        changed = 0
        refreshed_blocks = []
        for row, block_text in enumerate(self._geo_blocks):
            refreshed_block, did_change = self._refresh_surface_block_label(block_text)
            refreshed_blocks.append(refreshed_block)
            if did_change:
                changed += 1
        if changed:
            self._geo_blocks = refreshed_blocks
        return changed

    def _refresh_body_reference_order_from_model(self):
        changed = 0
        refreshed_blocks = []
        for row, block_text in enumerate(self._geo_blocks):
            data = self._parse_body_block_data(block_text)
            if not data or not data.get("body_refs"):
                refreshed_blocks.append(block_text)
                continue
            sorted_refs = sorted(int(ref_id) for ref_id in (data.get("body_refs") or []))
            if list(data.get("body_refs") or []) == sorted_refs:
                refreshed_blocks.append(block_text)
                continue
            refreshed_blocks.append(
                self._render_body_module_block_with_refs(
                    data.get("kind", "BODY"),
                    int(data.get("body_id", 0) or 0),
                    data.get("label", ""),
                    int(data.get("material", 1) or 1),
                    list(data.get("surface_pairs") or []),
                    sorted_refs,
                )
            )
            changed += 1
        if changed:
            self._geo_blocks = refreshed_blocks
        return changed

    def _refresh_from_editor_and_labels(self):
        if getattr(self, "_updating_from_model", False):
            return
        block_row = self._selected_surface_block_row()
        if block_row < 0:
            block_row = self._selected_body_module_block_row()
        if block_row < 0:
            block_row = None
        self._sync_model_from_editor()
        label_changed = self._refresh_surface_labels_from_model()
        body_ref_changed = self._refresh_body_reference_order_from_model()
        changed = int(label_changed) + int(body_ref_changed)
        if changed:
            self._write_model_to_editor(
                block_row=block_row,
                preserve_block_list_view=True,
                mark_modified=True,
            )
            msg_parts = []
            if label_changed:
                msg_parts.append(f"{label_changed} surface label(s)")
            if body_ref_changed:
                msg_parts.append(f"{body_ref_changed} BODY reference order block(s)")
            msg = "[GEO] Refresh updated " + " and ".join(msg_parts) + " from the current editor values.\n"
            self.console.log(msg, "ok")
        else:
            self.console.log("[GEO] Refresh re-read the current editor text. No derived surface labels or BODY reference ordering needed updating.\n", "muted")

    def _write_model_to_editor(self, block_row=None, preserve_block_list_view=False, mark_modified=True):
        old_text = self.editor.toPlainText()
        text = self._render_geo_text_from_model()
        self._set_editor_text(text)
        self._geo_header_lines, self._geo_blocks, self._geo_end_line, self._geo_block_meta = self._parse_geo_model(text)
        self._surface_id_snapshot = self._surface_id_list_from_blocks(self._geo_blocks)
        self._refresh_block_list(selected_row=block_row, preserve_view=preserve_block_list_view)
        self._refresh_body_block_list()
        self._update_geo_material_link_ui()
        if mark_modified and text != old_text:
            self._mark_geo_modified()

    def _surface_id_from_completed_header(self, block_text):
        first = next((ln for ln in (block_text or "").splitlines() if ln.strip()), "")
        match = re.match(r"^\s*SURFACE\s*\((.{4})\)\s*", first, re.IGNORECASE)
        if not match:
            return None
        field = match.group(1)
        if not re.fullmatch(r"\s*\d+", field):
            return None
        try:
            return int(field)
        except ValueError:
            return None

    def _surface_id_list_from_blocks(self, blocks):
        return [self._surface_id_from_completed_header(block) for block in (blocks or [])]

    def _merged_surface_id_snapshot(self, blocks):
        current = self._surface_id_list_from_blocks(blocks)
        previous = list(getattr(self, "_surface_id_snapshot", []))
        merged = []
        for row, sid in enumerate(current):
            if sid is not None:
                merged.append(sid)
            elif row < len(previous):
                merged.append(previous[row])
            else:
                merged.append(None)
        return merged

    def _replace_surface_references_in_text(self, text, old_sid, new_sid):
        if old_sid <= 0 or new_sid <= 0 or old_sid == new_sid:
            return text

        def repl(match):
            return f"{match.group(1)}{new_sid:4d}{match.group(2)}"

        pat = re.compile(
            rf"(^\s*SURFACE\s*\()\s*{old_sid}\s*(\)\s*,\s*SIDE POINTER\s*=)",
            re.IGNORECASE | re.MULTILINE,
        )
        return pat.sub(repl, text)

    def _propagate_completed_surface_id_edit(self):
        if getattr(self, "_updating_from_model", False):
            return
        text = self.editor.toPlainText()
        header, blocks, end_line, meta = self._parse_geo_model(text)
        current_ids = self._surface_id_list_from_blocks(blocks)
        previous_ids = list(getattr(self, "_surface_id_snapshot", []))

        changed = []
        for row, new_sid in enumerate(current_ids):
            if new_sid is None or row >= len(previous_ids):
                continue
            old_sid = previous_ids[row]
            if old_sid is None or old_sid == new_sid:
                continue
            changed.append((row, old_sid, new_sid))

        if not changed:
            return

        new_text = text
        for _row, old_sid, new_sid in changed:
            new_text = self._replace_surface_references_in_text(new_text, old_sid, new_sid)

        if new_text == text:
            self._geo_header_lines, self._geo_blocks, self._geo_end_line, self._geo_block_meta = header, blocks, end_line, meta
            self._surface_id_snapshot = current_ids
            self._refresh_block_list()
            self._refresh_body_block_list()
            return

        cursor = self.editor.textCursor()
        pos = cursor.position()
        anchor = cursor.anchor()
        scroll = self.editor.verticalScrollBar().value()
        self._set_editor_text(new_text)
        doc_len = self.editor.document().characterCount() - 1
        cursor = QTextCursor(self.editor.document())
        cursor.setPosition(max(0, min(anchor, doc_len)))
        cursor.setPosition(max(0, min(pos, doc_len)), QTextCursor.MoveMode.KeepAnchor)
        self.editor.setTextCursor(cursor)
        self.editor.verticalScrollBar().setValue(scroll)

        for _row, old_sid, new_sid in changed:
            self._move_surface_builder_hint(old_sid, new_sid)
        self._geo_header_lines, self._geo_blocks, self._geo_end_line, self._geo_block_meta = self._parse_geo_model(new_text)
        self._surface_id_snapshot = self._surface_id_list_from_blocks(self._geo_blocks)
        self._refresh_block_list()
        self._refresh_body_block_list()

    def _update_block_actions(self):
        has_sel = False
        has_block_sel = False
        if hasattr(self, "lst_blocks") and self.lst_blocks.currentRow() >= 0:
            item = self.lst_blocks.currentItem()
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            has_sel = bool(payload)
            has_block_sel = bool(payload and payload.get("type") == "block")
        if hasattr(self, "btn_blocks_edit"):
            self.btn_blocks_edit.setEnabled(has_block_sel)
        if hasattr(self, "btn_blocks_delete"):
            self.btn_blocks_delete.setEnabled(has_block_sel)
        if hasattr(self, "btn_blocks_clone_menu"):
            self.btn_blocks_clone_menu.setEnabled(has_block_sel)
        if hasattr(self, "btn_blocks_group_menu"):
            self.btn_blocks_group_menu.setEnabled(has_sel)
        if hasattr(self, "btn_blocks_up"):
            self.btn_blocks_up.setEnabled(has_block_sel)
        if hasattr(self, "btn_blocks_down"):
            self.btn_blocks_down.setEnabled(has_block_sel)

    def _update_body_block_actions(self):
        has_sel = False
        has_block_sel = False
        if hasattr(self, "lst_body_blocks") and self.lst_body_blocks.currentRow() >= 0:
            item = self.lst_body_blocks.currentItem()
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            has_sel = bool(payload)
            has_block_sel = bool(payload and payload.get("type") == "block")
        if hasattr(self, "btn_body_blocks_edit"):
            self.btn_body_blocks_edit.setEnabled(has_block_sel)
        if hasattr(self, "btn_body_blocks_delete"):
            self.btn_body_blocks_delete.setEnabled(has_block_sel)
        if hasattr(self, "btn_body_blocks_clone_menu"):
            self.btn_body_blocks_clone_menu.setEnabled(has_block_sel)
        if hasattr(self, "btn_body_blocks_group_menu"):
            self.btn_body_blocks_group_menu.setEnabled(has_sel)
        if hasattr(self, "btn_body_blocks_up"):
            self.btn_body_blocks_up.setEnabled(has_block_sel)
        if hasattr(self, "btn_body_blocks_down"):
            self.btn_body_blocks_down.setEnabled(has_block_sel)

    def _scroll_line_to_top(self, line_number):
        """Force the given line number to the top of the viewport."""
        sb = self.editor.verticalScrollBar()
        block = self.editor.document().findBlockByNumber(max(0, line_number))
        if not block.isValid():
            return
        target = max(sb.minimum(), min(sb.maximum(), int(line_number)))
        sb.setValue(target)

        # Converge by comparing with the current first visible block.
        # Some Qt styles/platforms offset by a few lines.
        iterations = 0
        first_visible = self.editor.firstVisibleBlock().blockNumber()
        while first_visible != line_number and iterations < 4:
            delta = int(line_number - first_visible)
            if delta == 0:
                break
            next_val = max(sb.minimum(), min(sb.maximum(), sb.value() + delta))
            if next_val == sb.value():
                break
            sb.setValue(next_val)
            first_visible = self.editor.firstVisibleBlock().blockNumber()
            iterations += 1

    def _jump_to_meta(self, meta):
        if not meta:
            return
        start_line = meta.get("start_line", 0)
        end_line = meta.get("end_line", start_line)

        doc = self.editor.document()
        start_block = doc.findBlockByNumber(max(0, start_line))
        end_block = doc.findBlockByNumber(max(0, end_line))
        if not start_block.isValid():
            return
        if not end_block.isValid():
            end_block = start_block

        cursor = QTextCursor(doc)
        start_pos = start_block.position()
        end_pos = end_block.position() + max(0, end_block.length() - 1)
        cursor.setPosition(end_pos)
        cursor.setPosition(start_pos, QTextCursor.MoveMode.KeepAnchor)
        self.editor.setTextCursor(cursor)
        QTimer.singleShot(0, lambda ln=start_line: self._scroll_line_to_top(ln))

    def _jump_to_block_row(self, block_row):
        if block_row < 0 or block_row >= len(self._geo_blocks):
            return
        if not self._focus_surface_list_block_row(block_row):
            self._focus_body_module_list_block_row(block_row)
        meta = self._geo_block_meta[block_row] if block_row < len(self._geo_block_meta) else None
        self._jump_to_meta(meta)

    def _jump_to_block(self, row):
        if row < 0 or not hasattr(self, "lst_blocks") or row >= self.lst_blocks.count():
            return
        item = self.lst_blocks.item(row)
        payload = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not payload:
            return
        if payload.get("type") == "group":
            name = payload.get("name", "")
            if name in self._surface_group_collapsed:
                self._surface_group_collapsed.discard(name)
            else:
                self._surface_group_collapsed.add(name)
            self._refresh_block_list()
            return
        self._jump_to_meta(payload.get("meta"))

    def _jump_to_body_module(self, row):
        if row < 0 or not hasattr(self, "lst_body_blocks") or row >= self.lst_body_blocks.count():
            return
        item = self.lst_body_blocks.item(row)
        payload = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not payload:
            return
        if payload.get("type") == "group":
            name = payload.get("name", "")
            if name in self._geo_group_collapsed:
                self._geo_group_collapsed.discard(name)
            else:
                self._geo_group_collapsed.add(name)
            self._refresh_body_block_list()
            return
        if payload.get("type") != "block":
            return
        block_row = payload.get("block_row", -1)
        self._jump_to_block_row(block_row)

    def _prompt_block_text(self, title, initial_text):
        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle(title)
        dlg.resize(760, 460)
        dlg.setStyleSheet(
            f"QDialog {{ background:{P['bg']}; }}"
            f"QLabel   {{ color:{P['fg']}; }}"
        )

        edit = QPlainTextEdit(initial_text)
        edit.setStyleSheet(editor_css())
        edit.setTabStopDistance(4 * edit.fontMetrics().horizontalAdvance(" "))

        buttons = QDialogButtonBox(
            QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel
        )
        buttons.setStyleSheet(
            f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:3px; padding:4px 16px; }}"
            f"QPushButton:hover {{ background:{P['bg3']}; }}"
        )
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)

        lay = QVBoxLayout(dlg)
        lay.setSpacing(10)
        lay.addWidget(edit, stretch=1)
        lay.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        return edit.toPlainText()

    def _build_block_from_existing(self, row, duplicate=False):
        self._sync_model_from_editor()
        if row < 0 or row >= len(self._geo_blocks):
            return None
        block_text = self._geo_blocks[row]
        stripped = (block_text or "").lstrip()
        if stripped.upper().startswith("SURFACE"):
            data = self._parse_surface_block_data(block_text)
            if not data:
                return None
            source_surface_id = data.get("surface_id")
            hint = self._surface_builder_hint(
                source_surface_id,
                expected_key=data["key"],
                purge_mismatch=True,
            )
            build_key = data["key"]
            mode_override = hint.get("mode") or self._infer_surface_edit_mode(data["key"], data, source_surface_id)
            if hint.get("builder_state"):
                data = dict(data)
                data["builder_state"] = dict(hint["builder_state"])
            surface_id = None if duplicate else source_surface_id
            body_id = None if duplicate else data.get("body_id")
            if duplicate:
                surface_id = self.editor._next_counter_id("surface")
            return self._build_surface_from_dialog(
                build_key,
                initial=data,
                surface_id=surface_id,
                mode_override=mode_override,
            )
        if stripped.upper().startswith("BODY") or stripped.upper().startswith("MODULE"):
            data = self._parse_body_block_data(block_text)
            if not data:
                return None
            block_id = None if duplicate else data.get("body_id")
            if duplicate:
                block_id = self.editor._next_counter_id("body")
            return self._build_body_module_from_dialog(
                data["kind"],
                initial=data,
                body_id=block_id,
                duplicate_surfaces=duplicate,
            )
        return None

    def _edit_selected_block(self):
        self._sync_model_from_editor()
        row = self._selected_surface_block_row()
        if row < 0 or row >= len(self._geo_blocks):
            return
        old_data = self._parse_surface_block_data(self._geo_blocks[row])
        old_surface_id = int(old_data.get("surface_id", 0)) if old_data else 0
        updated = self._build_block_from_existing(row, duplicate=False)
        if updated is None:
            return
        if old_data and (old_data.get("key") or "").startswith("surface_"):
            self._remember_surface_builder_hint_from_generated(updated)
        if not updated.strip():
            QMessageBox.warning(self, "Empty block", "Block cannot be empty.")
            return
        self._geo_blocks[row] = updated.strip("\n")
        new_data = self._parse_surface_block_data(self._geo_blocks[row])
        new_surface_id = int(new_data.get("surface_id", 0)) if new_data else 0
        if old_surface_id > 0 and new_surface_id > 0 and old_surface_id != new_surface_id:
            self._move_surface_builder_hint(old_surface_id, new_surface_id)
        self._write_model_to_editor(block_row=row)

    def _edit_selected_body_module(self):
        self._sync_model_from_editor()
        row = self._selected_body_module_block_row()
        if row < 0 or row >= len(self._geo_blocks):
            return
        data = self._parse_body_block_data(self._geo_blocks[row])
        if not data:
            QMessageBox.warning(self, "Body/Module", "Could not parse selected BODY/MODULE block.")
            return
        updated = self._build_body_module_from_dialog(
            data.get("kind", "BODY"),
            initial=data,
            body_id=data.get("body_id"),
            duplicate_surfaces=False,
        )
        if updated is None:
            return
        if not str(updated).strip():
            QMessageBox.warning(self, "Empty block", "Block cannot be empty.")
            return
        self._geo_blocks[row] = str(updated).strip("\n")
        self._write_model_to_editor(block_row=row)

    def _collect_label_manager_rows(self):
        rows = []
        for block_row, block_text in enumerate(self._geo_blocks):
            first = next((ln for ln in (block_text or "").splitlines() if (ln or "").strip()), "")
            match = re.match(r"^\s*(SURFACE|BODY|MODULE)\s*\(\s*(\d+)\s*\)\s*(.*)$", first, re.IGNORECASE)
            if not match:
                continue
            rows.append(
                {
                    "block_row": block_row,
                    "kind": match.group(1).upper(),
                    "id": int(match.group(2)),
                    "label": (match.group(3) or "").strip(),
                }
            )
        return rows

    def _set_block_header_label(self, block_text, label):
        lines = (block_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        label = self._sanitize_label(label)
        for idx, line in enumerate(lines):
            match = re.match(r"^(\s*(?:SURFACE|BODY|MODULE)\s*\(\s*\d+\s*\)\s*)(.*)$", line, re.IGNORECASE)
            if match:
                lines[idx] = f"{match.group(1)}{label}"
                break
        return "\n".join(lines).strip("\n")

    def _set_block_header_id_label(self, block_text, block_id, label):
        lines = (block_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        label = self._sanitize_label(label)
        for idx, line in enumerate(lines):
            match = re.match(r"^(\s*(SURFACE|BODY|MODULE)\s*\()\s*\d+\s*(\)\s*)(.*)$", line, re.IGNORECASE)
            if match:
                lines[idx] = f"{match.group(1)}{int(block_id):4d}{match.group(3)}{label}"
                break
        return "\n".join(lines).strip("\n")

    def _label_manager_row_snapshot(self, table, row):
        snapshot = []
        for col in range(table.columnCount()):
            item = table.item(row, col)
            snapshot.append(item.clone() if item is not None else None)
        return snapshot

    def _set_label_manager_row_snapshot(self, table, row, snapshot):
        for col, item in enumerate(snapshot):
            table.setItem(row, col, item)

    def _refresh_label_manager_order_column(self, table):
        for row in range(table.rowCount()):
            item = table.item(row, 0)
            if item is None:
                item = QTableWidgetItem()
                table.setItem(row, 0, item)
            item.setText(f"{row + 1:02d}")

    def _label_manager_row_kind(self, table, row):
        item = table.item(row, 1) if table is not None else None
        return (item.text().strip().upper() if item and item.text() else "")

    def _move_label_manager_rows(self, table, direction):
        if table is None:
            return False
        selection_model = table.selectionModel()
        if selection_model is None:
            return False
        rows = sorted({index.row() for index in selection_model.selectedRows()})
        if not rows:
            current = table.currentRow()
            if current >= 0:
                rows = [current]
        if not rows:
            return False
        if any(self._label_manager_row_kind(table, row) != "SURFACE" for row in rows):
            QMessageBox.information(
                self,
                "Label Manager",
                "Row reordering is currently enabled only for SURFACE blocks.\n"
                "BODY/MODULE rows stay fixed to protect linked-body dependencies.",
            )
            return False
        moved = False
        if direction < 0:
            if rows[0] <= 0:
                return False
            if self._label_manager_row_kind(table, rows[0] - 1) != "SURFACE":
                QMessageBox.information(
                    self,
                    "Label Manager",
                    "SURFACE rows can only move within the SURFACE-only slots for now.\n"
                    "They cannot be moved across BODY/MODULE rows.",
                )
                return False
            for row in rows:
                current_snapshot = self._label_manager_row_snapshot(table, row)
                previous_snapshot = self._label_manager_row_snapshot(table, row - 1)
                self._set_label_manager_row_snapshot(table, row - 1, current_snapshot)
                self._set_label_manager_row_snapshot(table, row, previous_snapshot)
            new_rows = [row - 1 for row in rows]
            moved = True
        else:
            if rows[-1] >= table.rowCount() - 1:
                return False
            if self._label_manager_row_kind(table, rows[-1] + 1) != "SURFACE":
                QMessageBox.information(
                    self,
                    "Label Manager",
                    "SURFACE rows can only move within the SURFACE-only slots for now.\n"
                    "They cannot be moved across BODY/MODULE rows.",
                )
                return False
            for row in reversed(rows):
                current_snapshot = self._label_manager_row_snapshot(table, row)
                next_snapshot = self._label_manager_row_snapshot(table, row + 1)
                self._set_label_manager_row_snapshot(table, row + 1, current_snapshot)
                self._set_label_manager_row_snapshot(table, row, next_snapshot)
            new_rows = [row + 1 for row in rows]
            moved = True
        if not moved:
            return False
        self._refresh_label_manager_order_column(table)
        table.clearSelection()
        for row in new_rows:
            table.selectRow(row)
        table.setCurrentCell(new_rows[0], min(max(table.currentColumn(), 0), table.columnCount() - 1))
        return True

    def _open_label_manager(self):
        self._sync_model_from_editor()
        entries = self._collect_label_manager_rows()
        if not entries:
            QMessageBox.information(self, "Label Manager", "No SURFACE/BODY/MODULE blocks were found.")
            return

        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle("Label Manager")
        dlg.resize(920, 540)
        dlg.setStyleSheet(
            f"QDialog {{ background:{P['bg']}; }}"
            f"QLabel   {{ color:{P['fg']}; }}"
        )
        lay = QVBoxLayout(dlg)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(8)
        info = QLabel(
            "Bulk edit labels for SURFACE/BODY/MODULE blocks.\n"
            f"Max label length is {GEO_LABEL_MAX_LEN} characters.\n"
            "Use Up/Down to reorder rows; applying a reordered list rewrites block order and runs Auto ID.\n"
            "For now, only SURFACE rows can be reordered. BODY/MODULE order stays fixed."
        )
        info.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(info)

        table_row = QHBoxLayout()
        table_row.setContentsMargins(0, 0, 0, 0)
        table_row.setSpacing(8)

        tbl = QTableWidget(len(entries), 5, dlg)
        tbl.setHorizontalHeaderLabels(["Order", "Type", "ID", "Current Label", "New Label"])
        tbl.verticalHeader().setVisible(False)
        tbl.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
        tbl.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)
        tbl.setStyleSheet(
            f"QTableWidget {{ background:{P['bg']}; color:{P['fg']}; border:1px solid {P['border']}; border-radius:4px; gridline-color:{P['border']}; }}"
            f"QTableWidget::item {{ background:{P['bg']}; color:{P['fg']}; }}"
            f"QTableWidget::item:selected {{ background:{P['sel']}; color:{P['fg']}; }}"
            f"QHeaderView::section {{ background:{P['bg2']}; color:{P['fg2']}; border:0; padding:4px; }}"
        )
        tbl.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(1, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(2, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(3, QHeaderView.ResizeMode.Stretch)
        tbl.horizontalHeader().setSectionResizeMode(4, QHeaderView.ResizeMode.Stretch)
        for row, entry in enumerate(entries):
            fixed_values = [f"{row + 1:02d}", entry["kind"], str(entry["id"]), entry["label"]]
            for col, value in enumerate(fixed_values):
                item = QTableWidgetItem(value)
                item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                if col == 0:
                    item.setData(Qt.ItemDataRole.UserRole, int(entry["block_row"]))
                tbl.setItem(row, col, item)
            editable = QTableWidgetItem(entry["label"])
            tbl.setItem(row, 4, editable)
        table_row.addWidget(tbl, stretch=1)

        reorder_col = QVBoxLayout()
        reorder_col.setContentsMargins(0, 0, 0, 0)
        reorder_col.setSpacing(6)
        btn_up = QPushButton("Up")
        btn_down = QPushButton("Down")
        for btn in (btn_up, btn_down):
            btn.setStyleSheet(
                f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
                f" border:1px solid {P['border']}; border-radius:3px; padding:4px 14px; }}"
                f"QPushButton:hover {{ background:{P['bg3']}; }}"
            )
            btn.setSizePolicy(QSizePolicy.Policy.Fixed, QSizePolicy.Policy.Fixed)
        btn_up.clicked.connect(lambda: self._move_label_manager_rows(tbl, -1))
        btn_down.clicked.connect(lambda: self._move_label_manager_rows(tbl, 1))
        reorder_col.addWidget(btn_up)
        reorder_col.addWidget(btn_down)
        reorder_col.addStretch(1)
        table_row.addLayout(reorder_col)

        lay.addLayout(table_row, stretch=1)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel, parent=dlg)
        buttons.setStyleSheet(
            f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:3px; padding:4px 16px; }}"
            f"QPushButton:hover {{ background:{P['bg3']}; }}"
        )
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return

        entry_block_rows = [int(entry["block_row"]) for entry in entries]
        reordered_block_rows = []
        for row in range(tbl.rowCount()):
            order_item = tbl.item(row, 0)
            source_block_row = order_item.data(Qt.ItemDataRole.UserRole) if order_item is not None else None
            if source_block_row is None:
                continue
            reordered_block_rows.append(int(source_block_row))
        order_changed = reordered_block_rows != entry_block_rows
        if order_changed:
            original_non_surface_positions = {
                idx: int(entry["block_row"])
                for idx, entry in enumerate(entries)
                if entry["kind"].upper() != "SURFACE"
            }
            for idx, source_block_row in enumerate(reordered_block_rows):
                fixed_block_row = original_non_surface_positions.get(idx)
                if fixed_block_row is not None and int(source_block_row) != fixed_block_row:
                    QMessageBox.warning(
                        self,
                        "Label Manager",
                        "BODY/MODULE rows cannot be reordered yet.\n"
                        "Only SURFACE rows may be moved for now.",
                    )
                    return

        new_blocks = list(self._geo_blocks)
        changed_rows = []
        trimmed = 0
        reordered_entry_blocks = []
        for row in range(tbl.rowCount()):
            source_block_row = int(tbl.item(row, 0).data(Qt.ItemDataRole.UserRole))
            entry = next((candidate for candidate in entries if int(candidate["block_row"]) == source_block_row), None)
            if entry is None:
                continue
            candidate = (tbl.item(row, 4).text() if tbl.item(row, 4) else "")
            clean = self._sanitize_label(candidate)
            if candidate.strip() != clean:
                trimmed += 1
            block_row = int(entry["block_row"])
            block_text = self._geo_blocks[block_row]
            if clean != entry["label"]:
                block_text = self._set_block_header_label(block_text, clean)
                changed_rows.append(block_row)
            reordered_entry_blocks.append(block_text)

        if order_changed:
            ordered_target_rows = sorted(entry_block_rows)
            for target_row, block_text in zip(ordered_target_rows, reordered_entry_blocks):
                new_blocks[target_row] = block_text
        if not changed_rows and not order_changed:
            self.status_message.emit("Label Manager: no label or order changes.")
            return

        self._geo_blocks = new_blocks
        self._write_model_to_editor()
        if order_changed:
            self._auto_id_geometry()
        focus_rows = sorted(set(changed_rows + (sorted(entry_block_rows)[:1] if order_changed and entry_block_rows else [])))
        if focus_rows:
            self._jump_to_block_row(focus_rows[0])
        msg_parts = []
        if changed_rows:
            msg_parts.append(f"updated {len(changed_rows)} label(s)")
        if order_changed:
            msg_parts.append("reordered block rows and ran Auto ID")
        msg = "Label Manager " + " and ".join(msg_parts) + "."
        if trimmed:
            msg += f" {trimmed} value(s) were trimmed to {GEO_LABEL_MAX_LEN} chars."
        self.status_message.emit(msg)
        self.console.log(f"[GEO] {msg}\n", "ok")

    def _propagate_surface_id_change(self, old_sid, new_sid, skip_row=-1):
        pat = re.compile(
            rf"(^\s*SURFACE\s*\(\s*){old_sid}(\s*\)\s*,\s*SIDE POINTER\s*=\s*\(\s*[+\-\s\d]+\s*\)\s*$)",
            re.IGNORECASE | re.MULTILINE,
        )
        for idx, block_text in enumerate(self._geo_blocks):
            if idx == skip_row:
                continue
            src = block_text or ""
            dst = pat.sub(rf"\g<1>{new_sid:4d}\g<2>", src)
            if dst != src:
                self._geo_blocks[idx] = dst

    def _auto_id_geometry(self):
        autosave_path = self._write_geo_autosave_snapshot("before_autoid", force=True)
        if autosave_path is not None:
            self.console.log(f"[GEO] Backup before Auto ID: {autosave_path}\n", "info")
        self._sync_model_from_editor()
        if not self._geo_blocks:
            return

        surface_header_pat = re.compile(
            r"(^\s*SURFACE\s*\()\s*(\d+)\s*(\)\s*(?!,).*)$",
            re.IGNORECASE | re.MULTILINE,
        )
        surface_ref_pat = re.compile(
            r"(^\s*SURFACE\s*\()\s*(\d+)\s*(\)\s*,\s*SIDE POINTER\s*=)",
            re.IGNORECASE | re.MULTILINE,
        )
        body_header_pat = re.compile(
            r"(^\s*(?:BODY|MODULE)\s*\()\s*(\d+)\s*(\)\s*.*)$",
            re.IGNORECASE | re.MULTILINE,
        )
        body_ref_pat = re.compile(r"(^\s*BODY\s*\()\s*(\d+)\s*(\)\s*$)", re.IGNORECASE | re.MULTILINE)

        surface_occurrences = {}
        surface_header_by_row = {}
        body_occurrences = {}
        body_ref_occurrences = {}
        body_header_by_row = {}
        surface_seen = set()
        duplicate_surface_ids = set()
        surface_hint_assignments = []
        next_surface_id = 1
        next_body_id = 1

        def first_meaningful_line(block_text):
            return next(
                (
                    ln for ln in (block_text or "").splitlines()
                    if ln.strip() and ln.strip() != SEP
                ),
                "",
            )

        # First pass: assign new ids only to true block headers. BODY(...) lines inside
        # MODULE blocks are references, not definitions, so they are handled separately.
        for row, block_text in enumerate(self._geo_blocks):
            first_line = first_meaningful_line(block_text)
            match = surface_header_pat.match(first_line)
            if match:
                old_sid = int(match.group(2))
                if old_sid in surface_seen:
                    duplicate_surface_ids.add(old_sid)
                surface_seen.add(old_sid)
                surface_occurrences.setdefault(old_sid, []).append((row, next_surface_id))
                surface_header_by_row[row] = next_surface_id
                surface_hint_assignments.append((old_sid, next_surface_id))
                next_surface_id += 1
                continue
            match = body_header_pat.match(first_line)
            if match:
                kind_match = re.match(r"^\s*(BODY|MODULE)\b", first_line, re.IGNORECASE)
                kind = (kind_match.group(1).upper() if kind_match else "BODY")
                old_bid = int(match.group(2))
                body_occurrences.setdefault(old_bid, []).append((row, next_body_id))
                body_ref_occurrences.setdefault(old_bid, []).append((row, next_body_id))
                body_header_by_row[row] = next_body_id
                next_body_id += 1

        def _mapped_ref_id(old_id, ref_block_row, occurrence_map):
            occs = occurrence_map.get(int(old_id)) or []
            if not occs:
                return int(old_id)
            chosen = None
            for occ_row, new_id in occs:
                if occ_row < ref_block_row:
                    chosen = int(new_id)
                else:
                    break
            if chosen is not None:
                return chosen
            return int(occs[0][1])

        def replace_surface_header(match, block_row):
            new_sid = int(surface_header_by_row.get(block_row, int(match.group(2))))
            return f"{match.group(1)}{new_sid:4d}{match.group(3)}"

        def replace_surface_ref(match, block_row):
            old_sid = int(match.group(2))
            new_sid = _mapped_ref_id(old_sid, block_row, surface_occurrences)
            return f"{match.group(1)}{new_sid:4d}{match.group(3)}"

        def replace_body_header(match, block_row):
            new_bid = int(body_header_by_row.get(block_row, int(match.group(2))))
            return f"{match.group(1)}{new_bid:4d}{match.group(3)}"

        def replace_body_ref(match, block_row):
            old_bid = int(match.group(2))
            new_bid = _mapped_ref_id(old_bid, block_row, body_ref_occurrences)
            return f"{match.group(1)}{new_bid:4d}{match.group(3)}"

        updated_blocks = []
        for block_row, block_text in enumerate(self._geo_blocks):
            updated = block_text or ""
            first_line = first_meaningful_line(updated)
            if surface_header_pat.match(first_line):
                updated = surface_header_pat.sub(lambda m, row=block_row: replace_surface_header(m, row), updated, count=1)
            elif body_header_pat.match(first_line):
                original_body_data = self._parse_body_block_data(updated)
                if original_body_data:
                    updated = self._render_body_module_block_with_refs(
                        original_body_data.get("kind", "BODY"),
                        int(body_header_by_row.get(block_row, int(original_body_data.get("body_id", 0) or 0))),
                        original_body_data.get("label", ""),
                        int(original_body_data.get("material", 1) or 1),
                        [
                            (_mapped_ref_id(sid, block_row, surface_occurrences), side)
                            for sid, side in list(original_body_data.get("surface_pairs") or [])
                        ],
                        [
                            _mapped_ref_id(ref_id, block_row, body_ref_occurrences)
                            for ref_id in list(original_body_data.get("body_refs") or [])
                        ],
                    )
                else:
                    updated = body_header_pat.sub(lambda m, row=block_row: replace_body_header(m, row), updated, count=1)
                    updated = surface_ref_pat.sub(lambda m, row=block_row: replace_surface_ref(m, row), updated)
                    updated = body_ref_pat.sub(lambda m, row=block_row: replace_body_ref(m, row), updated)
            else:
                updated = surface_ref_pat.sub(lambda m, row=block_row: replace_surface_ref(m, row), updated)
                updated = body_ref_pat.sub(lambda m, row=block_row: replace_body_ref(m, row), updated)
            updated_blocks.append(updated.strip("\n"))

        self._geo_blocks = updated_blocks
        rebuilt_surface_hints = {}
        for old_sid, new_sid in surface_hint_assignments:
            hint = dict(self._surface_builder_hints.get(int(old_sid)) or {})
            if hint:
                rebuilt_surface_hints[int(new_sid)] = hint
        self._surface_builder_hints = rebuilt_surface_hints
        self._write_model_to_editor()
        self.console.log(
            f"[GEO] Auto ID complete: {next_surface_id - 1} surfaces, {next_body_id - 1} body/module blocks.\n",
            "ok",
        )
        if duplicate_surface_ids:
            dupes = ", ".join(str(sid) for sid in sorted(duplicate_surface_ids))
            QMessageBox.warning(
                self,
                "Duplicate surface IDs",
                f"Auto ID finished, but duplicate old surface IDs were present: {dupes}.\n"
                "References to duplicated old IDs were mapped to the last matching prior definition in file order when possible, because the original references are ambiguous.",
            )

    def _render_body_block(self, kind, body_id, label, material, surface_pairs):
        label = self._sanitize_label(label)
        if (kind or "").upper() == "MODULE":
            lines = [f"MODULE  ({body_id:4d}) {label}"]
        else:
            lines = [f"BODY    ({body_id:4d}) {label}"]
        lines.append(self._fmt_material_line(material))
        for sid, side in surface_pairs:
            lines.append(f"SURFACE ({sid:4d}), SIDE POINTER=({self._fmt_side_pointer(side)})")
        return "\n".join(lines)

    def _collect_body_module_block_map_for_blocks(self, blocks):
        result = {}
        for row, block_text in enumerate(blocks or []):
            first = next((ln for ln in (block_text or "").splitlines() if ln.strip()), "")
            match = re.match(r"^\s*(BODY|MODULE)\s*\(\s*(\d+)\s*\)\s*(.*)$", first, re.IGNORECASE)
            if not match:
                continue
            result[int(match.group(2))] = {
                "row": row,
                "kind": match.group(1).upper(),
                "label": (match.group(3) or "").strip(),
            }
        return result

    def _collect_body_module_block_map(self):
        return self._collect_body_module_block_map_for_blocks(self._geo_blocks)

    def _collect_surface_block_map_for_blocks(self, blocks):
        result = {}
        for row, block_text in enumerate(blocks or []):
            stripped = (block_text or "").lstrip().upper()
            if not stripped.startswith("SURFACE"):
                continue
            surfs, _ = _parse_geo(block_text)
            if len(surfs) != 1:
                continue
            surf = next(iter(surfs.values()))
            result[surf["id"]] = {
                "row": row,
                "surface": surf,
            }
        return result

    def _collect_surface_block_map(self):
        return self._collect_surface_block_map_for_blocks(self._geo_blocks)

    def _current_editor_hover_preview_maps(self):
        editor = getattr(self, "editor", None)
        if editor is None:
            return [], {}, {}
        doc = editor.document()
        revision = int(doc.revision()) if doc is not None else -1
        cache = getattr(self, "_editor_hover_preview_cache", None)
        if cache and cache.get("revision") == revision:
            return (
                list(cache.get("blocks") or []),
                dict(cache.get("surface_map") or {}),
                dict(cache.get("body_map") or {}),
            )
        text = editor.toPlainText()
        _header, blocks, _end, _meta = self._parse_geo_model(text)
        surface_map = self._collect_surface_block_map_for_blocks(blocks)
        body_map = self._collect_body_module_block_map_for_blocks(blocks)
        self._editor_hover_preview_cache = {
            "revision": revision,
            "blocks": list(blocks or []),
            "surface_map": dict(surface_map),
            "body_map": dict(body_map),
        }
        return blocks, surface_map, body_map

    def _geo_editor_reference_target(self, cursor, pos_in_block=None):
        if cursor is None:
            return None
        block = cursor.block()
        if not block.isValid():
            return None
        line = block.text() or ""
        if not line.strip():
            return None
        pos = cursor.positionInBlock() if pos_in_block is None else int(pos_in_block)
        blocks, surface_map, body_map = self._current_editor_hover_preview_maps()
        for match in re.finditer(r"\b(SURFACE|BODY|MODULE)\s*\(\s*(\d+)\s*\)", line, re.IGNORECASE):
            if pos < match.start() or pos > match.end():
                continue
            kind = (match.group(1) or "").upper()
            ref_id = int(match.group(2))
            info = None
            if kind == "SURFACE":
                info = surface_map.get(ref_id)
            elif kind == "BODY":
                body_info = body_map.get(ref_id)
                if body_info and (body_info.get("kind") or "").upper() == "BODY":
                    info = body_info
            elif kind == "MODULE":
                module_info = body_map.get(ref_id)
                if module_info and (module_info.get("kind") or "").upper() == "MODULE":
                    info = module_info
            row = int(info.get("row", -1)) if info else -1
            if 0 <= row < len(blocks):
                return {
                    "kind": kind,
                    "id": ref_id,
                    "row": row,
                    "block_text": str(blocks[row] or "").strip(),
                }
        return None

    def _geo_editor_hover_preview(self, cursor, pos_in_block=None):
        target = self._geo_editor_reference_target(cursor, pos_in_block)
        return str(target.get("block_text") or "").strip() if target else ""

    def _focus_body_module_list_block_row(self, block_row):
        if not hasattr(self, "lst_body_blocks"):
            return False
        for row in range(self.lst_body_blocks.count()):
            item = self.lst_body_blocks.item(row)
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if not payload or payload.get("type") != "block":
                continue
            if int(payload.get("block_row", -1)) == int(block_row):
                self.lst_body_blocks.setCurrentRow(row)
                return True
        return False

    def _geo_editor_ctrl_click_jump(self, cursor, pos_in_block=None):
        target = self._geo_editor_reference_target(cursor, pos_in_block)
        if not target:
            return False
        if target["kind"] in ("BODY", "MODULE"):
            self._focus_body_module_list_block_row(target["row"])
        self._jump_to_block_row(int(target["row"]))
        return True

    def _collect_surface_reference_info(self):
        refs = {}
        for block_text in self._geo_blocks:
            data = self._parse_body_block_data(block_text)
            if not data:
                continue
            kind = (data.get("kind", "BODY") or "BODY").upper()
            prefix = "M" if kind == "MODULE" else "B"
            body_name = f"{prefix}{int(data.get('body_id', 0))}"
            for sid, _side in data.get("surface_pairs", []):
                refs.setdefault(int(sid), {"count": 0, "users": []})
                if body_name not in refs[int(sid)]["users"]:
                    refs[int(sid)]["users"].append(body_name)
                    refs[int(sid)]["count"] += 1
        return refs

    def _renumber_surface_ids_from(self, start_sid):
        start_sid = int(start_sid)
        header_pat = re.compile(r"(^\s*SURFACE\s*\()\s*(\d+)\s*(\)\s+)", re.IGNORECASE | re.MULTILINE)
        ref_pat = re.compile(r"(^\s*SURFACE\s*\()\s*(\d+)\s*(\)\s*,\s*SIDE POINTER\s*=)", re.IGNORECASE | re.MULTILINE)

        def bump_header(match):
            sid = int(match.group(2))
            if sid < start_sid:
                return match.group(0)
            return f"{match.group(1)}{sid + 1:4d}{match.group(3)}"

        def bump_ref(match):
            sid = int(match.group(2))
            if sid < start_sid:
                return match.group(0)
            return f"{match.group(1)}{sid + 1:4d}{match.group(3)}"

        for idx, block_text in enumerate(self._geo_blocks):
            updated = header_pat.sub(bump_header, block_text or "")
            updated = ref_pat.sub(bump_ref, updated)
            self._geo_blocks[idx] = updated

    def _surface_row_by_id(self, sid):
        sid = int(sid)
        for row, block_text in enumerate(self._geo_blocks):
            first = next((ln for ln in (block_text or "").splitlines() if ln.strip()), "")
            match = re.match(r"^\s*SURFACE\s*\(\s*(\d+)\s*\)", first, re.IGNORECASE)
            if match and int(match.group(1)) == sid:
                return row
        return -1

    def _set_surface_header_id_label(self, block_text, sid, label):
        lines = (block_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        label = self._sanitize_label(label)
        for idx, line in enumerate(lines):
            if re.match(r"^\s*SURFACE\s*\(", line, re.IGNORECASE):
                lines[idx] = re.sub(
                    r"^(\s*SURFACE\s*\()\s*\d+\s*(\)\s*).*$",
                    lambda m: f"{m.group(1)}{int(sid):4d}{m.group(2)}{label}",
                    line,
                    count=1,
                    flags=re.IGNORECASE,
                )
                break
        return "\n".join(lines).strip("\n")

    def _duplicate_shared_surfaces_for_body(self, block_row, body_data, duplicate_requests):
        identity_map = {int(sid): int(sid) for sid, _side in body_data.get("surface_pairs", [])}
        if not duplicate_requests:
            return block_row, list(body_data.get("surface_pairs", [])), identity_map

        pair_ids = {int(sid): int(sid) for sid, _side in body_data.get("surface_pairs", [])}
        request_current = {int(sid): int(sid) for sid in duplicate_requests}
        duplicate_final = {}

        for original_sid in sorted(duplicate_requests, reverse=True):
            current_sid = request_current.get(int(original_sid), int(original_sid))
            duplicate_sid = current_sid + 1
            original_row = self._surface_row_by_id(current_sid)
            if original_row < 0:
                continue

            self._renumber_surface_ids_from(duplicate_sid)
            for sid in list(pair_ids):
                if pair_ids[sid] >= duplicate_sid:
                    pair_ids[sid] += 1
            for sid in list(request_current):
                if request_current[sid] >= duplicate_sid:
                    request_current[sid] += 1
            for sid in list(duplicate_final):
                if duplicate_final[sid] >= duplicate_sid:
                    duplicate_final[sid] += 1

            label = duplicate_requests.get(original_sid) or f"surface {duplicate_sid}"
            duplicate_block = self._set_surface_header_id_label(
                self._geo_blocks[original_row],
                duplicate_sid,
                label,
            )
            insert_row = original_row + 1
            self._geo_blocks.insert(insert_row, duplicate_block)
            if insert_row <= block_row:
                block_row += 1
            duplicate_final[int(original_sid)] = duplicate_sid

        new_pairs = []
        for sid, side in body_data.get("surface_pairs", []):
            sid = int(sid)
            new_sid = duplicate_final.get(sid, pair_ids.get(sid, sid))
            new_pairs.append((new_sid, side))
        final_id_map = {sid: duplicate_final.get(sid, pair_ids.get(sid, sid)) for sid in pair_ids}
        return block_row, new_pairs, final_id_map

    def _estimate_body_center(self, surface_pairs, surface_map):
        axis_values = {"X": [], "Y": [], "Z": []}
        for sid, _side in surface_pairs:
            info = surface_map.get(sid)
            if not info:
                continue
            surf = info["surface"]
            params = dict(surf.get("params", {}))
            indices = list(surf.get("indices", [0, 0, 0, 0, 0]))
            if indices == [0, 0, 0, 0, 0]:
                ax = float(params.get("AX", 0.0) or 0.0)
                ay = float(params.get("AY", 0.0) or 0.0)
                az = float(params.get("AZ", 0.0) or 0.0)
                a0 = float(params.get("A0", 0.0) or 0.0)
                coeffs = [("X", ax), ("Y", ay), ("Z", az)]
                non_zero = [(name, coef) for name, coef in coeffs if abs(coef) > 1e-15]
                if len(non_zero) == 1:
                    axis, coef = non_zero[0]
                    axis_values[axis].append(-a0 / coef)
            else:
                for axis in ("X", "Y", "Z"):
                    key = f"{axis}-SHIFT"
                    if key in params:
                        axis_values[axis].append(float(params.get(key, 0.0) or 0.0))
        return {
            axis: (sum(vals) / len(vals) if vals else 0.0)
            for axis, vals in axis_values.items()
        }

    def _is_plane_surface(self, surf):
        indices = list((surf or {}).get("indices", [0, 0, 0, 0, 0]))
        if indices == [0, 0, 0, 0, 0]:
            return True
        if indices == [0, 0, 0, 1, 0]:
            return True
        label = ((surf or {}).get("label", "") or "").lower()
        if "plane" in label and indices[:3].count(0) >= 2:
            return True
        return False

    def _collect_body_surface_fields(self, body_data, surface_map):
        rows = []
        seen = set()
        for sid, _side in body_data.get("surface_pairs", []):
            if sid in seen:
                continue
            seen.add(sid)
            info = surface_map.get(sid)
            if not info:
                continue
            surf = info.get("surface", {})
            if self._is_plane_surface(surf):
                continue
            params = dict(surf.get("params", {}))
            editable = {}
            for key in ("X-SCALE", "Y-SCALE", "Z-SCALE", "X-SHIFT", "Y-SHIFT", "Z-SHIFT"):
                if key in params:
                    editable[key] = float(params.get(key, 0.0) or 0.0)
            if editable:
                rows.append({
                    "sid": sid,
                    "surface_label": (surf.get("label", "") or "").strip(),
                    "editable": editable,
                })
        return rows

    def _collect_body_plane_limit_fields(self, body_data, surface_map):
        grouped = {"X": [], "Y": [], "Z": []}
        seen = set()
        for sid, _side in body_data.get("surface_pairs", []):
            if sid in seen:
                continue
            seen.add(sid)
            info = surface_map.get(sid)
            if not info:
                continue
            surf = info.get("surface", {})
            indices = list(surf.get("indices", [0, 0, 0, 0, 0]))
            if indices != [0, 0, 0, 0, 0]:
                continue
            p = dict(surf.get("params", {}))
            ax = float(p.get("AX", 0.0) or 0.0)
            ay = float(p.get("AY", 0.0) or 0.0)
            az = float(p.get("AZ", 0.0) or 0.0)
            a0 = float(p.get("A0", 0.0) or 0.0)
            coeffs = [("X", ax), ("Y", ay), ("Z", az)]
            nz = [(axis, coef) for axis, coef in coeffs if abs(coef) > 1e-15]
            if len(nz) != 1:
                continue
            axis, coef = nz[0]
            pos = -a0 / coef
            grouped[axis].append({
                "sid": sid,
                "axis": axis,
                "coef": coef,
                "pos": pos,
                "surface_label": (surf.get("label", "") or "").strip(),
            })

        limits = []
        for axis in ("X", "Y", "Z"):
            entries = sorted(grouped[axis], key=lambda e: e["pos"])
            if len(entries) < 2:
                continue
            lo = entries[0]
            hi = entries[-1]
            limits.append({"axis": axis, "kind": "min", **lo})
            limits.append({"axis": axis, "kind": "max", **hi})
        return limits

    def _set_surface_param_line(self, block_text, key, value):
        raw = (block_text or "").replace("\r\n", "\n").replace("\r", "\n")
        lines = raw.split("\n")
        body_start = next(
            (i for i, ln in enumerate(lines) if re.match(r"^\s*(BODY|MODULE)\b", ln, re.IGNORECASE)),
            len(lines),
        )
        key_u = key.upper()
        key_re = re.compile(rf"^\s*{re.escape(key)}\s*=", re.IGNORECASE)
        if key_u in ZERO_DEFAULT_GEO_PARAMS and abs(float(value)) < 1e-15:
            lines = [
                ln for i, ln in enumerate(lines)
                if not (i < body_start and key_re.match(ln))
            ]
            lines, _body_start = self._normalize_surface_transform_separator(lines)
            return "\n".join(lines).strip("\n")
        for i in range(body_start):
            if key_re.match(lines[i]):
                lines[i] = self._fmt_param_line(key, value)
                lines, _body_start = self._normalize_surface_transform_separator(lines)
                return "\n".join(lines).strip("\n")

        implicit_form = self._surface_is_implicit_form(self._surface_indices_from_lines(lines, body_start))
        sep_idx = next((i for i in range(body_start) if _is_transform_sep_line(lines[i])), None) if implicit_form else None
        if key_u in SURFACE_TRANSFORM_PARAM_KEYS:
            if sep_idx is not None:
                insert_at = sep_idx + 1
            else:
                insert_at = self._surface_transform_insert_index(lines, body_start)
            for i in range(insert_at, body_start):
                if self._surface_param_key_from_line(lines[i]) in SURFACE_TRANSFORM_PARAM_KEYS:
                    insert_at = i + 1
        else:
            insert_at = self._surface_transform_insert_index(lines, body_start)
            if sep_idx is not None:
                insert_at = min(insert_at, sep_idx)
        lines.insert(insert_at, self._fmt_param_line(key, value))
        lines, _body_start = self._normalize_surface_transform_separator(lines)
        return "\n".join(lines).strip("\n")

    def _shift_surface_block_for_center(self, block_text, dx, dy, dz):
        surfs, _ = _parse_geo(block_text)
        if len(surfs) != 1:
            return block_text
        surf = next(iter(surfs.values()))
        params = dict(surf.get("params", {}))
        indices = list(surf.get("indices", [0, 0, 0, 0, 0]))
        updated = block_text

        if indices == [0, 0, 0, 0, 0]:
            ax = float(params.get("AX", 0.0) or 0.0)
            ay = float(params.get("AY", 0.0) or 0.0)
            az = float(params.get("AZ", 0.0) or 0.0)
            a0 = float(params.get("A0", 0.0) or 0.0)
            a0_new = a0 - (ax * dx + ay * dy + az * dz)
            updated = self._set_surface_param_line(updated, "A0", a0_new)
            return updated

        deltas = {"X-SHIFT": dx, "Y-SHIFT": dy, "Z-SHIFT": dz}
        for key, delta in deltas.items():
            if abs(delta) < 1e-15:
                continue
            cur = float(params.get(key, 0.0) or 0.0)
            updated = self._set_surface_param_line(updated, key, cur + delta)
        return updated

    def _selected_body_module_block_row(self):
        if not hasattr(self, "lst_body_blocks"):
            return -1
        item = self.lst_body_blocks.currentItem()
        payload = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not payload or payload.get("type") != "block":
            return -1
        row = int(payload.get("block_row", -1))
        if row < 0 or row >= len(self._geo_blocks):
            return -1
        return row

    def _selected_surface_block_row(self):
        if not hasattr(self, "lst_blocks"):
            return -1
        item = self.lst_blocks.currentItem()
        payload = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not payload or payload.get("type") != "block":
            return -1
        row = int(payload.get("block_row", -1))
        if row < 0 or row >= len(self._geo_blocks):
            return -1
        return row

    def _collect_body_module_array_sources(self):
        entries = []
        for block_row, block_text in enumerate(self._geo_blocks):
            data = self._parse_body_block_data(block_text)
            if not data:
                continue
            kind = (data.get("kind") or "BODY").upper()
            bid = int(data.get("body_id", 0))
            label = (data.get("label") or "").strip()
            title = f"{kind} ({bid})"
            if label:
                title += f" {label}"
            entries.append({"row": block_row, "title": title, "data": data})
        return entries

    def _parse_array_offsets(self, copies_text, spacing_text, sequence_text):
        seq = (sequence_text or "").strip()
        if seq:
            tokens = [tok for tok in re.split(r"[,\s;]+", seq) if tok]
            if not tokens:
                raise ValueError("Spacing sequence is empty.")
            offsets = []
            total = 0.0
            for idx, tok in enumerate(tokens, start=1):
                try:
                    step = float(tok)
                except ValueError as exc:
                    raise ValueError(f"Spacing sequence value #{idx} is not numeric.") from exc
                if abs(step) < 1e-15:
                    raise ValueError("Spacing sequence values cannot be 0.")
                total += step
                offsets.append(total)
            return offsets

        try:
            copies = int((copies_text or "").strip())
        except ValueError as exc:
            raise ValueError("Copies must be an integer.") from exc
        if copies <= 0:
            raise ValueError("Copies must be greater than 0.")

        try:
            spacing = float((spacing_text or "").strip())
        except ValueError as exc:
            raise ValueError("Spacing must be numeric.") from exc
        if abs(spacing) < 1e-15:
            raise ValueError("Spacing cannot be 0.")

        return [spacing * i for i in range(1, copies + 1)]

    def _plane_lookup_key(self, axis, coord, digits=9):
        return ((axis or "X").upper(), round(float(coord), digits))

    def _single_axis_plane_info_from_surface(self, surf, tol=1e-9):
        if not surf:
            return None
        indices = list(surf.get("indices", [0, 0, 0, 0, 0]))
        if indices != [0, 0, 0, 0, 0]:
            return None
        params = dict(surf.get("params", {}))
        coeffs = {
            "X": float(params.get("AX", 0.0) or 0.0),
            "Y": float(params.get("AY", 0.0) or 0.0),
            "Z": float(params.get("AZ", 0.0) or 0.0),
        }
        nonzero = [(axis, coef) for axis, coef in coeffs.items() if abs(coef) > tol]
        if len(nonzero) != 1:
            return None
        axis, coef = nonzero[0]
        if "A0" not in params:
            return None
        coord = -float(params.get("A0", 0.0) or 0.0) / coef
        return {"axis": axis, "coord": coord, "coef": coef}

    def _single_axis_plane_info_from_block(self, block_text):
        surfs, _ = _parse_geo(block_text or "")
        if len(surfs) != 1:
            return None
        surf = next(iter(surfs.values()))
        return self._single_axis_plane_info_from_surface(surf)

    def _render_body_module_block_with_refs(self, kind, body_id, label, material, surface_pairs, body_refs):
        base = self._render_body_block(kind, body_id, label, material, surface_pairs)
        lines = base.splitlines()
        for ref_id in sorted(int(ref_id) for ref_id in (body_refs or [])):
            lines.append(f"BODY    ({int(ref_id):4d})")
        return "\n".join(lines)

    def _build_body_module_array_dialog(self, sources, default_row):
        source_by_row = {int(item["row"]): item for item in (sources or [])}
        if not source_by_row:
            return None

        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle("Create Body/Module Array")
        dlg.setMinimumWidth(760)
        dlg.setStyleSheet(
            f"QDialog {{ background:{P['bg']}; }}"
            f"QLabel   {{ color:{P['fg']}; }}"
            f"QGroupBox {{ color:{P['accent']}; border:1px solid {P['border']};"
            f" border-radius:4px; margin-top:6px; padding:6px; }}"
            f"QGroupBox::title {{ subcontrol-origin:margin; left:8px; }}"
        )

        root = QVBoxLayout(dlg)
        root.setSpacing(10)
        form = QFormLayout()
        form.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        form.setSpacing(8)

        cmb_source = QComboBox()
        cmb_source.setStyleSheet(combo_css())
        default_idx = 0
        for idx, entry in enumerate(sources):
            cmb_source.addItem(entry["title"], int(entry["row"]))
            if int(entry["row"]) == int(default_row):
                default_idx = idx
        cmb_source.setCurrentIndex(default_idx)
        form.addRow("Source block:", cmb_source)

        cmb_mode = QComboBox()
        cmb_mode.addItems(["Linear axis", "Guide surface normal"])
        cmb_mode.setStyleSheet(combo_css())
        cmb_mode.setToolTip("Guide mode currently supports linear limiting planes (AX/AY/AZ/A0).")
        form.addRow("Array mode:", cmb_mode)

        axis_row = QWidget()
        axis_lay = QHBoxLayout(axis_row)
        axis_lay.setContentsMargins(0, 0, 0, 0)
        axis_lay.setSpacing(8)
        cmb_axis = QComboBox()
        cmb_axis.addItems(["X", "Y", "Z"])
        cmb_axis.setStyleSheet(combo_css())
        axis_lay.addWidget(cmb_axis)
        axis_lay.addStretch()
        form.addRow("Axis:", axis_row)

        guide_row = QWidget()
        guide_lay = QGridLayout(guide_row)
        guide_lay.setContentsMargins(0, 0, 0, 0)
        guide_lay.setHorizontalSpacing(8)
        guide_lay.setVerticalSpacing(4)
        e_guide_sid = QLineEdit("")
        e_guide_sid.setStyleSheet(entry_css())
        e_guide_sid.setFixedWidth(80)
        guide_lay.addWidget(QLabel("Surface ID:"), 0, 0)
        guide_lay.addWidget(e_guide_sid, 0, 1)
        cmb_guide_dir = QComboBox()
        cmb_guide_dir.addItems(["+ normal", "- normal"])
        cmb_guide_dir.setStyleSheet(combo_css())
        cmb_guide_dir.setFixedWidth(120)
        guide_lay.addWidget(QLabel("Direction:"), 0, 2)
        guide_lay.addWidget(cmb_guide_dir, 0, 3)
        lbl_guide_info = QLabel("")
        lbl_guide_info.setStyleSheet(label_css(P["fg2"]))
        guide_lay.addWidget(lbl_guide_info, 1, 0, 1, 4)
        form.addRow("Guide:", guide_row)

        e_copies = QLineEdit("5")
        e_copies.setStyleSheet(entry_css())
        e_copies.setFixedWidth(80)
        form.addRow("Copies:", e_copies)

        e_spacing = QLineEdit("1.0")
        e_spacing.setStyleSheet(entry_css())
        e_spacing.setFixedWidth(100)
        form.addRow("Spacing (cm):", e_spacing)

        e_sequence = QLineEdit("")
        e_sequence.setStyleSheet(entry_css())
        e_sequence.setPlaceholderText("optional: 1,1,2,2")
        e_sequence.setToolTip("Optional spacing sequence between copies. If filled, it overrides Copies/Spacing.")
        form.addRow("Spacing sequence:", e_sequence)

        reuse_check = QCheckBox("Reuse identical limiting planes (AX/AY/AZ/A0)")
        reuse_check.setChecked(True)
        reuse_check.setStyleSheet(checkbox_css())
        form.addRow("", reuse_check)

        mode_note = QLabel(
            "Linear arrays are fully supported. Guide mode follows a selected linear plane normal.\n"
            "Surface-follow arrays for non-linear guides (sphere/cone/hyperboloid) are planned next."
        )
        mode_note.setWordWrap(True)
        mode_note.setStyleSheet(label_css(P["fg2"]))
        form.addRow("", mode_note)

        root.addLayout(form)

        surface_map = self._collect_surface_block_map()

        def suggest_guide_surface():
            row = int(cmb_source.currentData() or 0)
            source = source_by_row.get(row)
            if not source:
                return
            for sid, _side in source["data"].get("surface_pairs", []):
                info = surface_map.get(int(sid))
                plane = self._single_axis_plane_info_from_surface(info.get("surface", {}) if info else None)
                if plane:
                    e_guide_sid.setText(str(int(sid)))
                    return

        def update_guide_info():
            txt = (e_guide_sid.text() or "").strip()
            if not txt:
                lbl_guide_info.setText("Pick a SURFACE id with full linear plane definition (AX/AY/AZ/A0).")
                return
            try:
                sid = int(txt)
            except ValueError:
                lbl_guide_info.setText("Guide surface id must be numeric.")
                return
            info = surface_map.get(sid)
            if not info:
                lbl_guide_info.setText(f"S{sid} not found.")
                return
            plane = self._single_axis_plane_info_from_surface(info.get("surface", {}))
            if not plane:
                lbl_guide_info.setText(f"S{sid} is not a linear limiting plane (sphere/cone guides are pending).")
                return
            lbl_guide_info.setText(
                f"S{sid}: normal axis {plane['axis']} (coord {plane['coord']:.6g}, coef {plane['coef']:.6g})."
            )

        def refresh_mode():
            is_guide = (cmb_mode.currentText() or "").lower().startswith("guide")
            axis_row.setVisible(not is_guide)
            guide_row.setVisible(is_guide)

        cmb_source.currentIndexChanged.connect(lambda _idx: suggest_guide_surface())
        cmb_source.currentIndexChanged.connect(lambda _idx: update_guide_info())
        e_guide_sid.textChanged.connect(lambda _txt: update_guide_info())
        cmb_mode.currentIndexChanged.connect(lambda _idx: refresh_mode())
        suggest_guide_surface()
        update_guide_info()
        refresh_mode()

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css())
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        root.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None

        source_row = int(cmb_source.currentData() or -1)
        source = source_by_row.get(source_row)
        if not source:
            QMessageBox.warning(self, "Array", "Could not resolve selected source BODY/MODULE.")
            return None

        try:
            offsets = self._parse_array_offsets(e_copies.text(), e_spacing.text(), e_sequence.text())
        except ValueError as exc:
            QMessageBox.warning(self, "Array", str(exc))
            return None

        mode = (cmb_mode.currentText() or "Linear axis").strip().lower()
        axis = (cmb_axis.currentText() or "X").strip().upper()
        direction = 1.0
        guide_sid = None
        if mode.startswith("guide"):
            sid_txt = (e_guide_sid.text() or "").strip()
            try:
                guide_sid = int(sid_txt)
            except ValueError:
                QMessageBox.warning(self, "Guide surface", "Guide surface id must be an integer.")
                return None
            info = surface_map.get(guide_sid)
            plane = self._single_axis_plane_info_from_surface(info.get("surface", {}) if info else None)
            if not plane:
                QMessageBox.warning(
                    self,
                    "Guide surface",
                    "Guide mode currently supports only linear limiting planes (AX/AY/AZ/A0).\n"
                    "For spheres/cones/hyperboloids, this mode will be added in the next step.",
                )
                return None
            axis = plane["axis"]
            normal_sign = 1.0 if float(plane["coef"]) >= 0.0 else -1.0
            direction = normal_sign * (1.0 if (cmb_guide_dir.currentText() or "").startswith("+") else -1.0)

        scaled_offsets = [float(off) * direction for off in offsets]
        return {
            "source_row": source_row,
            "axis": axis,
            "offsets": scaled_offsets,
            "reuse_planes": bool(reuse_check.isChecked()),
            "mode": mode,
            "guide_sid": guide_sid,
        }

    def _build_body_module_array_blocks(self, source_data, axis, offsets, reuse_planes=True):
        source_pairs = list(source_data.get("surface_pairs", []))
        if not source_pairs and (source_data.get("kind", "BODY") or "BODY").upper() == "BODY":
            return [], []

        surface_map = self._collect_surface_block_map()
        body_map = self._collect_body_module_block_map()
        next_sid = (max(surface_map.keys()) + 1) if surface_map else 1
        next_bid = (max(body_map.keys()) + 1) if body_map else 1

        plane_lookup = {}
        if reuse_planes:
            for sid, info in surface_map.items():
                plane = self._single_axis_plane_info_from_surface(info.get("surface", {}))
                if not plane:
                    continue
                key = self._plane_lookup_key(plane["axis"], plane["coord"])
                plane_lookup.setdefault(key, int(sid))

        generated = []
        missing = []
        axis = (axis or "X").upper()

        for copy_idx, offset in enumerate(offsets, start=1):
            dx = dy = dz = 0.0
            if axis == "X":
                dx = float(offset)
            elif axis == "Y":
                dy = float(offset)
            else:
                dz = float(offset)

            sid_map = {}
            for sid, _side in source_pairs:
                sid = int(sid)
                if sid in sid_map:
                    continue
                info = surface_map.get(sid)
                if not info:
                    sid_map[sid] = sid
                    missing.append(sid)
                    continue

                src_block = self._geo_blocks[info["row"]]
                shifted = self._shift_surface_block_for_center(src_block, dx, dy, dz)
                plane = self._single_axis_plane_info_from_block(shifted)
                reused_sid = None
                if reuse_planes and plane:
                    reused_sid = plane_lookup.get(self._plane_lookup_key(plane["axis"], plane["coord"]))

                if reused_sid is not None:
                    sid_map[sid] = int(reused_sid)
                    continue

                surf_label = (info.get("surface", {}).get("label", "") or "").strip()
                label = self._sanitize_label(f"{surf_label} a{copy_idx}" if surf_label else f"S{sid} a{copy_idx}")
                new_sid = next_sid
                next_sid += 1
                shifted = self._set_surface_header_id_label(shifted, new_sid, label)
                generated.append(shifted)
                sid_map[sid] = new_sid

                if reuse_planes and plane:
                    plane_lookup[self._plane_lookup_key(plane["axis"], plane["coord"])] = int(new_sid)

            new_pairs = [(int(sid_map.get(int(sid), int(sid))), int(side)) for sid, side in source_pairs]
            kind = (source_data.get("kind") or "BODY").upper()
            base_label = (source_data.get("label") or ("hollow module" if kind == "MODULE" else "label")).strip()
            body_label = self._sanitize_label(f"{base_label} a{copy_idx}")
            body_block = self._render_body_module_block_with_refs(
                kind,
                next_bid,
                body_label,
                int(source_data.get("material", 1)),
                new_pairs,
                list(source_data.get("body_refs", [])),
            )
            next_bid += 1
            generated.append(body_block)

        return generated, sorted(set(int(s) for s in missing))

    def _array_selected_body_module(self):
        self._sync_model_from_editor()
        sources = self._collect_body_module_array_sources()
        if not sources:
            QMessageBox.information(self, "Array", "No BODY/MODULE blocks found.")
            return

        default_row = self._selected_body_module_block_row()
        config = self._build_body_module_array_dialog(sources, default_row)
        if not config:
            return

        source_row = int(config.get("source_row", -1))
        source_entry = next((item for item in sources if int(item["row"]) == source_row), None)
        if not source_entry:
            QMessageBox.warning(self, "Array", "Could not resolve source BODY/MODULE block.")
            return

        axis = (config.get("axis") or "X").upper()
        offsets = list(config.get("offsets", []))
        if not offsets:
            QMessageBox.warning(self, "Array", "No array offsets were generated.")
            return

        blocks, missing = self._build_body_module_array_blocks(
            source_entry["data"],
            axis=axis,
            offsets=offsets,
            reuse_planes=bool(config.get("reuse_planes", True)),
        )
        if not blocks:
            QMessageBox.warning(self, "Array", "No new geometry blocks were generated.")
            return

        self._insert_geo_blocks(blocks)
        created_copies = len(offsets)
        self.console.log(
            f"[GEO] Array created from {source_entry['title']}: {created_copies} copy(ies), axis {axis}, "
            f"{len(blocks)} block(s) added.\n",
            "ok",
        )
        if missing:
            missing_txt = ", ".join(str(sid) for sid in missing)
            QMessageBox.warning(
                self,
                "Array",
                "Array generated, but some source surfaces were not found and were kept by id reference:\n"
                f"{missing_txt}",
            )

    def _prompt_body_center_edit(self, body_data, center, surface_rows, plane_rows):
        self._sync_model_from_editor()
        kind = body_data.get("kind", "BODY")
        default_label = self._sanitize_label(body_data.get("label", "") or ("hollow module" if kind == "MODULE" else "label"))

        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle(f"Edit {kind} - High-Level")
        dlg.setMinimumWidth(820)
        dlg.setStyleSheet(
            f"QDialog {{ background:{P['bg']}; }}"
            f"QLabel   {{ color:{P['fg']}; }}"
            f"QGroupBox {{ color:{P['accent']}; border:1px solid {P['border']};"
            f" border-radius:4px; margin-top:6px; padding:6px; }}"
            f"QGroupBox::title {{ subcontrol-origin:margin; left:8px; }}"
        )

        layout = QVBoxLayout(dlg)
        layout.setSpacing(10)

        grp_block = QGroupBox("Block")
        form_block = QFormLayout(grp_block)
        form_block.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        form_block.setSpacing(8)

        e_label = QLineEdit(default_label)
        e_label.setStyleSheet(entry_css())
        e_label.setMaxLength(GEO_LABEL_MAX_LEN)
        form_block.addRow("Label:", e_label)

        e_kind = QComboBox()
        e_kind.addItems(["BODY", "MODULE"])
        e_kind.setCurrentText("MODULE" if kind == "MODULE" else "BODY")
        e_kind.setStyleSheet(combo_css())
        form_block.addRow("Type:", e_kind)

        material_widget, cmb_material = self._build_geo_material_selector(body_data.get("material", 1))
        form_block.addRow("Material:", material_widget)
        layout.addWidget(grp_block)

        grp_center = QGroupBox("Center")
        row_center = QHBoxLayout(grp_center)
        row_center.setContentsMargins(8, 8, 8, 8)
        row_center.setSpacing(10)

        row_center.addWidget(QLabel("X:"))
        e_cx = QLineEdit(f"{center.get('X', 0.0):.6g}")
        e_cx.setStyleSheet(entry_css())
        e_cx.setFixedWidth(140)
        row_center.addWidget(e_cx)

        row_center.addWidget(QLabel("Y:"))
        e_cy = QLineEdit(f"{center.get('Y', 0.0):.6g}")
        e_cy.setStyleSheet(entry_css())
        e_cy.setFixedWidth(140)
        row_center.addWidget(e_cy)

        row_center.addWidget(QLabel("Z:"))
        e_cz = QLineEdit(f"{center.get('Z', 0.0):.6g}")
        e_cz.setStyleSheet(entry_css())
        e_cz.setFixedWidth(140)
        row_center.addWidget(e_cz)
        row_center.addStretch()
        layout.addWidget(grp_center)

        grp_linked = QGroupBox("Linked Surfaces")
        lay_linked = QVBoxLayout(grp_linked)
        lay_linked.setSpacing(8)

        surface_param_edits = {}
        surface_param_original = {}
        duplicate_surface_widgets = {}
        surface_dup_header = None
        plane_dup_header = None
        if surface_rows:
            lbl_sc = QLabel("Surfaces")
            lbl_sc.setStyleSheet(label_css(P["fg2"]))
            lay_linked.addWidget(lbl_sc)

            grid_scales = QGridLayout()
            grid_scales.setHorizontalSpacing(8)
            grid_scales.setVerticalSpacing(6)
            grid_scales.addWidget(QLabel("Duplicate"), 0, 0)
            grid_scales.addWidget(QLabel("Surface"), 0, 1)
            grid_scales.addWidget(QLabel("X-SCALE"), 0, 2)
            grid_scales.addWidget(QLabel("Y-SCALE"), 0, 3)
            grid_scales.addWidget(QLabel("Z-SCALE"), 0, 4)
            grid_scales.addWidget(QLabel("X-SHIFT"), 0, 5)
            grid_scales.addWidget(QLabel("Y-SHIFT"), 0, 6)
            grid_scales.addWidget(QLabel("Z-SHIFT"), 0, 7)
            surface_dup_header = QLabel("New Label")
            surface_dup_header.setVisible(False)
            grid_scales.addWidget(surface_dup_header, 0, 8)

            r = 1
            for row in surface_rows:
                sid = int(row["sid"])
                shared_users = list(row.get("shared_users", []))
                if shared_users:
                    chk_dup = QCheckBox()
                    chk_dup.setStyleSheet(label_css(P["fg"]))
                    grid_scales.addWidget(chk_dup, r, 0, 2, 1)
                    e_label_dup = QLineEdit(f"S{sid} copy")
                    e_label_dup.setStyleSheet(entry_css())
                    e_label_dup.setMaxLength(GEO_LABEL_MAX_LEN)
                    e_label_dup.setVisible(False)
                    chk_dup.toggled.connect(e_label_dup.setVisible)
                    duplicate_surface_widgets[sid] = (chk_dup, e_label_dup)
                else:
                    dash = QLabel("-")
                    dash.setStyleSheet(label_css(P["fg2"]))
                    grid_scales.addWidget(dash, r, 0, 2, 1)
                    e_label_dup = QLabel("")

                cell_widget = QWidget()
                cell_lay = QVBoxLayout(cell_widget)
                cell_lay.setContentsMargins(0, 0, 0, 0)
                cell_lay.setSpacing(1)
                lbl_sid = QLabel(f"S{sid}")
                cell_lay.addWidget(lbl_sid)
                if shared_users:
                    lbl_note = QLabel(f"shared with {', '.join(shared_users)}")
                    lbl_note.setStyleSheet(label_css(P["fg2"]))
                    cell_lay.addWidget(lbl_note)
                else:
                    cell_lay.addStretch()
                grid_scales.addWidget(cell_widget, r, 1, 2, 1)
                for c, key in enumerate(("X-SCALE", "Y-SCALE", "Z-SCALE", "X-SHIFT", "Y-SHIFT", "Z-SHIFT"), start=2):
                    if key in row.get("editable", {}):
                        edit = QLineEdit(f"{float(row['editable'][key]):.6g}")
                        edit.setStyleSheet(entry_css())
                        edit.setFixedWidth(96)
                        grid_scales.addWidget(edit, r, c, 2, 1)
                        surface_param_edits[(sid, key)] = edit
                        surface_param_original[(sid, key)] = float(row["editable"][key])
                    else:
                        dash = QLabel("-")
                        dash.setStyleSheet(label_css(P["fg2"]))
                        grid_scales.addWidget(dash, r, c, 2, 1)
                if shared_users:
                    grid_scales.addWidget(e_label_dup, r, 8, 2, 1)
                r += 2
            grid_scales.setColumnStretch(9, 1)
            lay_linked.addLayout(grid_scales)

        plane_axis_rows = {}
        if plane_rows:
            lbl_lim = QLabel("Planes")
            lbl_lim.setStyleSheet(label_css(P["fg2"]))
            lay_linked.addWidget(lbl_lim)

            grid_limits = QGridLayout()
            grid_limits.setHorizontalSpacing(8)
            grid_limits.setVerticalSpacing(6)
            grid_limits.addWidget(QLabel("Duplicate"), 0, 0)
            grid_limits.addWidget(QLabel("Plane"), 0, 1)
            grid_limits.addWidget(QLabel("Min"), 0, 2)
            grid_limits.addWidget(QLabel("Max"), 0, 3)
            plane_dup_header = QLabel("New Label")
            plane_dup_header.setVisible(False)
            grid_limits.addWidget(plane_dup_header, 0, 4)

            axis_map = {}
            for item in plane_rows:
                axis = item["axis"]
                if axis not in axis_map:
                    axis_map[axis] = {}
                axis_map[axis][item["kind"]] = item

            r = 1
            for axis in ("X", "Y", "Z"):
                pair = axis_map.get(axis)
                if not pair or "min" not in pair or "max" not in pair:
                    continue
                lo = pair["min"]
                hi = pair["max"]
                shared_ids = []
                shared_users = []
                for bound in (lo, hi):
                    if bound.get("shared_users"):
                        shared_ids.append(int(bound["sid"]))
                        shared_users.extend(bound.get("shared_users", []))
                shared_users = sorted(set(shared_users))
                if shared_ids:
                    chk_dup = QCheckBox()
                    chk_dup.setStyleSheet(label_css(P["fg"]))
                    grid_limits.addWidget(chk_dup, r, 0, 2, 1)
                    e_label_dup = QLineEdit(f"{axis} plane copy")
                    e_label_dup.setStyleSheet(entry_css())
                    e_label_dup.setMaxLength(GEO_LABEL_MAX_LEN)
                    e_label_dup.setVisible(False)
                    chk_dup.toggled.connect(e_label_dup.setVisible)
                    duplicate_surface_widgets[("plane", axis)] = (chk_dup, e_label_dup, shared_ids, {"min": int(lo["sid"]), "max": int(hi["sid"])})
                else:
                    dash = QLabel("-")
                    dash.setStyleSheet(label_css(P["fg2"]))
                    grid_limits.addWidget(dash, r, 0, 2, 1)
                    e_label_dup = QLabel("")

                plane_widget = QWidget()
                plane_lay = QVBoxLayout(plane_widget)
                plane_lay.setContentsMargins(0, 0, 0, 0)
                plane_lay.setSpacing(1)
                plane_lay.addWidget(QLabel(f"{axis}"))
                if shared_users:
                    lbl_note = QLabel(f"shared with {', '.join(shared_users)}")
                    lbl_note.setStyleSheet(label_css(P["fg2"]))
                    plane_lay.addWidget(lbl_note)
                else:
                    plane_lay.addStretch()
                grid_limits.addWidget(plane_widget, r, 1, 2, 1)

                e_lo = QLineEdit(f"{float(lo['pos']):.6g}")
                e_lo.setStyleSheet(entry_css())
                e_lo.setFixedWidth(140)
                e_lo.setToolTip(f"S{int(lo['sid'])} {axis} minimum")
                grid_limits.addWidget(e_lo, r, 2, 2, 1)

                e_hi = QLineEdit(f"{float(hi['pos']):.6g}")
                e_hi.setStyleSheet(entry_css())
                e_hi.setFixedWidth(140)
                e_hi.setToolTip(f"S{int(hi['sid'])} {axis} maximum")
                grid_limits.addWidget(e_hi, r, 3, 2, 1)
                if shared_ids:
                    grid_limits.addWidget(e_label_dup, r, 4, 2, 1)

                plane_axis_rows[axis] = {
                    "min": {"sid": int(lo["sid"]), "coef": float(lo["coef"]), "old": float(lo["pos"]), "edit": e_lo},
                    "max": {"sid": int(hi["sid"]), "coef": float(hi["coef"]), "old": float(hi["pos"]), "edit": e_hi},
                }
                r += 2
            grid_limits.setColumnStretch(5, 1)
            lay_linked.addLayout(grid_limits)

        if not surface_rows and not plane_rows:
            lbl_none = QLabel("No editable linked surface values found.")
            lbl_none.setStyleSheet(label_css(P["fg2"]))
            lay_linked.addWidget(lbl_none)

        def _update_duplicate_headers():
            surface_active = False
            plane_active = False
            for key, payload in duplicate_surface_widgets.items():
                chk = payload[0]
                if not chk.isChecked():
                    continue
                if isinstance(key, tuple) and key[0] == "plane":
                    plane_active = True
                else:
                    surface_active = True
            if surface_dup_header is not None:
                surface_dup_header.setVisible(surface_active)
            if plane_dup_header is not None:
                plane_dup_header.setVisible(plane_active)

        for payload in duplicate_surface_widgets.values():
            payload[0].toggled.connect(lambda _checked=False: _update_duplicate_headers())
        _update_duplicate_headers()

        layout.addWidget(grp_linked)

        buttons = QDialogButtonBox(
            QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel
        )
        buttons.setStyleSheet(
            f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:3px; padding:4px 16px; }}"
            f"QPushButton:hover {{ background:{P['bg3']}; }}"
        )
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        layout.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None

        label = self._sanitize_label((e_label.text() or "").strip() or default_label)
        try:
            material = self._geo_material_selector_value(cmb_material)
        except ValueError:
            QMessageBox.warning(self, "Invalid material", "Material must be an integer.")
            return None

        try:
            cx = float((e_cx.text() or "").strip())
            cy = float((e_cy.text() or "").strip())
            cz = float((e_cz.text() or "").strip())
        except ValueError:
            QMessageBox.warning(self, "Invalid center", "Center X, Y and Z must be numeric.")
            return None

        surface_param_updates = {}
        for key, edit in surface_param_edits.items():
            txt = (edit.text() or "").strip()
            try:
                new_val = float(txt)
            except ValueError:
                QMessageBox.warning(self, "Invalid value", f"{key[1]} for surface {key[0]} must be numeric.")
                return None
            old_val = float(surface_param_original.get(key, 0.0))
            if abs(new_val - old_val) > 1e-12:
                surface_param_updates[key] = new_val

        plane_limit_updates = []
        for axis, pair in plane_axis_rows.items():
            try:
                lo_new = float((pair["min"]["edit"].text() or "").strip())
                hi_new = float((pair["max"]["edit"].text() or "").strip())
            except ValueError:
                QMessageBox.warning(self, "Invalid limit", f"{axis} limits must be numeric.")
                return None
            if lo_new > hi_new:
                QMessageBox.warning(self, "Invalid limit", f"{axis} min cannot be greater than {axis} max.")
                return None

            if abs(lo_new - pair["min"]["old"]) > 1e-12:
                plane_limit_updates.append({
                    "sid": pair["min"]["sid"],
                    "coef": pair["min"]["coef"],
                    "pos": lo_new,
                })
            if abs(hi_new - pair["max"]["old"]) > 1e-12:
                plane_limit_updates.append({
                    "sid": pair["max"]["sid"],
                    "coef": pair["max"]["coef"],
                    "pos": hi_new,
                })

        duplicate_surfaces = {}
        for key, payload in duplicate_surface_widgets.items():
            chk = payload[0]
            if not chk.isChecked():
                continue
            edit = payload[1]
            label_dup = self._sanitize_label((edit.text() or "").strip())
            if not label_dup:
                QMessageBox.warning(self, "Missing duplicate label", "Add a label for the duplicated shared surface.")
                return None
            if isinstance(key, tuple) and key[0] == "plane":
                sid_map = payload[3]
                if sid_map.get("min") in payload[2]:
                    duplicate_surfaces[int(sid_map["min"])] = f"{label_dup} min"
                if sid_map.get("max") in payload[2]:
                    duplicate_surfaces[int(sid_map["max"])] = f"{label_dup} max"
            else:
                duplicate_surfaces[int(key)] = label_dup

        return {
            "kind": (e_kind.currentText() or "BODY").strip().upper(),
            "label": label,
            "material": material,
            "center": {"X": cx, "Y": cy, "Z": cz},
            "surface_param_updates": surface_param_updates,
            "plane_limit_updates": plane_limit_updates,
            "duplicate_surfaces": duplicate_surfaces,
        }

    def _edit_selected_body_module_center(self):
        row = self.lst_body_blocks.currentRow() if hasattr(self, "lst_body_blocks") else -1
        if row < 0 or row >= (self.lst_body_blocks.count() if hasattr(self, "lst_body_blocks") else 0):
            return
        item = self.lst_body_blocks.item(row)
        payload = item.data(Qt.ItemDataRole.UserRole) if item else None
        if not payload:
            return
        block_row = payload.get("block_row", -1)
        if block_row < 0 or block_row >= len(self._geo_blocks):
            return

        body_data = self._parse_body_block_data(self._geo_blocks[block_row])
        if not body_data:
            QMessageBox.warning(self, "Body/Module", "Could not parse selected BODY/MODULE block.")
            return

        surface_map = self._collect_surface_block_map()
        reference_info = self._collect_surface_reference_info()
        center_before = self._estimate_body_center(body_data.get("surface_pairs", []), surface_map)
        surface_rows = self._collect_body_surface_fields(body_data, surface_map)
        plane_rows = self._collect_body_plane_limit_fields(body_data, surface_map)
        for row_data in surface_rows:
            info = reference_info.get(int(row_data["sid"]), {})
            row_data["shared_users"] = list(info.get("users", [])) if int(info.get("count", 0)) > 1 else []
        for row_data in plane_rows:
            info = reference_info.get(int(row_data["sid"]), {})
            row_data["shared_users"] = list(info.get("users", [])) if int(info.get("count", 0)) > 1 else []
        updated = self._prompt_body_center_edit(body_data, center_before, surface_rows, plane_rows)
        if not updated:
            return

        block_row, selected_surface_pairs, surface_id_map = self._duplicate_shared_surfaces_for_body(
            block_row,
            body_data,
            updated.get("duplicate_surfaces", {}),
        )
        body_data["surface_pairs"] = selected_surface_pairs
        surface_map = self._collect_surface_block_map()

        center_after = updated["center"]
        dx = center_after["X"] - center_before["X"]
        dy = center_after["Y"] - center_before["Y"]
        dz = center_after["Z"] - center_before["Z"]

        seen_surface_ids = set()
        missing_surface_ids = []
        for sid, _side in selected_surface_pairs:
            if sid in seen_surface_ids:
                continue
            seen_surface_ids.add(sid)
            info = surface_map.get(sid)
            if not info:
                missing_surface_ids.append(sid)
                continue
            surf_row = info["row"]
            self._geo_blocks[surf_row] = self._shift_surface_block_for_center(
                self._geo_blocks[surf_row], dx, dy, dz
            )

        for (sid, key), value in updated.get("surface_param_updates", {}).items():
            sid = int(surface_id_map.get(int(sid), int(sid)))
            info = surface_map.get(sid)
            if not info:
                missing_surface_ids.append(sid)
                continue
            surf_row = info["row"]
            self._geo_blocks[surf_row] = self._set_surface_param_line(
                self._geo_blocks[surf_row], key, value
            )

        for item in updated.get("plane_limit_updates", []):
            sid = int(surface_id_map.get(int(item.get("sid", 0)), int(item.get("sid", 0))))
            info = surface_map.get(sid)
            if not info:
                missing_surface_ids.append(sid)
                continue
            coef = float(item.get("coef", 0.0) or 0.0)
            if abs(coef) < 1e-15:
                continue
            pos = float(item.get("pos", 0.0) or 0.0)
            a0_new = -coef * pos
            surf_row = info["row"]
            self._geo_blocks[surf_row] = self._set_surface_param_line(
                self._geo_blocks[surf_row], "A0", a0_new
            )

        updated_kind = (updated.get("kind", body_data.get("kind", "BODY")) or "BODY").upper()
        if updated_kind not in ("BODY", "MODULE"):
            updated_kind = body_data.get("kind", "BODY")
        self._geo_blocks[block_row] = self._render_body_block(
            updated_kind,
            int(body_data.get("body_id", 1)),
            updated["label"],
            int(updated["material"]),
            list(selected_surface_pairs),
        )
        self._write_model_to_editor()
        self._jump_to_block_row(block_row)

        if missing_surface_ids:
            missing_text = ", ".join(str(sid) for sid in sorted(set(missing_surface_ids)))
            QMessageBox.warning(
                self,
                "Missing surfaces",
                f"Updates were applied, but these linked surfaces were not found: {missing_text}",
            )

    def _duplicate_block_at_row(self, row, focus="surface"):
        if row < 0 or row >= len(self._geo_blocks):
            return
        duplicated = self._build_block_from_existing(row, duplicate=True)
        if duplicated is None:
            QMessageBox.warning(self, "Duplicate block", "Structured duplicate is only available for SURFACE, BODY, or MODULE blocks.")
            return
        if isinstance(duplicated, list):
            new_blocks = [str(block).strip("\n") for block in duplicated if str(block).strip()]
        else:
            new_blocks = [duplicated.strip("\n")] if duplicated.strip() else []
        if not new_blocks:
            return
        self._remember_surface_builder_hint_from_generated(new_blocks)
        self._sync_model_from_editor()
        self._geo_blocks.extend(new_blocks)
        self._write_model_to_editor()
        inserted_rows = list(range(len(self._geo_blocks) - len(new_blocks), len(self._geo_blocks)))
        target_row = inserted_rows[-1] if inserted_rows else row
        self._jump_to_block_row(target_row)

    def _duplicate_selected_block(self):
        self._duplicate_block_at_row(self._selected_surface_block_row(), focus="surface")

    def _duplicate_selected_body_module(self):
        self._duplicate_block_at_row(self._selected_body_module_block_row(), focus="body")

    def _mirrored_label(self, label, axis):
        base = self._sanitize_label(label or "")
        suffix = f" {axis.upper()}m"
        room = max(0, GEO_LABEL_MAX_LEN - len(suffix))
        if not base:
            base = "mirror"
        return self._sanitize_label((base[:room].rstrip() + suffix).strip())

    def _mirror_surface_block_text(self, block_text, new_sid, axis):
        axis = (axis or "X").upper()
        surface_info = self._parse_surface_block_data(block_text)
        if not surface_info:
            return None
        try:
            surfs, _bodies = _parse_geo(block_text)
            surf = next(iter(surfs.values()))
            indices = list(surf.get("indices", []))
        except Exception:
            return None
        lines = (block_text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        mirrored_lines = []
        for line in lines:
            m = re.match(r"^\s*([A-Z0-9\-]+)\s*=\(\s*([+\-]?(?:\d+(?:\.\d*)?|\.\d+)(?:[Ee][+\-]?\d+)?)\s*,", line, re.IGNORECASE)
            if not m:
                mirrored_lines.append(line)
                continue
            key = m.group(1).upper()
            try:
                value = float(m.group(2))
            except ValueError:
                mirrored_lines.append(line)
                continue
            new_value = value
            if key == f"{axis}-SHIFT":
                new_value = -value
            elif indices == [0, 0, 0, 0, 0] and key == f"A{axis}":
                new_value = -value
            mirrored_lines.append(self._fmt_param_line(key, new_value))
        mirrored_text = "\n".join(mirrored_lines).strip("\n")
        return self._set_surface_header_id_label(
            mirrored_text,
            new_sid,
            self._mirrored_label(surface_info.get("label", ""), axis),
        )

    def _mirror_block_at_row(self, row):
        if row < 0 or row >= len(self._geo_blocks):
            return False
        axis, ok = QInputDialog.getItem(self, "Mirror block", "Mirror axis:", ["X", "Y", "Z"], 0, False)
        if not ok:
            return False
        block_text = self._geo_blocks[row]
        stripped = (block_text or "").lstrip().upper()
        new_blocks = []
        if stripped.startswith("SURFACE"):
            new_sid = self.editor._next_counter_id("surface")
            mirrored = self._mirror_surface_block_text(block_text, new_sid, axis)
            if not mirrored:
                QMessageBox.warning(self, "Mirror block", "Could not mirror this SURFACE block.")
                return False
            new_blocks = [mirrored]
        elif stripped.startswith("BODY") or stripped.startswith("MODULE"):
            data = self._parse_body_block_data(block_text)
            if not data:
                QMessageBox.warning(self, "Mirror block", "Could not parse this BODY/MODULE block.")
                return False
            if data.get("body_refs"):
                QMessageBox.warning(self, "Mirror block", "Mirroring BODY/MODULE blocks with linked BODY references is not available yet.")
                return False
            surface_map = self._collect_surface_block_map()
            mirrored_pairs = []
            for sid, side in data.get("surface_pairs", []):
                info = surface_map.get(int(sid))
                if not info:
                    QMessageBox.warning(self, "Mirror block", f"Linked SURFACE {sid} was not found.")
                    return False
                new_sid = self.editor._next_counter_id("surface")
                mirrored_surface = self._mirror_surface_block_text(self._geo_blocks[info["row"]], new_sid, axis)
                if not mirrored_surface:
                    QMessageBox.warning(self, "Mirror block", f"Could not mirror linked SURFACE {sid}.")
                    return False
                new_blocks.append(mirrored_surface)
                mirrored_pairs.append((new_sid, side))
            new_body_id = self.editor._next_counter_id("body")
            new_body = self._render_body_block(
                data.get("kind", "BODY"),
                new_body_id,
                self._mirrored_label(data.get("label", ""), axis),
                int(data.get("material", 1) or 1),
                mirrored_pairs,
            )
            new_blocks.append(new_body)
        else:
            QMessageBox.warning(self, "Mirror block", "Mirroring is only available for SURFACE, BODY, or MODULE blocks.")
            return False
        if not new_blocks:
            return False
        self._sync_model_from_editor()
        self._geo_blocks.extend([blk.strip("\n") for blk in new_blocks if str(blk).strip()])
        self._write_model_to_editor()
        target_row = len(self._geo_blocks) - 1
        self._jump_to_block_row(target_row)
        self.console.log(f"[GEO] Mirrored block across {axis.upper()} axis.\n", "ok")
        return True

    def _mirror_selected_block(self):
        self._mirror_block_at_row(self._selected_surface_block_row())

    def _mirror_selected_body_module(self):
        self._mirror_block_at_row(self._selected_body_module_block_row())

    def _selected_surface_group_identities(self):
        if not hasattr(self, "lst_blocks"):
            return []
        identities = []
        for item in self.lst_blocks.selectedItems():
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if not payload or payload.get("type") != "block":
                continue
            block_row = int(payload.get("block_row", -1))
            if block_row < 0 or block_row >= len(self._geo_blocks):
                continue
            ident = self._block_identity(self._geo_blocks[block_row])
            if ident and ident[0] == "SURFACE":
                identities.append(ident)
        if identities:
            return identities
        block_row = self._selected_surface_block_row()
        if 0 <= block_row < len(self._geo_blocks):
            ident = self._block_identity(self._geo_blocks[block_row])
            if ident and ident[0] == "SURFACE":
                return [ident]
        return []

    def _group_selected_surfaces(self):
        identities = self._selected_surface_group_identities()
        if not identities:
            QMessageBox.information(self, "Group", "Select one or more SURFACE blocks first.")
            return
        name, ok = QInputDialog.getText(self, "Group SURFACE blocks", "Group name:")
        name = (name or "").strip()
        if not ok or not name:
            return
        existing = [ident for ident in self._surface_groups.get(name, []) if ident not in identities]
        self._surface_groups[name] = existing + identities
        self._surface_group_collapsed.discard(name)
        self._refresh_block_list()
        self.console.log(f"[GEO] Group '{name}' now contains {len(self._surface_groups[name])} SURFACE block(s).\n", "ok")

    def _ungroup_selected_surfaces(self):
        identities = set(self._selected_surface_group_identities())
        if not identities:
            QMessageBox.information(self, "Ungroup", "Select SURFACE blocks to remove from visual groups.")
            return
        removed = 0
        for name in list(self._surface_groups):
            kept = []
            for ident in self._surface_groups[name]:
                if ident in identities:
                    removed += 1
                else:
                    kept.append(ident)
            if kept:
                self._surface_groups[name] = kept
            else:
                self._surface_groups.pop(name, None)
                self._surface_group_collapsed.discard(name)
        self._refresh_block_list()
        self.console.log(f"[GEO] Removed {removed} SURFACE group link(s).\n", "ok")

    def _selected_body_group_identities(self):
        if not hasattr(self, "lst_body_blocks"):
            return []
        identities = []
        for item in self.lst_body_blocks.selectedItems():
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if not payload or payload.get("type") != "block":
                continue
            block_row = payload.get("block_row", -1)
            if block_row < 0 or block_row >= len(self._geo_blocks):
                continue
            ident = self._block_identity(self._geo_blocks[block_row])
            if ident and ident[0] in ("BODY", "MODULE"):
                identities.append(ident)
        if identities:
            return identities
        row = self.lst_body_blocks.currentRow()
        if row >= 0:
            item = self.lst_body_blocks.item(row)
            payload = item.data(Qt.ItemDataRole.UserRole) if item else None
            if payload and payload.get("type") == "block":
                block_row = payload.get("block_row", -1)
                if 0 <= block_row < len(self._geo_blocks):
                    ident = self._block_identity(self._geo_blocks[block_row])
                    if ident and ident[0] in ("BODY", "MODULE"):
                        return [ident]
        return []

