        outer.addLayout(row_3d_c)
        self.btn_render3d = QPushButton("Render 3D")
        self.btn_render3d.setToolTip("Render the current 3D geometry volume.")
        self.btn_render3d.setStyleSheet(btn_css(P["bg2"], 130))
        self.btn_render3d.clicked.connect(self._render_3d)
        self.btn_gpu3d = QPushButton("GPU Live 3D")
        gpu3d_tooltip = (
            "Render a boundary point-cloud in the hardware-accelerated OpenGL viewer.\n"
            "Same sampling as Lite boundary cloud mode — drag to orbit, wheel to zoom.\n"
            + ("OpenGL 3.3 available." if _OPENGL_AVAILABLE else "OpenGL unavailable on this system.")
        )
        self.btn_gpu3d.setToolTip(gpu3d_tooltip)
        self.btn_gpu3d.setStyleSheet(btn_css(P["bg2"], 110))
        self.btn_gpu3d.setEnabled(_OPENGL_AVAILABLE)
        self.btn_gpu3d.clicked.connect(self._render_3d_gpu)
        self.btn_native3d = QPushButton("Native 3D")
        self.btn_native3d.setToolTip("Show the native gview3d bridge inside this Geometry tab using the current Studio geometry.")
        self.btn_native3d.setStyleSheet(btn_css(P["bg2"], 96))
        self.btn_native3d.clicked.connect(self._open_gview3d_interface)
        self.btn_reset3d = QPushButton("Reset")
        self.btn_reset3d.setToolTip("Recalculate 2D center/span and 3D min/max values from the current geometry.")
        self.btn_reset3d.setStyleSheet(btn_css(P["bg2"], 72))
        self.btn_reset3d.clicked.connect(self._auto_set_ranges)
        row_3d_actions = QHBoxLayout()
        row_3d_actions.setContentsMargins(0, 0, 0, 0)
        row_3d_actions.setSpacing(6)
        row_3d_actions.addWidget(self.btn_render3d)
        row_3d_actions.addWidget(self.btn_gpu3d)
        row_3d_actions.addWidget(self.btn_native3d)
        row_3d_actions.addWidget(self.btn_reset3d)
        row_3d_actions.addStretch(1)
        self.chk_render_gpu = QCheckBox("GPU classify (CuPy)")
        self.chk_render_gpu.setStyleSheet(checkbox_css())
        self.chk_render_gpu.setToolTip(
            "Use GPU (CuPy/CUDA) for geometry point-classification during 2D and 3D renders.\n"
            "Gives 10-30× speedup at resolution ≥5. Frees CPU cores for penmain simulations.\n"
            "Requires a CUDA-capable GPU with CuPy installed."
        )
        self.chk_render_gpu.setChecked(_RENDER_GPU_ENABLED)
        self.chk_render_gpu.setVisible(_CUPY_AVAILABLE)
        self.chk_render_gpu.stateChanged.connect(self._toggle_render_gpu)
        row_3d_actions.addWidget(self.chk_render_gpu)
