    def _make_file_toolbar(self):
        tb = QFrame()
        tb.setStyleSheet(
            f"QFrame {{ background:{P['bg2']};"
            f" border-bottom:1px solid {P['border']}; }}")
        lay = QHBoxLayout(tb)
        lay.setContentsMargins(6, 4, 6, 4)
        lay.setSpacing(6)

        for text, tip, slot in [
            ("New",   "New .in file",  self._new_in),
            ("Open", "Open .in file", self._open_in),
            ("Save", "Save .in file", self._save_in),
            ("Save As...", "Save .in file as", self._save_in_as),
        ]:
            b = QPushButton(text)
            b.setToolTip(tip)
            b.setStyleSheet(btn_css(width=78 if text == "Save As..." else None))
            b.clicked.connect(slot)
            lay.addWidget(b)

        upd_title_btn = QPushButton("Update Title")
        upd_title_btn.setToolTip(
            "Set TITLE to {filename}_SPOSIT-x_y_z-SCONE-... based on the current .in values. "
            "Skipped if the title already matches the pattern."
        )
        upd_title_btn.setStyleSheet(btn_css(width=100))
        upd_title_btn.clicked.connect(self._update_in_title)
        lay.addWidget(upd_title_btn)

        lay.addStretch()
        self.lbl_in_path = QLabel("No file open")
        self.lbl_in_path.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(self.lbl_in_path)
        return tb

    def _show_help(self):
        show_help_dialog(
            self,
            "Simulation (.in) Help",
            f"""
            <h2 style="color:{P['accent']};">Simulation (.in)</h2>
            <p>This tab edits PENELOPE <b>.in</b> files and launches <code>penmain &lt; current_file.in</code> from the selected case folder.</p>
            <h3>Source Definition</h3>
            <ul>
              <li><b>SKPAR</b> selects the primary particle: 1 electron, 2 photon, 3 positron.</li>
              <li><b>SENERG</b> is a single energy. <b>SPECTR</b> is a spectrum table with energy-bin lower limits and probabilities.</li>
              <li><b>SPOSIT</b> is the source position <code>X Y Z</code> in cm.</li>
              <li><b>SCONE</b> is <code>theta phi alpha</code>: polar direction, azimuth, and cone opening angle. The particle editor has an angle-diagram Help button.</li>
            </ul>
            <h3>Materials And Geometry</h3>
            <ul>
              <li><b>Add/Edit Materials</b> manages <code>MFNAME</code>/<code>MSIMPA</code> pairs and can use a dedicated material folder.</li>
              <li><b>Set Geometry File</b> writes or replaces <code>GEOMFN</code>. Its picker can use a persistent geometry folder.</li>
              <li><b>Create Case</b> copies the active input, linked geometry, and material files into a run folder.</li>
            </ul>
            <h3>Run And Batch</h3>
            <ul>
              <li><b>Run Simulation</b> runs the active input in the current run folder.</li>
              <li><b>Run Batch</b> scans complete case subfolders under Case Root and runs inputs with the selected thread limit.</li>
              <li><b>Run Selected</b> lets you choose a subset of cases.</li>
              <li><b>Has dmp</b> filters batch candidates to cases that already contain a dump file.</li>
              <li><b>Use dmp</b> compares <code>NSIMSH</code> with <code>penmain-res.dat</code>: equal showers are skipped, higher requested showers resume from dump, and lower requested showers restart fresh.</li>
              <li><b>Kill</b> stops the selected run. <b>Kill All</b> kills the full process tree and clears queued runs.</li>
            </ul>
            <h3>Safety</h3>
            <ul>
              <li>Changing source, spectrum, geometry, or materials makes old output/dump files unsafe to reuse; the studio archives stale <code>.dat</code>/<code>.dmp</code> outputs where possible.</li>
              <li>If a dump is empty or corrupted, it is moved aside and the run is retried once.</li>
              <li>Changing only <code>NSIMSH</code>, <code>TIME</code>, or <code>DUMPP</code> is treated as a lower-risk continuation edit.</li>
            </ul>
            """,
        )

    @staticmethod
    def _separator_line():
        line = QFrame()
        line.setFrameShape(QFrame.Shape.HLine)
        line.setStyleSheet(f"color:{P['border']};")
        return line

    def _build_sim_section_sidebar(self):
        self._sim_section_buttons = {}
        self._sim_section_toggles = {}
        group = QGroupBox("PENELOPE Input Blocks")
        group.setToolTip("Manual-oriented control of the main penmain input-file sections.")
        group.setStyleSheet(group_css())
        lay = QVBoxLayout(group)
        lay.setContentsMargins(8, 12, 8, 8)
        lay.setSpacing(6)

        hint = QLabel(
            "Blocks are listed in the same penmain input order described in the manual. "
            "Required blocks open their editor; optional blocks use one checkbox, and the block is only added if you confirm the setup."
        )
        hint.setWordWrap(True)
        hint.setStyleSheet(label_css(P["fg2"], size=8))
        lay.addWidget(hint)
        for spec in SIM_SECTION_SPECS:
            key = spec["key"]
            if key == "psf":
                continue
            if spec.get("required"):
                btn = QPushButton(spec["title"])
                btn.setToolTip(spec["description"])
                btn.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
                btn.setStyleSheet(btn_css())
                btn.clicked.connect(lambda _checked=False, current_key=key: self._open_sim_section(current_key))
                lay.addWidget(btn)
                self._sim_section_buttons[key] = btn
                self._sim_section_toggles[key] = None
                if key == "source":
                    self.btn_particle_source = btn
                elif key == "materials":
                    self.btn_materials_section = btn
                elif key == "geometry":
                    self.btn_geometry_section = btn
                elif key == "job":
                    self.btn_job_properties = btn
            else:
                chk = QCheckBox(spec["title"])
                chk.setToolTip(spec["description"])
                chk.setStyleSheet(checkbox_css())
                chk.toggled.connect(lambda checked, current_key=key: self._handle_optional_sim_section_toggle(current_key, checked))
                lay.addWidget(chk)
                self._sim_section_buttons[key] = None
                self._sim_section_toggles[key] = chk
                if key == "interaction":
                    self.chk_interaction_forcing = chk
                elif key == "emerging":
                    self.chk_emerging_particles = chk
                elif key == "impact":
                    self.chk_impact_detectors = chk
                elif key == "endet":
                    self.chk_energy_deposition = chk
                elif key == "dose":
                    self.chk_dose_distribution = chk
                elif key == "psf":
                    self.chk_psf_section = chk

        return group

    def _sim_section_title_matches(self, key, line):
        spec = SIM_SECTION_SPEC_MAP.get(key, {})
        low = str(line or "").strip().lower()
        if not low:
            return False
        return any(alias in low for alias in spec.get("aliases", ()))

    def _has_psf_section(self):
        text = self._get_text()
        if re.search(r"^\s*(IPSFN|IPSPLI|WGTWIN|EPMAX)\b", text, re.IGNORECASE | re.MULTILINE):
            return True
        return any(self._sim_section_title_matches("psf", line) for line in text.split("\n"))

    def _sim_section_is_present(self, key):
        if key == "source":
            return True
        if key == "psf":
            return self._has_psf_section()
        if key == "materials":
            return True
        if key == "geometry":
            return True
        if key == "interaction":
            return self._has_interaction_forcing()
        if key == "emerging":
            return self._has_emerging_particles()
        if key == "impact":
            return self._has_impact_detectors()
        if key == "endet":
            return self._has_energy_deposition_detectors()
        if key == "dose":
            return self._has_dose_distribution()
        if key == "job":
            return self._has_job_properties_section()
        return False

    def _set_sim_section_enabled(self, key, enabled):
        if key == "psf":
            self._set_psf_section_enabled(enabled)
        elif key == "interaction":
            self._set_interaction_forcing_enabled(enabled)
        elif key == "emerging":
            self._set_emerging_particles_enabled(enabled)
        elif key == "impact":
            self._set_impact_detectors_enabled(enabled)
        elif key == "endet":
            self._set_energy_deposition_enabled(enabled)
        elif key == "dose":
            self._set_dose_distribution_enabled(enabled)
        elif key == "job":
            self._set_job_properties_enabled(enabled)

    def _handle_optional_sim_section_toggle(self, key, checked):
        if checked:
            if key == "interaction":
                choice = QMessageBox.question(
                    self,
                    "Interaction forcing",
                    "Add the Interaction forcing block with the current Studio default values?",
                    QMessageBox.StandardButton.Ok | QMessageBox.StandardButton.Cancel,
                    QMessageBox.StandardButton.Ok,
                )
                if choice == QMessageBox.StandardButton.Ok:
                    self._set_interaction_forcing_enabled(True)
            elif key == "emerging":
                choice = QMessageBox.question(
                    self,
                    "Emerging particles",
                    "Add the Emerging particles block with the current Studio default values?",
                    QMessageBox.StandardButton.Ok | QMessageBox.StandardButton.Cancel,
                    QMessageBox.StandardButton.Ok,
                )
                if choice == QMessageBox.StandardButton.Ok:
                    self._set_emerging_particles_enabled(True)
            else:
                self._open_sim_section(key)
            if not self._sim_section_is_present(key):
                toggle = self._sim_section_toggles.get(key)
                if toggle is not None:
                    toggle.blockSignals(True)
                    toggle.setChecked(False)
                    toggle.blockSignals(False)
        else:
            self._set_sim_section_enabled(key, False)

    def _open_sim_section(self, key):
        if key == "source":
            self._cmd_particle_source()
        elif key == "psf":
            self._cmd_particle_source()
        elif key == "materials":
            self._cmd_edit_materials()
        elif key == "geometry":
            self._cmd_geomfn()
        elif key == "interaction":
            self._set_interaction_forcing_enabled(True)
        elif key == "emerging":
            self._set_emerging_particles_enabled(True)
        elif key == "impact":
            self._cmd_add_impdet()
        elif key == "endet":
            self._cmd_add_endetc()
        elif key == "dose":
            self._cmd_dose_distribution()
        elif key == "job":
            self._cmd_job_properties()

    def _update_sim_section_sidebar(self):
        buttons = getattr(self, "_sim_section_buttons", {})
        toggles = getattr(self, "_sim_section_toggles", {})
        if not buttons or not toggles:
            return
        for spec in SIM_SECTION_SPECS:
            key = spec["key"]
            present = self._sim_section_is_present(key)
            required = bool(spec.get("required"))
            btn = buttons.get(key)
            toggle = toggles.get(key)
            if btn is not None:
                btn.setStyleSheet(btn_css(P["bg3"] if present else P["bg2"]))
            if toggle is not None:
                toggle.blockSignals(True)
                toggle.setChecked(present)
                toggle.setStyleSheet(checkbox_css())
                toggle.blockSignals(False)

    #  File ops 

    def _new_in(self):
        self.editor.setPlainText(DEFAULT_IN_TEMPLATE)
        self._in_path = None
        self._run_folder = None
        self._source_energy_mode = ""
        self._spectr_source_path = ""
        self._spectr_prob_column = 6
        self._spectr_auto_sync_enabled = False
        self._last_auto_spectr_key = None
        self._spectr_source_kind = "file"
        self._spectr_database_label = ""
        self.lbl_in_path.setText("Untitled")
        self.editor.document().setModified(False)
        self._set_sim_blocks_visible(True)
        self._update_sim_action_labels()

    def _open_in(self, path=None):
        if not path:
            path, _ = QFileDialog.getOpenFileName(
                self, "Open .in file", self._in_open_start_folder(),
                "PENELOPE input (*.in);;All files (*.*)")
        if not path:
            return
        try:
            raw  = Path(path).read_bytes()
            text = _decode_text_bytes(raw).replace("\r\n", "\n").replace("\r", "\n")
            self.editor.setPlainText(text)
            self._in_path = path
            self._source_energy_mode = ""
            self._spectr_source_path = ""
            self._spectr_prob_column = 6
            self._spectr_auto_sync_enabled = False
            self._last_auto_spectr_key = None
            self._spectr_source_kind = "file"
            self._spectr_database_label = ""
            self._load_spectr_link(path)
            opened_folder = Path(path).parent
            self._run_folder = opened_folder
            self.lbl_in_path.setText(os.path.basename(path))
            self.editor.document().setModified(False)
            self.console.log(f"[SIM] Opened: {path}\n", "info")
            self._report_phase_space_input_status(path, text)
            self._set_workspace_root(opened_folder, log_label="Current case root")
            self._update_file_source_labels()
            self.status_message.emit(f"Input: {os.path.basename(path)}")
            self._set_sim_blocks_visible(True)
            self._update_sim_action_labels()
        except Exception as e:
            QMessageBox.critical(self, "Error", str(e))

    def _normalize_in_for_save_guard(self, text):
        lines = []
        ignore_re = re.compile(r"^\s*(NSIMSH|TIME|DUMPP)\b", re.IGNORECASE)
        for line in (text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n"):
            if ignore_re.match(line):
                continue
            lines.append(line.rstrip())
        while lines and not lines[-1].strip():
            lines.pop()
        return "\n".join(lines)

    def _has_significant_in_save_change(self, path, new_text):
        path = Path(path)
        if not path.exists() or not path.is_file():
            return False
        try:
            old_text = _decode_text_bytes(path.read_bytes())
        except Exception:
            return False
        return (
            self._normalize_in_for_save_guard(old_text)
            != self._normalize_in_for_save_guard(new_text)
        )

    def _analyze_in_keywords(self, text):
        lines = (text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        fixed_lines = list(lines)
        issues = []
        section = ""
        section_re = re.compile(r"^\s*>{3,}\s*(.*?)\s*$")
        keyword_re = re.compile(r"^(\s*)([A-Z][A-Z0-9]*)\b(.*)$")
        current_material_row = None
        material_rows_missing_msimpa = []

        def section_key_from_title(title):
            title = (title or "").lower()
            if "source definition" in title:
                return "source"
            if "phase-space file" in title or "input phase-space" in title:
                return "psf"
            if "material data" in title:
                return "materials"
            if "geometry definition" in title or "geometry and local simulation parameters" in title:
                return "geometry"
            if "interaction forcing" in title:
                return "forcing"
            if "emerging particles" in title:
                return "emerging"
            if "impact detectors" in title:
                return "impdet"
            if "energy deposition detectors" in title:
                return "endet"
            if "dose distribution" in title:
                return "dose"
            if "job properties" in title:
                return "job"
            return ""

        def closest_keyword(keyword, allowed):
            if not allowed:
                return ""
            matches = difflib.get_close_matches(keyword, sorted(allowed), n=1, cutoff=0.55)
            return matches[0] if matches else ""

        for idx, line in enumerate(lines, start=1):
            stripped = line.strip()
            sec = section_re.match(line)
            if sec:
                section = section_key_from_title(sec.group(1).strip())
                continue
            if not stripped or stripped == "." or stripped.startswith("["):
                continue
            km = keyword_re.match(line)
            if not km:
                continue
            indent, keyword, rest = km.groups()
            keyword_u = keyword.upper()
            fixed_line = fixed_lines[idx - 1]
            if "\t" in line:
                fixed_line = fixed_line.replace("\t", " ")
                issues.append(f"L{idx}: tabs found in '{keyword_u}' line; replaced tabs with spaces.")
            if section == "geometry" and keyword_u == "EABS":
                fixed_line = re.sub(r"^(\s*)EABS\b", r"\1EABSB", fixed_line, count=1, flags=re.IGNORECASE)
                fixed_line = fixed_line.replace("EABS(1:3)", "EABSB(1:3)")
                issues.append(f"L{idx}: keyword 'EABS' inside Geometry definition should be 'EABSB'.")
                keyword_u = "EABSB"
            elif keyword_u not in self.IN_RUNTIME_KEYWORDS:
                allowed = set(self.IN_GLOBAL_KEYWORDS)
                if section:
                    allowed |= set(self.IN_SECTION_KEYWORDS.get(section, set()))
                suggestion = closest_keyword(keyword_u, allowed or self.IN_RUNTIME_KEYWORDS)
                if suggestion:
                    issues.append(f"L{idx}: unknown keyword '{keyword_u}'" + (f" in {section} section" if section else "") + f"; did you mean '{suggestion}'?")
                else:
                    issues.append(f"L{idx}: unknown keyword '{keyword_u}'" + (f" in {section} section." if section else "."))
            else:
                allowed_here = set(self.IN_GLOBAL_KEYWORDS)
                if section:
                    allowed_here |= set(self.IN_SECTION_KEYWORDS.get(section, set()))
                if section and keyword_u not in allowed_here:
                    suggestion = closest_keyword(keyword_u, self.IN_SECTION_KEYWORDS.get(section, set()))
                    if suggestion and suggestion != keyword_u:
                        issues.append(f"L{idx}: keyword '{keyword_u}' is unusual in {section} section; expected something like '{suggestion}'.")
                    elif keyword_u not in self.IN_GLOBAL_KEYWORDS:
                        issues.append(f"L{idx}: keyword '{keyword_u}' appears outside its usual section ({section}).")

            if keyword_u == "MFNAME":
                current_material_row = idx
            elif keyword_u == "MSIMPA":
                current_material_row = None
            elif current_material_row is not None:
                material_rows_missing_msimpa.append(current_material_row)
                current_material_row = None
            fixed_lines[idx - 1] = fixed_line

        if current_material_row is not None:
            material_rows_missing_msimpa.append(current_material_row)
        for row in sorted(set(material_rows_missing_msimpa)):
            issues.append(f"L{row}: MFNAME should normally be followed by an MSIMPA line.")
        fixed_text = "\n".join(fixed_lines)
        return issues, fixed_text

    def _validate_in_text_before_save(self, text):
        issues, fixed_text = self._analyze_in_keywords(text)
        if not issues:
            return True, text
        box = QMessageBox(self)
        box.setIcon(QMessageBox.Icon.Warning)
        box.setWindowTitle("Input validation")
        box.setText("The .in file has keyword/format issues that can break a PENELOPE run.")
        box.setInformativeText("Do you want Studio to fix them before saving?")
        fix_btn = box.addButton("Fix and Save", QMessageBox.ButtonRole.AcceptRole)
        save_btn = box.addButton("Save Anyway", QMessageBox.ButtonRole.ActionRole)
        cancel_btn = box.addButton("Cancel", QMessageBox.ButtonRole.RejectRole)
        box.setDefaultButton(fix_btn)
        box.setDetailedText("\n".join(issues))
        box.exec()
        clicked = box.clickedButton()
        if clicked is fix_btn:
            return True, fixed_text
        if clicked is save_btn:
            return True, text
        return False, text

    def _archive_before_significant_in_save(self, path):
        path = Path(path)
        folder = path.parent
        if not folder.exists() or not folder.is_dir():
            return None
        archive_root = folder / "input change backups"
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        archive_dir = archive_root / stamp
        idx = 1
        while archive_dir.exists():
            archive_dir = archive_root / f"{stamp}_{idx}"
            idx += 1
        archive_dir.mkdir(parents=True, exist_ok=True)
        copied = 0
        moved_outputs = 0

        def should_skip(item):
            try:
                resolved = item.resolve()
                if resolved == archive_root.resolve() or archive_root.resolve() in resolved.parents:
                    return True
            except Exception:
                pass
            return False

        for item in sorted(folder.iterdir(), key=lambda p: p.name.lower()):
            if should_skip(item):
                continue
            target = archive_dir / item.name
            if item.is_dir():
                shutil.copytree(
                    item,
                    target,
                    ignore=shutil.ignore_patterns("input change backups"),
                )
                copied += 1
            elif item.is_file():
                if item.suffix.lower() in {".dat", ".dmp"}:
                    shutil.move(str(item), str(target))
                    moved_outputs += 1
                else:
                    shutil.copy2(item, target)
                    copied += 1
        self.console.log(
            f"[SIM] Significant .in change archived current case to {archive_dir}. "
            f"Copied {copied} item(s), moved {moved_outputs} .dat/.dmp output file(s).\n",
            "warn",
        )
        return archive_dir

    def _write_in_to_path(self, path):
        text = self.editor.toPlainText()
        ok, text = self._validate_in_text_before_save(text)
        if not ok:
            raise RuntimeError("Save cancelled by user after input validation.")
        old_text = ""
        path_obj = Path(path)
        if path_obj.exists():
            try:
                old_text = _decode_text_bytes(path_obj.read_bytes())
            except Exception:
                old_text = ""
        old_folder = self._in_folder()
        if self._has_significant_in_save_change(path, text):
            self._archive_before_significant_in_save(path)
        path_obj.write_bytes(_encode_text_bytes(text))
        self._in_path = path
        if self._run_folder is None or Path(path).parent != old_folder:
            self._run_folder = Path(path).parent
        self._save_spectr_link(path)
        if self.editor.toPlainText() != text:
            self._set_text(text)
        self.lbl_in_path.setText(os.path.basename(self._in_path))
        self.editor.document().setModified(False)
        self.console.log(f"[SIM] Saved: {self._in_path}\n", "ok")
        app_log(summarize_line_changes(old_text, text, f"Saved input {self._in_path}"), "SIM")
        self.status_message.emit(f"Input: {os.path.basename(path)}")

    def _save_in(self):
        if not self._in_path:
            return self._save_in_as()
        try:
            self._write_in_to_path(self._in_path)
            return True
        except Exception as e:
            QMessageBox.critical(self, "Error", str(e))
            return False

    def _save_in_as(self):
        start = self._in_save_start_path()
        path, _ = QFileDialog.getSaveFileName(
            self, "Save .in file as", start,
            "PENELOPE input (*.in);;All files (*.*)")
        if not path:
            return False
        if not Path(path).suffix:
            path += ".in"
        try:
            self._write_in_to_path(path)
            return True
        except Exception as e:
            QMessageBox.critical(self, "Error", str(e))
            return False

    def _on_modified(self):
        name = os.path.basename(self._in_path) if self._in_path else "Untitled"
        self.lbl_in_path.setText(f"{name} *")
        self._update_sim_action_labels()
        self._sync_impdet_energy_to_source()
        self._auto_sync_spectr_from_particle()

    #  Smart-edit helpers 

    def _get_text(self):
        if self._staged_in_text is not None:
            return str(self._staged_in_text)
        return self.editor.toPlainText()

    def has_unsaved_changes(self):
        return self.editor.document().isModified()

    def _set_text(self, text):
        if self._staged_in_text is not None:
            self._staged_in_text = str(text or "")
            if callable(self._staged_update_callback):
                try:
                    self._staged_update_callback()
                except Exception:
                    pass
            return
        cur_pos = self.editor.textCursor().position()
        self.editor.setPlainText(text)
        cur = self.editor.textCursor()
        cur.setPosition(max(0, min(cur_pos, len(text))))
        self.editor.setTextCursor(cur)

    def _in_folder(self):
        if self._staged_in_path:
            try:
                return Path(self._staged_in_path).parent
            except Exception:
                pass
        if self._in_path:
            return Path(self._in_path).parent
        # No .in saved yet — prefer Documents, then cwd.
        try:
            docs = Path.home() / "Documents"
            if docs.is_dir():
                return docs
        except Exception:
            pass
        return Path.cwd()

    def _begin_staged_in_edit_session(self, text, in_path, *, geo_folder=None, mat_folder=None, on_change=None):
        self._staged_in_text = str(text or "")
        self._staged_in_path = str(in_path) if in_path else ""
        self._staged_geo_list_folder = str(geo_folder) if geo_folder else None
        self._staged_mat_list_folder = str(mat_folder) if mat_folder else None
        self._staged_update_callback = on_change
        if callable(self._staged_update_callback):
            try:
                self._staged_update_callback()
            except Exception:
                pass

    def _end_staged_in_edit_session(self):
        self._staged_in_text = None
        self._staged_in_path = None
        self._staged_geo_list_folder = None
        self._staged_mat_list_folder = None
        self._staged_update_callback = None

    def _project_instructions_folder(self):
        """Return the project instructions folder path, or None if no project is active."""
        if not self._project_root:
            return None
        folders = dict((self._project_meta or {}).get("folders") or {})
        rel = folders.get("instructions", PROJECT_DIR_INSTRUCTIONS)
        try:
            return Path(self._project_root) / rel
        except Exception:
            return None

    def _project_geometry_folder(self):
        if not self._project_root:
            return None
        folders = dict((self._project_meta or {}).get("folders") or {})
        rel = folders.get("geometry", PROJECT_DIR_GEOMETRY)
        try:
            return Path(self._project_root) / rel
        except Exception:
            return None

    def _project_materials_folder(self):
        if not self._project_root:
            return None
        folders = dict((self._project_meta or {}).get("folders") or {})
        rel = folders.get("materials", PROJECT_DIR_MATERIALS)
        try:
            return Path(self._project_root) / rel
        except Exception:
            return None

    def _in_open_start_folder(self):
        """Starting folder for the Open .in dialog."""
        if self._in_path:
            return str(Path(self._in_path).parent)
        inst = self._instructions_root_path()
        try:
            inst.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        return str(inst)

    def _in_save_start_path(self):
        """Starting path for Save .in As dialog."""
        if self._in_path:
            return self._in_path
        inst = self._instructions_root_path()
        try:
            inst.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        return str(inst / "simulation.in")

    def _spectr_link_sidecar_path(self, in_path=None):
        target = Path(in_path) if in_path else (Path(self._in_path) if self._in_path else None)
        if target is None:
            return None
        return target.with_suffix(target.suffix + ".spectr_link.json")

    def _load_spectr_link(self, in_path):
        sidecar = self._spectr_link_sidecar_path(in_path)
        self._spectr_source_path = ""
        self._spectr_auto_sync_enabled = False
        self._spectr_source_kind = "file"
        self._spectr_database_label = ""
        if sidecar is None or not sidecar.exists():
            return
        try:
            data = json.loads(sidecar.read_text(encoding="utf-8"))
            self._spectr_source_kind = str(data.get("source_kind", "file") or "file").strip().lower() or "file"
            if self._spectr_source_kind == "database":
                self._spectr_database_label = str(data.get("database_label", "") or "").strip()
                db_raw = str(data.get("database_path", "") or "").strip()
                if db_raw:
                    candidate = Path(db_raw)
                    if not candidate.is_absolute():
                        candidate = Path(in_path).parent / candidate
                    self._spectr_database_path = str(candidate.resolve()) if candidate.exists() else str(candidate)
                return
            raw = str(data.get("spectrum_path", "")).strip()
            if not raw:
                return
            candidate = Path(raw)
            if not candidate.is_absolute():
                candidate = Path(in_path).parent / candidate
            if candidate.exists():
                self._spectr_source_path = str(candidate.resolve())
                self._spectr_auto_sync_enabled = True
                self.console.log(f"[SIM] SPECTR link loaded: {self._spectr_source_path}\n", "info")
        except Exception as exc:
            self.console.log(f"[SIM] Failed to load SPECTR link: {exc}\n", "warn")

    def _save_spectr_link(self, in_path):
        sidecar = self._spectr_link_sidecar_path(in_path)
        if sidecar is None:
            return
        defaults = self._current_source_defaults()
        is_spectr = defaults.get("energy_type") == "SPECTR"
        if is_spectr and getattr(self, "_spectr_source_kind", "file") == "database" and str(getattr(self, "_spectr_database_label", "") or "").strip():
            try:
                db_path = str(getattr(self, "_spectr_database_path", "") or "").strip()
                in_dir = Path(in_path).parent
                stored_db = ""
                if db_path:
                    src = Path(db_path)
                    try:
                        stored_db = str(src.resolve().relative_to(in_dir.resolve()))
                    except Exception:
                        stored_db = str(src.resolve()) if src.exists() else str(src)
                payload = {
                    "source_kind": "database",
                    "database_label": str(getattr(self, "_spectr_database_label", "") or "").strip(),
                    "database_path": stored_db,
                    "saved_at": datetime.now().isoformat(timespec="seconds"),
                }
                sidecar.write_text(json.dumps(payload, indent=2), encoding="utf-8")
            except Exception as exc:
                self.console.log(f"[SIM] Failed to save SPECTR link: {exc}\n", "warn")
            return
        source_path = str(getattr(self, "_spectr_source_path", "") or "").strip()
        if (not is_spectr) or (not source_path) or (not self._spectr_auto_sync_enabled):
            try:
                if sidecar.exists():
                    sidecar.unlink()
            except Exception:
                pass
            return
        try:
            src = Path(source_path)
            in_dir = Path(in_path).parent
            try:
                stored = str(src.resolve().relative_to(in_dir.resolve()))
            except Exception:
                stored = str(src.resolve())
            payload = {
                "source_kind": "file",
                "spectrum_path": stored,
                "saved_at": datetime.now().isoformat(timespec="seconds"),
            }
            sidecar.write_text(json.dumps(payload, indent=2), encoding="utf-8")
        except Exception as exc:
            self.console.log(f"[SIM] Failed to save SPECTR link: {exc}\n", "warn")

    def _folder_files(self, suffix):
        folder = self._material_list_folder() if str(suffix).lower() == ".mat" else self._in_folder()
        try:
            return sorted((p.name for p in folder.glob(f"*{suffix}") if p.is_file()), key=str.lower)
        except Exception:
            return []

    def _has_source_keywords(self):
        return bool(re.search(r"^\s*(SKPAR|SENERG|SPECTR|SPOSIT|SCONE)\b", self._get_text(), re.MULTILINE))

    def _set_sim_blocks_visible(self, visible):
        if hasattr(self, "sim_blocks_section"):
            self.sim_blocks_section.setVisible(bool(visible))

    def _update_sim_action_labels(self):
        if self._staged_in_text is not None:
            if callable(self._staged_update_callback):
                try:
                    self._staged_update_callback()
                except Exception:
                    pass
            return
        if hasattr(self, "chk_impact_detectors"):
            self.chk_impact_detectors.blockSignals(True)
            self.chk_impact_detectors.setChecked(self._has_impact_detectors())
            self.chk_impact_detectors.blockSignals(False)
        if hasattr(self, "chk_energy_deposition"):
            self.chk_energy_deposition.blockSignals(True)
            self.chk_energy_deposition.setChecked(self._has_energy_deposition_detectors())
            self.chk_energy_deposition.blockSignals(False)
        if hasattr(self, "chk_dose_distribution"):
            self.chk_dose_distribution.blockSignals(True)
            self.chk_dose_distribution.setChecked(self._has_dose_distribution())
            self.chk_dose_distribution.blockSignals(False)
        if hasattr(self, "chk_interaction_forcing"):
            self.chk_interaction_forcing.blockSignals(True)
            self.chk_interaction_forcing.setChecked(self._has_interaction_forcing())
            self.chk_interaction_forcing.blockSignals(False)
        if hasattr(self, "chk_emerging_particles"):
            self.chk_emerging_particles.blockSignals(True)
            self.chk_emerging_particles.setChecked(self._has_emerging_particles())
            self.chk_emerging_particles.blockSignals(False)
        self._refresh_sim_blocks()
        self._update_sim_section_sidebar()

    def _tree_item(self, parent, title, value="", action="", payload=None):
        label = str(title) if value in ("", None) else f"{title}: {value}"
        item = QTreeWidgetItem([label])
        item.setData(0, Qt.ItemDataRole.UserRole, action)
        item.setData(0, Qt.ItemDataRole.UserRole + 1, payload)
        flags = item.flags()
        if action == "material" and parent is not None:
            flags |= Qt.ItemFlag.ItemIsDragEnabled
        else:
            flags &= ~Qt.ItemFlag.ItemIsDragEnabled
        if action in {"materials", "material_list"}:
            flags |= Qt.ItemFlag.ItemIsDropEnabled
        else:
            flags &= ~Qt.ItemFlag.ItemIsDropEnabled
        item.setFlags(flags)
        if parent is None:
            self.sim_blocks.addTopLevelItem(item)
        else:
            parent.addChild(item)
        return item

    def _refresh_sim_blocks(self):
        if not hasattr(self, "sim_blocks"):
            return
        self.sim_blocks.blockSignals(True)
        expanded = set()
        for idx in range(self.sim_blocks.topLevelItemCount()):
            item = self.sim_blocks.topLevelItem(idx)
            if item.isExpanded():
                expanded.add(item.text(0))
        self.sim_blocks.clear()

        text = self._get_text()
        title_match = re.search(r"^\s*TITLE\s*(.*)$", text, re.IGNORECASE | re.MULTILINE)
        title_value = title_match.group(1).strip() if title_match else "(missing)"
        title_root = self._tree_item(None, "Title", "", "title")
        self._tree_item(title_root, "Title label", title_value, "title")

        source = self._current_source_defaults()
        source_root = self._tree_item(None, ">>>>>>>> Source definition.", "", "source")
        particles = {"1": "electron", "2": "photon", "3": "positron"}
        skpar_root = self._tree_item(source_root, "SKPAR", "", "skpar")
        self._tree_item(skpar_root, "Value", f"{source['particle']} - {particles.get(source['particle'], 'unknown')}", "skpar")
        energy_root = self._tree_item(source_root, "SENERG/SPECTR", source["energy_type"], "energy")
        if source["energy_type"] == "SPECTR":
            spectra = source.get("spectrum_lines", [])
            if source.get("spectrum_source_kind") == "database":
                path_label = source.get("spectrum_db_label") or "Database spectrum"
            else:
                path_label = source.get("spectrum_path") or "None"
            if spectra:
                path_label = f"{path_label} ({len(spectra)} row(s))"
            self._tree_item(energy_root, "SPECTR", path_label, "spectr")
            if spectra:
                first = spectra[0].split()
                last = spectra[-1].split()
                rng = f"{first[1] if len(first) > 1 else '?'} to {last[1] if len(last) > 1 else '?'}"
                self._tree_item(energy_root, "SPECTR range", rng, "spectr")
        else:
            self._tree_item(energy_root, "SENERG", f"{source['energy_value']} {source['energy_unit']}", "senerg")
        sposit_root = self._tree_item(source_root, "SPOSIT", "", "sposit")
        self._tree_item(sposit_root, "Value", ", ".join(source["sposit"]), "sposit")
        scone_root = self._tree_item(source_root, "SCONE", "", "scone")
        self._tree_item(scone_root, "Value", ", ".join(source["scone"]), "scone")

        ipsfn_names = self._ipsfn_file_names(text)
        if ipsfn_names:
            psf_root = self._tree_item(None, ">>>>>>>> Input phase-space file (psf).", "", "psf")
            for token in ipsfn_names:
                resolved = self._resolve_input_reference_file("IPSFN", token, self._in_path, run_folder=self._run_folder) if self._in_path else None
                label = f"{Path(token).name} ({'ready' if resolved else 'missing'})"
                self._tree_item(psf_root, "IPSFN", label, "psf")

        material_root = self._tree_item(None, ">>>>>>>> Material data and simulation parameters.", "", "materials")
        material_list = self._tree_item(material_root, "Linked material list", "", "material_list")
        material_entries = self._material_entries()
        if material_entries:
            for idx, entry in enumerate(material_entries, start=1):
                child = self._tree_item(material_list, f"Material {idx}", entry.get("name", ""), "material", idx - 1)
                self._tree_item(child, "MSIMPA", " ".join(entry.get("values", [])), "material_param", idx - 1)
        else:
            self._tree_item(material_list, "No materials", "Add/Edit Materials", "materials")

        geom_root = self._tree_item(None, ">>>>>>>> Geometry and local simulation parameters.", "", "geometry")
        self._tree_item(geom_root, "Geo file linked", self._current_geom_filename() or "(missing)", "geometry")

        if self._has_interaction_forcing():
            interaction_root = self._tree_item(None, ">>>>>>>> Interaction forcing.", "", "interaction")
            self._tree_item(interaction_root, "NA", "default IFORCE block", "interaction")
        if self._has_emerging_particles():
            emerging_root = self._tree_item(None, ">>>>>>>> Emerging particles. Energy and angular distributions.", "", "emerging")
            self._tree_item(emerging_root, "NA", "single-energy values follow SENERG", "emerging")
        if self._has_impact_detectors():
            impact_root = self._tree_item(None, ">>>>>>>> Impact detectors (up to 25 different detectors).", "", "impact")
            imp_count = len(re.findall(r"^\s*IMPDET\b", text, re.IGNORECASE | re.MULTILINE))
            self._tree_item(impact_root, "List of >>> Impdets", f"{imp_count} detector(s)", "impact")
        if self._has_energy_deposition_detectors():
            endet_root = self._tree_item(None, ">>>>>>>> Energy deposition detectors (up to 25).", "", "endet")
            endet_count = len(re.findall(r"^\s*ENDETC\b", text, re.IGNORECASE | re.MULTILINE))
            self._tree_item(endet_root, "List of >>> Endets", f"{endet_count} detector(s)", "endet")
        if self._has_dose_distribution():
            dose_root = self._tree_item(None, ">>>>>>>> Dose distribution.", "", "dose")
            current = self._current_dose_distribution_values()
            summary = (
                f"X[{current.get('x_min','?')}, {current.get('x_max','?')}], "
                f"Y[{current.get('y_min','?')}, {current.get('y_max','?')}], "
                f"Z[{current.get('z_min','?')}, {current.get('z_max','?')}], "
                f"N=({current.get('nx','?')}, {current.get('ny','?')}, {current.get('nz','?')})"
            )
            self._tree_item(dose_root, "Dose box", summary, "dose")
        if self._has_job_properties_section():
            job_root = self._tree_item(None, ">>>>>>>> Job properties.", "", "job")
            self._tree_item(job_root, "Value", "dump filename and DUMPP", "job")
        nsim = re.search(r"^\s*(NSIMSH\b[^\n]*)", text, re.IGNORECASE | re.MULTILINE)
        time = re.search(r"^\s*(TIME\b[^\n]*)", text, re.IGNORECASE | re.MULTILINE)
        self._tree_item(None, nsim.group(1).strip() if nsim else "NSIMSH: (missing)", "", "nsimsh")
        self._tree_item(None, time.group(1).strip() if time else "TIME: (missing)", "", "time")

        for idx in range(self.sim_blocks.topLevelItemCount()):
            item = self.sim_blocks.topLevelItem(idx)
            item.setExpanded(
                item.text(0) in expanded
                or item.text(0).startswith(">>>>>>>> Source")
                or item.text(0).startswith(">>>>>>>> Material")
                or item.text(0).startswith(">>>>>>>> Geometry")
            )
        self.sim_blocks.blockSignals(False)

    def _selected_sim_block_action(self):
        item = self.sim_blocks.currentItem() if hasattr(self, "sim_blocks") else None
        if not item:
            return "", None
        action = item.data(0, Qt.ItemDataRole.UserRole) or ""
        payload = item.data(0, Qt.ItemDataRole.UserRole + 1)
        return action, payload

    def _add_sim_block(self):
        menu = QMenu(self)
        menu.addAction("Source definition", self._cmd_particle_source)
        menu.addAction("Material data and simulation parameters", self._cmd_add_material)
        menu.addAction("Geometry and local simulation parameters", self._cmd_geomfn)
        menu.addAction("Impact detectors", self._cmd_add_impdet)
        menu.addAction("Energy-deposition detectors", self._cmd_add_endetc)
        menu.addAction("Dose distribution", self._cmd_dose_distribution)
        menu.addSeparator()
        menu.addAction("Interaction forcing", lambda: self._set_interaction_forcing_enabled(True))
        menu.addAction("Emerging particles", lambda: self._set_emerging_particles_enabled(True))
        menu.addAction("Energy-deposition detectors", lambda: self._set_energy_deposition_enabled(True))
        menu.addAction("Dose distribution", lambda: self._set_dose_distribution_enabled(True))
        menu.addAction("Job properties", lambda: self._set_job_properties_enabled(True))
        menu.exec(QCursor.pos())

    def _show_sim_block_context_menu(self, pos):
        item = self.sim_blocks.itemAt(pos)
        if item:
            self.sim_blocks.setCurrentItem(item)
        action, payload = self._selected_sim_block_action()
        menu = QMenu(self)
        menu.setStyleSheet(
            f"QMenu {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; }}"
            f"QMenu::item:selected {{ background:{P['sel']}; }}"
        )

        if not action:
            self._add_common_block_actions(menu)
        elif action == "source":
            menu.addAction("Source definition", self._cmd_particle_source)
            menu.addSeparator()
            menu.addAction("Add/Edit SKPAR", self._cmd_edit_skpar)
            menu.addAction("Add/Edit SENERG", self._cmd_edit_senerg)
            menu.addAction("Add/Edit SPECTR", self._cmd_edit_spectr)
            menu.addAction("Add/Edit SPOSIT", self._cmd_edit_sposit)
            menu.addAction("Add/Edit SCONE", self._cmd_edit_scone)
            menu.addSeparator()
            menu.addAction("Delete Source Block", self._delete_selected_sim_block)
        elif action == "psf":
            menu.addAction("Source definition", self._cmd_particle_source)
            menu.addAction("Remove Input phase-space file", self._delete_selected_sim_block)
        elif action == "energy":
            menu.addAction("Choose SENERG or SPECTR", self._cmd_edit_energy_mode)
            menu.addAction("Delete Energy", self._delete_selected_sim_block)
        elif action in {"skpar", "senerg", "spectr", "sposit", "scone"}:
            editors = {
                "skpar": ("Edit SKPAR", self._cmd_edit_skpar),
                "senerg": ("Edit SENERG", self._cmd_edit_senerg),
                "spectr": ("Edit SPECTR", self._cmd_edit_spectr),
                "sposit": ("Edit SPOSIT", self._cmd_edit_sposit),
                "scone": ("Edit SCONE", self._cmd_edit_scone),
            }
            label, slot = editors[action]
            menu.addAction(label, slot)
            menu.addAction(f"Delete {action.upper()}", self._delete_selected_sim_block)
        elif action == "materials":
            menu.addAction("Add/Edit Materials", self._cmd_edit_materials)
            menu.addAction("Edit/Organize Materials", self._cmd_edit_materials)
            menu.addAction("Delete All Materials", self._delete_selected_sim_block)
        elif action == "material_list":
            menu.addAction("Edit/Organize Linked Materials", self._cmd_edit_materials)
            menu.addAction("Add/Edit Materials", self._cmd_edit_materials)
            menu.addAction("Delete All Materials", self._delete_selected_sim_block)
        elif action in {"material", "material_param"}:
            if payload is not None:
                if action == "material":
                    menu.addAction("Edit MFNAME", lambda p=int(payload): self._cmd_edit_material_name(p))
                else:
                    menu.addAction("Edit MSIMPA", lambda p=int(payload): self._cmd_edit_material_msimpa(p))
            menu.addAction("Edit/Organize All Materials", self._cmd_edit_materials)
            menu.addAction("Delete/Unlink This Material", self._delete_selected_sim_block)
            menu.addSeparator()
            menu.addAction("Drag inside Materials to reorder", lambda: None).setEnabled(False)
            menu.addAction("Drag outside tree to unlink/delete", lambda: None).setEnabled(False)
        elif action == "geometry":
            menu.addAction("Edit Geometry File", self._cmd_geomfn)
            menu.addAction("Delete Geometry Block", self._delete_selected_sim_block)
        elif action == "impact":
            menu.addAction("Add/Edit Impact Detector", self._cmd_add_impdet)
            menu.addAction("Remove Impact Detectors", self._delete_selected_sim_block)
        elif action == "endet":
            menu.addAction("Add/Edit Energy-Deposition Detector", self._cmd_add_endetc)
            menu.addAction("Remove Energy-Deposition Detectors", self._delete_selected_sim_block)
        elif action == "dose":
            menu.addAction("Edit Dose Distribution", self._cmd_dose_distribution)
            menu.addAction("Remove Dose Distribution", self._delete_selected_sim_block)
        elif action == "interaction":
            menu.addAction("Interaction Forcing", lambda: self._handle_optional_sim_section_toggle("interaction", True))
            menu.addAction("Remove Interaction Forcing", self._delete_selected_sim_block)
        elif action == "emerging":
            menu.addAction("Emerging Particles", lambda: self._handle_optional_sim_section_toggle("emerging", True))
            menu.addAction("Remove Emerging Particles", self._delete_selected_sim_block)
        elif action == "job":
            menu.addAction("Edit Job Properties", self._cmd_job_properties)
            menu.addAction("Remove Job Properties", self._delete_selected_sim_block)
        elif action == "nsimsh":
            menu.addAction("Edit Showers (NSIMSH)", self._cmd_nsimsh)
            menu.addAction("Delete NSIMSH", self._delete_selected_sim_block)
        elif action == "time":
            menu.addAction("Edit Time Limit", self._cmd_time)
            menu.addAction("Delete TIME", self._delete_selected_sim_block)
        elif action == "title":
            menu.addAction("Edit TITLE", self._edit_title_block)
        else:
            self._add_common_block_actions(menu)

        if menu.actions():
            menu.exec(self.sim_blocks.viewport().mapToGlobal(pos))

    def _add_common_block_actions(self, menu):
        menu.addAction("Source definition", self._cmd_particle_source)
        menu.addAction("Material data and simulation parameters", self._cmd_edit_materials)
        menu.addAction("Geometry and local simulation parameters", self._cmd_geomfn)
        menu.addAction("Impact detectors", self._cmd_add_impdet)
        menu.addAction("Energy-deposition detectors", self._cmd_add_endetc)
        menu.addAction("Dose distribution", self._cmd_dose_distribution)
        menu.addAction("Job properties", self._cmd_job_properties)
        menu.addSeparator()
        menu.addAction("Interaction forcing", lambda: self._handle_optional_sim_section_toggle("interaction", True))
        menu.addAction("Emerging particles", lambda: self._handle_optional_sim_section_toggle("emerging", True))

    def _replace_source_attribute(self, keywords, new_lines):
        self._replace_section_keywords("Source definition", keywords, new_lines)
        self._normalize_source_section_order()

    def _cmd_edit_skpar(self):
        defaults = self._current_source_defaults()
        dlg = QDialog(self)
        dlg.setWindowTitle("Edit SKPAR")
        dlg.setModal(True)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        form = QFormLayout()
        cmb = QComboBox()
        cmb.addItems(["1 - electron", "2 - photon", "3 - positron"])
        cmb.setCurrentIndex({"1": 0, "2": 1, "3": 2}.get(defaults["particle"], 1))
        cmb.setStyleSheet(combo_css())
        form.addRow("SKPAR:", cmb)
        lay.addLayout(form)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        particle = cmb.currentText().split(" ", 1)[0]
        self._replace_source_attribute(
            ("SKPAR",),
            [f"SKPAR  {particle}        [Primary particles: 1=electron, 2=photon, 3=positron]"],
        )
        self._sync_impdet_energy_to_source()
        self.console.log("[SIM] SKPAR updated.\n", "ok")

    def _cmd_edit_senerg(self):
        defaults = self._current_source_defaults()
        dlg = QDialog(self)
        dlg.setWindowTitle("Edit SENERG")
        dlg.setModal(True)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        row = QWidget()
        row_lay = QHBoxLayout(row)
        row_lay.setContentsMargins(0, 0, 0, 0)
        row_lay.setSpacing(6)
        e_energy = QLineEdit(defaults["energy_value"])
        e_energy.setStyleSheet(entry_css())
        e_energy.setFixedWidth(120)
        cmb_unit = QComboBox()
        cmb_unit.addItems(["keV", "MeV"])
        cmb_unit.setCurrentText(defaults["energy_unit"])
        cmb_unit.setStyleSheet(combo_css())
        cmb_unit.setFixedWidth(78)
        row_lay.addWidget(e_energy)
        row_lay.addWidget(cmb_unit)
        row_lay.addStretch()
        form = QFormLayout()
        form.addRow("SENERG:", row)
        lay.addLayout(form)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        energy = self._format_unit_energy(e_energy.text(), cmb_unit.currentText())
        self._source_energy_mode = "SENERG"
        self._spectr_source_path = ""
        self._spectr_auto_sync_enabled = False
        self._replace_source_attribute(
            ("SENERG", "SPECTR"),
            [f"SENERG {energy:<16}    [Initial energy (monoenergetic sources only)]"],
        )
        self._sync_impdet_energy_to_source()
        self.console.log("[SIM] SENERG updated.\n", "ok")

    def _cmd_edit_energy_mode(self):
        dlg = QDialog(self)
        dlg.setWindowTitle("Choose Energy Type")
        dlg.setModal(True)
        dlg.setMinimumWidth(420)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        note = QLabel("Choose which energy block is active under SENERG/SPECTR.")
        note.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(note)
        row = QHBoxLayout()
        btn_senerg = QPushButton("SENERG")
