    def _cmd_edit_spectr(self):
        defaults = self._current_source_defaults()
        dlg = QDialog(self)
        dlg.setWindowTitle("Edit SPECTR")
        dlg.setModal(True)
        dlg.setMinimumWidth(660)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        mode_combo = QComboBox()
        mode_combo.addItems(["File (.dat/.txt)", "Spectrum Database"])
