        form = QFormLayout()
        form.addRow("Source:", mode_combo)

        path_row = QWidget()
        path_lay = QHBoxLayout(path_row)
        path_lay.setContentsMargins(0, 0, 0, 0)
        path_lay.setSpacing(6)
        e_path = QLineEdit("")
        e_path.setStyleSheet(entry_css())
        e_path.setReadOnly(True)
        e_path.setPlaceholderText("Existing SPECTR will be preserved; choose a file to replace")
        browse = QPushButton("Browse...")
        browse.setStyleSheet(btn_css(P["bg2"], 92))
        def choose():
            path, _ = QFileDialog.getOpenFileName(
                self,
                "Choose spectrum file",
                str(self._in_folder()),
                "Spectrum data (*.dat *.txt);;All files (*.*)",
            )
            if path:
                e_path.setText(path)

        browse.clicked.connect(choose)
        path_lay.addWidget(e_path, stretch=1)
        path_lay.addWidget(browse)
        form.addRow("SPECTR:", path_row)

        db_row = QWidget()
        db_lay = QHBoxLayout(db_row)
        db_lay.setContentsMargins(0, 0, 0, 0)
        db_lay.setSpacing(6)
        cmb_db = QComboBox()
        cmb_db.setStyleSheet(combo_css())
        cmb_db.setMinimumWidth(280)
        create_db_btn = QPushButton("Add/Edit Spectrum")
        create_db_btn.setStyleSheet(btn_css(P["bg2"], 130))
        db_lay.addWidget(cmb_db, stretch=1)
        db_lay.addWidget(create_db_btn)
        form.addRow("Database:", db_row)

        def refresh_db_choices(selected_label=""):
            labels = self._spectrum_database_choices()
            cmb_db.blockSignals(True)
            cmb_db.clear()
            cmb_db.addItems(labels)
            if selected_label and selected_label in labels:
                cmb_db.setCurrentText(selected_label)
            cmb_db.blockSignals(False)

        refresh_db_choices(defaults.get("spectrum_db_label", ""))
        create_db_btn.clicked.connect(lambda: refresh_db_choices(self._cmd_create_spectrum() or cmb_db.currentText()))

        particle = str(defaults.get("particle", "2")).strip()
        prob_col = self._spectr_prob_col_for_particle(particle)
        prob_lbl = QLabel(f"Column {prob_col} (from SKPAR={particle})")
        prob_lbl.setStyleSheet(label_css(P["fg2"]))
        form.addRow("Probability:", prob_lbl)
        lay.addLayout(form)
        note = QLabel("SPECTR imports energy from column 1 and uses probability column from SKPAR: 1->4, 2->6, 3->8.")
        note.setStyleSheet(label_css(P["fg2"]))
        note.setWordWrap(True)
        lay.addWidget(note)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)

        def update_mode():
            use_db = mode_combo.currentIndex() == 1
            path_row.setVisible(not use_db)
            db_row.setVisible(use_db)
            note.setVisible(not use_db)

        mode_combo.currentTextChanged.connect(lambda _txt: update_mode())
        update_mode()
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        if mode_combo.currentIndex() == 1:
            label = self._normalize_spectrum_label(cmb_db.currentText())
            if not label:
                QMessageBox.warning(self, "Missing spectrum", "Choose a spectrum from the database.")
                return
            try:
                entry = next(entry for entry in self._load_spectrum_database() if entry["label"] == label)
                lines = self._spectr_lines_from_database_rows(entry["rows"])
            except StopIteration:
                QMessageBox.warning(self, "Missing spectrum", "The selected spectrum is no longer available in the database.")
                return
            except ValueError as exc:
                QMessageBox.warning(self, "Invalid spectrum", str(exc))
                return
            self._spectr_source_kind = "database"
            self._spectr_database_label = label
            self._spectr_source_path = ""
            self._spectr_auto_sync_enabled = False
        else:
            spectrum_path = (e_path.text() or "").strip()
            if spectrum_path:
                try:
                    lines = self._spectr_lines_from_file(spectrum_path, prob_col=prob_col)
                except ValueError as exc:
                    QMessageBox.warning(self, "Invalid spectrum", str(exc))
                    return
                self._spectr_source_kind = "file"
                self._spectr_database_label = ""
                self._spectr_source_path = spectrum_path
                self._spectr_prob_column = prob_col
                self._spectr_auto_sync_enabled = True
            elif defaults["spectrum_lines"]:
                cached_path = str(getattr(self, "_spectr_source_path", "") or "").strip()
                if self._spectr_auto_sync_enabled and cached_path and Path(cached_path).is_file():
                    try:
                        lines = self._spectr_lines_from_file(cached_path, prob_col=prob_col)
                    except ValueError:
                        lines = list(defaults["spectrum_lines"])
                else:
                    lines = list(defaults["spectrum_lines"])
                self._spectr_source_kind = "file"
                self._spectr_database_label = ""
                self._spectr_prob_column = prob_col
            else:
                self._spectr_source_kind = "file"
                self._spectr_database_label = ""
                self._spectr_source_path = ""
                lines = []
                self._spectr_auto_sync_enabled = False
        self._source_energy_mode = "SPECTR"
        self._replace_source_attribute(("SENERG", "SPECTR"), lines)
        if self._spectr_source_kind == "database":
            self.console.log(f"[SIM] SPECTR updated from database: {self._spectr_database_label}\n", "ok")
        else:
            self.console.log(f"[SIM] SPECTR updated (energy col 1, prob col {prob_col}).\n", "ok")

