    def _apply_material_block_order(self, order):
        entries = self._material_entries()
        if not entries or sorted(order) != list(range(len(entries))) or order == list(range(len(entries))):
            self._refresh_sim_blocks()
            return
        reordered = [entries[idx] for idx in order]
        self._rewrite_material_entries(reordered)
        self.console.log("[SIM] Materials reordered from Simulation Blocks.\n", "ok")

    def _unlink_dropped_sim_block(self, action, payload):
        if action == "material" and payload is not None:
            self._delete_material_occurrence(int(payload))
            self.console.log("[SIM] Material unlinked by dragging out of Simulation Blocks.\n", "warn")

    def _edit_selected_sim_block(self, *args):
        action, payload = self._selected_sim_block_action()
        if action == "title":
            self._edit_title_block()
        elif action == "source":
            self._cmd_particle_source()
        elif action == "energy":
            self._cmd_edit_energy_mode()
        elif action == "skpar":
            self._cmd_edit_skpar()
        elif action == "senerg":
            self._cmd_edit_senerg()
        elif action == "spectr":
            self._cmd_edit_spectr()
        elif action == "sposit":
            self._cmd_edit_sposit()
        elif action == "scone":
            self._cmd_edit_scone()
        elif action == "psf":
            self._cmd_particle_source()
        elif action in {"materials", "material_list"}:
            self._cmd_edit_materials() if self._material_entries() else self._cmd_add_material()
        elif action == "material" and payload is not None:
            self._cmd_edit_material_name(int(payload))
        elif action == "material_param" and payload is not None:
            self._cmd_edit_material_msimpa(int(payload))
        elif action == "geometry":
            self._cmd_geomfn()
        elif action == "impact":
            self._cmd_add_impdet()
        elif action == "endet":
            self._cmd_add_endetc()
        elif action == "dose":
            self._cmd_dose_distribution()
        elif action == "interaction":
            self._handle_optional_sim_section_toggle("interaction", True)
        elif action == "emerging":
            self._handle_optional_sim_section_toggle("emerging", True)
        elif action == "job":
            self._cmd_job_properties()
        elif action == "nsimsh":
            self._cmd_nsimsh()
        elif action == "time":
            self._cmd_time()

    def _delete_selected_sim_block(self):
        action, payload = self._selected_sim_block_action()
        if action == "source":
            self._remove_keywords(("SKPAR", "SENERG", "SPECTR", "SPOSIT", "SCONE"))
        elif action == "skpar":
            self._remove_keywords(("SKPAR",))
        elif action in {"energy", "senerg", "spectr"}:
            self._remove_keywords(("SENERG", "SPECTR"))
        elif action == "sposit":
            self._remove_keywords(("SPOSIT",))
        elif action == "scone":
            self._remove_keywords(("SCONE",))
        elif action == "psf":
            self._set_psf_section_enabled(False)
        elif action in {"material", "material_param"} and payload is not None:
            self._delete_material_occurrence(int(payload))
        elif action == "materials":
            self._remove_keywords(("MFNAME", "MSIMPA"))
        elif action == "geometry":
            self._remove_keywords(("GEOMFN", "DSMAX", "EABSB"))
        elif action == "impact":
            self._set_impact_detectors_enabled(False)
        elif action == "endet":
            self._set_energy_deposition_enabled(False)
        elif action == "dose":
            self._set_dose_distribution_enabled(False)
        elif action == "interaction":
            self._set_interaction_forcing_enabled(False)
        elif action == "emerging":
            self._set_emerging_particles_enabled(False)
        elif action == "job":
            self._set_job_properties_enabled(False)
        elif action == "nsimsh":
            self._remove_keywords(("NSIMSH",))
        elif action == "time":
            self._remove_keywords(("TIME",))

    def _edit_title_block(self):
        current = ""
        match = re.search(r"^\s*TITLE\s*(.*)$", self._get_text(), re.IGNORECASE | re.MULTILINE)
        if match:
            current = match.group(1).strip()
        dlg = QDialog(self)
        dlg.setWindowTitle("Edit TITLE")
        dlg.setModal(True)
        dlg.setMinimumWidth(620)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        form = QFormLayout()
        edit = QLineEdit(current)
        edit.setStyleSheet(entry_css())
        form.addRow("TITLE:", edit)
        lay.addLayout(form)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return
        line = f"TITLE  {edit.text().strip()}"
        if match:
            lines = self._get_text().split("\n")
            lines[self._line_index_at_pos(match.start())] = line
            self._set_text("\n".join(lines))
        else:
            self._set_text(line + "\n" + self._get_text())
        self._update_sim_action_labels()

    def _line_index_at_pos(self, pos):
        return self._get_text()[:pos].count("\n")

    def _remove_keywords(self, keywords):
        keyword_re = re.compile(r"^\s*(?:" + "|".join(re.escape(k) for k in keywords) + r")\b", re.IGNORECASE)
        lines = [line for line in self._get_text().split("\n") if not keyword_re.match(line)]
        self._set_text("\n".join(lines))
        self._update_sim_action_labels()

    def _delete_material_occurrence(self, occurrence):
        lines = self._get_text().split("\n")
        out = []
        seen = -1
        skip_next_msimpa = False
        for line in lines:
            if skip_next_msimpa and re.match(r"^\s*MSIMPA\b", line, re.IGNORECASE):
                skip_next_msimpa = False
                continue
            skip_next_msimpa = False
            if re.match(r"^\s*MFNAME\b", line, re.IGNORECASE):
                seen += 1
                if seen == occurrence:
                    skip_next_msimpa = True
                    continue
            out.append(line)
        self._set_text("\n".join(out))
        self._update_sim_action_labels()

    def _has_job_properties_section(self):
        return self._section_bounds("Job properties")[1] is not None

    def _has_impact_detectors(self):
        return bool(re.search(r"^\s*(IMPDET|IDBODY)\b", self._get_text(), re.IGNORECASE | re.MULTILINE))

    def _has_energy_deposition_detectors(self):
        return bool(re.search(r"^\s*(ENDETC|EDBODY|EDSPC)\b", self._get_text(), re.IGNORECASE | re.MULTILINE))

    def _has_interaction_forcing(self):
        return bool(re.search(r"^\s*IFORCE\b", self._get_text(), re.IGNORECASE | re.MULTILINE))

    def _has_emerging_particles(self):
        return bool(re.search(r"^\s*(NBE|NBANGL)\b", self._get_text(), re.IGNORECASE | re.MULTILINE))

    def _has_dose_distribution(self):
        return bool(re.search(r"^\s*(GRIDX|GRIDY|GRIDZ|GRIDBN)\b", self._get_text(), re.IGNORECASE | re.MULTILINE))

    def _sim_section_spec_for_title(self, title):
        title_l = str(title or "").strip().lower()
        if not title_l:
            return None
        for spec in SIM_SECTION_SPECS:
            names = [spec.get("title", "")] + list(spec.get("aliases", ()))
            for name in names:
                low = str(name or "").strip().lower()
                if not low:
                    continue
                if title_l == low or title_l in low or low in title_l:
                    return spec
        return None

    def _section_aliases_for_title(self, title):
        spec = self._sim_section_spec_for_title(title)
        if spec is None:
            return [str(title or "").strip().lower()]
        names = [spec.get("title", "")] + list(spec.get("aliases", ()))
        aliases = []
        for name in names:
            low = str(name or "").strip().lower()
            if low and low not in aliases:
                aliases.append(low)
        return aliases or [str(title or "").strip().lower()]

    def _section_bounds_in_lines(self, lines, title):
        aliases = self._section_aliases_for_title(title)
        start = None
        for i, line in enumerate(lines):
            low = line.lower()
            if any(alias in low for alias in aliases):
                start = i
                break
        if start is None:
            return lines, None, None
        end = len(lines)
        for i in range(start + 1, len(lines)):
            low = lines[i].lower()
            if ">>>>>>>>" in low:
                end = i
                break
        return lines, start, end

    def _section_bounds(self, title):
        return self._section_bounds_in_lines(self._get_text().split("\n"), title)

    def _section_header_for_title(self, title):
        spec = self._sim_section_spec_for_title(title)
        key = spec.get("key") if spec else None
        header_map = {
            "source": "       >>>>>>>> Source definition.",
            "psf": "       >>>>>>>> Input phase-space file (psf).",
            "materials": "       >>>>>>>> Material data and simulation parameters.",
            "geometry": "       >>>>>>>> Geometry and local simulation parameters.",
            "interaction": "       >>>>>>>> Interaction forcing.",
            "emerging": "       >>>>>>>> Emerging particles. Energy and angular distributions.",
            "impact": "       >>>>>>>> Impact detectors (up to 25 different detectors).",
            "endet": "       >>>>>>>> Energy deposition detectors (up to 25).",
            "dose": "       >>>>>>>> Dose distribution.",
            "job": "       >>>>>>>> Job properties.",
        }
        if key in header_map:
            return header_map[key]
        return f"       >>>>>>>> {title}."

    def _insert_index_for_new_section(self, title, lines):
        spec = self._sim_section_spec_for_title(title)
        if spec is None:
            return next((i for i, line in enumerate(lines) if re.match(r"^\s*END\b", line, re.IGNORECASE)), len(lines))
        order = [entry["key"] for entry in SIM_SECTION_SPECS]
        try:
            idx = order.index(spec["key"])
        except ValueError:
            return next((i for i, line in enumerate(lines) if re.match(r"^\s*END\b", line, re.IGNORECASE)), len(lines))
        for later_key in order[idx + 1:]:
            later_title = SIM_SECTION_SPEC_MAP[later_key]["title"]
            _, later_start, _ = self._section_bounds_in_lines(lines, later_title)
            if later_start is not None:
                return later_start
        return next((i for i, line in enumerate(lines) if re.match(r"^\s*END\b", line, re.IGNORECASE)), len(lines))

    def _ensure_sim_section(self, title):
        lines, start, end = self._section_bounds(title)
        if start is not None:
            return lines, start, end
        lines = self._get_text().split("\n")
        insert_at = self._insert_index_for_new_section(title, lines)
        lines[insert_at:insert_at] = [self._section_header_for_title(title), "       ."]
        self._set_text("\n".join(lines))
        return self._section_bounds(title)

    def _insert_index_before_section_dot(self, lines, start, end):
        if start is None:
            for i, line in enumerate(lines):
                if re.match(r"^\s*END\b", line):
                    return i
            return len(lines)
        for i in range(start + 1, end):
            if lines[i].strip() == ".":
                return i
        return end

    def _replace_section_keywords(self, title, keywords, new_lines):
        lines, start, end = self._ensure_sim_section(title)
        keyword_re = re.compile(r"^\s*(?:" + "|".join(re.escape(k) for k in keywords) + r")\b", re.IGNORECASE)
        section = [line for line in lines[start + 1:end] if not keyword_re.match(line)]
        insert_rel = next((i for i, line in enumerate(section) if line.strip() == "."), len(section))
        section[insert_rel:insert_rel] = list(new_lines)
        lines[start + 1:end] = section
        self._set_text("\n".join(lines))
        self._update_sim_action_labels()

    def _extract_section_lines_from_text(self, text, title):
        lines = str(text or "").split("\n")
        _, start, end = self._section_bounds_in_lines(lines, title)
        if start is None:
            return None
        return list(lines[start:end])

    def _replace_section_in_text(self, text, title, new_section_lines):
        lines = str(text or "").split("\n")
        _, start, end = self._section_bounds_in_lines(lines, title)
        replacement = list(new_section_lines) if new_section_lines is not None else None
        if start is None:
            if replacement is None:
                return "\n".join(lines)
            insert_at = self._insert_index_for_new_section(title, lines)
            lines[insert_at:insert_at] = replacement
            return "\n".join(lines)
        if replacement is None:
            del lines[start:end]
        else:
            lines[start:end] = replacement
        return "\n".join(lines)

    def _changed_sim_sections_between_texts(self, original_text, edited_text):
        titles = [
            "Source definition",
            "Input phase-space file (psf)",
            "Material data and simulation parameters",
            "Geometry and local simulation parameters",
            "Interaction forcing",
            "Emerging particles",
            "Impact detectors",
            "Energy deposition detectors",
            "Dose distribution",
            "Job properties",
        ]
        changes = []
        for title in titles:
            before = self._extract_section_lines_from_text(original_text, title)
            after = self._extract_section_lines_from_text(edited_text, title)
            if before != after:
                changes.append((title, after))
        return changes

    def _apply_section_changes_to_text(self, text, changes):
        updated = str(text or "")
        for title, new_section_lines in list(changes or []):
            updated = self._replace_section_in_text(updated, title, new_section_lines)
        return updated

    def _extract_section_keyword_lines(self, text, title, keywords):
        section_lines = self._extract_section_lines_from_text(text, title)
        if not section_lines:
            return []
        keyword_re = re.compile(
            r"^\s*(?:" + "|".join(re.escape(str(k)) for k in tuple(keywords)) + r")\b",
            re.IGNORECASE,
        )
        return [
            line
            for line in list(section_lines or [])[1:]
            if line.strip() != "." and keyword_re.match(line)
        ]

    def _replace_keywords_in_section_text(self, text, title, keywords, new_lines):
        lines = str(text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        _, start, end = self._section_bounds_in_lines(lines, title)
        if start is None:
            insert_at = self._insert_index_for_new_section(title, lines)
            lines[insert_at:insert_at] = [self._section_header_for_title(title), "       ."]
            _, start, end = self._section_bounds_in_lines(lines, title)
        keyword_re = re.compile(
            r"^\s*(?:" + "|".join(re.escape(str(k)) for k in tuple(keywords)) + r")\b",
            re.IGNORECASE,
        )
        section = [line for line in lines[start + 1:end] if not keyword_re.match(line)]
        insert_rel = next((i for i, line in enumerate(section) if line.strip() == "."), len(section))
        section[insert_rel:insert_rel] = list(new_lines or [])
        lines[start + 1:end] = section
        return "\n".join(lines)

    def _extract_keyword_line_from_text(self, text, keyword):
        match = re.search(
            r"^\s*" + re.escape(str(keyword)) + r"\b.*$",
            str(text or ""),
            re.IGNORECASE | re.MULTILINE,
        )
        return match.group(0) if match else None

    def _remove_keyword_line_from_text(self, text, keyword):
        lines = str(text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
        pat = re.compile(r"^\s*" + re.escape(str(keyword)) + r"\b", re.IGNORECASE)
        return "\n".join([line for line in lines if not pat.match(line)])

    def _changed_global_keyword_lines_between_texts(self, original_text, edited_text, keywords=("RSEED", "NSIMSH", "TIME")):
        changes = []
        for keyword in tuple(keywords or ()):
            before = self._extract_keyword_line_from_text(original_text, keyword)
            after = self._extract_keyword_line_from_text(edited_text, keyword)
            if before != after:
                changes.append((str(keyword), after))
        return changes

    def _apply_global_keyword_line_changes_to_text(self, text, changes):
        updated = str(text or "")
        for keyword, new_line in list(changes or []):
            if new_line is None:
                updated = self._remove_keyword_line_from_text(updated, keyword)
            else:
                updated, _ = self._replace_or_insert_line_in_text(updated, keyword, new_line)
        return updated

    def _source_attribute_patch_from_texts(self, original_text, edited_text):
        patches = []
        specs = (
            (("SKPAR",), "SKPAR"),
            (("SENERG", "SPECTR"), "ENERGY"),
            (("SPOSIT",), "SPOSIT"),
            (("SCONE",), "SCONE"),
        )
        for keywords, _label in specs:
            before = self._extract_section_keyword_lines(original_text, "Source definition", keywords)
            after = self._extract_section_keyword_lines(edited_text, "Source definition", keywords)
            if before != after:
                patches.append((tuple(keywords), after))
        return patches

    def _apply_source_attribute_patch_to_text(self, text, source_patch):
        updated = str(text or "")
        for keywords, new_lines in list(source_patch or []):
            updated = self._replace_keywords_in_section_text(updated, "Source definition", keywords, new_lines)
        return updated

    def _collect_sim_block_edit_changes(self, original_text, edited_text):
        section_changes = [
            (title, new_section_lines)
            for title, new_section_lines in self._changed_sim_sections_between_texts(original_text, edited_text)
            if title != "Source definition"
        ]
        source_patch = self._source_attribute_patch_from_texts(original_text, edited_text)
        global_changes = self._changed_global_keyword_lines_between_texts(original_text, edited_text)
        return {
            "section_changes": section_changes,
            "source_patch": source_patch,
            "global_changes": global_changes,
        }

    def _apply_sim_block_edit_changes_to_text(self, text, changes):
        updated = str(text or "")
        payload = dict(changes or {})
        updated = self._apply_section_changes_to_text(updated, payload.get("section_changes") or [])
        updated = self._apply_source_attribute_patch_to_text(updated, payload.get("source_patch") or [])
        updated = self._apply_global_keyword_line_changes_to_text(updated, payload.get("global_changes") or [])
        return updated

    def _normalize_source_section_order(self):
        if self._normalizing_source_order:
            return
        lines, start, end = self._section_bounds("Source definition")
        if start is None:
            return
        section = list(lines[start + 1:end])
        if not section:
            return
        kw_re = re.compile(r"^\s*(SKPAR|SENERG|SPECTR|SPOSIT|SCONE)\b", re.IGNORECASE)
        skpar = []
        energy = []
        sposit = []
        scone = []
        others = []
        for line in section:
            m = kw_re.match(line)
            if not m:
                others.append(line)
                continue
            kw = m.group(1).upper()
            if kw == "SKPAR":
                if not skpar:
                    skpar.append(line)
            elif kw in {"SENERG", "SPECTR"}:
                energy.append(line)
            elif kw == "SPOSIT":
                if not sposit:
                    sposit.append(line)
            elif kw == "SCONE":
                if not scone:
                    scone.append(line)
        reordered = [*skpar, *energy, *sposit, *scone, *others]
        if reordered == section:
            return
        lines[start + 1:end] = reordered
        self._normalizing_source_order = True
        try:
            self._set_text("\n".join(lines))
        finally:
            self._normalizing_source_order = False

    def _insert_lines_in_section(self, title, new_lines):
        lines, start, end = self._ensure_sim_section(title)
        insert_at = self._insert_index_before_section_dot(lines, start, end)
        lines[insert_at:insert_at] = list(new_lines)
        self._set_text("\n".join(lines))
        self._update_sim_action_labels()

    def _current_geom_filename(self):
        match = re.search(r"^\s*GEOMFN\s+(\S+)", self._get_text(), re.IGNORECASE | re.MULTILINE)
        return match.group(1).strip() if match else ""

    def _current_geom_path(self):
        name = self._current_geom_filename()
        if not name:
            return None
        path = Path(name)
        if path.is_absolute():
            return path
        # Resolve relative GEOMFN against Workspace Root first (if chosen),
        # then against the current .in folder.
        candidates = []
        if self._geo_list_folder:
            candidates.append(Path(self._geo_list_folder) / path.name)
        if self._workspace_root:
            candidates.append(self._workspace_folder() / path.name)
        candidates.append(self._in_folder() / path.name)
        for candidate in candidates:
            if candidate.exists():
                return candidate
        return candidates[0] if candidates else (self._in_folder() / path.name)

    def _geomfn_list_folder(self):
        if self._staged_geo_list_folder:
            return Path(self._staged_geo_list_folder)
        if self._geo_list_folder:
            return Path(self._geo_list_folder)
        project_geom = self._project_geometry_folder()
        if project_geom is not None:
            return project_geom
        return self._in_folder()

    def _geo_files_in_folder(self, folder):
        try:
            return sorted(
                (p.name for p in Path(folder).glob("*.geo") if p.is_file()),
                key=str.lower,
            )
        except Exception:
            return []

    def _material_list_folder(self):
        if self._staged_mat_list_folder:
            return Path(self._staged_mat_list_folder)
        if self._mat_list_folder:
            return Path(self._mat_list_folder)
        project_mats = self._project_materials_folder()
        if project_mats is not None:
            return project_mats
        return self._in_folder()

    def _material_executable_folder(self):
        raw = str(self._effective_executable_paths().get("material", "") or "").strip()
        resolved = self._resolve_case_executable_path(raw)
        if not resolved:
            return None
        try:
            return Path(resolved).parent
        except Exception:
            return None

    def _material_dropdown_files(self):
        files = []
        seen = set()
        folders = [self._material_list_folder(), self._material_executable_folder()]
        for folder in folders:
            if not folder:
                continue
            try:
                candidates = sorted((p.name for p in Path(folder).glob("*.mat") if p.is_file()), key=str.lower)
            except Exception:
                candidates = []
            for name in candidates:
                key = name.lower()
                if key in seen:
                    continue
                seen.add(key)
                files.append(name)
        return files

    def _material_folder_hint_text(self):
        base = f"Material folder: {self._material_list_folder()}"
        exe_folder = self._material_executable_folder()
        if exe_folder:
            return base + f"\nmaterial.exe folder: {exe_folder}"
        return base + "\nmaterial.exe folder: not found"

    def _instructions_root_path(self):
        if self._instructions_root:
            return Path(self._instructions_root)
        proj_inst = self._project_instructions_folder()
        if proj_inst is not None:
            return proj_inst
        if self._in_path:
            return Path(self._in_path).parent
        return Path.cwd()

    def _choose_instructions_root(self):
        if self._project_root:
            QMessageBox.information(
                self,
                "Instructions Root",
                "The instructions root is locked to the project instructions folder while a project is active.",
            )
            return
        start = str(self._instructions_root_path())
        folder = QFileDialog.getExistingDirectory(self, "Choose instructions root folder", start)
        if not folder:
            return
        self._instructions_root = str(Path(folder))
        self._update_file_source_labels()
        self.console.log(f"[SIM] Instructions root set: {self._instructions_root}\n", "info")

    def _update_file_source_labels(self):
        if self._staged_in_text is not None:
            if callable(self._staged_update_callback):
                try:
                    self._staged_update_callback()
                except Exception:
                    pass
            return
        if hasattr(self, "lbl_instructions_root"):
            inst_path = self._instructions_root_path()
            self.lbl_instructions_root.setText(f"Instructions: {inst_path}")
        if hasattr(self, "btn_instructions_root"):
            self.btn_instructions_root.setEnabled(not bool(self._project_root))
        if hasattr(self, "lbl_geo_source_folder"):
            if self._geo_list_folder:
                text = f"Geometry folder: {self._geomfn_list_folder()}"
            elif self._project_root:
                text = f"Geometry folder: {self._geomfn_list_folder()} (project default)"
            else:
                text = "Geometry folder: current .in folder"
            self.lbl_geo_source_folder.setText(text)
        if hasattr(self, "lbl_mat_source_folder"):
            if self._mat_list_folder:
                text = f"Material folder: {self._material_list_folder()}"
            elif self._project_root:
                text = f"Material folder: {self._material_list_folder()} (project default)"
            else:
                text = "Material folder: current .in folder"
            self.lbl_mat_source_folder.setText(text)

    def _choose_geo_source_folder(self):
        folder = QFileDialog.getExistingDirectory(
            self,
            "Choose folder with .geo files",
            str(self._geomfn_list_folder()),
        )
        if not folder:
            return
        self._geo_list_folder = str(Path(folder))
        self._update_file_source_labels()
        self.console.log(f"[SIM] Geometry source folder set: {self._geo_list_folder}\n", "info")

    def _choose_mat_source_folder(self):
        folder = QFileDialog.getExistingDirectory(
            self,
            "Choose folder with .mat files",
            str(self._material_list_folder()),
        )
        if not folder:
            return
        self._mat_list_folder = str(Path(folder))
        self._update_file_source_labels()
        self.console.log(f"[SIM] Material source folder set: {self._mat_list_folder}\n", "info")

    def _reset_file_source_folders(self):
        if self._project_root:
            project_geom = self._project_geometry_folder()
            project_mats = self._project_materials_folder()
            self._geo_list_folder = str(project_geom) if project_geom is not None else None
            self._mat_list_folder = str(project_mats) if project_mats is not None else None
            log_message = "[SIM] Geometry/material source folders reset to the active project's geometry/material folders.\n"
        else:
            self._geo_list_folder = None
            self._mat_list_folder = None
            log_message = "[SIM] Geometry/material source folders reset to current .in folder.\n"
        self._update_file_source_labels()
        self.console.log(log_message, "info")

    def _mfname_material_names(self, text):
        names = []
        seen = set()
        for line in (text or "").replace("\r\n", "\n").replace("\r", "\n").split("\n"):
            match = re.match(r"^\s*MFNAME\s+([^\[]+)", line, re.IGNORECASE)
            if not match:
                continue
            raw = match.group(1).strip()
            if not raw:
                continue
            # PENELOPE material filenames are normally one token. If a path with
            # spaces was pasted, keep the full field before the comment marker.
            name = raw if (".mat" in raw.lower() and " " in raw.strip()) else raw.split()[0]
            name = name.strip().strip('"')
            if not name:
                continue
            key = Path(name).name.lower()
            if key not in seen:
                names.append(name)
                seen.add(key)
        return names

    def _resolve_material_file(self, name, search_folders):
        path = Path(name)
        if path.is_absolute() and path.exists():
            return path
        target_name = path.name
        for folder in search_folders:
            candidate = Path(folder) / target_name
            if candidate.exists() and candidate.is_file():
                return candidate
        lowered = target_name.lower()
        for folder in search_folders:
            try:
                for candidate in Path(folder).glob("*.mat"):
                    if candidate.name.lower() == lowered:
                        return candidate
            except OSError:
                continue
        return None

    def _workspace_folder(self):
        return Path(self._workspace_root) if self._workspace_root else self._in_folder()

    def _path_resolve_key(self, path):
        if not path:
            return ""
        try:
            return str(Path(path).resolve()).lower()
        except Exception:
            return str(Path(path)).lower()

    def _solo_run_folder_for_input(self, in_path):
        return Path(in_path).parent / "solo_case"

    def _set_workspace_root(self, folder, log_label=None):
        folder = str(Path(folder))
        self._workspace_root = folder
        if hasattr(self, "lbl_workspace_root"):
            self.lbl_workspace_root.setText(f"Case Root: {self._project_display_path_text(folder)}")
            self.lbl_workspace_root.setToolTip(folder)
        self._refresh_workspace_root_choices(preferred=folder)
        if log_label:
            self.console.log(f"[SIM] {log_label}: {folder}\n", "info")

    def _project_case_root_folder(self):
        if not self._project_root:
            return None
        folders = dict((self._project_meta or {}).get("folders") or {})
        return Path(self._project_root) / folders.get("cases", PROJECT_DIR_CASES)

    def _project_batch_root_candidates_from_log(self):
        if not self._project_root:
            return []
        try:
            self._refresh_project_batch_entries_from_folders(display_root=self._workspace_folder())
        except Exception:
            pass
        path = self._project_batch_case_creation_log_path()
        if not path or not path.exists():
            return []
        candidates = []
        try:
            payload = json.loads(path.read_text(encoding="utf-8"))
            entries = payload.get("entries", []) if isinstance(payload, dict) else []
        except Exception:
            return []
        root = Path(self._project_root)
        for entry in entries:
            if not isinstance(entry, dict):
                continue
            rel = str(entry.get("batch_root", "") or "").strip()
            candidate = None
            if rel:
                candidate = root / rel
            else:
                cases = entry.get("cases", [])
                if isinstance(cases, list) and cases:
                    first = cases[0]
                    if isinstance(first, dict):
                        case_rel = str(first.get("case_folder", "") or "").strip()
                        if case_rel:
                            candidate = (root / case_rel).parent
            if candidate and candidate.exists() and candidate.is_dir():
                candidates.append(candidate)
        return candidates

    def _batch_container_case_dirs(self, folder):
        folder = Path(folder)
        if not folder.exists() or not folder.is_dir():
            return []
        result = []
        skip = self._BATCH_SKIP_FOLDER_NAMES
        try:
            children = sorted(folder.iterdir())
        except OSError:
            return []
        for child in children:
            if not child.is_dir():
                continue
            if child.name.startswith(".") or child.name.lower() in skip:
                continue
            if self._is_batch_workspace(child):
                result.append(child)
        return result

    def _batch_root_matches_display_root(self, batch_root, display_root):
        if not batch_root or not display_root:
            return False
        try:
            Path(batch_root).resolve().relative_to(Path(display_root).resolve())
            return True
        except Exception:
            return False

    def _refresh_project_batch_entries_from_folders(self, display_root=None):
        if not self._project_root:
            return []
        path = self._project_batch_case_creation_log_path()
        existing_entries = [
            entry for entry in self._read_project_log_entries(path)
            if isinstance(entry, dict)
        ]
        existing_by_root = {}
        for entry in existing_entries:
            root_path = self._resolve_project_logged_path(entry.get("batch_root"))
            key = self._path_resolve_key(root_path)
            if key:
                existing_by_root[key] = entry

        scan_root = self._project_case_root_folder() or self._workspace_folder()
        scan_root = Path(scan_root)
        if not scan_root.exists() or not scan_root.is_dir():
            return []

        refreshed = []
        skip = self._BATCH_SKIP_FOLDER_NAMES
        for dirpath_str, dirnames, _ in os.walk(str(scan_root)):
            dirpath = Path(dirpath_str)
            dirnames[:] = sorted(d for d in dirnames if d.lower() not in skip and not d.startswith("."))
            case_dirs = self._batch_container_case_dirs(dirpath)
            if not case_dirs:
                continue
            if not (dirpath.name.lower().startswith("batch_") or len(case_dirs) >= 2):
                continue
            existing = dict(existing_by_root.get(self._path_resolve_key(dirpath), {}) or {})
            logged_cases = {}
            for record in list(existing.get("cases") or []):
                if not isinstance(record, dict):
                    continue
                record_dir = self._resolve_project_logged_path(record.get("case_folder"))
                key = self._path_resolve_key(record_dir)
                if key:
                    logged_cases[key] = dict(record)
            cases = []
            for case_dir in case_dirs:
                key = self._path_resolve_key(case_dir)
                record = dict(logged_cases.get(key, {}))
                in_files = sorted(case_dir.glob("*.in"))
                geo_files = sorted(case_dir.glob("*.geo"))
                record["case_folder"] = self._project_relative_path_text(case_dir)
                record["case_name"] = case_dir.name
                record["in_file"] = in_files[0].name if in_files else str(record.get("in_file") or "")
                if not str(record.get("geo_file") or "").strip() and geo_files:
                    record["geo_file"] = geo_files[0].name
                cases.append(record)
            entry = existing
            entry["project_root"] = self._project_root or ""
            entry["batch_root"] = self._project_relative_path_text(dirpath)
            entry["target_root"] = self._project_relative_path_text(dirpath.parent)
            entry["case_count"] = len(cases)
            entry["cases"] = cases
            if not str(entry.get("batch_label") or "").strip():
                name = dirpath.name
                match_suffix = re.match(r"^batch_.+_\d{8}_\d{6}_(.+)$", name, re.IGNORECASE)
                if match_suffix and match_suffix.group(1):
                    entry["batch_label"] = match_suffix.group(1)
                else:
                    match_prefix = re.match(r"^(.*?)_batch_[^_]+_\d{8}_\d{6}$", name, re.IGNORECASE)
                    entry["batch_label"] = match_prefix.group(1) if match_prefix and match_prefix.group(1) else ""
            if not str(entry.get("timestamp") or "").strip():
                try:
                    entry["timestamp"] = datetime.fromtimestamp(dirpath.stat().st_mtime).isoformat(timespec="seconds")
                except Exception:
                    entry["timestamp"] = datetime.now().isoformat(timespec="seconds")
            source_stem = self._batch_source_stem_from_root_name(dirpath)
            if source_stem:
                instructions_root = self._project_instructions_folder() or self._instructions_root_path()
                candidate_in = Path(instructions_root) / f"{source_stem}.in"
                if candidate_in.exists():
                    entry["source_in_path"] = self._project_relative_path_text(candidate_in)
            if not str(entry.get("source_in_path") or "").strip() and cases:
                first_in = str(cases[0].get("in_file") or "").strip()
                if first_in:
                    entry["source_in_path"] = self._project_relative_path_text(dirpath / case_dirs[0].name / first_in)
            if not str(entry.get("geo_source_path") or "").strip() and cases:
                first_geo = str(cases[0].get("geo_file") or "").strip()
                if first_geo:
                    entry["geo_source_path"] = self._project_relative_path_text(dirpath / case_dirs[0].name / first_geo)
            if not str(entry.get("geo_file") or "").strip() and cases:
                entry["geo_file"] = str(cases[0].get("geo_file") or "").strip()
            refreshed.append(entry)

        refreshed.sort(
            key=lambda entry: (
                Path(self._resolve_project_logged_path(entry.get("batch_root")) or scan_root).stat().st_mtime
                if (self._resolve_project_logged_path(entry.get("batch_root")) or scan_root).exists()
                else 0.0
            ),
            reverse=True,
        )
        try:
            self._write_project_log_entries(path, "penelope_studio_batch_case_creation_log_v1", refreshed)
        except Exception as exc:
            self.console.log(f"[SIM] Could not refresh batch case log from folders: {exc}\n", "warn")

        display_root = Path(display_root) if display_root else self._workspace_folder()
        filtered = [
            entry for entry in refreshed
            if self._batch_root_matches_display_root(self._resolve_project_logged_path(entry.get("batch_root")), display_root)
        ]
        return filtered or refreshed

    def _workspace_root_choice_label(self, folder):
        path = Path(folder)
        if self._project_root:
            try:
                rel = path.resolve().relative_to(Path(self._project_root).resolve()).as_posix()
                if rel == (self._project_case_root_folder().resolve().relative_to(Path(self._project_root).resolve()).as_posix() if self._project_case_root_folder() else ""):
                    return f"{rel}  (project cases)"
                return rel
            except Exception:
                pass
        return str(path)

    def _workspace_root_choices(self):
        items = []
        seen = set()

        def add(path):
            if not path:
                return
            p = Path(path)
            try:
                key = str(p.resolve())
            except Exception:
                key = str(p)
            if key in seen:
                return
            if not p.exists():
                return
            seen.add(key)
            items.append(p)

        current = Path(self._workspace_root) if self._workspace_root else self._workspace_folder()
        add(current)
        add(self._project_case_root_folder())
        for candidate in self._project_batch_root_candidates_from_log():
            add(candidate)
        return items

    def _refresh_workspace_root_choices(self, preferred=None):
        combo = getattr(self, "cmb_workspace_roots", None)
        if combo is None:
            return
        choices = self._workspace_root_choices()
        current_data = str(preferred or combo.currentData() or self._workspace_root or self._workspace_folder())
        combo.blockSignals(True)
        combo.clear()
        for path in choices:
            combo.addItem(self._workspace_root_choice_label(path), str(path))
        idx = combo.findData(current_data)
        if idx < 0 and choices:
            idx = 0
        if idx >= 0:
            combo.setCurrentIndex(idx)
        combo.blockSignals(False)
        if hasattr(self, "btn_use_workspace_root"):
            self.btn_use_workspace_root.setEnabled(combo.count() > 0)

    def _apply_selected_workspace_root(self):
        combo = getattr(self, "cmb_workspace_roots", None)
        if combo is None:
            return
        folder = str(combo.currentData() or "").strip()
        if not folder:
            return
        self._set_workspace_root(folder, log_label="Case root")
        self._update_file_source_labels()

    def _choose_workspace_root(self):
        start = str(self._workspace_folder())
        folder = QFileDialog.getExistingDirectory(
            self,
            "Choose case root folder",
            start,
        )
        if not folder:
            return
        self._set_workspace_root(folder, log_label="Case root")
        self._update_file_source_labels()

    def _normalize_case_group_rel(self, raw_value):
        text = str(raw_value or "").strip().replace("\\", "/")
        if not text:
            return ""
        parts = []
        for part in text.split("/"):
            part = re.sub(r'[<>:"/\\|?*]+', "_", part).strip(" ._")
            if not part or part in {".", ".."}:
                continue
            parts.append(part)
        return "/".join(parts)

    def _project_case_groups(self):
        meta = self._project_meta or {}
        groups = []
        for entry in (meta.get("case_groups") or []):
            rel = self._normalize_case_group_rel(entry)
            if rel and rel not in groups:
                groups.append(rel)
        return groups

    def _select_case_group_for_creation(self, case_root):
        if not self._project_root:
            return "", False
        case_root = Path(case_root)
        groups = self._project_case_groups()
        if not groups and not self._active_case_group:
            return "", False
        if self._active_case_group and self._active_case_group not in groups:
            groups.append(self._active_case_group)
        if groups and not self._active_case_group:
            self._active_case_group = groups[0]
        if len(groups) == 1 and self._active_case_group:
            selected = self._normalize_case_group_rel(self._active_case_group)
            try:
                (case_root / selected).mkdir(parents=True, exist_ok=True)
            except Exception as exc:
                QMessageBox.warning(self, "Case Group", f"Could not create group folder:\n{case_root / selected}\n\n{exc}")
                return "", True
            return selected, False
        options = ["(no group)"] + groups
        current = self._normalize_case_group_rel(self._active_case_group)
        index = options.index(current) if current in options else 0
        choice, ok = QInputDialog.getItem(
            self,
            "Case Group",
            "Choose target group folder under cases:",
            options,
            index,
            False,
        )
        if not ok:
            return "", True
        selected = "" if choice == "(no group)" else self._normalize_case_group_rel(choice)
        if selected:
            target = case_root / selected
            try:
                target.mkdir(parents=True, exist_ok=True)
            except Exception as exc:
                QMessageBox.warning(self, "Case Group", f"Could not create group folder:\n{target}\n\n{exc}")
                return "", True
        self._active_case_group = selected
        return selected, False

    def _resolve_template_dir(self, case_root):
        case_root = Path(case_root)
        candidates = [case_root / "template"]
        if self._project_root:
            project_root = Path(self._project_root)
            candidates.extend([project_root / "template", project_root.parent / "template"])
        else:
            candidates.append(case_root.parent / "template")
        candidates.append(Path(__file__).resolve().parent / "template")
        for candidate in candidates:
            if candidate.exists() and candidate.is_dir():
                return candidate
        return candidates[0]

    def apply_project_context(self, project_root, project_meta=None):
        root = Path(project_root)
        meta = dict(project_meta or {})
        folders = dict(meta.get("folders") or {})
        case_root = root / folders.get("cases", PROJECT_DIR_CASES)
        geom_root = root / folders.get("geometry", PROJECT_DIR_GEOMETRY)
        mat_root = root / folders.get("materials", PROJECT_DIR_MATERIALS)
        self._project_root = str(root)
        self._project_meta = meta
        self._active_case_group = self._normalize_case_group_rel(self._project_meta.get("default_case_group", ""))
        case_root.mkdir(parents=True, exist_ok=True)
        geom_root.mkdir(parents=True, exist_ok=True)
        mat_root.mkdir(parents=True, exist_ok=True)
        self._set_workspace_root(case_root, log_label="Project case root")
        self._geo_list_folder = str(geom_root)
        self._mat_list_folder = str(mat_root)
        instructions_root = root / folders.get("instructions", PROJECT_DIR_INSTRUCTIONS)
        self._instructions_root = str(instructions_root)
        saved_penmain = str(self._global_executables.get("penmain", "") or "").strip()
        if saved_penmain:
            self._sim_exe = saved_penmain
        self._update_file_source_labels()

    def set_global_executables(self, paths):
        merged = dict(self._global_executables)
        merged.update(dict(paths or {}))
        self._global_executables = merged

    def set_spectrum_database_path(self, path):
        self._spectr_database_path = str(path or "").strip()

    def _effective_executable_paths(self):
        return dict(self._global_executables)

    def _copy_linked_executables_to_case(self, case_dir, exec_paths=None):
        copied = 0
        exec_map = dict(exec_paths or self._effective_executable_paths())
        for key in ("penmain",):
            raw_path = exec_map.get(key, "")
            resolved = self._resolve_case_executable_path(raw_path)
            if not resolved:
                continue
            exe_path = Path(resolved)
            target = Path(case_dir) / exe_path.name
            if self._safe_copy_file(exe_path, target, overwrite=True) or target.exists():
                copied += 1
            if key == "penmain":
                data_file = exe_path.with_name("penmain.dat")
                if data_file.exists() and data_file.is_file():
                    self._safe_copy_file(data_file, Path(case_dir) / data_file.name, overwrite=True)
        return copied

    def _resolve_case_executable_path(self, raw_path):
        text = str(raw_path or "").strip()
        if not text:
            return ""
        try:
            path = Path(text)
            if path.exists() and path.is_file():
                try:
                    return str(path.resolve())
                except Exception:
                    return str(path)
        except Exception:
            pass
        found = shutil.which(text)
        return str(Path(found).resolve()) if found else ""

    def _display_case_executable_value(self, raw_path):
        resolved = self._resolve_case_executable_path(raw_path)
        if resolved:
            return resolved
        text = str(raw_path or "").strip()
        try:
            path = Path(text)
            if path.is_absolute():
                return str(path)
        except Exception:
            pass
        return ""

    def _is_valid_case_executable(self, raw_path):
        return bool(self._resolve_case_executable_path(raw_path))

    def _store_case_executable_paths(self, updates):
        clean = {key: str(value or "").strip() for key, value in dict(updates or {}).items() if str(value or "").strip()}
        if not clean:
            return
        self.set_global_executables(clean)
        main = self.window()
        if main and hasattr(main, "_gview2d"):
            if "gview2d" in clean:
                main._gview2d = clean["gview2d"]
            if "gview3d" in clean:
                main._gview3d = clean["gview3d"]
            if "penmain" in clean:
                main._penmain = clean["penmain"]
            if "material" in clean:
                main._material_exe = clean["material"]
            if hasattr(main, "_save_app_settings"):
                try:
                    main._save_app_settings()
                except Exception:
                    pass
        if "penmain" in clean:
            self.set_sim_executable(clean["penmain"])

    def _missing_case_resources_dialog(
        self,
        geo_path,
        mat_folder,
        missing_mats,
        missing_execs,
        *,
        title="Create Case - Missing Resources",
        intro_text=None,
    ):
        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle(title)
        dlg.resize(760, 420)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(8)

        if intro_text is None:
            intro_text = (
                "Create Case can continue without a template folder, but some required resources were not found.\n"
                "Fill only the missing items below."
            )
        info = QLabel(intro_text)
        info.setWordWrap(True)
        info.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(info)

        form = QFormLayout()
        form.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        widgets = {}

        if geo_path is None or not Path(geo_path).exists():
            row = QHBoxLayout()
            edit = QLineEdit("" if geo_path is None else str(geo_path))
            edit.setStyleSheet(entry_css())
            row.addWidget(edit, stretch=1)
            btn = QPushButton("Browse")
            btn.setStyleSheet(btn_css(width=76))
            btn.clicked.connect(lambda _checked=False, e=edit: e.setText(QFileDialog.getOpenFileName(dlg, "Choose geometry file", str(self._geomfn_list_folder()), "Geometry (*.geo);;All files (*.*)")[0] or e.text()))
            row.addWidget(btn)
            form.addRow("Geometry file:", row)
            widgets["geo"] = edit

        if missing_mats:
            row = QVBoxLayout()
            msg = QLabel("Missing .mat files: " + ", ".join(missing_mats))
            msg.setWordWrap(True)
            msg.setStyleSheet(label_css(P["fg2"], size=9))
            folder_row = QHBoxLayout()
            edit = QLineEdit(str(mat_folder or self._material_list_folder()))
            edit.setStyleSheet(entry_css())
            folder_row.addWidget(edit, stretch=1)
            btn = QPushButton("Folder")
            btn.setStyleSheet(btn_css(width=76))
            btn.clicked.connect(lambda _checked=False, e=edit: e.setText(QFileDialog.getExistingDirectory(dlg, "Choose material folder", e.text() or str(self._material_list_folder())) or e.text()))
            folder_row.addWidget(btn)
            row.addWidget(msg)
            row.addLayout(folder_row)
            form.addRow("Material folder:", row)
            widgets["mat_folder"] = edit

        labels = {"gview2d": "gview2d.exe:", "gview3d": "gview3d.exe:", "penmain": "penmain.exe:"}
        effective = self._effective_executable_paths()
        for key in missing_execs:
            row = QHBoxLayout()
            edit = QLineEdit(self._display_case_executable_value(effective.get(key, "")))
            edit.setStyleSheet(entry_css())
            row.addWidget(edit, stretch=1)
            btn = QPushButton("Browse")
            btn.setStyleSheet(btn_css(width=76))
            btn.clicked.connect(lambda _checked=False, e=edit: e.setText(QFileDialog.getOpenFileName(dlg, "Select executable", e.text() or "", "Executables (*.exe);;All files (*.*)")[0] or e.text()))
            row.addWidget(btn)
            form.addRow(labels.get(key, key + ":"), row)
            widgets[key] = edit

        lay.addLayout(form)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)

        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        return {key: (widget.text() or "").strip() for key, widget in widgets.items()}

    def _ensure_runtime_resources(self, run_folder, geo_path, mat_folder, missing_mats, missing_execs):
        if not missing_mats and not missing_execs and geo_path and Path(geo_path).exists():
            return {
                "geo": str(geo_path),
                "mat_folder": str(mat_folder or ""),
                "copied_execs": [],
            }

        overrides = self._missing_case_resources_dialog(
            geo_path,
            mat_folder,
            missing_mats,
            missing_execs,
            title="Run Simulation - Missing Resources",
            intro_text=(
                "The selected run folder is missing one or more runtime resources.\n"
                "Choose only the missing files below. Studio will copy just those missing items into the run folder."
            ),
        )
        if overrides is None:
            return None

        if overrides.get("geo"):
            geo_path = Path(overrides["geo"])
            self._geo_list_folder = str(geo_path.parent)
        if overrides.get("mat_folder"):
            mat_folder = Path(overrides["mat_folder"])
            self._mat_list_folder = str(mat_folder)

        copied_execs = []
        exec_updates = {}
        for key in missing_execs:
            raw_value = str(overrides.get(key, "")).strip()
            if not raw_value:
                continue
            resolved = self._resolve_case_executable_path(raw_value)
            if not resolved:
                raise FileNotFoundError(f"Executable path is invalid for {key}: {raw_value}")
            exec_updates[key] = resolved
            source = Path(resolved)
            target = Path(run_folder) / source.name
            if self._safe_copy_file(source, target, overwrite=False) or target.exists():
                copied_execs.append(target.name)
        if exec_updates:
            self._store_case_executable_paths(exec_updates)
            self._update_file_source_labels()

        return {
            "geo": str(geo_path) if geo_path else "",
            "mat_folder": str(mat_folder or ""),
            "copied_execs": copied_execs,
        }

    def _workspace_cm_token(self, value):
        if value is None:
            return "unknown"
        try:
            value = abs(float(value))
        except (TypeError, ValueError):
            return "unknown"
        if abs(value - round(value)) < 1e-6:
            return str(int(round(value)))
        token = f"{value:.2f}".rstrip("0").rstrip(".")
        return token.replace(".", "p")

    def _workspace_safe_token(self, value, fallback="unknown"):
        text = str(value or "").strip()
        if not text:
            return fallback
        text = re.sub(r'[<>:"/\\|?*]+', "_", text)
        text = re.sub(r"\s+", "_", text)
        text = text.strip(" ._")
        return text or fallback

    def _case_variant_number_text(self, value):
        try:
            number = float(str(value or "0").strip().replace(",", "."))
        except (TypeError, ValueError):
            number = 0.0
        if abs(number) < 5e-13:
            number = 0.0
        return f"{number:.2f}".rstrip("0").rstrip(".") or "0"

    def _case_variant_energy_token_text(self, value_kev):
        try:
            number_kev = float(str(value_kev or "0").strip().replace(",", "."))
        except (TypeError, ValueError):
            number_kev = 0.0
        if abs(number_kev) < 5e-13:
            number_kev = 0.0
        if abs(number_kev) >= 1000.0:
            value_mev = number_kev / 1000.0
            return f"{self._case_variant_number_text(value_mev)}MeV"
        return f"{self._case_variant_number_text(number_kev)}keV"

    def _case_variant_source_tokens(self, spec, selected_keys=None):
        selected = {str(key or "").strip().lower() for key in list(selected_keys or DEFAULT_BATCH_FOLDER_TOKEN_KEYS)}
        tokens = []
        if "senerg" in selected and spec.get("senerg_kev") not in (None, ""):
            tokens.append(f"SENERG-{self._case_variant_energy_token_text(spec.get('senerg_kev'))}")
        spectr_range = spec.get("spectr_range") or ()
        spectr_last = spec.get("spectr_last_kev")
        if "spectr" in selected and (spectr_last not in (None, "") or len(spectr_range) == 2):
            energy_value = spectr_last if spectr_last not in (None, "") else spectr_range[1]
            tokens.append("SPECTR-" + self._case_variant_energy_token_text(energy_value))
        sposit = spec.get("sposit") or ()
        if "sposit" in selected and len(sposit) == 3:
            tokens.append("SPOSIT-" + "_".join(self._case_variant_number_text(v) for v in sposit))
        scone = spec.get("scone") or ()
        if "scone" in selected and len(scone) == 3:
            tokens.append("SCONE-" + "_".join(self._case_variant_number_text(v) for v in scone))
        return tokens

    def _case_variant_base_name(self, value, fallback="case"):
        text = self._workspace_safe_token(value, fallback or "case")
        if not text:
            return fallback or "case"
        match = re.search(r"(?:(?<=.)_|(?<=.)-)(?=(?:SENERG|SPECTR|SPOSIT|SCONE)-)", text, re.IGNORECASE)
        if match:
            text = text[:match.start()]
        text = text.strip("_-")
        return text or (fallback or "case")

    def _case_variant_folder_name(self, base_name, spec):
        parts = [self._case_variant_base_name(base_name, "case")]
        selected_keys = list(spec.get("folder_token_keys") or DEFAULT_BATCH_FOLDER_TOKEN_KEYS)
        for token in self._case_variant_source_tokens(spec, selected_keys):
            safe = self._workspace_safe_token(token, "")
            if safe:
                parts.append(safe)
        name = "_".join(part for part in parts if part)
        return name or "case"

    def _case_variant_title(self, base_name, spec):
        parts = [self._case_variant_base_name(base_name, "case")]
        parts.extend(self._case_variant_source_tokens(spec))
        return "_".join(part for part in parts if part) or "case"

    def _resolved_case_variant_spec(self, base_text, spec, *, case_name, in_filename, geo_override_path="", mat_folder=""):
        final_text = self._apply_case_variant_source_overrides(base_text, spec)
        final_spec = self._case_spec_from_in_text(
            case_name,
            in_filename,
            final_text,
            geo_override_path=geo_override_path or "",
            mat_folder=mat_folder or "",
        )
        if "case_name" in spec:
            final_spec["case_name"] = self._case_variant_base_name(spec.get("case_name"), case_name or "case")
        if "in_filename" in spec:
            final_spec["in_filename"] = self._case_variant_in_filename(spec.get("in_filename"), case_name or "simulation")
        if geo_override_path:
            final_spec["geo_override_path"] = str(geo_override_path)
        if mat_folder:
            final_spec["mat_folder"] = str(mat_folder)
        if "folder_token_keys" in spec:
            final_spec["folder_token_keys"] = list(spec.get("folder_token_keys") or [])
        return final_spec, final_text

    def _case_variant_in_filename(self, value, fallback_stem):
        raw = self._workspace_safe_token(value, fallback_stem or "simulation")
        if not raw.lower().endswith(".in"):
            raw += ".in"
        return raw

    def _case_source_from_target(self, xa, ya, za, radius, beta, gamma, alpha):
        beta_rad = math.radians(float(beta))
        gamma_rad = math.radians(float(gamma))
        xf = float(xa) + float(radius) * math.sin(beta_rad) * math.cos(gamma_rad)
        yf = float(ya) + float(radius) * math.sin(beta_rad) * math.sin(gamma_rad)
        zf = float(za) + float(radius) * math.cos(beta_rad)
        theta = 180.0 - float(beta)
        phi = (180.0 + float(gamma)) % 360.0
        return (
            [f"{xf:.8g}", f"{yf:.8g}", f"{zf:.8g}"],
            [f"{theta:.8g}", f"{phi:.8g}", f"{float(alpha):.8g}"],
        )

    def _particle_type_token_from_in_text(self, text):
        match = re.search(r"^\s*SKPAR\s+(\d+)", text or "", re.IGNORECASE | re.MULTILINE)
        particle = match.group(1) if match else ""
        return {
            "1": "electron",
            "2": "photon",
            "3": "positron",
        }.get(particle, "particle")

    def _energy_type_token_from_in_text(self, text):
        raw = text or ""
        if re.search(r"^\s*SPECTR\b", raw, re.IGNORECASE | re.MULTILINE):
            return "spectr"
        if re.search(r"^\s*SENERG\b", raw, re.IGNORECASE | re.MULTILINE):
            return "senerg"
        return "energy"

    def _nsimsh_token_from_in_text(self, text):
        match = re.search(r"^\s*NSIMSH\s+([^\s\[]+)", text or "", re.IGNORECASE | re.MULTILINE)
        if not match:
            return "nsimsh"
        return self._workspace_safe_token(match.group(1), "nsimsh")

    def _geo_file_token(self, geo_path):
        if not geo_path:
            return "geometry"
        try:
            return self._workspace_safe_token(Path(geo_path).stem, "geometry")
        except Exception:
            return "geometry"

    def _particle_distance_cm_from_in_text(self, text):
        match = re.search(
            r"^\s*SPOSIT\s+([+\-]?(?:\d+(?:\.\d*)?|\.\d+)(?:[Ee][+\-]?\d+)?)",
            text or "",
            re.IGNORECASE | re.MULTILINE,
        )
        if not match:
            return None
        try:
            return abs(float(match.group(1)))
        except ValueError:
            return None

    def _beam_token_from_workspace_inputs(self, text, in_path, geo_path):
        joined = " ".join(
            str(part)
            for part in (
                in_path.stem if in_path else "",
                geo_path.stem if geo_path else "",
                text or "",
            )
        ).lower()
        if "linac" in joined or "8mev" in joined or "8_mev" in joined:
            return "LINAC"
        if "x_ray" in joined or "x-ray" in joined or "x ray" in joined or "120k" in joined:
            return "x_ray"
        return "simulation"

    def _wall_thickness_cm_from_geo(self, geo_path, geo_text):
        sources = []
        if geo_text:
            first_line = (geo_text.replace("\r\n", "\n").replace("\r", "\n").split("\n") or [""])[0]
            sources.extend([first_line, geo_text[:500]])
        if geo_path:
            p = Path(geo_path)
            sources.extend([p.stem, p.name, str(p.parent.name)])
        patterns = [
            r"\b(?:wall|wt)\s*=?\s*([+\-]?\d+(?:[.,]\d+)?)\s*cm\b",
            r"(?<!\d)([+\-]?\d+(?:[.,]\d+)?)\s*cm\b",
        ]
        for src in sources:
            for pattern in patterns:
                match = re.search(pattern, src or "", re.IGNORECASE)
                if match:
                    try:
                        return abs(float(match.group(1).replace(",", ".")))
                    except ValueError:
                        continue
        return None

    def _phantom_body_distance_cm_from_geo_text(self, geo_text):
        if not geo_text:
            return None
        try:
            surfaces, _bodies = _parse_geo(geo_text)
        except Exception:
            return None
        phantom_words = ("perna", "corpo", "pescoco", "pescoço", "cabeca", "cabeça", "braco", "braço")
        values = []
        for sid, surf in surfaces.items():
            label = (surf.get("label") or "").lower()
            if not any(word in label for word in phantom_words):
                continue
            params = surf.get("params", {})
            if "X-SHIFT" in params:
                values.append(abs(float(params["X-SHIFT"])))
        if not values:
            for sid in (7, 9, 12, 13, 14, 15, 16):
                params = surfaces.get(sid, {}).get("params", {})
                if "X-SHIFT" in params:
                    values.append(abs(float(params["X-SHIFT"])))
        if not values:
            return None
        values.sort()
        return values[len(values) // 2]

    def _workspace_material_count_token(self, in_text, geo_text):
        count = len(self._mfname_material_names(in_text))
        if count <= 0:
            count = len(_geo_header_material_labels(geo_text or ""))
        return f"mat{max(0, int(count))}"

    def _workspace_body_count_token(self, geo_text):
        try:
            _surfs, bodies = _parse_geo(geo_text or "")
            count = len(bodies)
        except Exception:
            count = 0
        return f"b{max(0, int(count))}"

    def _workspace_surface_count_token(self, geo_text):
        try:
            surfs, _bodies = _parse_geo(geo_text or "")
            count = len(surfs)
        except Exception:
            count = 0
        return f"s{max(0, int(count))}"

    def _workspace_name_components_from_files(self, in_path, geo_path):
        in_text = self._get_text()
        try:
            geo_text = Path(geo_path).read_text(encoding="utf-8", errors="replace") if geo_path else ""
        except OSError:
            geo_text = ""
        return {
            "beam": self._beam_token_from_workspace_inputs(in_text, in_path, geo_path),
            "particle_type": self._particle_type_token_from_in_text(in_text),
            "energy_type": self._energy_type_token_from_in_text(in_text),
            "in_file": self._workspace_safe_token(Path(in_path).stem if in_path else "simulation"),
            "geo_file": self._geo_file_token(geo_path),
            "nsimsh": self._nsimsh_token_from_in_text(in_text),
            "particle_distance_cm": f"pd{self._workspace_cm_token(self._particle_distance_cm_from_in_text(in_text))}cm",
            "body_distance_cm": f"bd{self._workspace_cm_token(self._phantom_body_distance_cm_from_geo_text(geo_text))}cm",
            "wall_thickness_cm": f"wt{self._workspace_cm_token(self._wall_thickness_cm_from_geo(geo_path, geo_text))}cm",
            "material_count": self._workspace_material_count_token(in_text, geo_text),
            "body_count": self._workspace_body_count_token(geo_text),
            "surface_count": self._workspace_surface_count_token(geo_text),
        }

    def _case_name_from_fields(self, fields, in_path, geo_path):
        components = self._workspace_name_components_from_files(in_path, geo_path)
        ordered = []
        for field in (fields or []):
            key = str(field or "").strip().lower()
            value = components.get(key)
            if value:
                ordered.append(self._workspace_safe_token(value))
        if not ordered:
            ordered = [
                components["particle_type"],
                components["energy_type"],
                components["geo_file"],
                components["nsimsh"],
            ]
        name = "_".join(part for part in ordered if part)
        name = re.sub(r'[<>:"/\\|?*]+', "_", name).strip(" ._")
        return name or "simulation_workspace"

    def _case_folder_name_from_input(self, base_name, fields, in_path, geo_path):
        prefix = self._workspace_safe_token(base_name, "")
        components = self._workspace_name_components_from_files(in_path, geo_path)
        parts = []
        if prefix:
            parts.append(prefix)
        for field in (fields or []):
            key = str(field or "").strip().lower()
            value = components.get(key)
            if value:
                token = self._workspace_safe_token(value, "")
                if token:
                    parts.append(token)
        name = "_".join(part for part in parts if part)
        name = re.sub(r'[<>:"/\\|?*]+', "_", name).strip(" ._")
        return name or "simulation_workspace"

    def _case_creation_name_dialog(self, in_path, geo_path):
        defaults = _sanitize_project_case_field_list(
            (self._project_meta or {}).get("case_name_fields") or PROJECT_CASE_FIELD_DEFAULTS
        ) or list(PROJECT_CASE_FIELD_DEFAULTS)
        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle("Create Case Name")
        dlg.resize(760, 440)
        dlg.setStyleSheet(
            f"QDialog {{ background:{P['bg']}; }}"
            f"QLabel {{ color:{P['fg']}; }}"
        )
        lay = QVBoxLayout(dlg)
        lay.setContentsMargins(10, 10, 10, 10)
        lay.setSpacing(8)

        hint = QLabel(
            "Write the case name you want first. Selected automatic tokens are appended after it with underscores."
        )
        hint.setWordWrap(True)
        hint.setStyleSheet(label_css(P["fg2"], size=9))
        lay.addWidget(hint)

        form = QFormLayout()
        form.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        e_name = QLineEdit(Path(in_path).stem if in_path else "case")
        e_name.setStyleSheet(entry_css())
        form.addRow("Case Name:", e_name)
        lay.addLayout(form)

        tokens_box = QGroupBox("Append tokens")
        tokens_box.setStyleSheet(group_css())
        tokens_lay = QVBoxLayout(tokens_box)
        tokens_lay.setContentsMargins(8, 8, 8, 8)
        tokens_lay.setSpacing(6)
        tokens_hint = QLabel("Choose the automatic fields to append after the typed case name.")
        tokens_hint.setWordWrap(True)
        tokens_hint.setStyleSheet(label_css(P["fg2"], size=9))
        tokens_lay.addWidget(tokens_hint)

        token_checks = []
        grid = QGridLayout()
        grid.setHorizontalSpacing(16)
        grid.setVerticalSpacing(4)
        for idx, (field_key, field_label, field_source) in enumerate(PROJECT_CASE_FIELD_SPECS):
            chk = QCheckBox(field_label)
            chk.setStyleSheet(checkbox_css())
            chk.setChecked(field_key in defaults)
            chk._case_field_key = field_key
            token_checks.append(chk)
            row = idx // 3
            col = (idx % 3) * 2
            grid.addWidget(chk, row, col)
            src_lbl = QLabel(field_source)
            src_lbl.setStyleSheet(label_css(P["fg2"], size=8))
            grid.addWidget(src_lbl, row, col + 1)
        tokens_lay.addLayout(grid)
        lay.addWidget(tokens_box)

        lbl_preview = QLabel("")
        lbl_preview.setWordWrap(True)
        lbl_preview.setStyleSheet(label_css(P["fg2"], size=9))
        lay.addWidget(lbl_preview)

        def refresh_preview():
            selected = [chk._case_field_key for chk in token_checks if chk.isChecked()]
            preview = self._case_folder_name_from_input(e_name.text(), selected, in_path, geo_path)
            lbl_preview.setText(f"Folder preview: {preview}")

        e_name.textChanged.connect(refresh_preview)
        for chk in token_checks:
            chk.toggled.connect(refresh_preview)
        refresh_preview()

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(
            f"QPushButton {{ background:{P['bg2']}; color:{P['fg']};"
            f" border:1px solid {P['border']}; border-radius:3px; padding:4px 16px; }}"
            f"QPushButton:hover {{ background:{P['bg3']}; }}"
        )
        btn_batch = buttons.addButton("Create Case Batch...", QDialogButtonBox.ButtonRole.ActionRole)
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        btn_batch.clicked.connect(lambda: dlg.done(2))
        lay.addWidget(buttons)

        result = dlg.exec()
        if result == 2:
            count, ok = QInputDialog.getInt(
                self,
                "Create Case Batch",
                "How many cases do you want to create?",
                3,
                1,
                100,
                1,
            )
            if not ok:
                return None
            return {"mode": "batch", "count": int(count)}
        if result != QDialog.DialogCode.Accepted:
            return None
        base_name = self._workspace_safe_token(e_name.text(), "")
        if not base_name:
            QMessageBox.warning(self, "Create Case", "Case Name cannot be empty.")
            return None
        selected = _sanitize_project_case_field_list([chk._case_field_key for chk in token_checks if chk.isChecked()])
        return self._case_folder_name_from_input(base_name, selected, in_path, geo_path)

    def _spectr_range_from_lines(self, lines):
        energies = []
        for line in list(lines or []):
            match = re.match(r"^\s*SPECTR\s+([^\s\[]+)", str(line or ""), re.IGNORECASE)
            if not match:
                continue
            try:
                ev = float(match.group(1))
            except ValueError:
                continue
            energies.append(ev / 1000.0)
        if not energies:
            return ()
        return (min(energies), max(energies))

    def _source_defaults_from_text(
        self,
        text,
        spectrum_path="",
        spectrum_db_path="",
        spectrum_db_label="",
        spectrum_prob_col=None,
    ):
        defaults = {
            "particle": "2",
            "energy_type": "SENERG",
            "energy_value": "130",
            "energy_unit": "keV",
            "spectrum_source_kind": "file",
            "spectrum_path": spectrum_path or "",
            "spectrum_db_path": spectrum_db_path or "",
            "spectrum_db_label": spectrum_db_label or "",
            "spectrum_prob_col": spectrum_prob_col or 6,
            "spectrum_lines": [],
            "sposit": ["0.0", "0.0", "0.0"],
            "scone": ["0", "0", "0"],
        }

        match = re.search(r"^\s*SKPAR\s+(\S+)", text or "", re.IGNORECASE | re.MULTILINE)
        if match and match.group(1) in {"1", "2", "3"}:
            defaults["particle"] = match.group(1)

        spectr_lines = [
            line.strip()
            for line in (text or "").splitlines()
            if re.match(r"^\s*SPECTR\b", line, re.IGNORECASE)
        ]
        if spectr_lines:
            defaults["energy_type"] = "SPECTR"
            defaults["spectrum_lines"] = spectr_lines
            defaults["spectrum_prob_col"] = self._spectr_prob_col_for_particle(defaults["particle"])
        else:
            match = re.search(r"^\s*SENERG\s+([^\s\[]+)", text or "", re.IGNORECASE | re.MULTILINE)
            if match:
                defaults["energy_type"] = "SENERG"
                raw = match.group(1).strip()
                lowered = raw.lower()
                try:
                    value = float(raw)
                    if value >= 1e6:
                        defaults["energy_value"] = f"{value / 1e6:g}"
                        defaults["energy_unit"] = "MeV"
                    else:
                        defaults["energy_value"] = f"{value / 1e3:g}"
                        defaults["energy_unit"] = "keV"
                except ValueError:
                    if lowered.endswith("e6"):
                        defaults["energy_value"] = raw[:-2]
                        defaults["energy_unit"] = "MeV"
                    elif lowered.endswith("e3"):
                        defaults["energy_value"] = raw[:-2]
                        defaults["energy_unit"] = "keV"
                    else:
                        defaults["energy_value"] = raw
                        defaults["energy_unit"] = "keV"

        match = re.search(r"^\s*SPOSIT\s+([^\[]+)", text or "", re.IGNORECASE | re.MULTILINE)
        if match:
            vals = match.group(1).split()[:3]
            if len(vals) == 3:
                defaults["sposit"] = vals

        match = re.search(r"^\s*SCONE\s+([^\[]+)", text or "", re.IGNORECASE | re.MULTILINE)
        if match:
            vals = match.group(1).split()[:3]
            if len(vals) == 3:
                defaults["scone"] = vals
        return defaults

    def _read_project_log_entries(self, path):
        if not path or not Path(path).exists():
            return []
        try:
            payload = json.loads(Path(path).read_text(encoding="utf-8"))
        except Exception:
            return []
        entries = payload.get("entries", []) if isinstance(payload, dict) else []
        return entries if isinstance(entries, list) else []

    def _resolve_project_logged_path(self, raw_path):
        if not raw_path:
            return None
        target = Path(str(raw_path))
        if target.is_absolute():
            return target
        if self._project_root:
            return Path(self._project_root) / target
        return target

    def _case_spec_from_in_text(self, case_name, in_filename, text, geo_override_path="", mat_folder=""):
        defaults = self._source_defaults_from_text(text)
        base_case_name = self._case_variant_base_name(case_name, "case")
        spec = {
            "case_name": base_case_name,
            "in_filename": self._case_variant_in_filename(in_filename, base_case_name or "simulation"),
            "geo_override_path": str(geo_override_path or ""),
            "mat_folder": str(mat_folder or ""),
        }
        if defaults["energy_type"] == "SENERG":
            spec["senerg_kev"] = defaults["energy_value"] if defaults["energy_unit"] == "keV" else str(float(defaults["energy_value"]) * 1000.0)
        elif defaults["spectrum_lines"]:
            spec["spectr_lines"] = list(defaults["spectrum_lines"])
            spec["spectr_range"] = self._spectr_range_from_lines(defaults["spectrum_lines"])
            try:
                spec["spectr_last_kev"] = float(str(defaults["spectrum_lines"][-1].split()[0]).replace(",", "."))
            except Exception:
                pass
        if defaults["sposit"]:
            spec["sposit"] = list(defaults["sposit"])
        if defaults["scone"]:
            spec["scone"] = list(defaults["scone"])
        return spec

    def _case_variant_spec_from_log_record(self, record):
        if not isinstance(record, dict):
            return None
        variant = dict(record.get("variant") or {})
        case_name = self._case_variant_base_name(str(variant.get("case_name") or record.get("case_name") or "case").strip(), "case")
        in_filename = str(variant.get("in_filename") or record.get("in_file") or f"{case_name}.in").strip()
        case_dir = self._resolve_project_logged_path(record.get("case_folder"))
        geo_source_path = self._resolve_project_logged_path(record.get("geo_source_path"))
        geo_override_path = geo_source_path if geo_source_path and geo_source_path.exists() else None
        mat_folder = case_dir if case_dir and case_dir.exists() and any(case_dir.glob("*.mat")) else None
        if variant:
            spec = {
                "case_name": case_name,
                "in_filename": self._case_variant_in_filename(in_filename, case_name or "simulation"),
                "geo_override_path": str(geo_override_path or ""),
                "mat_folder": str(mat_folder or ""),
            }
            if str(variant.get("senerg_kev", "")).strip():
                spec["senerg_kev"] = str(variant.get("senerg_kev")).strip()
            if str(variant.get("spectr_file", "")).strip():
                spec["spectr_file"] = str(variant.get("spectr_file")).strip()
            spectr_range = variant.get("spectr_range_kev")
            if isinstance(spectr_range, (list, tuple)) and len(spectr_range) == 2:
                spec["spectr_range"] = tuple(spectr_range)
            if variant.get("spectr_last_kev") not in (None, ""):
                spec["spectr_last_kev"] = variant.get("spectr_last_kev")
            sposit = variant.get("sposit_cm")
            if isinstance(sposit, (list, tuple)) and len(sposit) == 3:
                spec["sposit"] = [str(v) for v in sposit]
            scone = variant.get("scone_deg")
            if isinstance(scone, (list, tuple)) and len(scone) == 3:
                spec["scone"] = [str(v) for v in scone]
            folder_token_keys = [str(k or "").strip().lower() for k in list(variant.get("folder_token_keys") or []) if str(k or "").strip()]
            if folder_token_keys:
                spec["folder_token_keys"] = folder_token_keys
            return spec
        if not case_dir or not case_dir.exists():
            return None
        in_path = case_dir / in_filename
        if not in_path.exists():
            in_files = sorted(case_dir.glob("*.in"))
            if not in_files:
                return None
            in_path = in_files[0]
        try:
            text = _decode_text_bytes(in_path.read_bytes())
        except Exception:
            return None
        return self._case_spec_from_in_text(case_name, in_path.name, text, geo_override_path=geo_override_path or "", mat_folder=mat_folder or "")

    def _batch_spec_value_text(self, spec, key):
        if key == "senerg_kev":
            value = spec.get("senerg_kev")
            return f"{value} keV" if value not in (None, "") else "(unchanged)"
        if key == "spectr":
            if spec.get("spectr_range") and len(spec.get("spectr_range")) == 2:
                low, high = spec.get("spectr_range")
                return f"{self._case_variant_number_text(low)}-{self._case_variant_number_text(high)} keV"
            if spec.get("spectr_file"):
                return Path(str(spec.get("spectr_file"))).name
            if spec.get("spectr_lines"):
                return "inline spectrum"
            return "(unchanged)"
        if key == "sposit":
            values = spec.get("sposit") or ()
            if len(values) == 3:
                return "(" + ", ".join(str(v) for v in values) + ")"
            return "(unchanged)"
        if key == "scone":
            values = spec.get("scone") or ()
            if len(values) == 3:
                return "(" + ", ".join(str(v) for v in values) + ")"
            return "(unchanged)"
        if key == "geo_override_path":
            value = str(spec.get("geo_override_path") or "").strip()
            return Path(value).name if value else "(unchanged)"
        if key == "mat_folder":
            value = str(spec.get("mat_folder") or "").strip()
            return Path(value).name if value else "(unchanged)"
        return str(spec.get(key, ""))

    def _batch_before_value_text(self, context, key):
        if not context:
            return "(new row)"
        text = str(context.get("case_text") or "")
        defaults = self._source_defaults_from_text(text)
        if key == "senerg_kev":
            if defaults.get("energy_type") == "SENERG" and defaults.get("energy_value") not in (None, ""):
                try:
                    if defaults.get("energy_unit") == "eV":
                        return f"{float(defaults.get('energy_value')) / 1000.0:g} keV"
                except Exception:
                    pass
                return f"{defaults.get('energy_value')} {defaults.get('energy_unit') or 'keV'}"
            return "(unset)"
        if key == "spectr":
            lines = list(defaults.get("spectrum_lines") or [])
            if lines:
                rng = self._spectr_range_from_lines(lines)
                if rng and len(rng) == 2:
                    return f"{self._case_variant_number_text(rng[0])}-{self._case_variant_number_text(rng[1])} keV"
                return "inline spectrum"
            return "(unset)"
        if key == "sposit":
            values = defaults.get("sposit") or ()
            if len(values) == 3:
                return "(" + ", ".join(str(v) for v in values) + ")"
            return "(unset)"
        if key == "scone":
            values = defaults.get("scone") or ()
            if len(values) == 3:
                return "(" + ", ".join(str(v) for v in values) + ")"
            return "(unset)"
        if key == "geo_override_path":
            geo_path = context.get("geo_path")
            return Path(geo_path).name if geo_path else "(unset)"
        if key == "mat_folder":
            mat_folder = context.get("mat_folder")
            return Path(mat_folder).name if mat_folder else "(unset)"
        return "(unset)"

    def _build_batch_edit_change_records(self, row_contexts, edited_specs):
        change_records = []
        keys = ("senerg_kev", "spectr", "sposit", "scone", "geo_override_path", "mat_folder")
        for idx, spec in enumerate(list(edited_specs or []), start=1):
            context = row_contexts[idx - 1] if idx - 1 < len(row_contexts) else None
            case_before = Path(context["case_dir"]).name if context else "(new row)"
            case_after = str(spec.get("case_name") or case_before)
            changes = []
            for key in keys:
                present = (
                    key in spec
                    or (key == "spectr" and (spec.get("spectr_file") or spec.get("spectr_lines")))
                )
                if not present:
                    continue
                before = self._batch_before_value_text(context, key)
                after = self._batch_spec_value_text(spec, key)
                changes.append({"field": key, "before": before, "after": after})
            change_records.append(
                {
                    "row": idx,
                    "case_before": case_before,
                    "case_after": case_after,
                    "changes": changes,
                }
            )
        if len(edited_specs or []) < len(row_contexts or []):
            for idx in range(len(edited_specs) + 1, len(row_contexts) + 1):
                context = row_contexts[idx - 1]
                change_records.append(
                    {
                        "row": idx,
                        "case_before": Path(context["case_dir"]).name,
                        "case_after": "(omitted in duplicate)",
                        "changes": [{"field": "row", "before": "present", "after": "omitted"}],
                    }
                )
        return change_records

    def _batch_edit_change_summary_text(self, change_records):
        lines = []
        for record in list(change_records or []):
            case_label = f"Case {record.get('row')}: {record.get('case_before')} -> {record.get('case_after')}"
            lines.append(case_label)
            for change in list(record.get("changes") or []):
                field = str(change.get("field") or "").replace("_", " ")
                lines.append(f"  {field}: {change.get('before')} -> {change.get('after')}")
        return "\n".join(lines) if lines else "No selected changes."

    def _log_project_batch_edit(self, mode, entry, source_in_path, batch_root, group_rel, change_records):
        path = self._project_batch_edit_log_path()
        if not path:
            return
        payload = {
            "timestamp": datetime.now().isoformat(timespec="seconds"),
            "project_root": self._project_root or "",
            "mode": str(mode or ""),
            "group_rel": str(group_rel or ""),
            "source_in_path": self._project_relative_path_text(source_in_path or ""),
            "selected_batch_root": self._project_relative_path_text(self._resolve_project_logged_path((entry or {}).get("batch_root")) or ""),
            "target_batch_root": self._project_relative_path_text(batch_root or ""),
            "changes": list(change_records or []),
        }
        try:
            self._append_project_log_entry(path, "penelope_studio_batch_case_edit_log_v1", payload)
            self.console.log(f"[SIM] Project batch edit log updated: {path.name}\n", "info")
        except Exception as exc:
            self.console.log(f"[SIM] Could not update batch edit log: {exc}\n", "warn")

    def _select_logged_case_record_dialog(self):
        if not self._project_root:
            QMessageBox.information(self, "Edit Case", "Open a project first so Studio can read the case creation log.")
            return None
        entries = [
            entry for entry in self._read_project_log_entries(self._project_case_creation_log_path())
            if isinstance(entry, dict)
        ]
        if not entries:
            QMessageBox.information(self, "Edit Case", "No project case creation log entries were found.")
            return None
        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle("Edit Case")
        dlg.setMinimumWidth(760)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        hint = QLabel("Choose a previously created case to edit or duplicate with block-based changes.")
        hint.setWordWrap(True)
        hint.setStyleSheet(label_css(P["fg2"], size=9))
        lay.addWidget(hint)
        lst = QListWidget()
        lst.setStyleSheet(
            f"QListWidget {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; border-radius:4px; }}"
            f"QListWidget::item:selected {{ background:{P['sel']}; }}"
        )
        for entry in reversed(entries):
            case_name = str(entry.get("case_name") or "?")
            stamp = str(entry.get("timestamp") or "")
            case_folder = str(entry.get("case_folder") or "")
            detail = f"{case_name}  |  {stamp}  |  {case_folder}"
            item = QListWidgetItem(detail)
            item.setData(Qt.ItemDataRole.UserRole, entry)
            item.setToolTip(detail)
            lst.addItem(item)
        if lst.count():
            lst.setCurrentRow(0)
        lay.addWidget(lst)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)
        if dlg.exec() != QDialog.DialogCode.Accepted or not lst.currentItem():
            return None
        return lst.currentItem().data(Qt.ItemDataRole.UserRole)

    def _select_logged_batch_entry_dialog(self):
        if not self._project_root:
            QMessageBox.information(self, "Edit Batch", "Open a project first so Studio can read the batch creation log.")
            return None
        current_root = self._workspace_folder()
        entries = self._refresh_project_batch_entries_from_folders(display_root=current_root)
        if not entries:
            QMessageBox.information(
                self,
                "Edit Batch",
                f"No batch folders were found under the current Case Root.\n\n{current_root}",
            )
            return None
        dlg = QDialog(self)
        dlg.setModal(True)
        dlg.setWindowTitle("Edit Batch")
        dlg.setMinimumWidth(820)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        hint = QLabel(
            f"Choose a batch folder found under the current Case Root.\n\nCurrent root: {current_root}"
        )
        hint.setWordWrap(True)
        hint.setStyleSheet(label_css(P["fg2"], size=9))
        lay.addWidget(hint)
        lst = QListWidget()
        lst.setStyleSheet(
            f"QListWidget {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; border-radius:4px; }}"
            f"QListWidget::item:selected {{ background:{P['sel']}; }}"
        )
        for entry in entries:
            batch_root = str(entry.get("batch_root") or "")
            stamp = str(entry.get("timestamp") or "")
            count = int(entry.get("case_count", 0) or 0)
            detail = f"{Path(batch_root).name or batch_root}  |  {count} case(s)  |  {stamp}"
            item = QListWidgetItem(detail)
