            e_in.setStyleSheet(entry_css())
            top_form.addWidget(hdr_case, 0, 0)
            top_form.addWidget(chk_senerg, 0, 1)
            top_form.addWidget(chk_spectr, 0, 2)
            top_form.addWidget(chk_sposit, 0, 3)
