        def _parse_float_field(key):
            raw = (calc_edits[key].text() or "").strip().replace(",", ".")
            if not raw:
                raw = "0"
            return float(raw)

        def _fmt_calc_value(value):
            if abs(value) < 5e-13:
                value = 0.0
            return f"{value:.8g}"

        def apply_source_calculation():
            try:
                xa = _parse_float_field("XA")
                ya = _parse_float_field("YA")
                za = _parse_float_field("ZA")
                radius = _parse_float_field("R")
                beta = _parse_float_field("beta")
                gamma = _parse_float_field("gamma")
                alpha = _parse_float_field("alpha")
            except ValueError:
                QMessageBox.warning(dlg, "Invalid source calculation", "Use numeric values for target, distance, beta, gamma, and alpha.")
                return
            beta_rad = math.radians(beta)
            gamma_rad = math.radians(gamma)
            xf = xa + radius * math.sin(beta_rad) * math.cos(gamma_rad)
            yf = ya + radius * math.sin(beta_rad) * math.sin(gamma_rad)
            zf = za + radius * math.cos(beta_rad)
            theta = 180.0 - beta
            phi = (180.0 + gamma) % 360.0
            pos_edits["X"].setText(_fmt_calc_value(xf))
            pos_edits["Y"].setText(_fmt_calc_value(yf))
            pos_edits["Z"].setText(_fmt_calc_value(zf))
            cone_edits["theta"].setText(_fmt_calc_value(theta))
            cone_edits["phi"].setText(_fmt_calc_value(phi))
            cone_edits["alpha"].setText(_fmt_calc_value(alpha))
            self._append_scone_calculation_log(
                {
                    "context": "particle_source_editor",
                    "mode": "target_beta_gamma",
                    "input": {
                        "target": {"x": xa, "y": ya, "z": za},
                        "distance_r": radius,
                        "beta_deg": beta,
                        "gamma_deg": gamma,
                        "alpha_deg": alpha,
                    },
                    "output": {
                        "sposit": {
                            "x": _fmt_calc_value(xf),
                            "y": _fmt_calc_value(yf),
                            "z": _fmt_calc_value(zf),
                        },
                        "scone": {
                            "theta_deg": _fmt_calc_value(theta),
                            "phi_deg": _fmt_calc_value(phi),
                            "alpha_deg": _fmt_calc_value(alpha),
                        },
                    },
                }
            )

        def load_target_values():
            path, _ = QFileDialog.getOpenFileName(
                dlg,
                "Load source calculation values",
                str(self._in_folder()),
                "Data files (*.xlsx *.xlsm *.txt *.csv *.dat);;All files (*.*)",
            )
            if not path:
                return
            keys = ["XA", "YA", "ZA", "R", "beta", "gamma", "alpha"]
            values = {}
            try:
                suffix = Path(path).suffix.lower()
                if suffix in {".xlsx", ".xlsm"}:
                    try:
                        import openpyxl
                    except Exception as exc:
                        QMessageBox.warning(dlg, "Missing openpyxl", f"Could not read XLSX files:\n{exc}")
                        return
                    wb = openpyxl.load_workbook(path, data_only=True)
                    ws = wb.active
                    rows = list(ws.iter_rows(values_only=True))
                    header_map = {}
                    if rows:
                        for col, value in enumerate(rows[0]):
                            norm = re.sub(r"[^A-Z0-9]+", "", str(value or "").upper())
                            header_map[norm] = col
                    aliases = {
                        "XA": {"XA", "X", "TARGETX", "XALVO"},
                        "YA": {"YA", "Y", "TARGETY", "YALVO"},
                        "ZA": {"ZA", "Z", "TARGETZ", "ZALVO"},
                        "R": {"R", "DISTANCE", "DISTANCIA"},
                        "beta": {"BETA", "B"},
                        "gamma": {"GAMMA", "GAMA", "G"},
                        "alpha": {"ALPHA", "ALFA", "A"},
                    }
                    if len(rows) >= 2 and header_map:
                        for key, names in aliases.items():
                            for name in names:
                                if name in header_map:
                                    value = rows[1][header_map[name]]
                                    if value is not None and str(value).strip():
                                        values[key] = str(value)
                                    break
                    if not values:
                        nums = []
                        for row in rows:
                            for value in row:
                                try:
                                    nums.append(float(str(value).replace(",", ".")))
                                except Exception:
                                    pass
                        values = {key: str(nums[idx]) for idx, key in enumerate(keys[:len(nums)])}
                else:
                    src = Path(path).read_text(encoding="utf-8", errors="ignore")
                    labelled = {}
                    for key in keys:
                        m = re.search(rf"\b{re.escape(key)}\b\s*[:=,;\s]\s*([-+]?\d+(?:[.,]\d+)?(?:[eE][-+]?\d+)?)", src, re.IGNORECASE)
                        if m:
                            labelled[key] = m.group(1)
                    if labelled:
                        values = labelled
                    else:
                        nums = re.findall(r"[-+]?\d+(?:[.,]\d+)?(?:[eE][-+]?\d+)?", src)
                        values = {key: nums[idx] for idx, key in enumerate(keys[:len(nums)])}
            except Exception as exc:
                QMessageBox.warning(dlg, "Could not load values", str(exc))
                return
            if not values:
                QMessageBox.warning(dlg, "No values found", "Could not find XA, YA, ZA, R, beta, gamma, alpha values in that file.")
                return
            for key, value in values.items():
                if key in calc_edits:
                    calc_edits[key].setText(str(value).replace(",", "."))

        calc_btn.clicked.connect(lambda: calc_group.setVisible(not calc_group.isVisible()))
        apply_calc_btn.clicked.connect(apply_source_calculation)
        load_target_btn.clicked.connect(load_target_values)

        note = QLabel("SPECTR from file imports energy from column 1 and uses probability column from SKPAR: 1->4, 2->6, 3->8. Database spectra use the saved energy/probability pairs directly.")
        note.setStyleSheet(label_css(P["fg2"]))
        note.setVisible(False)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        ok_btn = buttons.button(QDialogButtonBox.StandardButton.Ok)

        def update_energy_mode():
            simple_mode = cmb_source_mode.currentIndex() == 0
            is_spectrum = cmb_energy_type.currentText().startswith("SPECTR")
            use_db = cmb_spectrum_source.currentIndex() == 1
            lbl_senerg.setVisible(simple_mode and not is_spectrum)
            energy_row.setVisible(simple_mode and not is_spectrum)
            lbl_spectr.setVisible(simple_mode and is_spectrum)
            e_spectrum.setVisible(simple_mode and is_spectrum and not use_db)
            lbl_spectrum_source.setVisible(simple_mode and is_spectrum)
            cmb_spectrum_source.setVisible(simple_mode and is_spectrum)
            lbl_spectrum_db.setVisible(simple_mode and is_spectrum and use_db)
            db_row.setVisible(simple_mode and is_spectrum and use_db)
            note.setVisible(simple_mode and is_spectrum)
            ok_btn.setEnabled(True)

        def update_source_mode():
            simple_mode = cmb_source_mode.currentIndex() == 0
            for lbl, widget in simple_rows:
                lbl.setVisible(simple_mode)
                widget.setVisible(simple_mode)
            lbl_calc.setVisible(simple_mode)
            psf_box.setVisible(not simple_mode)
            update_energy_mode()

        cmb_energy_type.currentTextChanged.connect(lambda _txt: update_energy_mode())
        cmb_spectrum_source.currentTextChanged.connect(lambda _txt: update_energy_mode())
        cmb_source_mode.currentTextChanged.connect(lambda _txt: update_source_mode())
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)

        lay = QVBoxLayout(dlg)
        lay.addLayout(form)
        lay.addWidget(psf_box)
        lay.addWidget(note)
        lay.addWidget(buttons)
        update_source_mode()
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return

        if cmb_source_mode.currentIndex() == 1:
            values = {
                "IPSFN file": e_ipsfn.text(),
                "IPSPLI": e_ipspli.text(),
                "WGTWIN min": e_wgtwin_min.text(),
                "WGTWIN max": e_wgtwin_max.text(),
                "EPMAX (eV)": e_epmax.text(),
            }
            if self._apply_phase_space_input_values(values):
                self.console.log("[SIM] Source definition updated (input psf file mode).\n", "ok")
            return

        particle = cmb_particle.currentText().split(" ", 1)[0]
        use_spectrum = cmb_energy_type.currentText().startswith("SPECTR")
        energy = self._format_unit_energy(e_energy.text(), cmb_unit.currentText())
        x = (pos_edits["X"].text() or "0.0").strip()
        y = (pos_edits["Y"].text() or "0.0").strip()
        z = (pos_edits["Z"].text() or "0.0").strip()
        theta = (cone_edits["theta"].text() or "0").strip()
        phi = (cone_edits["phi"].text() or "0").strip()
        alpha = (cone_edits["alpha"].text() or "0").strip()
        prob_col = self._spectr_prob_col_for_particle(particle)
        energy_lines = []
        if use_spectrum:
            if cmb_spectrum_source.currentIndex() == 1:
                db_label = self._normalize_spectrum_label(cmb_spectrum_db.currentText())
                if not db_label:
                    QMessageBox.warning(self, "Missing spectrum", "Choose a spectrum from the database.")
                    return
                try:
                    db_entry = next(entry for entry in self._load_spectrum_database() if entry["label"] == db_label)
                    energy_lines = self._spectr_lines_from_database_rows(db_entry["rows"])
                except StopIteration:
                    QMessageBox.warning(self, "Missing spectrum", "The selected database spectrum was not found.")
                    return
                except ValueError as exc:
                    QMessageBox.warning(self, "Invalid spectrum", str(exc))
                    return
                self._spectr_source_kind = "database"
                self._spectr_database_label = db_label
                self._spectr_source_path = ""
                self._spectr_auto_sync_enabled = False
            else:
                spectrum_path = (e_spectrum.text() or "").strip()
                if not spectrum_path and source_defaults["spectrum_lines"]:
                    cached_path = str(getattr(self, "_spectr_source_path", "") or "").strip()
                    if self._spectr_auto_sync_enabled and cached_path and Path(cached_path).is_file():
                        try:
                            energy_lines = self._spectr_lines_from_file(cached_path, prob_col=prob_col)
                        except ValueError:
                            energy_lines = list(source_defaults["spectrum_lines"])
                    else:
                        energy_lines = list(source_defaults["spectrum_lines"])
                    self._spectr_source_kind = "file"
                    self._spectr_database_label = ""
                    self._spectr_prob_column = prob_col
                elif not spectrum_path:
                    QMessageBox.warning(self, "Missing spectrum", "Choose a spectrum file or a spectrum database entry for SPECTR.")
                    return
                else:
                    try:
                        energy_lines = self._spectr_lines_from_file(spectrum_path, prob_col=prob_col)
                    except ValueError as exc:
                        QMessageBox.warning(self, "Invalid spectrum", str(exc))
                        return
                    self._spectr_source_kind = "file"
                    self._spectr_database_label = ""
                    self._spectr_source_path = spectrum_path
                    self._spectr_prob_column = prob_col
                    self._spectr_auto_sync_enabled = True
        else:
            energy_lines = [f"SENERG {energy:<16}    [Initial energy (monoenergetic sources only)]"]
        self._source_energy_mode = "SPECTR" if use_spectrum else "SENERG"
        if not use_spectrum:
            self._spectr_source_path = ""
            self._spectr_auto_sync_enabled = False
            self._spectr_source_kind = "file"
            self._spectr_database_label = ""

        self._set_psf_section_enabled(False)

        self._replace_source_attribute(
            ("SKPAR", "SENERG", "SPECTR", "SPOSIT", "SCONE"),
            [
                f"SKPAR  {particle}        [Primary particles: 1=electron, 2=photon, 3=positron]",
                *energy_lines,
                f"SPOSIT {x} {y} {z}                    [Coordinates of the source]",
                f"SCONE  {theta} {phi} {alpha}                       [Conical beam; theta phi alpha in deg]",
            ],
        )
        self._sync_impdet_energy_to_source()
        if use_spectrum:
            if self._spectr_source_kind == "database":
                self.console.log(f"[SIM] Source definition updated (SPECTR database: {self._spectr_database_label}).\n", "ok")
            else:
                self.console.log(f"[SIM] Source definition updated (SPECTR prob col {prob_col}).\n", "ok")
        else:
            self.console.log("[SIM] Source definition updated.\n", "ok")

