    def _material_msimpa_from_row(self, row):
        params = {label: (edit.text() or "").strip() for label, edit in row["params"].items()}
        return (
            f"{params['EABS_e']} {params['EABS_ph']} {params['EABS_pos']}"
            f" {params['C1']} {params['C2']} {params['WCC']} {params['WCR']}"
        )

    def _material_order_value(self, text, fallback):
        try:
            return (float((text or "").strip()), fallback)
        except ValueError:
            return (float("inf"), fallback)

    def _msimpa_values(self, line):
        if not line or not re.match(r"^\s*MSIMPA\b", line, re.IGNORECASE):
            return DEFAULT_MSIMPA.split()
        raw = re.sub(r"^\s*MSIMPA\b", "", line, flags=re.IGNORECASE)
        raw = raw.split("[", 1)[0]
        vals = raw.split()
        defaults = DEFAULT_MSIMPA.split()
        return (vals + defaults)[:7]

    def _material_entries(self):
        lines = self._get_text().split("\n")
        entries = []
        i = 0
        while i < len(lines):
            line = lines[i]
            if not re.match(r"^\s*MFNAME\b", line, re.IGNORECASE):
                i += 1
                continue
            raw = re.sub(r"^\s*MFNAME\b", "", line, flags=re.IGNORECASE)
            name = raw.split("[", 1)[0].strip()
            msimpa_line = ""
            msimpa_index = None
            if i + 1 < len(lines) and re.match(r"^\s*MSIMPA\b", lines[i + 1], re.IGNORECASE):
                msimpa_line = lines[i + 1]
                msimpa_index = i + 1
                i += 1
            values = self._msimpa_values(msimpa_line)
            entries.append({
                "name": name,
                "mfname_line": line,
                "msimpa_line": msimpa_line,
                "mfname_index": i,
                "msimpa_index": msimpa_index,
                "values": values,
                "msimpa": " ".join(values),
            })
            i += 1
        return entries

    def _rewrite_material_entries(self, entries):
        lines, start, end = self._section_bounds("Material data and simulation parameters")
        if start is None:
            self._insert_lines_in_section(
                "Material data and simulation parameters",
                [
                    f"MFNAME {entry['name']:<26}[Material file, up to 20 chars]"
                    if idx % 2 == 0 else
                    f"MSIMPA {entry['msimpa']:<26}     [EABS(1:3),C1,C2,WCC,WCR]"
                    for pair in entries
                    for idx, entry in enumerate((pair, pair))
                ],
            )
            return

        keyword_re = re.compile(r"^\s*(MFNAME|MSIMPA)\b", re.IGNORECASE)
        section = [line for line in lines[start + 1:end] if not keyword_re.match(line)]
        insert_rel = next((i for i, line in enumerate(section) if line.strip() == "."), len(section))
        new_lines = []
        for entry in entries:
            new_lines.append(f"MFNAME {entry['name']:<26}[Material file, up to 20 chars]")
            new_lines.append(f"MSIMPA {entry['msimpa']:<26}     [EABS(1:3),C1,C2,WCC,WCR]")
        section[insert_rel:insert_rel] = new_lines
        lines[start + 1:end] = section
        self._set_text("\n".join(lines))
        self._update_sim_action_labels()

    def _import_material_files_to_project(self, parent=None):
        target_dir = self._project_materials_folder()
        if target_dir is None:
            QMessageBox.warning(parent or self, "Import materials", "Open a project first so Studio knows which project materials folder should receive the imported .mat files.")
            return False
        start_dir = str(self._material_list_folder() or self._in_folder())
        paths, _ = QFileDialog.getOpenFileNames(
            parent or self,
            "Import materials to project folder",
            start_dir,
            "Material files (*.mat);;All files (*.*)",
        )
        if not paths:
            return False
        target_dir.mkdir(parents=True, exist_ok=True)
        copied = 0
        skipped = 0
        for raw in paths:
            src = Path(raw)
            dst = target_dir / src.name
            try:
                changed = self._safe_copy_file(src, dst, overwrite=False)
                if changed:
                    copied += 1
                else:
                    skipped += 1
            except Exception as exc:
                self.console.log(f"[SIM] Material import failed for {src.name}: {exc}\n", "warn")
                skipped += 1
        self._mat_list_folder = str(target_dir)
        self._update_file_source_labels()
        self.console.log(f"[SIM] Imported {copied} material file(s) into project folder; {skipped} skipped.\n", "ok" if copied else "warn")
        return copied > 0

    def _cmd_edit_materials(self):
        entries = self._material_entries()
        mat_files = self._material_dropdown_files()
        dlg = QDialog(self)
        dlg.setWindowTitle("Add/Edit Materials")
        dlg.setModal(True)
