        fields = {}
        rows = [
            ("x_min", "X min", 0, 0), ("x_max", "X max", 0, 2),
            ("y_min", "Y min", 1, 0), ("y_max", "Y max", 1, 2),
            ("z_min", "Z min", 2, 0), ("z_max", "Z max", 2, 2),
            ("nx", "NX bins", 3, 0), ("ny", "NY bins", 3, 2), ("nz", "NZ bins", 3, 4),
        ]
        for key, label, row, col in rows:
            form.addWidget(QLabel(label + ":"), row, col)
