ANALYSIS_SUMMARY_FIELDS = (
    ("Simulation time", "Simulation time"),
    ("Simulation speed", "Simulation speed"),
    ("Simulated primary showers", "Sim primary showers"),
    ("Primary particles", "Primary particle"),
)
ANALYSIS_BODY_CACHE_FILE = "analysis_body_volumes.json"
ANALYSIS_BODY_CACHE_VERSION = 1


def _analysis_geomfn_name_from_text(text):
    match = re.search(r"^\s*GEOMFN\s+(\S+)", text or "", re.IGNORECASE | re.MULTILINE)
    if not match:
        return ""
    raw = match.group(1).strip()
    return Path(raw).name if raw else ""


def _analysis_preferred_geo_file(folder):
    folder = Path(folder)
    search_dirs = [folder] + list(folder.parents[:2])
    preferred_names = []
    seen_names = set()
    for search_dir in search_dirs:
        for in_file in sorted(search_dir.glob("*.in")):
            try:
                geom_name = _analysis_geomfn_name_from_text(_decode_text_bytes(in_file.read_bytes()))
            except Exception:
                geom_name = ""
            if geom_name and geom_name.lower() not in seen_names:
                preferred_names.append(geom_name)
                seen_names.add(geom_name.lower())
    for search_dir in search_dirs:
        geo_files = sorted(search_dir.glob("*.geo"))
        if not geo_files:
            continue
        for preferred in preferred_names:
            for geo_file in geo_files:
                if geo_file.name.lower() == preferred.lower():
                    return geo_file
        return geo_files[0]
    return None


def _analysis_preferred_rep_file(folder, geo_file=None):
    folder = Path(folder)
    search_dirs = [folder] + list(folder.parents[:2])
    preferred_names = []
    seen_names = set()
    geo_candidate = Path(geo_file) if geo_file else None
    if geo_candidate:
        for candidate in _linked_rep_candidates_for_geo(geo_candidate):
            key = candidate.name.lower()
            if key not in seen_names:
                preferred_names.append(candidate.name)
                seen_names.add(key)
    for search_dir in search_dirs:
        for in_file in sorted(search_dir.glob("*.in")):
            try:
                geom_name = _analysis_geomfn_name_from_text(_decode_text_bytes(in_file.read_bytes()))
            except Exception:
                geom_name = ""
            if not geom_name:
                continue
            for rep_name in (Path(geom_name).with_suffix(".rep").name, "geometry.rep"):
                key = rep_name.lower()
                if key not in seen_names:
                    preferred_names.append(rep_name)
                    seen_names.add(key)
    for search_dir in search_dirs:
        for preferred in preferred_names:
            candidate = search_dir / preferred
            try:
                if _rep_file_is_valid(candidate):
                    return candidate
            except Exception:
                continue
        try:
            rep_files = sorted(search_dir.glob("*.rep"))
        except Exception:
            rep_files = []
        for rep_file in rep_files:
            if _rep_file_is_valid(rep_file):
                return rep_file
    return None


def _analysis_summary_lines(text, source_info=None):
    lines = []
    for raw_label, display_label in ANALYSIS_SUMMARY_FIELDS:
        match = re.search(
            rf"^\s*{re.escape(raw_label)}\s*(?:\.{{2,}}|:)?\s*(.*)$",
            text or "",
            re.IGNORECASE | re.MULTILINE,
        )
        if match:
            value = match.group(1).strip()
            if value:
                lines.append(f"{display_label}: {value}")
    source_info = source_info or {}
    if source_info.get("sposit_col"):
        lines.append(f"SPOSIT: {source_info['sposit_col']}")
    if source_info.get("scone_col"):
        lines.append(f"SCONE: {source_info['scone_col']}")
    return lines


def _analysis_geo_sha256(path):
    path = Path(path)
    try:
        return hashlib.sha256(path.read_bytes()).hexdigest()
    except Exception:
        return ""


class AnalysisLoadWorker(QObject):
    """Worker that loads all analysis data for a folder off the main thread."""
    finished = Signal(object)
    error    = Signal(object)

    def __init__(self, folder, geo_body_for_result_id_fn, matching_in_token_fn, extract_source_fn,
                 body_geometry_summary_fn, estimate_all_body_masses_fn, body_geometry_type_fn, serial=None):
        super().__init__()
        self._folder = Path(folder)
        self._serial = serial
        self._geo_body_for_result_id    = geo_body_for_result_id_fn
        self._matching_in_token         = matching_in_token_fn
        self._extract_source_info       = extract_source_fn
        self._body_geometry_summary     = body_geometry_summary_fn
        self._estimate_all_body_masses  = estimate_all_body_masses_fn
        self._body_geometry_type        = body_geometry_type_fn

    def run(self):
        try:
            folder = self._folder
            result = {"folder": str(folder), "serial": self._serial}
            health = _penmain_result_health(folder)
            result["result_health"] = health

            # --- material densities (folder → parent → grandparent) ---
            mat_densities = {}
            _search_dirs = [folder] + list(folder.parents[:2])
            _mat_re = re.compile(
                r"\*+\s*(\d+)(?:st|nd|rd|th)\s+material.*?"
                r"Mass density\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\s*g/cm\*\*3",
                re.IGNORECASE | re.DOTALL,
            )
            for _sd in _search_dirs:
                _matdat = _sd / "material.dat"
                if _matdat.exists():
                    try:
                        _t = _decode_text_bytes(_matdat.read_bytes())
                        for _m in _mat_re.finditer(_t):
                            mat_densities[int(_m.group(1))] = float(_m.group(2))
                    except Exception:
                        pass
                if mat_densities:
                    break
            if not mat_densities:
                for _sd in _search_dirs:
                    _mats = sorted(_sd.glob("*.mat"))
                    if not _mats:
                        continue
                    for idx, mat in enumerate(_mats, start=1):
                        try:
                            _t = _decode_text_bytes(mat.read_bytes())
                            _m = re.search(r"Mass density\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\s*g/cm\*\*3", _t, re.IGNORECASE)
                            if _m:
                                mat_densities[idx] = float(_m.group(1))
                        except Exception:
                            continue
                    if mat_densities:
                        break
            result["material_densities"] = mat_densities

            # --- geo context (folder → parent → grandparent) ---
            geo_bodies = {}; body_geometry = {}; geo_surfaces = {}
            geo_body_defs = {}; result_body_defs = {}; body_masses = {}
            geo_file = _analysis_preferred_geo_file(folder)
            if geo_file:
                try:
                    text = _decode_text_bytes(geo_file.read_bytes())
                    surfaces, bodies = _parse_geo(text)
                    geo_surfaces = surfaces
                    geo_body_defs = {int(b["id"]): b for b in bodies}
                    result_body_defs = {idx: b for idx, b in enumerate(bodies, start=1)}
                    geo_bodies = {int(b["id"]): b.get("label", "").strip() for b in bodies}
                    body_geometry = {
                        int(b["id"]): self._body_geometry_summary(b, surfaces)
                        for b in bodies
                    }
                    body_masses = {}
                except Exception:
                    pass
            result.update({
                "geo_bodies": geo_bodies,
                "body_geometry": body_geometry,
                "geo_surfaces": geo_surfaces,
                "geo_body_defs": geo_body_defs,
                "result_body_defs": result_body_defs,
                "body_masses": body_masses,
            })

            # --- penmain results ---
            res_path = folder / "penmain-res.dat"
            sim_time_sec = None; sim_showers = None
            sim_time_text = ""; sim_showers_text = ""
            summary_bits = []; body_results = []
            source_info = self._extract_source_info(folder)
            if res_path.exists():
                text = _decode_text_bytes(res_path.read_bytes())
                summary_bits = _analysis_summary_lines(text, source_info)
                if health.get("incomplete"):
                    summary_bits.insert(0, f"Incomplete run: {health.get('reason')}")
                mt = re.search(r"Simulation time\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)\s*sec", text, re.IGNORECASE)
                ms = re.search(r"Simulated primary showers\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)", text, re.IGNORECASE)
                if mt:
                    try: sim_time_sec = float(mt.group(1)); sim_time_text = mt.group(1)
                    except ValueError: pass
                if ms:
                    try: sim_showers = float(ms.group(1)); sim_showers_text = ms.group(1)
                    except ValueError: pass
                body_re = re.compile(
                    r"^\s*Body\s+(\d+)\s+\.+\s+([+\-]?\d+\.\d+E[+\-]\d+)\s+\+-\s+([+\-]?\d+\.\d+E[+\-]\d+)\s+eV\s+\(effic\.\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\)",
                    re.IGNORECASE | re.MULTILINE,
                )
                for m in body_re.finditer(text):
                    body_id = int(m.group(1))
                    geo_body = result_body_defs.get(body_id) or geo_body_defs.get(body_id)
                    geo_body_id = int(geo_body["id"]) if geo_body else body_id
                    label_str = (geo_body.get("label", "").strip() if geo_body else "") or f"Body {body_id}"
                    energy = float(m.group(2)); stu = float(m.group(3))
                    error = abs(stu / energy * 100.0) if energy else ""
                    geom = body_geometry.get(geo_body_id, "coords not available from .geo")
                    if geo_body and geo_body_id != body_id:
                        geom = f"geo BODY({geo_body_id}) {label_str}; {geom}"
                    body_results.append({
                        "body_id": body_id, "geo_body_id": geo_body_id,
                        "component": label_str,
                        "edep": energy, "dedep": stu, "error": error,
                        "effic": m.group(4),
                        "geometry": geom,
                        "geometry_type": self._body_geometry_type(geo_body, geo_surfaces) if geo_body else "Unknown",
                        "mass": "", "dose": "", "ddose": "",
                    })
            result.update({
                "sim_time_sec": sim_time_sec, "sim_showers": sim_showers,
                "sim_time_text": sim_time_text, "sim_showers_text": sim_showers_text,
                "summary_text": "\n".join(summary_bits) if summary_bits else (res_path.name if res_path.exists() else "No penmain-res.dat found."),
                "body_results": body_results,
                "source_info": source_info,
            })
            self.finished.emit(result)
        except Exception:
            import traceback
            self.error.emit({"serial": self._serial, "error": traceback.format_exc()})


class AnalysisTab(QWidget):
    status_message = Signal(str)
    DOSE_HEADERS = [
        "Case", "Body", "Component",
        "Edep (eV)", "dE (eV)", "Mass (kg)",
        "Dose (eV/g)", "dDose (eV/g)",
        "Edep (J)", "dE (J)", "Error (%)",
        "Dose (Gy)", "dDose (Gy)",
        "N ref", "Time ref (s)", "Target Err (%)", "NSIMSH @5%", "Time @5% (s)",
        "Quality", "Geometry Type",
    ]
    DOSE_CONFIG_SHEET = "__DOSE_CONFIG__"
    EV_TO_J = 1.602176634e-19
    TARGET_ERR_PCT = 5.0
    RISK_CANDIDATE_N = (3e6, 1e7, 3e7, 1e8)

    def __init__(self, parent=None):
        super().__init__(parent)
        self._project_root = None
        self._workspace = None
        self._multi_root = None
        self._dose_xlsx = None
        self._dose_xlsx_user_selected = False
        self._dose_workbook_config = None
        self._geo_bodies = {}
        self._body_geometry = {}
        self._geo_surfaces = {}
        self._geo_body_defs = {}
        self._result_body_defs = {}
        self._material_densities = {}
        self._analysis_rep_file = None
        self._body_volumes = {}
        self._body_masses = {}
        self._body_results = []
        self._sim_time_sec = None
        self._sim_showers = None
        self._sim_time_text = ""
        self._sim_showers_text = ""
        self._target_err_pct = self.TARGET_ERR_PCT
        self._risk_default_nref = 3e6
        self._risk_default_time_ref = 1800.0
        self._risk_default_error_ref = 50.0
        self._analysis_log = None
        self._current_source_col = ""
        self._split_groups = []
        self._analysis_selected_file = None
        self._analysis_load_thread = None
        self._analysis_load_worker = None
        self._analysis_load_serial = 0
        # Restore GPU preference; apply to module global so worker threads see it.
        if _CUPY_AVAILABLE:
            _qs = QSettings("CodAI", "PenelopeStudio")
            global _ANALYSIS_GPU_ENABLED
            _ANALYSIS_GPU_ENABLED = _qs.value("analysis/gpu_enabled", False, type=bool)
        self._build()

    def _build(self):
        root = QVBoxLayout(self)
        root.setContentsMargins(8, 8, 8, 8)
        root.setSpacing(8)

        root_row = QFrame()
        root_row.setStyleSheet(f"QFrame {{ background:{P['bg2']}; border:1px solid {P['border']}; border-radius:6px; }}")
        root_lay = QHBoxLayout(root_row)
        root_lay.setContentsMargins(8, 6, 8, 6)
        root_lay.setSpacing(8)
        multi_root_widget, self.lbl_multi_root = make_help_label(
            "Case Root: none",
            "Folder scanned for completed cases and batch analysis candidates.",
            style=label_css(P["fg2"]),
            return_label=True,
        )
        self.lbl_multi_root.setStyleSheet(label_css(P["fg2"]))
