    def _configure_body_table_columns(self):
        if not hasattr(self, "tbl_bodies"):
            return
        header = self.tbl_bodies.horizontalHeader()
        widths = {
            0: 44,
            2: 96,
            3: 96,
            4: 96,
            5: 96,
            6: 78,
            7: 96,
            8: 96,
            9: 104,
            10: 104,
            11: 110,
            12: 92,
            13: 92,
            14: 86,
            15: 108,
            16: 104,
        }
        header.setMinimumSectionSize(36)
        header.setStretchLastSection(False)
        header.setSectionResizeMode(0, QHeaderView.ResizeMode.Fixed)
        header.setSectionResizeMode(1, QHeaderView.ResizeMode.Stretch)
        self.tbl_bodies.setColumnWidth(1, 280)
        for col, width in widths.items():
            if col == 1:
                continue
            header.setSectionResizeMode(col, QHeaderView.ResizeMode.Fixed)
            self.tbl_bodies.setColumnWidth(col, width)

    def _show_help(self):
        show_help_dialog(
            self,
            "Analysis (.dat) Help",
            f"""
            <h2 style="color:{P['accent']};">Analysis (.dat)</h2>
            <p>This tab reads completed simulation cases and turns PENELOPE output into body-level energy, mass, and dose summaries.</p>
            <h3>Case Selection</h3>
            <ul>
              <li><b>Select Case</b> opens one run folder containing <code>penmain-res.dat</code>, a linked <code>.geo</code>, and material files.</li>
              <li><b>Reload</b> reparses the current case after files change.</li>
              <li>The case summary shows run status, showers, time, linked geometry, and available output files.</li>
              <li>Dose output files such as <code>x-dose.dat</code>, <code>y-dose.dat</code>, <code>z-dose.dat</code>, and <code>3d-dose.dat</code> now appear in the file list when present.</li>
            </ul>
            <h3>Dose Calculation</h3>
            <ul>
              <li>Deposited energy and uncertainty come from <code>penmain-res.dat</code>.</li>
              <li>Mass is estimated from geometry volume and material density when the needed information is available.</li>
              <li>Dose is reported both as <b>Gy</b> and <b>eV/g</b>. Gy uses <code>D = E / m</code> after converting eV to joules with <code>1.602176634e-19</code>; eV/g uses deposited energy directly over mass in grams.</li>
              <li>The table includes body rows and a total row for the selected case.</li>
              <li><b>3D Dose...</b> now offers two MATLAB helpers: a case-specific script saved inside the current case folder, or a reusable browser script saved at a chosen cases/root folder.</li>
              <li>The browser script scans subfolders recursively under a chosen root and saves PNG plots beside each <code>3d-dose*.dat</code>.</li>
            </ul>
            <h3>Excel Output</h3>
            <ul>
              <li><b>Dose XLSX...</b> selects or creates the dose workbook used for appending rows.</li>
              <li><b>Append Dosage Rows</b> writes the current case into the selected workbook.</li>
              <li><b>Case Root...</b> selects a folder containing many completed cases.</li>
              <li><b>Multi Append</b> scans candidate cases under Case Root and updates <code>auto_Dose.xlsx</code>, replacing an existing case if it is already present.</li>
              <li><b>Combine penmain-res...</b> combines multiple independent split-runs by actual simulated showers and exports <code>combined_analysis_summary.txt</code> plus <code>combined_analysis.json</code>.</li>
            </ul>
            <h3>Split-Run Combination</h3>
            <ul>
              <li>The combined result assumes equivalent geometry, materials, source settings, detector/bin settings, and body IDs.</li>
              <li>PENELOPE printed <code>+-</code> uncertainty is treated as 3 sigma for the combined uncertainty calculation.</li>
            </ul>
            <h3>Quality Hints</h3>
            <ul>
              <li>Large error percentages usually mean more showers are needed for that body.</li>
              <li>Zero deposited energy usually means the beam missed the body, the geometry is wrong, or the run did not actually sample interactions in that region.</li>
              <li>Use the body coordinate notes under each row to sanity-check whether geometry and source direction agree.</li>
            </ul>
            """,
        )

    def _log_analysis(self, text, kind="info"):
        msg = (text or "").strip()
        if not msg:
            return
        if self._analysis_log is not None:
            self._analysis_log.log(msg + "\n", kind)

    def _choose_workspace(self):
        start = str(self._workspace or Path.cwd())
        folder = QFileDialog.getExistingDirectory(self, "Select analysis case", start)
        if folder:
            self._load_workspace(Path(folder))

    def _choose_dose_xlsx(self):
        start_dir = self._workspace or Path.cwd()
        if self._dose_xlsx is not None:
            start_dir = self._dose_xlsx.parent
        start = start_dir / (self._dose_xlsx.name if self._dose_xlsx else "dose_analysis.xlsx")
        dialog = QFileDialog(
            self,
            "Select existing or create dose workbook",
            str(start_dir),
            "Excel workbook (*.xlsx);;All files (*.*)",
        )
        dialog.setAcceptMode(QFileDialog.AcceptMode.AcceptSave)
        dialog.setFileMode(QFileDialog.FileMode.AnyFile)
        dialog.setDefaultSuffix("xlsx")
        dialog.setOption(QFileDialog.Option.DontConfirmOverwrite, True)
        dialog.selectFile(str(start))
        if not dialog.exec():
            return
        selected = dialog.selectedFiles()
        if not selected:
            return
        path = selected[0]
        if not path:
            return
        if not path.lower().endswith(".xlsx"):
            path += ".xlsx"
        chosen_path = Path(path)
        self._dose_xlsx = chosen_path
        self._dose_xlsx_user_selected = True
        self._dose_workbook_config = None
        state = "existing" if self._dose_xlsx.exists() else "will be created on append"
        self._update_dose_xlsx_label(state)
        self.status_message.emit(f"Dose workbook selected: {self._dose_xlsx}")
        self._log_analysis(f"Dose workbook selected: {self._dose_xlsx} ({state}).", "info")
        self._refresh_dose_columns()

    def _extract_source_info_from_in(self, folder):
        """Read the .in file in folder and return SPOSIT, SCONE, and energy mode info."""
        _, text = self._first_in_text_for_folder(folder)
        if not text:
            return {}
        def tokens(keyword):
            m = re.search(r"^\s*" + re.escape(keyword) + r"\s+(.+?)(?:\s*\[|$)", text, re.IGNORECASE | re.MULTILINE)
            return m.group(1).strip().split() if m else []
        sposit = tokens("SPOSIT")
        scone = tokens("SCONE")
        sposit_col = "_".join(sposit) if sposit else ""
        scone_col = "_".join(scone) if scone else ""
        parts = [p for p in [sposit_col, scone_col] if p]
        source_col = "_".join(parts) if parts else ""
        if re.search(r"^\s*SPECTR\b", text, re.IGNORECASE | re.MULTILINE):
            energy_mode = "SPECTR"
            m = re.search(r"^\s*SPECTR\s+(.+?)(?:\s*\[|$)", text, re.IGNORECASE | re.MULTILINE)
            energy_info = m.group(1).strip() if m else ""
        elif re.search(r"^\s*SENERG\b", text, re.IGNORECASE | re.MULTILINE):
            energy_mode = "SENERG"
            m = re.search(r"^\s*SENERG\s+(.+?)(?:\s*\[|$)", text, re.IGNORECASE | re.MULTILINE)
            energy_info = m.group(1).strip() if m else ""
        else:
            energy_mode = ""
            energy_info = ""
        return {
            "sposit_col": sposit_col,
            "scone_col": scone_col,
            "source_col": source_col,
            "energy_mode": energy_mode,
            "energy_info": energy_info,
        }

    def _scan_split_groups_validated(self, root_folder):
        """Scan root_folder recursively and return validated split groups.

        A group is valid when:
        - 2+ folders share the same key signature (SKPAR/SPECTR/SPOSIT/SCONE/MFNAME/GEOMFN)
        - All kept members have distinct RSEED pairs (default (1,1) if absent)
        """
        root = Path(root_folder)
        raw_groups = {}
        for folder in sorted(root.rglob("*")):
            if not folder.is_dir():
                continue
            res = folder / "penmain-res.dat"
            if not res.exists():
                continue
            sig, in_path = self._compatibility_signature_from_in(folder)
            if not sig:
                continue
            key = (
                sig.get("SKPAR", ()),
                sig.get("SPECTR", ()),
                sig.get("SPOSIT", ()),
                sig.get("SCONE", ()),
                tuple(sorted(sig.get("MFNAME", ()))),
                sig.get("GEOMFN", ()),
            )
            seed_meta = self._seed_metadata_for_folder(folder)
            rseed = (int(seed_meta.get("seed1", 1) or 1), int(seed_meta.get("seed2", 1) or 1))
            raw_groups.setdefault(key, []).append({"folder": folder, "res": res, "rseed": rseed, "sig": sig, "in_path": in_path})
        def _kw_vals(sig, keyword):
            """Return just the values from the first matching keyword line.
            e.g. 'SPOSIT 0 0 -10  [Coordinates ...]' → '0 0 -10'
            """
            lines = sig.get(keyword, ())
            if not lines:
                return "?"
            val = re.sub(rf"^\s*{re.escape(keyword)}\s*", "", lines[0], flags=re.IGNORECASE)
            val = re.sub(r"\s*\[.*$", "", val).strip()
            return val or "?"

        def _fmt_ev(e_ev):
            """Format an energy in eV as a compact human-readable string."""
            try:
                e = float(e_ev)
            except (TypeError, ValueError):
                return str(e_ev)
            if e >= 1e6:
                return f"{e / 1e6:.4g} MeV"
            if e >= 1e3:
                return f"{e / 1e3:.4g} keV"
            return f"{e:.4g} eV"

        def _spectrum_label(sig, in_path):
            """Return a short spectrum label: sidecar database label > SENERG > SPECTR Emax."""
            # 1. Named label from spectr_link sidecar (set by the spectrum editor).
            # in_path is the .in file already found during the scan — no re-read needed.
            try:
                sidecar_fn = getattr(self, "_spectr_link_sidecar_path", None)
                if in_path and sidecar_fn:
                    sidecar = sidecar_fn(in_path)
                    if sidecar and sidecar.exists():
                        data = json.loads(sidecar.read_text(encoding="utf-8"))
                        label = str(data.get("database_label", "") or "").strip()
                        if label:
                            return label
                        sp = str(data.get("spectrum_path", "") or "").strip()
                        if sp:
                            return Path(sp).stem
            except (OSError, json.JSONDecodeError, ValueError):
                pass
            # 2. Monoenergetic source
            senerg_lines = sig.get("SENERG", ())
            if senerg_lines:
                raw = re.sub(r"^\s*SENERG\s*", "", senerg_lines[0], flags=re.IGNORECASE)
                raw = re.sub(r"\s*\[.*$", "", raw).strip().split()[0] if raw.strip() else ""
                try:
                    return _fmt_ev(float(raw)) + " mono"
                except (ValueError, IndexError):
                    pass
            # 3. Spectrum table: report the maximum energy bin
            spectr_lines = sig.get("SPECTR", ())
            energies = []
            for line in spectr_lines:
                parts = re.sub(r"\[.*$", "", line).split()
                # SPECTR  E_eV  P — parts[0]="SPECTR", parts[1]=E
                if len(parts) >= 2:
                    try:
                        energies.append(float(parts[1]))
                    except ValueError:
                        pass
            if energies:
                return f"spectrum ≤{_fmt_ev(max(energies))}"
            return "?"

        validated = []
        for gid, (key, members) in enumerate(raw_groups.items(), start=1):
            seen_seeds = {}
            deduped = []
            for m in members:
                rseed = m["rseed"]
                if rseed not in seen_seeds:
                    seen_seeds[rseed] = True
                    deduped.append(m)
            if len(deduped) >= 2:
                sample_sig = deduped[0]["sig"]
                validated.append({
                    "id":      gid,
                    "members": deduped,
                    "skpar":   _kw_vals(sample_sig, "SKPAR"),
                    "spectr":  _spectrum_label(sample_sig, deduped[0]["in_path"]),
                    "geomfn":  _kw_vals(sample_sig, "GEOMFN"),
                    "sposit":  _kw_vals(sample_sig, "SPOSIT"),
                    "scone":   _kw_vals(sample_sig, "SCONE"),
                })
        return validated

    def _write_combined_res_dat(self, runs, output_path):
        """Write a native-format penmain-res.dat containing the combined results."""
        total_showers = sum(float(run["showers"]) for run in runs if run.get("showers"))
        times = [float(run["time"]) for run in runs if run.get("time")]
        total_time = sum(times) if times else 0.0
        speed = (total_showers / total_time) if total_time > 0 else 0.0
        combined_fractions = self._combined_fractions(runs, total_showers)
        upbound = combined_fractions.get("upbound", {}).get("fraction") or 0.0
        downbound = combined_fractions.get("downbound", {}).get("fraction") or 0.0
        absorbed = combined_fractions.get("absorbed", {}).get("fraction") or 0.0
        warnings_inner = []
        body_rows = self._combine_body_rows_from_runs(runs, warnings_inner)

        def sfmt(val):
            if val in ("", None):
                return "+0.000000E+00"
            v = float(val)
            sign = "+" if v >= 0 else "-"
            return f"{sign}{abs(v):.6E}"

        lines = [
            "PENELOPE-2011. Results from PENMAIN (combined split-run output).",
            "",
            f"  Combined from {len(runs)} split runs by PENELOPE Simulation Studio V9.",
            f"  Created: {datetime.now().isoformat(timespec='seconds')}",
            "",
            f"  Simulation time ............ {total_time:.6E} sec",
            f"  Simulation speed ........... {speed:.6E} showers/sec",
            f"  Simulated primary showers .. {total_showers:.6E}",
            f"  Primary particles .......... {2}",
            f"  Upbound fraction ........... {upbound:.6E}",
            f"  Downbound fraction ......... {downbound:.6E}",
            f"  Absorption fraction ........ {absorbed:.6E}",
            "",
            "  Energy deposited in each body",
            "  ============================",
            "",
        ]
        for row in body_rows:
            body_id = row.get("body_id", 0)
            edep = row.get("edep") or 0.0
            dedep = row.get("dedep") or 0.0
            lines.append(
                f"  Body {body_id:<4} ............ {sfmt(edep)} +- {sfmt(dedep)} eV (effic. = +0.000000E+00)"
            )
        if warnings_inner:
            lines.extend(["", "  Combination warnings:"])
            for w in warnings_inner:
                lines.append(f"  # {w}")
        lines.extend(["", "  (End of combined output)", ""])
        output_path = Path(output_path)
        output_path.parent.mkdir(parents=True, exist_ok=True)
        output_path.write_text("\n".join(lines), encoding="utf-8")
        return output_path

    def _scan_and_populate_split_groups(self):
        root = self._multi_root
        if root is None:
            start = str(self._workspace or Path.cwd())
            folder = QFileDialog.getExistingDirectory(self, "Select root folder to scan for split groups", start)
            if not folder:
                return
            root = Path(folder)
            self._multi_root = root
            self._set_multi_root_label(root)
        self._log_analysis(f"Scanning for split groups under: {root}", "info")
        QApplication.processEvents()
        self._split_groups = self._scan_split_groups_validated(root)
        if not hasattr(self, "lst_split_groups"):
            return
        self.lst_split_groups.clear()
        if not self._split_groups:
            self.lst_split_groups.addItem("No valid split groups found (need 2+ runs with distinct RSEED).")
            return
        for grp in self._split_groups:
            label = (
                f"Group {grp['id']}  |  {len(grp['members'])} runs"
                f"  |  SKPAR={grp['skpar']}"
                f"  |  {grp['spectr']}"
                f"  |  SPOSIT={grp['sposit']}"
                f"  |  SCONE={grp['scone']}"
                f"  |  GEO={grp['geomfn']}"
            )
            item = QListWidgetItem(label)
            item.setData(Qt.ItemDataRole.UserRole, grp["id"])
            self.lst_split_groups.addItem(item)
        self._log_analysis(f"Found {len(self._split_groups)} valid split group(s).", "ok")

    def _selected_split_group(self):
        if not hasattr(self, "lst_split_groups"):
            return None
        cur = self.lst_split_groups.currentItem()
        if cur is None:
            return None
        gid = cur.data(Qt.ItemDataRole.UserRole)
        for grp in self._split_groups:
            if grp["id"] == gid:
                return grp
        return None

    def _open_selected_split_group(self):
        grp = self._selected_split_group()
        if grp is None:
            QMessageBox.information(self, "No group selected", "Select a split group from the list first.")
            return
        res_files = [Path(m["res"]) for m in grp["members"] if m.get("res")]
        existing_res_files = [path for path in res_files if path.exists() and path.is_file()]
        self._log_analysis(
            f"Opening group {grp['id']} with {len(existing_res_files)}/{len(res_files)} available run(s).",
            "info",
        )
        if len(existing_res_files) < 2:
            self._log_analysis(
                f"Group {grp['id']} could not be opened because fewer than two penmain-res.dat files are available.",
                "warn",
            )
            QMessageBox.warning(
                self,
                "Open Group",
                "Fewer than two valid penmain-res.dat files were found for the selected split group.",
            )
            return
        self.summary.setPlainText(
            f"Preparing combined analysis for split group {grp['id']}...\n"
            f"Runs found: {len(existing_res_files)}\n"
            f"Geometry: {grp.get('geomfn', '?')}\n"
            f"Source: {grp.get('spectr', '?')}"
        )
        self.status_message.emit(f"Opening split group {grp['id']}...")
        QApplication.processEvents()
        _clear_all_override_cursors()
        self._combine_penmain_result_files(existing_res_files)

    def _create_selected_split_group_res_dat(self):
        grp = self._selected_split_group()
        if grp is None:
            QMessageBox.information(self, "No group selected", "Select a split group from the list first.")
            return
        res_files = [m["res"] for m in grp["members"]]
        runs = []
        for path in res_files:
            try:
                parsed = self._parse_penmain_res_for_combine(path)
                if parsed.get("showers") and parsed.get("showers") > 0 and parsed.get("bodies"):
                    runs.append(parsed)
            except Exception as exc:
                self._log_analysis(f"Skipped {path}: {exc}", "warn")
        if len(runs) < 2:
            QMessageBox.warning(self, "Create res.dat", f"Fewer than 2 valid runs found for group {grp['id']}.")
            return
        sample_folder = Path(runs[0]["folder"])
        split_parent = sample_folder.parent
        # Default to a named subfolder so Multi Append labels the row clearly.
        # The folder name becomes the case identifier in the workbook.
        default_dir = split_parent / f"{split_parent.name}_combined"
        out_path, _ = QFileDialog.getSaveFileName(
            self,
            "Save combined penmain-res.dat",
            str(default_dir / "penmain-res.dat"),
            "PENELOPE results (penmain-res.dat);;DAT files (*.dat);;All files (*.*)",
        )
        if not out_path:
            return
        try:
            written = self._write_combined_res_dat(runs, out_path)
            case_label = Path(out_path).parent.name
            total_sh = sum(float(r["showers"]) for r in runs)
            self._log_analysis(f"Combined res.dat written: {written}  (Multi Append label: '{case_label}')", "ok")
            QMessageBox.information(
                self,
                "res.dat created",
                f"Combined penmain-res.dat written to:\n{written}\n\n"
                f"Combined from {len(runs)} runs  |  {total_sh:.6G} total showers\n\n"
                f"Multi Append case label: \"{case_label}\"\n"
                "Run Multi Append with 'Include individual split runs' OFF to see only this combined result.",
            )
        except Exception as exc:
            self._log_analysis(f"Failed to write combined res.dat: {exc}", "err")
            QMessageBox.critical(self, "Create res.dat", str(exc))

    def _choose_multi_root(self):
        start = str(self._multi_root or self._workspace or Path.cwd())
        folder = QFileDialog.getExistingDirectory(self, "Select case root folder", start)
        if not folder:
            return
        self._multi_root = Path(folder)
        self._set_multi_root_label(self._multi_root)
        self._refresh_analysis_workspace_candidates()
        self.status_message.emit(f"Analysis case root selected: {self._multi_root}")
        self._log_analysis(f"Multi-append case root selected: {self._multi_root}", "info")

    # ------------------------------------------------------------------ #
    #  Export native PENELOPE files                                       #
    # ------------------------------------------------------------------ #

    # Files recognised as native PENELOPE/simulation files.
    # Everything else (JSON manifests, XLSX workbooks, TXT summaries,
    # Python scripts, etc.) is excluded from the export.
    _NATIVE_EXTS   = frozenset({".mat", ".in", ".geo", ".dat", ".rep"})
    _NATIVE_NAMES  = frozenset({"penmain.exe"})

    def _export_native_case(self):
        """Copy a case folder to a destination keeping only native PENELOPE files."""
        # ── 1. Source folder ─────────────────────────────────────────────
        start_src = str(self._workspace or self._multi_root or Path.cwd())
        src_str = QFileDialog.getExistingDirectory(
            self, "Select case folder to export (source)", start_src
        )
        if not src_str:
            return
        src = Path(src_str)

        # ── 2. Destination folder ────────────────────────────────────────
        dst_str = QFileDialog.getExistingDirectory(
            self, "Select destination (a sub-folder named after the case will be created inside)", str(src.parent)
        )
        if not dst_str:
            return
        dst_root = Path(dst_str) / src.name

        # Guard: exact match AND destination inside source tree
        if dst_root == src or src in dst_root.parents:
            QMessageBox.warning(self, "Export Native", "Destination must be outside the source folder.")
            return
        if dst_root.exists():
            ans = QMessageBox.question(
                self, "Export Native",
                f"Destination already exists:\n{dst_root}\n\nFiles will be overwritten. Continue?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            )
            if ans != QMessageBox.StandardButton.Yes:
                return

        # ── 3. Walk and copy ─────────────────────────────────────────────
        QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)
        copied, skipped, errors = 0, 0, []
        seen_dirs: set = set()
        try:
            for src_file in src.rglob("*"):
                if not src_file.is_file():
                    continue
                is_native = (
                    src_file.suffix.lower() in self._NATIVE_EXTS
                    or src_file.name.lower() in self._NATIVE_NAMES
                )
                if not is_native:
                    skipped += 1
                    continue
                rel = src_file.relative_to(src)
                dst_file = dst_root / rel
                try:
                    if dst_file.parent not in seen_dirs:
                        dst_file.parent.mkdir(parents=True, exist_ok=True)
                        seen_dirs.add(dst_file.parent)
                    shutil.copy2(src_file, dst_file)
                    copied += 1
                except Exception as exc:
                    errors.append(f"{rel}: {exc}")
        finally:
            QApplication.restoreOverrideCursor()

        # ── 4. Report ────────────────────────────────────────────────────
        lines = [
            f"Exported {copied} native file(s) to:",
            str(dst_root),
            "",
            f"Skipped {skipped} non-native file(s).",
        ]
        if errors:
            lines += ["", f"Errors ({len(errors)}):"] + [f"  {e}" for e in errors[:15]]
            if len(errors) > 15:
                lines.append(f"  … and {len(errors) - 15} more (see log).")
            for e in errors:
                self._log_analysis(f"Export error: {e}", "err")
        self._log_analysis(
            f"Export native: {copied} files copied to {dst_root}; {skipped} non-native skipped; {len(errors)} error(s).",
            "ok" if not errors else "warn",
        )
        QMessageBox.information(self, "Export complete", "\n".join(lines))

    def apply_project_context(self, project_root, project_meta=None):
        root = Path(project_root)
        self._project_root = str(root)
        meta = dict(project_meta or {})
        folders = dict(meta.get("folders") or {})
        analysis_root = root / folders.get("analysis", PROJECT_DIR_ANALYSIS)
        cases_root = root / folders.get("cases", PROJECT_DIR_CASES)
        self._multi_root = cases_root if cases_root.exists() else root
        if hasattr(self, "lbl_multi_root"):
            rel = self._analysis_workspace_display_text(self._multi_root).replace("Case:\n", "").replace("\\\n", "\\")
            self.lbl_multi_root.setText(f"Case Root: {rel}")
            self.lbl_multi_root.setToolTip(str(self._multi_root))
        if (not self._dose_xlsx_user_selected) and analysis_root.exists():
            default_xlsx = analysis_root / "dose_analysis.xlsx"
            if default_xlsx.exists():
                self._dose_xlsx = default_xlsx
                self._dose_workbook_config = None
                if hasattr(self, "lbl_dose_xlsx"):
                    self._update_dose_xlsx_label("project default")
        self._refresh_analysis_workspace_candidates()
        self._log_analysis(f"Project context applied: {root}", "info")

    def _analysis_candidate_folders(self, root, strict=True):
        """Return folders under *root* that look like completed simulation cases.

        *strict=True* (default — used by the case combobox): folder must
        contain penmain-res.dat **and** local .geo **and** local .mat files.

        *strict=False* (used by Multi Append): only penmain-res.dat is
        required.  .geo and .mat are searched up the parent chain at load
        time, so split-run folders that share the parent's geometry and
        material files are found correctly regardless of nesting depth.
        """
        root = Path(root)
        if not root.exists():
            return []
        recursive = bool(
            hasattr(self, "chk_analysis_recursive")
            and self.chk_analysis_recursive.isChecked()
        )
        iterator = root.rglob("*") if recursive else root.iterdir()
        if strict:
            return [
                folder for folder in sorted(iterator)
                if (
                    folder.is_dir()
                    and (folder / "penmain-res.dat").exists()
                    and any(folder.glob("*.geo"))
                    and any(folder.glob("*.mat"))
                    and not _penmain_result_health(folder).get("incomplete")
                )
            ]
        # Relaxed: only penmain-res.dat required — .geo/.mat resolved at load time
        return [
            folder for folder in sorted(iterator)
            if (
                folder.is_dir()
                and (folder / "penmain-res.dat").exists()
                and not _penmain_result_health(folder).get("incomplete")
            )
        ]

    def _analysis_workspace_display_text(self, folder):
        folder = Path(folder)
        if self._project_root:
            try:
                root = Path(self._project_root).resolve()
                rel = str(folder.resolve().relative_to(root)).replace("/", "\\")
                rel = f"{root.name}\\{rel}" if rel else root.name
            except Exception:
                rel = str(folder)
        else:
            root = self._multi_root or folder.parent
            try:
                rel = str(folder.relative_to(root))
            except Exception:
                rel = str(folder)
        rel = rel.replace("/", "\\")
        rel_wrapped = rel.replace("\\", "\\\n")
        return f"Case:\n{rel_wrapped}"

    def _set_workspace_label(self, folder=None, text=None):
        if text is not None:
            self.lbl_workspace.setText(str(text))
            self.lbl_workspace.setToolTip(str(text))
            return
        if folder is None:
            self.lbl_workspace.setText("Case:")
            self.lbl_workspace.setToolTip("")
            return
        folder = Path(folder)
        label = self._analysis_workspace_display_text(folder)
        self.lbl_workspace.setText(label)
        self.lbl_workspace.setToolTip(str(folder))

    def _set_multi_root_label(self, root=None):
        if not hasattr(self, "lbl_multi_root"):
            return
        if not root:
            self.lbl_multi_root.setText("Case Root: none")
            self.lbl_multi_root.setToolTip("")
            return
        root = Path(root)
        if self._project_root:
            try:
                proj = Path(self._project_root).resolve()
                rel = str(root.resolve().relative_to(proj)).replace("/", "\\")
                display = f"{proj.name}\\{rel}" if rel else proj.name
            except Exception:
                display = str(root)
        else:
            display = str(root)
        self.lbl_multi_root.setText(f"Case Root: {display}")
        self.lbl_multi_root.setToolTip(str(root))

    def _refresh_analysis_workspace_candidates(self):
        if not hasattr(self, "cmb_analysis_workspace"):
            return
        self.cmb_analysis_workspace.clear()
        root = self._multi_root or (self._workspace.parent if self._workspace else None)
        if not root:
            self.cmb_analysis_workspace.addItem("No case root selected", "")
            return
        include_splits = bool(
            hasattr(self, "chk_include_splits") and self.chk_include_splits.isChecked()
        )
        # strict=True  → primary runs only (need local .geo + .mat + penmain-res.dat)
        # strict=False → also includes split-run subfolders (penmain-res.dat is enough)
        folders = self._analysis_candidate_folders(root, strict=not include_splits)
        if not folders:
            self.cmb_analysis_workspace.addItem("No completed cases found", "")
            return
        for folder in folders:
            # Relative path makes nested hierarchy unambiguous in the list
            try:
                label = str(folder.relative_to(root))
            except ValueError:
                label = folder.name
            # Mark split-run subfolders (no local .geo/.mat) with ↳
            is_split = not (any(folder.glob("*.geo")) and any(folder.glob("*.mat")))
            if is_split:
                label = "↳  " + label
            self.cmb_analysis_workspace.addItem(label, str(folder))
            self.cmb_analysis_workspace.setItemData(self.cmb_analysis_workspace.count() - 1, str(folder), Qt.ItemDataRole.ToolTipRole)
        if self._workspace:
            idx = self.cmb_analysis_workspace.findData(str(self._workspace))
            if idx >= 0:
                self.cmb_analysis_workspace.setCurrentIndex(idx)
                self.cmb_analysis_workspace.setToolTip(str(self._workspace))

    def _open_selected_analysis_workspace(self):
        if not hasattr(self, "cmb_analysis_workspace"):
            return
        path = self.cmb_analysis_workspace.currentData()
        if not path:
            QMessageBox.information(self, "Case", "Choose a completed case from the list, or select Case Root first.")
            return
        self._load_workspace(Path(path))

    def _load_workspace(self, folder):
        folder = Path(folder)
        if not folder.exists():
            return
        _clear_all_override_cursors()
        # Stop any still-running load before starting a new one so a slow
        # previous load cannot deliver _on_workspace_loaded after the new
        # one finishes and silently overwrite the fresher results.
        if self._analysis_load_thread and self._analysis_load_thread.isRunning():
            self._analysis_load_thread.quit()
            self._analysis_load_thread.wait(2000)
            _clear_all_override_cursors()
        # Monotonic serial — _on_workspace_loaded ignores any callback whose
        # serial no longer matches the most-recently-started load.
        self._analysis_load_serial += 1
        serial = self._analysis_load_serial

        self._log_analysis(f"Loading case: {folder}", "info")
        self._workspace = folder
        self._set_workspace_label(text="Case: loading…")
        if self._multi_root is None:
            self._multi_root = folder.parent
            self._set_multi_root_label(self._multi_root)
        self._refresh_analysis_workspace_candidates()
        if self._dose_xlsx is None:
            default_xlsx = folder / "dose_analysis.xlsx"
            if default_xlsx.exists():
                self._dose_xlsx = default_xlsx
                self._dose_xlsx_user_selected = False
                self._dose_workbook_config = None
                self._update_dose_xlsx_label("auto-detected")
        elif self._dose_xlsx_user_selected:
            self._update_dose_xlsx_label("locked")

        QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)
        self.summary.setPlainText("Loading…")
        self.tbl_bodies.setRowCount(0)

        worker = AnalysisLoadWorker(
            folder,
            self._geo_body_for_result_id,
            self._matching_in_token,
            self._extract_source_info_from_in,
            self._body_geometry_summary,
            self._estimate_all_body_masses_kg,
            self._body_geometry_type,
            serial=serial,
        )
        thread = QThread(self)
        worker.moveToThread(thread)
        thread.started.connect(worker.run)
        worker.finished.connect(self._on_workspace_loaded_payload, Qt.ConnectionType.QueuedConnection)
        worker.error.connect(self._on_workspace_load_error_payload, Qt.ConnectionType.QueuedConnection)
        worker.finished.connect(thread.quit)
        worker.error.connect(thread.quit)
        thread.finished.connect(worker.deleteLater)
        self._analysis_load_thread = thread  # keep reference
        self._analysis_load_worker = worker
        thread.start()

    def _on_workspace_loaded_payload(self, data):
        data = dict(data or {})
        folder = Path(data.get("folder") or self._workspace or Path.cwd())
        self._on_workspace_loaded(data, folder, data.get("serial"))

    def _on_workspace_loaded(self, data, folder, serial=None):
        # Discard results from a superseded load — a newer _load_workspace call
        # has already started (higher serial) so applying this stale payload
        # would silently overwrite fresher data.
        if serial is not None and serial != self._analysis_load_serial:
            _clear_all_override_cursors()
            return
        _clear_all_override_cursors()
        self._material_densities = data.get("material_densities", {})
        self._geo_bodies         = data.get("geo_bodies", {})
        self._body_geometry      = data.get("body_geometry", {})
        self._geo_surfaces       = data.get("geo_surfaces", {})
        self._geo_body_defs      = data.get("geo_body_defs", {})
        self._result_body_defs   = data.get("result_body_defs", {})
        self._body_masses        = data.get("body_masses", {})
        self._body_results       = data.get("body_results", [])
        self._sim_time_sec       = data.get("sim_time_sec")
        self._sim_showers        = data.get("sim_showers")
        self._sim_time_text      = data.get("sim_time_text", "")
        self._sim_showers_text   = data.get("sim_showers_text", "")
        src_info = data.get("source_info", {})
        self._current_source_col = src_info.get("source_col", "")

        self._resolve_analysis_body_cache(folder, log=True)

        # Update matching_in_token values
        self._sim_showers_text = self._matching_in_token("NSIMSH", self._sim_showers, self._sim_showers_text)
        self._sim_time_text    = self._matching_in_token("TIME",   self._sim_time_sec,   self._sim_time_text)

        if hasattr(self, "lbl_reference_values"):
            n_txt, t_txt = self._reference_display_values()
            self.lbl_reference_values.setText(f"N ref: {n_txt or '-'}    Time ref: {t_txt or '-'}")

        self.summary.setPlainText(data.get("summary_text", ""))

        self._populate_file_list(folder)
        self._refresh_dose_columns()
        self._set_workspace_label(folder)
        self.status_message.emit(f"Analysis case: {folder.name}")
        if self._body_results:
            available_masses = sum(1 for result in self._body_results if result.get("mass") not in ("", None))
            self._log_analysis(f"Mass context: {available_masses}/{len(self._body_results)} bodies have mass and dose.", "info")
        self._log_analysis(f"Case ready: {folder.name}; body rows={len(self._body_results)}.", "ok")
        QTimer.singleShot(0, _clear_all_override_cursors)

    def _on_workspace_load_error_payload(self, payload):
        if isinstance(payload, dict):
            err = str(payload.get("error", "") or "")
            serial = payload.get("serial")
        else:
            err = str(payload or "")
            serial = None
        self._on_workspace_load_error(err, serial)

    def _on_workspace_load_error(self, err, serial=None):
        if serial is not None and serial != self._analysis_load_serial:
            _clear_all_override_cursors()
            return
        _clear_all_override_cursors()
        self._log_analysis(f"Case load error: {err}", "err")
        self.summary.setPlainText(f"Load error:\n{err[:500]}")
        self._set_workspace_label(text="Case: load failed")
        QTimer.singleShot(0, _clear_all_override_cursors)

    def _populate_file_list(self, folder):
        self.lst_files.clear()
        groups = [
            ("Run log", ["penmain.dat"]),
            ("Results", ["penmain-res.dat"]),
            ("Energy distributions", sorted(p.name for p in folder.glob("energy-*.dat"))),
            ("Angular distributions", sorted(p.name for p in folder.glob("polar-angle-*.dat"))),
            ("Impact detectors", sorted(p.name for p in folder.glob("spc-impdet-*.dat"))),
            ("Energy-deposition detectors", sorted(p.name for p in folder.glob("spc-enddet-*.dat"))),
            ("Dose profiles", [name for name in ("x-dose.dat", "y-dose.dat", "z-dose.dat") if (folder / name).exists()]),
            ("3D dose maps", sorted(p.name for p in folder.glob("3d-dose*.dat"))),
        ]
        for group, names in groups:
            header = QListWidgetItem(group)
            header.setFlags(header.flags() & ~Qt.ItemFlag.ItemIsSelectable)
            header.setForeground(QColor(P["accent"]))
            header.setToolTip(group)
            self.lst_files.addItem(header)
            for name in names:
                if (folder / name).exists():
                    item = QListWidgetItem(f"  {name}")
                    full_path = str(folder / name)
                    item.setData(Qt.ItemDataRole.UserRole, full_path)
                    item.setToolTip(full_path)
                    self.lst_files.addItem(item)

    def _show_selected_file_summary(self, current, _previous):
        path = Path(current.data(Qt.ItemDataRole.UserRole)) if current and current.data(Qt.ItemDataRole.UserRole) else None
        self._analysis_selected_file = path
        if not path or not path.exists():
            return
        if path.name.lower() == "penmain-res.dat":
            self._parse_penmain_results(path)
            return
        if path.name.lower() in {"x-dose.dat", "y-dose.dat", "z-dose.dat"}:
            self.summary.setPlainText(self._summarize_axis_dose_file(path))
            return
        if path.name.lower().startswith("3d-dose") and path.suffix.lower() == ".dat":
            self.summary.setPlainText(self._summarize_3d_dose_file(path))
            return
        lines = _decode_text_bytes(path.read_bytes()).splitlines()
        preview = "\n".join(lines[:16])
        self.summary.setPlainText(f"{path.name}\n\n{preview}")

    def _load_numeric_dose_file(self, path, min_cols):
        data = np.loadtxt(str(path), comments="#")
        if data.ndim == 1:
            data = data.reshape(1, -1)
        if data.shape[1] < min_cols:
            raise ValueError(f"{path.name} has {data.shape[1]} columns; expected at least {min_cols}.")
        return data

    def _summarize_axis_dose_file(self, path):
        try:
            data = self._load_numeric_dose_file(path, 3)
        except Exception as exc:
            return f"{path.name}\n\nCould not parse dose profile:\n{exc}"
        coord = data[:, 0]
        dose = data[:, 1]
        err = data[:, 2]
        idx = int(np.argmax(dose)) if len(dose) else 0
        axis = path.name[0].upper()
        return (
            f"{path.name}\n\n"
            f"Axis: {axis}\n"
            f"Rows: {len(data)}\n"
            f"{axis} range: {float(np.min(coord)):.6g} to {float(np.max(coord)):.6g} cm\n"
            f"Max dose: {float(dose[idx]):.6g} eV/g at {axis}={float(coord[idx]):.6g} cm\n"
            f"Associated 3σ uncertainty: {float(err[idx]):.6g} eV/g\n\n"
            f"Preview:\n"
            + "\n".join(
                f"{float(row[0]): .6e}   {float(row[1]): .6e}   {float(row[2]): .6e}"
                for row in data[: min(12, len(data))]
            )
        )

    def _summarize_3d_dose_file(self, path):
        try:
            data = self._load_numeric_dose_file(path, 5)
        except Exception as exc:
            return f"{path.name}\n\nCould not parse 3D dose map:\n{exc}"
        x, y, z = data[:, 0], data[:, 1], data[:, 2]
        dose = data[:, 3]
        err = data[:, 4]
        idx = int(np.argmax(dose)) if len(dose) else 0
        unique_x = len(np.unique(np.round(x, 12)))
        unique_y = len(np.unique(np.round(y, 12)))
        unique_z = len(np.unique(np.round(z, 12)))
        return (
            f"{path.name}\n\n"
            f"Rows: {len(data)} voxels\n"
            f"Grid: {unique_x} x {unique_y} x {unique_z}\n"
            f"X range: {float(np.min(x)):.6g} to {float(np.max(x)):.6g} cm\n"
            f"Y range: {float(np.min(y)):.6g} to {float(np.max(y)):.6g} cm\n"
            f"Z range: {float(np.min(z)):.6g} to {float(np.max(z)):.6g} cm\n"
            f"Max dose: {float(dose[idx]):.6g} eV/g at "
            f"({float(x[idx]):.6g}, {float(y[idx]):.6g}, {float(z[idx]):.6g}) cm\n"
            f"Associated 3σ uncertainty: {float(err[idx]):.6g} eV/g\n\n"
            f"Use 3D Dose... to generate a MATLAB helper script for profiles and XY/XZ/YZ scatter views."
        )

    def _strip_3d_dose_headers_in_place(self, path):
        path = Path(path)
        text = _decode_text_bytes(path.read_bytes())
        lines = text.splitlines()
        numeric_lines = [line for line in lines if line.strip() and not line.lstrip().startswith("#")]
        if not numeric_lines:
            raise ValueError(f"No numeric 3D dose rows found in {path}")
        path.write_text("\n".join(numeric_lines) + "\n", encoding="utf-8")
        return path

    def _build_matlab_3d_dose_script(self, dose_paths, script_dir=None):
        dose_paths = [Path(path) for path in dose_paths]
        script_dir = Path(script_dir) if script_dir else None
        file_rows = []
        for idx, path in enumerate(dose_paths, start=1):
            ref_path = path
            if script_dir:
                try:
                    ref_path = Path(os.path.relpath(path, script_dir))
                except Exception:
                    ref_path = path.name
            safe_name = str(ref_path).replace("\\", "/").replace("'", "''")
            file_rows.extend(
                [
                    f"fid{idx} = fopen('{safe_name}', 'rt');",
                    f"if fid{idx} < 0, error('Could not open {safe_name}'); end",
                    f"cols{idx} = textscan(fid{idx}, '%f%f%f%f%f%f%f%f', 'CommentStyle', '#', 'CollectOutput', true, 'MultipleDelimsAsOne', true, 'Delimiter', {{' ', '\\t'}});",
                    f"fclose(fid{idx});",
                    f"S{idx} = cols{idx}{{1}};",
                    f"if isempty(S{idx}), error('No numeric rows found in {safe_name}'); end",
                ]
            )
        dose_rows = []
        sum_rows = ["doseT = zeros(size(x));"]
        legend_rows = []
        plot_rows_x = []
        plot_rows_y = []
        plot_rows_z = []
        for idx in range(1, len(dose_paths) + 1):
            dose_rows.append(f"dose{idx} = S{idx}(:,4);")
            sum_rows.append(f"doseT = doseT + dose{idx};")
            legend_rows.append(f"'dose{idx}'")
            plot_rows_x.append(f"plot(x(ix), dose{idx}(ix), '.'); hold on;")
            plot_rows_y.append(f"plot(y(iy), dose{idx}(iy), '.'); hold on;")
            plot_rows_z.append(f"plot(z(iz), dose{idx}(iz), '.'); hold on;")
        legend_rows.append("'total'")
        return (
            "% Auto-generated by Penelope Studio\n"
            "% Load one or more PENMAIN 3d-dose.dat files, sum column 4, and inspect\n"
            "% central profiles or XY/XZ/YZ slices.\n\n"
            + "\n".join(file_rows) + "\n\n"
            "x = S1(:,1);\n"
            "y = S1(:,2);\n"
            "z = S1(:,3);\n\n"
            + "\n".join(dose_rows) + "\n"
            + "\n".join(sum_rows) + "\n\n"
            "% Target slice centres and tolerances (cm) - edit these to match your target\n"
            "xT = 0.0;\n"
            "yT = 0.0;\n"
            "zT = 0.0;\n"
            "d = 0.5;\n\n"
            "tol_xy = 0.5;\n"
            "tol_xz = 0.3;\n"
            "tol_yz = 0.3;\n\n"
            "ix = find((abs(y - yT) <= d) .* (abs(z - zT) <= d));\n"
            "iy = find((abs(x - xT) <= d) .* (abs(z - zT) <= d));\n"
            "iz = find((abs(x - xT) <= d) .* (abs(y - yT) <= d));\n\n"
            + "\n".join(plot_rows_x) + "\n"
            "plot(x(ix), doseT(ix), 'k*');\n"
            "xlabel('x (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along X');\n"
            f"legend({', '.join(legend_rows)}); grid on; hold off;\n\n"
            "pause\n\n"
            + "\n".join(plot_rows_y) + "\n"
            "plot(y(iy), doseT(iy), 'k*');\n"
            "xlabel('y (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along Y');\n"
            f"legend({', '.join(legend_rows)}); grid on; hold off;\n\n"
            "pause\n\n"
            + "\n".join(plot_rows_z) + "\n"
            "plot(z(iz), doseT(iz), 'k*');\n"
            "xlabel('z (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along Z');\n"
            f"legend({', '.join(legend_rows)}); grid on; hold off;\n\n"
            "pause\n\n"
            "i_xy = find((abs(z - zT) < tol_xy) .* (doseT > 1e-10));\n"
            "scatter(x(i_xy), y(i_xy), 20, doseT(i_xy), 'filled');\n"
            "colorbar; xlabel('x (cm)'); ylabel('y (cm)'); title(['Dose distribution on XY (z = ', num2str(zT), ' cm)']); axis equal; grid on;\n\n"
            "pause\n\n"
            "i_xz = find((abs(y - yT) < tol_xz) .* (doseT > 1e-10));\n"
            "scatter(x(i_xz), z(i_xz), 20, doseT(i_xz), 'filled');\n"
            "colorbar; xlabel('x (cm)'); ylabel('z (cm)'); title(['Dose distribution on XZ (y = ', num2str(yT), ' cm)']); axis equal; grid on;\n\n"
            "pause\n\n"
            "i_yz = find((abs(x - xT) < tol_yz) .* (doseT > 1e-10));\n"
            "scatter(y(i_yz), z(i_yz), 20, doseT(i_yz), 'filled');\n"
            "colorbar; xlabel('y (cm)'); ylabel('z (cm)'); title(['Dose distribution on YZ (x = ', num2str(xT), ' cm)']); axis equal; grid on;\n"
        )

    def _build_matlab_3d_dose_browser_script(self):
        return (
            "% Auto-generated by Penelope Studio\n"
            "% Recursive 3D dose plot exporter.\n"
            "% Scans subfolders under this script''s folder, loads each 3d-dose*.dat,\n"
            "% and saves profile/slice PNG plots beside the dose file.\n\n"
            "rootDir = fileparts(mfilename('fullpath'));\n"
            "scanRoot = uigetdir(rootDir, 'Select root folder to scan recursively for 3d-dose data');\n"
            "if isequal(scanRoot, 0)\n"
            "    return;\n"
            "end\n\n"
            "% Target slice centres and tolerances (cm) - edit these to match your target\n"
            "xT = 4.0;\n"
            "yT = 3.0;\n"
            "zT = -2.2;\n"
            "d = 0.5;\n\n"
            "tol_xy = 0.5;\n"
            "tol_xz = 0.3;\n"
            "tol_yz = 0.3;\n\n"
            "allDirs = regexp(genpath(scanRoot), pathsep, 'split');\n"
            "processed = 0;\n"
            "for dIdx = 1:numel(allDirs)\n"
            "    caseDir = allDirs{dIdx};\n"
            "    if isempty(caseDir)\n"
            "        continue;\n"
            "    end\n"
            "    lowerDir = lower(caseDir);\n"
            "    if ~isempty(strfind(lowerDir, [filesep 'previous_runs'])) || ~isempty(strfind(lowerDir, [filesep 'dmps'])) || ~isempty(strfind(lowerDir, '_3d_dose_header_backup_'))\n"
            "        continue;\n"
            "    end\n"
            "    files = dir(fullfile(caseDir, '3d-dose*.dat'));\n"
            "    if isempty(files)\n"
            "        continue;\n"
            "    end\n"
            "    [~, order] = sort({files.name});\n"
            "    files = files(order);\n"
            "    try\n"
            "        clear x y z dose1 doseT ix iy iz i_xy i_xz i_yz;\n"
            "        for k = 1:numel(files)\n"
            "            dosePath = fullfile(caseDir, files(k).name);\n"
            "            fid = fopen(dosePath, 'rt');\n"
            "            if fid < 0\n"
            "                error(['Could not open ', dosePath]);\n"
            "            end\n"
            "            cols = textscan(fid, '%f%f%f%f%f%f%f%f', 'CommentStyle', '#', 'CollectOutput', true, 'MultipleDelimsAsOne', true, 'Delimiter', {' ', '\\t'});\n"
            "            fclose(fid);\n"
            "            Scur = cols{1};\n"
            "            if isempty(Scur)\n"
            "                error(['No numeric rows found in ', dosePath]);\n"
            "            end\n"
            "            if k == 1\n"
            "                x = Scur(:,1);\n"
            "                y = Scur(:,2);\n"
            "                z = Scur(:,3);\n"
            "                dose1 = Scur(:,4);\n"
            "                doseT = zeros(size(x));\n"
            "            end\n"
            "            doseT = doseT + Scur(:,4);\n"
            "        end\n"
            "        if numel(files) == 1\n"
            "            [~, doseStem, ~] = fileparts(files(1).name);\n"
            "        else\n"
            "            doseStem = '3d-dose_sum';\n"
            "        end\n"
            "        ix = find((abs(y - yT) <= d) .* (abs(z - zT) <= d));\n"
            "        iy = find((abs(x - xT) <= d) .* (abs(z - zT) <= d));\n"
            "        iz = find((abs(x - xT) <= d) .* (abs(y - yT) <= d));\n"
            "        i_xy = find((abs(z - zT) < tol_xy) .* (doseT > 1e-10));\n"
            "        i_xz = find((abs(y - yT) < tol_xz) .* (doseT > 1e-10));\n"
            "        i_yz = find((abs(x - xT) < tol_yz) .* (doseT > 1e-10));\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        plot(x(ix), dose1(ix), '.'); hold on; plot(x(ix), doseT(ix), 'k*');\n"
            "        xlabel('x (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along X'); legend('dose1', 'total'); grid on; hold off;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_profile_x.png'])); close(fig);\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        plot(y(iy), dose1(iy), '.'); hold on; plot(y(iy), doseT(iy), 'k*');\n"
            "        xlabel('y (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along Y'); legend('dose1', 'total'); grid on; hold off;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_profile_y.png'])); close(fig);\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        plot(z(iz), dose1(iz), '.'); hold on; plot(z(iz), doseT(iz), 'k*');\n"
            "        xlabel('z (cm)'); ylabel('Dose (eV/g)'); title('Dose profile along Z'); legend('dose1', 'total'); grid on; hold off;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_profile_z.png'])); close(fig);\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        scatter(x(i_xy), y(i_xy), 20, doseT(i_xy), 'filled');\n"
            "        colorbar; xlabel('x (cm)'); ylabel('y (cm)'); title(['Dose distribution on XY (z = ', num2str(zT), ' cm)']); axis equal; grid on;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_xy.png'])); close(fig);\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        scatter(x(i_xz), z(i_xz), 20, doseT(i_xz), 'filled');\n"
            "        colorbar; xlabel('x (cm)'); ylabel('z (cm)'); title(['Dose distribution on XZ (y = ', num2str(yT), ' cm)']); axis equal; grid on;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_xz.png'])); close(fig);\n"
            "\n"
            "        fig = figure('Visible', 'off');\n"
            "        scatter(y(i_yz), z(i_yz), 20, doseT(i_yz), 'filled');\n"
            "        colorbar; xlabel('y (cm)'); ylabel('z (cm)'); title(['Dose distribution on YZ (x = ', num2str(xT), ' cm)']); axis equal; grid on;\n"
            "        saveas(fig, fullfile(caseDir, [doseStem, '_yz.png'])); close(fig);\n"
            "\n"
            "        processed = processed + 1;\n"
            "        disp(['Saved 3D dose plots for ', caseDir]);\n"
            "    catch ME\n"
            "        disp(['Failed to process ', caseDir, ': ', ME.message]);\n"
            "    end\n"
            "end\n"
            "\n"
            "disp(['Processed case folders: ', num2str(processed)]);\n"
        )

    def _safe_matlab_script_stem(self, value):
        stem = re.sub(r"[^A-Za-z0-9_]+", "_", str(value or "dose_analysis")).strip("_")
        stem = re.sub(r"_+", "_", stem)
        if not stem:
            stem = "dose_analysis"
        if not re.match(r"^[A-Za-z]", stem):
            stem = f"ps_{stem}"
        return stem

    def _safe_matlab_script_path(self, path):
        path = Path(path)
        safe_stem = self._safe_matlab_script_stem(path.stem)
        return path.with_name(f"{safe_stem}.m")

    def _case_3d_dose_files(self, folder, selected_path=None):
        folder = Path(folder)
        selected = Path(selected_path) if selected_path else None
        if selected and selected.exists() and selected.parent == folder and selected.name.lower().startswith("3d-dose") and selected.suffix.lower() == ".dat":
            return [selected]
        return sorted(path for path in folder.glob("3d-dose*.dat") if path.is_file())

    def _default_case_3d_dose_script_path(self, folder):
        folder = Path(folder)
        return self._safe_matlab_script_path(folder / f"{self._safe_matlab_script_stem(folder.name)}_3d_dose_analysis.m")

    def _default_browser_3d_dose_script_path(self, root):
        root = Path(root)
        return self._safe_matlab_script_path(root / f"{self._safe_matlab_script_stem(root.name)}_3d_dose_browser.m")

    def _collect_3d_dose_case_groups(self, root):
        root = Path(root)
        groups = {}
        if not root.exists():
            return []
        for path in sorted(root.rglob("3d-dose*.dat")):
            if not path.is_file():
                continue
            lowered_parts = {part.lower() for part in path.parts}
            if "previous_runs" in lowered_parts or "dmps" in lowered_parts:
                continue
            groups.setdefault(path.parent, []).append(path)
        return [
            (folder, sorted(paths))
            for folder, paths in sorted(groups.items(), key=lambda item: str(item[0]).lower())
        ]

    def _create_matlab_3d_dose_browser_script(self):
        start_dir = str(self._multi_root or self._workspace or Path.cwd())
        root_str = QFileDialog.getExistingDirectory(
            self,
            "Select cases or batch root for the MATLAB 3D dose browser script",
            start_dir,
        )
        if not root_str:
            return
        root = Path(root_str)
        groups = self._collect_3d_dose_case_groups(root)
        if not groups:
            QMessageBox.information(self, "3D Dose", f"No 3d-dose*.dat files were found under:\n{root}")
            return
        stripped = 0
        for _case_folder, dose_files in groups:
            for path in dose_files:
                self._strip_3d_dose_headers_in_place(path)
                stripped += 1
        out_path = self._default_browser_3d_dose_script_path(root)
        script_text = self._build_matlab_3d_dose_browser_script()
        out_path.write_text(script_text, encoding="utf-8")
        self._log_analysis(
            f"3D dose browser script written: {out_path} (prepared {stripped} 3d-dose file(s) under {root})",
            "ok",
        )
        self.summary.setPlainText(
            f"3D dose browser script saved:\n{out_path}\n\n"
            f"Root:\n{root}\n\n"
            f"Prepared 3d-dose files: {stripped}\n"
            "Run the script in MATLAB to choose a root folder, scan its subfolders recursively, and save PNG plots beside each 3d-dose.dat."
        )
        QMessageBox.information(
            self,
            "3D Dose",
            f"3D dose browser script saved:\n{out_path}\n\n"
            f"Prepared {stripped} 3d-dose file(s) under:\n{root}",
        )

    def _create_matlab_3d_dose_case_script(self):
        if not self._workspace:
            QMessageBox.information(self, "3D Dose", "Open an Analysis case first for a case-specific script.")
            return
        folder = Path(self._workspace)
        paths = self._case_3d_dose_files(folder, getattr(self, "_analysis_selected_file", None))
        if not paths:
            QMessageBox.information(self, "3D Dose", f"No 3d-dose*.dat files were found in:\n{folder}")
            return
        prepared = [self._strip_3d_dose_headers_in_place(path) for path in paths]
        out_path = self._default_case_3d_dose_script_path(folder)
        script_text = self._build_matlab_3d_dose_script(prepared, out_path.parent)
        out_path.write_text(script_text, encoding="utf-8")
        self._log_analysis(f"Case 3D dose script written: {out_path}", "ok")
        self.summary.setPlainText(
            f"Case 3D dose script saved:\n{out_path}\n\n"
            "Prepared files:\n"
            + "\n".join(str(path) for path in prepared)
        )
        QMessageBox.information(
            self,
            "3D Dose",
            f"Case 3D dose script saved:\n{out_path}\n\nPrepared {len(prepared)} 3d-dose file(s).",
        )

    def _export_matlab_3d_dose_script(self):
        if not self._workspace and not self._multi_root:
            QMessageBox.information(self, "3D Dose", "Open an Analysis case or select a Case Root first.")
            return
        mode_box = QMessageBox(self)
        mode_box.setWindowTitle("3D Dose")
        mode_box.setText("Choose which MATLAB 3D dose helper to create.")
        btn_browser = mode_box.addButton("Create Dose Browser", QMessageBox.ButtonRole.AcceptRole)
        btn_case = mode_box.addButton("Create Case Script", QMessageBox.ButtonRole.ActionRole)
        btn_cancel = mode_box.addButton(QMessageBox.StandardButton.Cancel)
        mode_box.setDefaultButton(btn_browser)
        mode_box.exec()
        clicked = mode_box.clickedButton()
        if clicked is btn_browser:
            self._create_matlab_3d_dose_browser_script()
            return
        if clicked is btn_case:
            self._create_matlab_3d_dose_case_script()

    def _load_material_densities(self, folder):
        """Load material densities from *folder*, falling back to ancestor
        directories (up to 2 levels up) when the files are not present locally.

        Split-run subfolders typically share the parent's material files so
        this walk makes densities available without requiring file copies.
        """
        self._material_densities = {}
        # Prefer material.dat (numbered by PENELOPE during mat compilation) in
        # folder first, then parent, then grandparent.
        search_dirs = [Path(folder)] + list(Path(folder).parents[:2])
        mat_re = re.compile(
            r"\*+\s*(\d+)(?:st|nd|rd|th)\s+material.*?"
            r"Mass density\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\s*g/cm\*\*3",
            re.IGNORECASE | re.DOTALL,
        )
        for search_dir in search_dirs:
            matdat = search_dir / "material.dat"
            if matdat.exists():
                try:
                    text = _decode_text_bytes(matdat.read_bytes())
                    for m in mat_re.finditer(text):
                        self._material_densities[int(m.group(1))] = float(m.group(2))
                except Exception:
                    pass
            if self._material_densities:
                return
        # Fall back to individual *.mat files — same ancestor walk.
        # material.dat was not found anywhere, so use sorted index assignment.
        for search_dir in search_dirs:
            mats = sorted(search_dir.glob("*.mat"))
            if not mats:
                continue
            for idx, mat in enumerate(mats, start=1):
                try:
                    text = _decode_text_bytes(mat.read_bytes())
                    m = re.search(
                        r"Mass density\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\s*g/cm\*\*3",
                        text, re.IGNORECASE,
                    )
                    if m:
                        self._material_densities[idx] = float(m.group(1))
                except Exception:
                    continue
            if self._material_densities:
                return

    def _load_geo_context(self, folder):
        """Load geometry context from *folder*, falling back to ancestor
        directories (up to 2 levels up) when no .geo file is present locally.

        Split-run subfolders share the parent's geometry file so this walk
        makes body/surface data available without requiring a local copy.
        """
        self._geo_bodies = {}
        self._body_geometry = {}
        self._geo_surfaces = {}
        self._geo_body_defs = {}
        self._result_body_defs = {}
        self._analysis_rep_file = None
        self._body_volumes = {}
        self._body_masses = {}
        geo_file = _analysis_preferred_geo_file(folder)
        if not geo_file:
            return
        self._analysis_rep_file = _analysis_preferred_rep_file(folder, geo_file)
        try:
            text = _decode_text_bytes(geo_file.read_bytes())
            surfaces, bodies = _parse_geo(text)
        except Exception:
            return
        self._geo_surfaces = surfaces
        self._geo_body_defs = {int(body["id"]): body for body in bodies}
        # PENELOPE result files usually number "Body 1..N" by BODY/MODULE order,
        # which can differ from the explicit BODY(n) ids stored in the .geo file.
        self._result_body_defs = {idx: body for idx, body in enumerate(bodies, start=1)}
        self._geo_bodies = {int(body["id"]): body.get("label", "").strip() for body in bodies}
        self._body_geometry = {
            int(body["id"]): self._body_geometry_summary(body, surfaces)
            for body in bodies
        }
        self._body_masses = {}

    def _analysis_body_cache_path(self, folder):
        return Path(folder) / ANALYSIS_BODY_CACHE_FILE

    def _analysis_density_signature(self):
        return {
            str(int(mat_id)): float(density)
            for mat_id, density in sorted((self._material_densities or {}).items())
            if density is not None
        }

    def _analysis_body_cache_payload(self, geo_file, volumes_cm3, masses_kg):
        geo_file = Path(geo_file)
        entries = []
        for result_body_id, body in sorted((self._result_body_defs or {}).items()):
            geo_body_id = int(body.get("id", result_body_id) or result_body_id)
            entries.append({
                "result_body_id": int(result_body_id),
                "geo_body_id": geo_body_id,
                "label": (body.get("label", "") or "").strip(),
                "material_id": int(body.get("material", 0) or 0),
                "volume_cm3": volumes_cm3.get(geo_body_id),
                "mass_kg": masses_kg.get(geo_body_id),
            })
        return {
            "version": ANALYSIS_BODY_CACHE_VERSION,
            "created_at": datetime.now().isoformat(timespec="seconds"),
            "algorithm": "exclusive_body_classifier_sampling_v1",
            "calculation_order": ["volume_cm3", "mass_kg", "edep_eV", "dose"],
            "geo_file": geo_file.name,
            "geo_path": str(geo_file),
            "geo_sha256": _analysis_geo_sha256(geo_file),
            "density_signature": self._analysis_density_signature(),
            "entries": entries,
        }

    def _write_analysis_body_cache(self, folder, payload):
        try:
            self._analysis_body_cache_path(folder).write_text(json.dumps(payload, indent=2), encoding="utf-8")
            return True
        except Exception:
            return False

    def _read_analysis_body_cache(self, folder, geo_file):
        cache_path = self._analysis_body_cache_path(folder)
        if not cache_path.exists():
            return None
        try:
            payload = json.loads(cache_path.read_text(encoding="utf-8"))
        except Exception:
            return None
        if payload.get("version") != ANALYSIS_BODY_CACHE_VERSION:
            return None
        geo_hash = _analysis_geo_sha256(geo_file)
        if not geo_hash or payload.get("geo_sha256") != geo_hash:
            return None
        if not isinstance(payload.get("entries"), list) or not payload["entries"]:
            return None
        return payload

    def _volumes_from_analysis_body_cache(self, payload):
        volumes = {}
        for entry in payload.get("entries", []):
            try:
                geo_body_id = int(entry.get("geo_body_id"))
            except Exception:
                continue
            volumes[geo_body_id] = entry.get("volume_cm3")
        return volumes

    def _masses_from_body_volumes(self, volumes_cm3):
        masses = {}
        for geo_body_id, body in (self._geo_body_defs or {}).items():
            density = self._material_densities.get(int(body.get("material", 0) or 0))
            vol = volumes_cm3.get(int(geo_body_id))
            if density is None or vol in ("", None):
                masses[int(geo_body_id)] = None
            else:
                masses[int(geo_body_id)] = float(vol) * float(density) / 1000.0
        return masses

    def _find_matching_analysis_body_cache(self, folder, geo_file):
        root = self._multi_root or Path(folder).parent
        try:
            candidates = self._analysis_candidate_folders(root, strict=False)
        except Exception:
            candidates = []
        target_hash = _analysis_geo_sha256(geo_file)
        if not target_hash:
            return None, None
        for candidate in candidates:
            candidate = Path(candidate)
            if candidate.resolve() == Path(folder).resolve():
                continue
            payload = self._read_analysis_body_cache(candidate, geo_file)
            if payload and payload.get("geo_sha256") == target_hash:
                return candidate, payload
        return None, None

    def _resolve_analysis_body_cache(self, folder, log=True):
        folder = Path(folder)
        if not self._geo_surfaces or not self._geo_body_defs:
            self._body_volumes = {}
            self._body_masses = {}
            return "No geometry context available."
        geo_file = _analysis_preferred_geo_file(folder)
        if not geo_file:
            self._body_volumes = {}
            self._body_masses = {}
            return "No GEOMFN geometry available."

        payload = self._read_analysis_body_cache(folder, geo_file)
        source = "local cache"
        if payload is None:
            peer_folder, payload = self._find_matching_analysis_body_cache(folder, geo_file)
            if payload is not None:
                source = f"copied cache from {peer_folder.name}"
                self._write_analysis_body_cache(folder, payload)
        if payload is None:
            volumes = self._estimate_all_body_volumes_cm3(list(self._geo_body_defs.values()), self._geo_surfaces)
            self._body_volumes = dict(volumes or {})
            source = "calculated fresh"
        else:
            self._body_volumes = self._volumes_from_analysis_body_cache(payload)
        self._body_masses = self._masses_from_body_volumes(self._body_volumes)
        payload = self._analysis_body_cache_payload(geo_file, self._body_volumes, self._body_masses)
        self._write_analysis_body_cache(folder, payload)
        known_volumes = sum(1 for value in self._body_volumes.values() if value not in ("", None))
        known_masses = sum(1 for value in self._body_masses.values() if value not in ("", None))
        message = (
            f"Body cache: {source}; geo={Path(geo_file).name}; "
            f"volumes={known_volumes}/{len(self._geo_body_defs)}; "
            f"masses={known_masses}/{len(self._geo_body_defs)}."
        )
        rep_file = _analysis_preferred_rep_file(folder, geo_file)
        if rep_file:
            message = message[:-1] + f" rep={Path(rep_file).name}."
        if log:
            self._log_analysis(message, "info")
        return message

    def _geo_body_for_result_id(self, result_body_id):
        result_body_id = int(result_body_id)
        return self._result_body_defs.get(result_body_id) or self._geo_body_defs.get(result_body_id)

    def _geo_body_id_for_result_id(self, result_body_id):
        body = self._geo_body_for_result_id(result_body_id)
        if not body:
            return int(result_body_id)
        return int(body.get("id", result_body_id))

    def _body_geometry_summary(self, body, surfaces):
        axis_planes = {"x": [], "y": [], "z": []}
        shifts = []
        linked = []
        for sid, _side in body.get("surfaces", []):
            surf = surfaces.get(sid)
            if not surf:
                continue
            linked.append(f"S{sid}")
            p = surf.get("params", {})
            ax, ay, az = p.get("AX", 0.0), p.get("AY", 0.0), p.get("AZ", 0.0)
            a0 = p.get("A0", None)
            if a0 is not None:
                nonzero = [abs(ax) > 1e-12, abs(ay) > 1e-12, abs(az) > 1e-12]
                if sum(nonzero) == 1:
                    if nonzero[0]:
                        axis_planes["x"].append(-a0 / ax)
                    elif nonzero[1]:
                        axis_planes["y"].append(-a0 / ay)
                    else:
                        axis_planes["z"].append(-a0 / az)
            shift = (
                p.get("X-SHIFT", 0.0),
                p.get("Y-SHIFT", 0.0),
                p.get("Z-SHIFT", 0.0),
            )
            if any(abs(v) > 1e-12 for v in shift):
                shifts.append(shift)
        parts = []
        centers = []
        for axis, vals in axis_planes.items():
            if len(vals) >= 2:
                lo, hi = min(vals), max(vals)
                parts.append(f"{axis.upper()}[{lo:g}, {hi:g}]")
                centers.append((lo + hi) / 2.0)
        if len(centers) >= 2:
            parts.append("approx center from planes=" + ", ".join(f"{v:g}" for v in centers))
        elif shifts:
            avg = tuple(sum(vals[i] for vals in shifts) / len(shifts) for i in range(3))
            parts.append(f"shift center approx=({avg[0]:g}, {avg[1]:g}, {avg[2]:g})")
        if not parts:
            parts.append("coords not safely inferred")
        if linked:
            parts.append("linked " + ", ".join(linked))
        return "; ".join(parts)

    def _body_geometry_type(self, body, surfaces):
        shape_names = []
        for sid, _side in body.get("surfaces", []):
            surf = surfaces.get(sid)
            if not surf:
                continue
            indices = list(surf.get("indices", []))
            params = surf.get("params", {})
            label = (surf.get("label", "") or "").lower()
            if indices == [1, 1, 1, 0, -1] or "sphere" in label:
                shape_names.append("Sphere")
            elif sorted(indices[:3]) == [0, 1, 1] and any(k.endswith("-SCALE") for k in params):
                shape_names.append("Cylinder")
            elif indices[:3].count(1) >= 2 and -1 in indices[:3]:
                shape_names.append("Cone")
            elif "TORUS" in {k.upper() for k in params} or "torus" in label:
                shape_names.append("Torus")
        if shape_names:
            return "+".join(dict.fromkeys(shape_names))
        bounds = self._body_axis_bounds(body, surfaces)
        if len(bounds) >= 2:
            return "Plane-bounded volume"
        return "Unknown"

    def _body_axis_bounds(self, body, surfaces):
        axis_planes = {"X": [], "Y": [], "Z": []}
        shape_bounds = {"X": [], "Y": [], "Z": []}
        for sid, _side in body.get("surfaces", []):
            surf = surfaces.get(sid)
            if not surf:
                continue
            p = surf.get("params", {})
            coeffs = [("X", p.get("AX", 0.0)), ("Y", p.get("AY", 0.0)), ("Z", p.get("AZ", 0.0))]
            nonzero = [(axis, coeff) for axis, coeff in coeffs if abs(coeff or 0.0) > 1e-12]
            if len(nonzero) == 1 and "A0" in p:
                axis, coeff = nonzero[0]
                axis_planes[axis].append(-p["A0"] / coeff)
            for axis in ("X", "Y", "Z"):
                scale_key = f"{axis}-SCALE"
                shift_key = f"{axis}-SHIFT"
                if scale_key in p:
                    scale = abs(p.get(scale_key, 0.0) or 0.0)
                    shift = p.get(shift_key, 0.0) or 0.0
                    if scale > 0:
                        shape_bounds[axis].append((shift - scale, shift + scale))
        global_markers = _geo_axis_markers(surfaces)
        global_bounds = _geo_axis_bounds(surfaces)
        bounds = {}
        for axis in ("X", "Y", "Z"):
            if len(axis_planes[axis]) >= 2:
                bounds[axis] = (min(axis_planes[axis]), max(axis_planes[axis]))
            elif shape_bounds[axis]:
                lows = [lo for lo, _hi in shape_bounds[axis]]
                highs = [hi for _lo, hi in shape_bounds[axis]]
                bounds[axis] = (min(lows), max(highs))
            elif len(global_markers[axis]) >= 2:
                bounds[axis] = (min(global_markers[axis]), max(global_markers[axis]))
            else:
                gb = global_bounds[axis]
                if gb["low"] is not None and gb["high"] is not None:
                    bounds[axis] = (gb["low"], gb["high"])
                else:
                    return None
            if abs(bounds[axis][1] - bounds[axis][0]) < 1e-12:
                return None
        return bounds

    # ------------------------------------------------------------------ #
    #  Body volume / mass — physically correct exclusive volumes          #
    # ------------------------------------------------------------------ #

    def _sample_counts_for_body(self, bounds, target_samples):
        """Return (counts, lengths, volume_box) for stratified sampling."""
        lengths = np.array(
            [bounds[ax][1] - bounds[ax][0] for ax in ("X", "Y", "Z")], dtype=float
        )
        ratios = lengths / max(float(np.prod(lengths) ** (1.0 / 3.0)), 1e-30)
        base = (target_samples / max(float(np.prod(ratios)), 1e-9)) ** (1.0 / 3.0)
        counts = np.maximum(8, np.minimum(200, np.round(base * ratios).astype(int)))
        return counts, lengths, float(np.prod(lengths))

    def _estimate_all_body_volumes_cm3(self, bodies, surfaces):
        """Compute exclusive volumes (cm³) for every body simultaneously.

        Each body's bounding box is sampled and every sample point is
        classified using the **full** geometry with the same body-ordering
        convention as PENELOPE particle tracking.  A point is counted toward
        body A only if the classifier assigns it specifically to body A —
        meaning it is geometrically inside A *and* not overridden by a
        higher-priority inner body.

        This correctly handles all nesting topologies without any explicit
        body_refs enumeration:

        * Direct inclusion — brain inside skull: skull's samples that fall
          inside brain are classified as brain, never skull.
        * Partial overlap — cerebellum partly extending into skull: only the
          intersection region is subtracted from skull.
        * Transitive nesting — blood vessels → brain → skull: blood-vessel
          samples are classified as blood vessels, not passed up the chain.
        * Any combination of the above.

        Returns ``{body_id: volume_cm³ or None}``.
        """
        target_samples = 500_000 if (_ANALYSIS_GPU_ENABLED and _CUPY_AVAILABLE) else 70_000
        volumes: dict = {}
        for body in (bodies or []):
            body_id = int(body.get("id", 0) or 0)
            if body_id <= 0:
                volumes[body_id] = None
                continue
            bounds = self._body_axis_bounds(body, surfaces)
            if not bounds:
                volumes[body_id] = None
                continue
            counts, lengths, volume_box = self._sample_counts_for_body(bounds, target_samples)
            if np.any(lengths <= 0) or volume_box <= 0:
                volumes[body_id] = None
                continue
            xs = (np.linspace(bounds["X"][0], bounds["X"][1], counts[0], endpoint=False)
                  + lengths[0] / counts[0] / 2.0)
            ys = (np.linspace(bounds["Y"][0], bounds["Y"][1], counts[1], endpoint=False)
                  + lengths[1] / counts[1] / 2.0)
            zs = (np.linspace(bounds["Z"][0], bounds["Z"][1], counts[2], endpoint=False)
                  + lengths[2] / counts[2] / 2.0)
            Xg, Yg, Zg = np.meshgrid(xs, ys, zs, indexing="ij")
            X_flat = Xg.ravel().astype(np.float64, copy=False)
            Y_flat = Yg.ravel().astype(np.float64, copy=False)
            Z_flat = Zg.ravel().astype(np.float64, copy=False)
            # Full-geometry classification — same ordering as PENELOPE tracking.
            # _gpu=_ANALYSIS_GPU_ENABLED routes this through the CuPy path when
            # the analysis GPU checkbox is ticked, independently of the render GPU.
            classified = _classify_flat_vectorized(
                surfaces, bodies, X_flat, Y_flat, Z_flat,
                color_mode="BODY", _gpu=_ANALYSIS_GPU_ENABLED,
            )
            total = len(X_flat)
            inside = int(np.sum(classified == body_id))
            volumes[body_id] = volume_box * inside / total if total > 0 else None
        return volumes

    def _estimate_all_body_masses_kg(self, bodies, surfaces):
        """Compute mass (kg) for every body.  Returns ``{body_id: kg or None}``.

        Uses :meth:`_estimate_all_body_volumes_cm3` so volumes are correct
        exclusive volumes, not raw surface-intersection volumes.
        """
        volumes = self._estimate_all_body_volumes_cm3(bodies, surfaces)
        masses: dict = {}
        for body in (bodies or []):
            body_id = int(body.get("id", 0) or 0)
            density = self._material_densities.get(int(body.get("material", 0) or 0))
            vol = volumes.get(body_id)
            if density is None or vol is None:
                masses[body_id] = None
            else:
                masses[body_id] = vol * density / 1000.0   # g/cm³ × cm³ / 1000 → kg
        return masses

    def _estimate_body_volume_cm3(self, body, surfaces):
        """Single-body volume helper (delegates to the batch function)."""
        body_id = int(body.get("id", 0) or 0)
        bodies = list((getattr(self, "_geo_body_defs", {}) or {}).values()) or [body]
        return self._estimate_all_body_volumes_cm3(bodies, surfaces).get(body_id)

    def _estimate_body_mass_kg(self, body, surfaces):
        """Single-body mass helper (delegates to the batch function)."""
        body_id = int(body.get("id", 0) or 0)
        bodies = list((getattr(self, "_geo_body_defs", {}) or {}).values()) or [body]
        return self._estimate_all_body_masses_kg(bodies, surfaces).get(body_id)

    def _source_position_cm(self):
        if not self._workspace:
            return None
        for in_path in sorted(Path(self._workspace).glob("*.in")):
            try:
                text = _decode_text_bytes(in_path.read_bytes())
            except Exception:
                continue
            match = re.search(r"^\s*SPOSIT\s+([+\-]?\S+)\s+([+\-]?\S+)\s+([+\-]?\S+)", text, re.IGNORECASE | re.MULTILINE)
            if not match:
                continue
            vals = [self._parse_penelope_number(match.group(i)) for i in range(1, 4)]
            if all(v is not None for v in vals):
                return tuple(float(v) for v in vals)
        return None

    def _source_origin_distance_m(self):
        id_meta = self._workspace_id_metadata()
        if id_meta.get("pd_m") is not None:
            return id_meta["pd_m"]
        pos = self._source_position_cm()
        if not pos:
            return ""
        # Report the horizontal source-to-wall/origin distance. The source and
        # target are compared along the beam plane at the same Z height, so a
        # high source Z does not artificially increase this distance.
        x, y, _z = (float(v) for v in pos)
        return math.sqrt(x ** 2 + y ** 2) / 100.0

    def _source_body_distance_m(self, geo_body_id):
        id_meta = self._workspace_id_metadata()
        if id_meta.get("source_body_m") is not None:
            return id_meta["source_body_m"]
        pos = self._source_position_cm()
        body = self._geo_body_defs.get(int(geo_body_id)) if geo_body_id not in ("", None) else None
        if not pos or not body:
            return ""
        bounds = self._body_axis_bounds(body, self._geo_surfaces)
        if not bounds:
            return ""
        deltas = []
        # Same-Z straight-line distance: use X/Y only, not vertical offset.
        for axis, value in zip(("X", "Y"), pos[:2]):
            lo, hi = bounds.get(axis, (None, None))
            if lo is None or hi is None:
                return ""
            if value < lo:
                deltas.append(lo - value)
            elif value > hi:
                deltas.append(value - hi)
            else:
                deltas.append(0.0)
        return math.sqrt(sum(delta ** 2 for delta in deltas)) / 100.0

    def _workspace_id_metadata(self, name=None):
        if name is None:
            name = self._workspace.name if self._workspace else ""
        name = str(name or "")

        def parse_cm_token(prefix):
            match = re.search(
                rf"(?:^|[_\-\s]){re.escape(prefix)}([+\-]?\d+(?:[.,_p]\d+)?)(?:cm)?(?=$|[_\-\s])",
                name,
                re.IGNORECASE,
            )
            if not match:
                return None
            raw = match.group(1).replace(",", ".").replace("_", ".").replace("p", ".").replace("P", ".")
            try:
                return float(raw)
            except ValueError:
                return None

        pd_cm = parse_cm_token("pd")
        bd_cm = parse_cm_token("bd")
        wt_cm = parse_cm_token("wt")
        source_body_m = None
        if pd_cm is not None and bd_cm is not None:
            source_body_m = (pd_cm + bd_cm) / 100.0
        return {
            "pd_cm": pd_cm,
            "bd_cm": bd_cm,
            "wt_cm": wt_cm,
            "pd_m": None if pd_cm is None else pd_cm / 100.0,
            "bd_m": None if bd_cm is None else bd_cm / 100.0,
            "source_body_m": source_body_m,
        }

    def _case_metadata(self):
        name = self._workspace.name if self._workspace else ""
        dist = ""
        thick = ""
        id_meta = self._workspace_id_metadata(name)
        if id_meta.get("pd_m") is not None:
            dist = id_meta["pd_m"]
        if id_meta.get("wt_cm") is not None:
            thick = id_meta["wt_cm"]
        if dist != "" or thick != "":
            return name, dist, thick
        md = re.search(r"(?<![A-Za-z])(\d+(?:\.\d+)?)m(?![A-Za-z])", name, re.IGNORECASE)
        mt = re.search(r"(?<![A-Za-z])(\d+(?:\.\d+)?)cm(?![A-Za-z])", name, re.IGNORECASE)
        if md:
            dist = float(md.group(1))
        if mt:
            thick = float(mt.group(1))
        return name, dist, thick

    def _dose_body_column_index(self):
        return self.DOSE_HEADERS.index("Body")

    def _body_center_cm(self, geo_body_id):
        try:
            geo_body_id = int(geo_body_id)
        except (TypeError, ValueError):
            return None
        body = self._geo_body_defs.get(geo_body_id)
        if not body:
            return None
        bounds = self._body_axis_bounds(body, self._geo_surfaces)
        if not bounds:
            return None
        try:
            return tuple((float(bounds[axis][0]) + float(bounds[axis][1])) / 2.0 for axis in ("X", "Y", "Z"))
        except Exception:
            return None

    def _available_dose_target_bodies(self):
        choices = []
        for geo_body_id, body in sorted((self._geo_body_defs or {}).items()):
            label = str(body.get("label") or f"BODY({geo_body_id})").strip()
            center = self._body_center_cm(geo_body_id)
            center_text = "center unavailable"
            if center is not None:
                center_text = f"center=({center[0]:.2f}, {center[1]:.2f}, {center[2]:.2f}) cm"
            choices.append({
                "id": int(geo_body_id),
                "label": label,
                "display": f"Body {int(geo_body_id)}: {label}  [{center_text}]",
            })
        return choices

    def _read_dose_workbook_config(self, wb):
        if self.DOSE_CONFIG_SHEET not in wb.sheetnames:
            return None
        ws = wb[self.DOSE_CONFIG_SHEET]
        config = {}
        for row in range(1, ws.max_row + 1):
            key = str(ws.cell(row, 1).value or "").strip()
            if not key:
                continue
            config[key] = ws.cell(row, 2).value
        if not config:
            return None
        try:
            body_id = int(config.get("target_body_id"))
        except (TypeError, ValueError):
            return None
        mode = str(config.get("distance_mode") or "direct").strip().lower()
        if mode not in ("direct", "linear"):
            mode = "direct"
        axis = str(config.get("linear_axis") or "Z").strip().upper()
        if axis not in ("X", "Y", "Z"):
            axis = "Z"
        return {
            "target_body_id": body_id,
            "target_body_label": str(config.get("target_body_label") or f"BODY({body_id})"),
            "distance_mode": mode,
            "linear_axis": axis,
        }

    def _write_dose_workbook_config(self, wb, config):
        ws = wb[self.DOSE_CONFIG_SHEET] if self.DOSE_CONFIG_SHEET in wb.sheetnames else wb.create_sheet(self.DOSE_CONFIG_SHEET)
        ws.delete_rows(1, ws.max_row or 1)
        rows = [
            ("version", "1"),
            ("target_body_id", int(config["target_body_id"])),
            ("target_body_label", str(config.get("target_body_label") or "")),
            ("distance_mode", str(config.get("distance_mode") or "direct")),
            ("linear_axis", str(config.get("linear_axis") or "Z")),
        ]
        for idx, (key, value) in enumerate(rows, start=1):
            ws.cell(idx, 1).value = key
            ws.cell(idx, 2).value = value
        ws.sheet_state = "hidden"

    def _dose_workbook_config_summary(self, config=None):
        config = config or self._dose_workbook_config or {}
        if not config:
            return ""
        label = str(config.get("target_body_label") or f"BODY({config.get('target_body_id', '?')})")
        mode = str(config.get("distance_mode") or "direct")
        if mode == "linear":
            return f"target={label}; R=linear {config.get('linear_axis', 'Z')}"
        return f"target={label}; R=direct"

    def _update_dose_xlsx_label(self, state_text):
        if not self._dose_xlsx:
            self.lbl_dose_xlsx.setText("Dose workbook: none selected")
            self.lbl_dose_xlsx.setToolTip("")
            return
        display_path = str(self._dose_xlsx)
        if self._project_root:
            try:
                root = Path(self._project_root).resolve()
                rel = str(Path(self._dose_xlsx).resolve().relative_to(root)).replace("/", "\\")
                display_path = f"{root.name}\\{rel}" if rel else root.name
            except Exception:
                display_path = str(self._dose_xlsx)
        summary = self._dose_workbook_config_summary()
        if summary:
            self.lbl_dose_xlsx.setText(f"Dose workbook: {display_path} ({state_text}; {summary})")
        else:
            self.lbl_dose_xlsx.setText(f"Dose workbook: {display_path} ({state_text})")
        self.lbl_dose_xlsx.setToolTip(str(self._dose_xlsx))

    def _prompt_dose_workbook_config(self, existing=None):
        if not self._workspace or not self._geo_body_defs:
            QMessageBox.warning(
                self,
                "Dose workbook target",
                "Load an analysis case first so the workbook can be configured with a target body and R mode.",
            )
            return None
        bodies = self._available_dose_target_bodies()
        if not bodies:
            QMessageBox.warning(self, "Dose workbook target", "No BODY definitions are available in the current geometry.")
            return None
        existing = dict(existing or {})
        sposit = self._source_position_cm()

        dlg = QDialog(self)
        dlg.setWindowTitle("Dose Workbook Target")
        dlg.setModal(True)
        dlg.setMinimumWidth(680)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        intro = QLabel(
            "Choose the target BODY used to calculate the workbook distance column `R (m)`.\n"
            "Direct distance uses the BODY center and SPOSIT. Linear distance uses one chosen axis only."
        )
        intro.setWordWrap(True)
        intro.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(intro)

        form = QFormLayout()
        cmb_body = QComboBox()
        cmb_body.setStyleSheet(combo_dropdown_css())
        for body_info in bodies:
            cmb_body.addItem(body_info["display"], body_info)
        form.addRow("Target BODY:", cmb_body)

        cmb_mode = QComboBox()
        cmb_mode.setStyleSheet(combo_css())
        cmb_mode.addItem("Direct distance (SPOSIT to BODY center)", "direct")
        cmb_mode.addItem("Linear distance (axis-aligned)", "linear")
        form.addRow("Distance mode:", cmb_mode)

        cmb_axis = QComboBox()
        cmb_axis.setStyleSheet(combo_css())
        cmb_axis.addItems(["X", "Y", "Z"])
        form.addRow("Linear axis:", cmb_axis)
        lay.addLayout(form)

        lbl_preview = QLabel("")
        lbl_preview.setWordWrap(True)
        lbl_preview.setStyleSheet(label_css(P["fg2"], size=9))
        lay.addWidget(lbl_preview)

        def refresh_preview():
            body_info = cmb_body.currentData() or {}
            body_id = body_info.get("id")
            center = self._body_center_cm(body_id)
            mode = str(cmb_mode.currentData() or "direct")
            axis = cmb_axis.currentText().strip().upper() or "Z"
            cmb_axis.setEnabled(mode == "linear")
            if not sposit or center is None:
                preview = f"SPOSIT: {sposit or 'unavailable'}\nBODY center: {center or 'unavailable'}\nR preview: unavailable"
            else:
                if mode == "linear":
                    axis_idx = {"X": 0, "Y": 1, "Z": 2}[axis]
                    value = abs(float(center[axis_idx]) - float(sposit[axis_idx])) / 100.0
                    preview = (
                        f"SPOSIT: ({sposit[0]:.2f}, {sposit[1]:.2f}, {sposit[2]:.2f}) cm\n"
                        f"BODY center: ({center[0]:.2f}, {center[1]:.2f}, {center[2]:.2f}) cm\n"
                        f"R ({axis}-axis): {value:.6f} m"
                    )
                else:
                    value = math.sqrt(sum((float(center[i]) - float(sposit[i])) ** 2 for i in range(3))) / 100.0
                    preview = (
                        f"SPOSIT: ({sposit[0]:.2f}, {sposit[1]:.2f}, {sposit[2]:.2f}) cm\n"
                        f"BODY center: ({center[0]:.2f}, {center[1]:.2f}, {center[2]:.2f}) cm\n"
                        f"R (direct): {value:.6f} m"
                    )
            lbl_preview.setText(preview)

        default_body_id = existing.get("target_body_id")
        if default_body_id is not None:
            for i in range(cmb_body.count()):
                data = cmb_body.itemData(i) or {}
                if data.get("id") == default_body_id:
                    cmb_body.setCurrentIndex(i)
                    break
        default_mode = str(existing.get("distance_mode") or "direct")
        cmb_mode.setCurrentIndex(1 if default_mode == "linear" else 0)
        default_axis = str(existing.get("linear_axis") or "Z").upper()
        axis_idx = cmb_axis.findText(default_axis)
        if axis_idx >= 0:
            cmb_axis.setCurrentIndex(axis_idx)

        cmb_body.currentIndexChanged.connect(lambda _i: refresh_preview())
        cmb_mode.currentIndexChanged.connect(lambda _i: refresh_preview())
        cmb_axis.currentIndexChanged.connect(lambda _i: refresh_preview())
        refresh_preview()

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        lay.addWidget(buttons)
        if not dlg.exec():
            return None
        body_info = cmb_body.currentData() or {}
        return {
            "target_body_id": int(body_info["id"]),
            "target_body_label": str(body_info["label"]),
            "distance_mode": str(cmb_mode.currentData() or "direct"),
            "linear_axis": str(cmb_axis.currentText().strip().upper() or "Z"),
        }

    def _distance_r_m(self, config):
        config = config or self._dose_workbook_config or {}
        if not config:
            return ""
        sposit = self._source_position_cm()
        center = self._body_center_cm(config.get("target_body_id"))
        if not sposit or center is None:
            return ""
        mode = str(config.get("distance_mode") or "direct").lower()
        if mode == "linear":
            axis = str(config.get("linear_axis") or "Z").upper()
            axis_idx = {"X": 0, "Y": 1, "Z": 2}.get(axis, 2)
            return abs(float(center[axis_idx]) - float(sposit[axis_idx])) / 100.0
        return math.sqrt(sum((float(center[i]) - float(sposit[i])) ** 2 for i in range(3))) / 100.0

    def _load_openpyxl(self):
        try:
            import openpyxl
        except Exception as exc:
            QMessageBox.warning(self, "Missing openpyxl", f"Could not import openpyxl:\n{exc}")
            return None
        return openpyxl

    def _ensure_dose_workbook(self, path_override=None):
        openpyxl = self._load_openpyxl()
        if openpyxl is None:
            self._log_analysis("Could not load openpyxl. Install it to export dose rows.", "err")
            return None, None
        path = Path(path_override) if path_override is not None else self._dose_xlsx
        if path is None:
            path = (self._workspace or Path.cwd()) / "dose_analysis.xlsx"
            self._dose_xlsx = path
            self._dose_xlsx_user_selected = False
            self._dose_workbook_config = None
            self._update_dose_xlsx_label("will be created on append")
            self._log_analysis(f"Dose workbook not set; defaulting to: {path}", "info")
        else:
            self._dose_xlsx = path
        if path.exists():
            wb = openpyxl.load_workbook(path)
            ws = wb.active
            self._log_analysis(f"Opened workbook: {path}", "info")
        else:
            wb = openpyxl.Workbook()
            ws = wb.active
            ws.title = "Dose"
            self._log_analysis(f"Creating workbook: {path}", "info")
        changed = self._normalize_dose_sheet_headers(ws)
        if changed:
            self._log_analysis("Dose workbook headers were inserted/updated.", "warn")
        self._dose_workbook_config = self._read_dose_workbook_config(wb)
        self._update_dose_xlsx_label("existing" if path.exists() else "will be created on append")
        return wb, ws

    def _normalize_dose_sheet_headers(self, ws):
        old_headers = [
            str(ws.cell(1, col).value or "").strip()
            for col in range(1, max(ws.max_column, len(self.DOSE_HEADERS)) + 1)
        ]
        if old_headers[:len(self.DOSE_HEADERS)] == self.DOSE_HEADERS:
            return False
        old_map = {header: idx + 1 for idx, header in enumerate(old_headers) if header}
        old_rows = []
        for row_idx in range(2, ws.max_row + 1):
            row = []
            for header in self.DOSE_HEADERS:
                old_col = old_map.get(header)
                row.append(ws.cell(row_idx, old_col).value if old_col else "")
            old_rows.append(row)
        if ws.max_row:
            ws.delete_rows(1, ws.max_row)
        for col, header in enumerate(self.DOSE_HEADERS, start=1):
            ws.cell(1, col).value = header
        for row in old_rows:
            ws.append(row)
        return True

    def _set_dose_column_widths(self, ws):
        try:
            from openpyxl.utils import get_column_letter
        except Exception:
            return
        for col in range(1, len(self.DOSE_HEADERS) + 1):
            ws.column_dimensions[get_column_letter(col)].width = max(12, len(self.DOSE_HEADERS[col - 1]) + 2)

    def _dose_header_map(self, ws):
        return {
            str(ws.cell(1, c).value).strip(): c
            for c in range(1, ws.max_column + 1)
            if ws.cell(1, c).value not in (None, "")
        }

    def _apply_dose_number_formats(self, ws):
        headers = self._dose_header_map(ws)
        scientific_headers = (
            "Edep (eV)",
            "dE (eV)",
            "Edep (J)",
            "dE (J)",
            "Mass (kg)",
            "Dose (Gy)",
            "dDose (Gy)",
            "Dose (eV/g)",
            "dDose (eV/g)",
            "NSIMSH @5%",
            "Time @5% (s)",
        )
        for header in scientific_headers:
            col = headers.get(header)
            if not col:
                continue
            for row in range(2, ws.max_row + 1):
                cell = ws.cell(row, col)
                if cell.value in ("", None):
                    continue
                if isinstance(cell.value, str):
                    try:
                        cell.value = float(cell.value.replace("D", "E").replace("d", "e"))
                    except ValueError:
                        continue
                cell.number_format = "0.000000E+00"

    def _apply_dose_quality_and_formatting(self, ws):
        try:
            from openpyxl.formatting.rule import FormulaRule
            from openpyxl.styles import PatternFill
            from openpyxl.utils import get_column_letter
        except Exception:
            return
        headers = self._dose_header_map(ws)
        self._apply_dose_number_formats(ws)
        err_col = headers.get("Error (%)")
        qual_col = headers.get("Quality")
        if not err_col or not qual_col:
            return
        max_row = max(ws.max_row, 1)
        err_letter = get_column_letter(err_col)
        last_col_letter = get_column_letter(len(self.DOSE_HEADERS))

        for row in range(2, max_row + 1):
            err_ref = f"{err_letter}{row}"
            ws.cell(row, qual_col).value = (
                f'=IF({err_ref}="","",IF({err_ref}>50,"Unreliable",IF({err_ref}>30,"Uncertain","Accepted")))'
            )

        data_range = f"A2:{last_col_letter}{max(max_row, 2)}"
        try:
            ws.conditional_formatting._cf_rules.clear()
        except Exception:
            pass
        red = PatternFill(fill_type="solid", fgColor="FDECEC")
        yellow = PatternFill(fill_type="solid", fgColor="FFF6DB")
        green = PatternFill(fill_type="solid", fgColor="EAF7EA")
        ws.conditional_formatting.add(
            data_range,
            FormulaRule(formula=[f"AND(ISNUMBER(${err_letter}2),${err_letter}2>50)"], fill=red, stopIfTrue=True),
        )
        ws.conditional_formatting.add(
            data_range,
            FormulaRule(formula=[f"AND(ISNUMBER(${err_letter}2),${err_letter}2>30,${err_letter}2<=50)"], fill=yellow, stopIfTrue=True),
        )
        ws.conditional_formatting.add(
            data_range,
            FormulaRule(formula=[f"AND(ISNUMBER(${err_letter}2),${err_letter}2<=30)"], fill=green, stopIfTrue=True),
        )

        ws.auto_filter.ref = f"A1:{last_col_letter}{max_row}"
        ws.freeze_panes = "A2"

    def _dose_rows_for_current_results(self):
        case = self._workspace.name if self._workspace else ""
        total_edep = 0.0
        total_dedep_sq = 0.0
        total_mass = 0.0
        missing_mass = False
        rows = []
        for result in self._body_results:
            total_edep += result["edep"]
            total_dedep_sq += result["dedep"] ** 2
            mass = result.get("mass", "")
            if mass in ("", None):
                missing_mass = True
            else:
                total_mass += float(mass)
            error_ref = result.get("error", "")
            edep_ref = result.get("edep", 0.0)
            n_ref, t_ref = self._reference_display_values()
            target_err, n_target, t_target = self._prediction_values(error_ref, edep_ref)
            edep_j = result["edep"] * self.EV_TO_J
            dedep_j = result["dedep"] * self.EV_TO_J
            rows.append([
                case,
                f"Body {result['body_id']}",
                result.get("component", ""),
                result["edep"],
                result["dedep"],
                mass,
                result.get("dose_ev_g", ""),
                result.get("ddose_ev_g", ""),
                edep_j,
                dedep_j,
                result["error"],
                result.get("dose", ""),
                result.get("ddose", ""),
                n_ref,
                t_ref,
                target_err,
                n_target,
                t_target,
                "",
                result.get("geometry_type", ""),
            ])
        total_dedep = total_dedep_sq ** 0.5
        total_error = abs(total_dedep / total_edep * 100.0) if total_edep else ""
        total_dose, total_ddose = ("", "")
        total_dose_ev_g, total_ddose_ev_g = ("", "")
        total_mass_value = ""
        if not missing_mass and total_mass > 0:
            total_mass_value = total_mass
            total_dose, total_ddose = self._dose_values(total_edep, total_dedep, total_mass)
            total_dose_ev_g, total_ddose_ev_g = self._dose_values_ev_per_g(total_edep, total_dedep, total_mass)
        n_ref_total, t_ref_total = self._reference_display_values()
        target_err, n_target_total, t_target_total = self._prediction_values(total_error, total_edep)
        total_edep_j = total_edep * self.EV_TO_J
        total_dedep_j = total_dedep * self.EV_TO_J
        rows.append([
            case,
            "TOTAL",
            "",
            total_edep,
            total_dedep,
            total_mass_value,
            total_dose_ev_g,
            total_ddose_ev_g,
            total_edep_j,
            total_dedep_j,
            total_error,
            total_dose,
            total_ddose,
            n_ref_total,
            t_ref_total,
            target_err,
            n_target_total,
            t_target_total,
            "",
            "Total",
        ])
        return case, rows

    def _remove_case_rows(self, ws, case):
        case = str(case)
        removed = 0
        row = ws.max_row
        while row >= 2:
            if str(ws.cell(row, 1).value or "") == case:
                ws.delete_rows(row, 1)
                removed += 1
            row -= 1
        return removed

    def _remove_total_rows_from_sheet(self, ws):
        removed = 0
        body_col = self._dose_body_column_index() + 1
        row = ws.max_row
        while row >= 2:
            if str(ws.cell(row, body_col).value or "").upper() == "TOTAL":
                ws.delete_rows(row, 1)
                removed += 1
            row -= 1
        return removed

    def _safe_filename_stem(self, value):
        stem = re.sub(r"[^A-Za-z0-9._-]+", "_", str(value or "Dose")).strip("._-")
        return stem or "Dose"

    def _multi_append_workbook_path(self, root):
        root = Path(root)
        root_name = self._safe_filename_stem(root.name or "root")
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        return root / f"{root_name}_{stamp}_Dose.xlsx"

    def _archive_previous_multi_appends(self, root, new_path):
        root = Path(root)
        old_dir = root / "old appends"
        moved = 0
        for path in root.glob("*_Dose.xlsx"):
            if path.resolve() == Path(new_path).resolve():
                continue
            if not path.is_file():
                continue
            try:
                old_dir.mkdir(parents=True, exist_ok=True)
                target = old_dir / path.name
                if target.exists():
                    target = old_dir / f"{path.stem}_{datetime.now().strftime('%Y%m%d_%H%M%S')}{path.suffix}"
                shutil.move(str(path), str(target))
                moved += 1
            except Exception as exc:
                self._log_analysis(f"Could not archive previous multi append file {path}: {exc}", "warn")
        return moved

    def _append_rows_to_sheet(self, ws, rows):
        for row in rows:
            ws.append(row)

    def _body_rows_only(self, rows):
        idx = self._dose_body_column_index()
        return [row for row in rows if not (len(row) > idx and str(row[idx]).upper() == "TOTAL")]

    def _total_rows_only(self, rows):
        idx = self._dose_body_column_index()
        return [row for row in rows if len(row) > idx and str(row[idx]).upper() == "TOTAL"]

    def _sync_totals_sheet(self, wb, rows):
        ws = wb["TOTALS"] if "TOTALS" in wb.sheetnames else wb.create_sheet("TOTALS")
        self._normalize_dose_sheet_headers(ws)
        total_rows = self._total_rows_only(rows)
        for row in total_rows:
            case = str(row[0])
            self._remove_case_rows(ws, case)
            ws.append(row)
        self._set_dose_column_widths(ws)
        self._apply_dose_quality_and_formatting(ws)

    def _safe_sheet_title(self, title, existing=()):
        base = re.sub(r"[:\\/?*\[\]]+", "_", str(title or "Group")).strip(" '")
        base = base[:31] or "Group"
        taken = {str(name).lower() for name in existing}
        if base.lower() not in taken:
            return base
        stem = base[:27]
        idx = 2
        while True:
            candidate = f"{stem}_{idx}"[:31]
            if candidate.lower() not in taken:
                return candidate
            idx += 1

    def _ensure_dose_sheet(self, wb, title):
        sheet_title = re.sub(r"[:\\/?*\[\]]+", "_", str(title or "Group")).strip(" '")[:31] or "Group"
        if sheet_title in wb.sheetnames:
            ws = wb[sheet_title]
        else:
            ws = wb.create_sheet(self._safe_sheet_title(sheet_title, wb.sheetnames))
        self._normalize_dose_sheet_headers(ws)
        return ws

    def _multi_append_options_dialog(self, workspaces):
        dlg = QDialog(self)
        dlg.setWindowTitle("Multi Append Options")
        dlg.setModal(True)
        dlg.setMinimumWidth(720)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        hint = QLabel(
            f"Detected {len(workspaces)} case(s). Normal append writes all body rows to the main sheet and all total rows to TOTALS. "
            "Group rows create extra sheets when all keywords match a case folder name."
        )
        hint.setWordWrap(True)
        hint.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(hint)
        normal_chk = QCheckBox("Normal append to main sheet")
        normal_chk.setChecked(True)
        normal_chk.setStyleSheet(checkbox_css())
        lay.addWidget(normal_chk)
        splits_chk = QCheckBox("Include individual split runs (folders with split_run_manifest.json)")
        splits_chk.setChecked(False)
        splits_chk.setToolTip(
            "When unchecked, individual split-run folders are skipped — only regular cases and "
            "manually-combined grouped results are appended. Check this to include every split run as its own row."
        )
        splits_chk.setStyleSheet(checkbox_css())
        lay.addWidget(splits_chk)
        group_chk = QCheckBox("Also create grouped sheets by keywords")
        group_chk.setStyleSheet(checkbox_css())
        lay.addWidget(group_chk)
        grid = QGridLayout()
        grid.setHorizontalSpacing(6)
        grid.setVerticalSpacing(5)
        for col, label in enumerate(("Active", "Keyword 1", "Keyword 2", "Keyword 3", "Sheet name")):
            head = QLabel(label)
            head.setStyleSheet(label_css(P["fg2"], bold=True))
            grid.addWidget(head, 0, col)
        rows = []
        presets = [("x_ray", "2m", ""), ("LINAC", "1m", ""), ("LINAC", "2m", ""), ("", "", ""), ("", "", ""), ("", "", "")]
        for row_idx, preset in enumerate(presets, start=1):
            active = QCheckBox()
            active.setChecked(any(str(value).strip() for value in preset))
            active.setStyleSheet(checkbox_css())
            edits = []
            grid.addWidget(active, row_idx, 0)
            for col, value in enumerate(preset, start=1):
                edit = QLineEdit(value)
                edit.setStyleSheet(entry_css())
                edit.setFixedWidth(110)
                edits.append(edit)
                grid.addWidget(edit, row_idx, col)
            sheet = QLineEdit("")
            sheet.setPlaceholderText("auto")
            sheet.setStyleSheet(entry_css())
            grid.addWidget(sheet, row_idx, 4)

            def mark_active(_text, chk=active):
                if str(_text).strip():
                    chk.setChecked(True)

            for edit in edits:
                edit.textChanged.connect(mark_active)
            rows.append((active, edits, sheet))
        lay.addLayout(grid)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.setStyleSheet(btn_css(P["bg2"]))
        buttons.accepted.connect(dlg.accept)
        buttons.rejected.connect(dlg.reject)
        lay.addWidget(buttons)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        specs = []
        if group_chk.isChecked():
            seen = set()
            for active, edits, sheet in rows:
                keywords = [e.text().strip() for e in edits if e.text().strip()]
                if not keywords:
                    continue
                if active.isChecked():
                    key = tuple(k.lower() for k in keywords)
                    if key in seen:
                        continue
                    seen.add(key)
                    title = sheet.text().strip() or "_".join(keywords)
                    specs.append({"keywords": keywords, "sheet": title})
        return normal_chk.isChecked(), splits_chk.isChecked(), specs

    def _mass_lookup_from_workbook(self):
        if not self._dose_xlsx or not self._dose_xlsx.exists():
            return {}, {}
        openpyxl = self._load_openpyxl()
        if openpyxl is None:
            return {}, {}
        try:
            wb = openpyxl.load_workbook(self._dose_xlsx, data_only=True)
        except Exception:
            return {}, {}
        ws = wb.active
        headers = {str(ws.cell(1, c).value).strip(): c for c in range(1, ws.max_column + 1) if ws.cell(1, c).value}
        body_col = headers.get("Body")
        comp_col = headers.get("Component")
        mass_col = headers.get("Mass (kg)")
        by_body, by_comp = {}, {}
        if not mass_col:
            return by_body, by_comp
        for row in range(2, ws.max_row + 1):
            mass = ws.cell(row, mass_col).value
            try:
                mass = float(mass)
            except (TypeError, ValueError):
                continue
            if body_col:
                body = ws.cell(row, body_col).value
                if body not in (None, ""):
                    by_body[str(body).strip()] = mass
            if comp_col:
                comp = ws.cell(row, comp_col).value
                if comp not in (None, ""):
                    by_comp[str(comp).strip().lower()] = mass
        return by_body, by_comp

    def _dose_values(self, edep_ev, dedep_ev, mass):
        try:
            mass = float(mass)
        except (TypeError, ValueError):
            return "", ""
        if mass <= 0:
            return "", ""
        return edep_ev * self.EV_TO_J / mass, dedep_ev * self.EV_TO_J / mass

    def _dose_values_ev_per_g(self, edep_ev, dedep_ev, mass):
        try:
            mass = float(mass)
        except (TypeError, ValueError):
            return "", ""
        if mass <= 0:
            return "", ""
        grams = mass * 1000.0
        if grams <= 0:
            return "", ""
        return float(edep_ev) / grams, float(dedep_ev) / grams

    def _toggle_analysis_gpu(self, _state):
        global _ANALYSIS_GPU_ENABLED
        _ANALYSIS_GPU_ENABLED = self.chk_gpu_mass.isChecked()
        QSettings("CodAI", "PenelopeStudio").setValue("analysis/gpu_enabled", _ANALYSIS_GPU_ENABLED)

    def _on_target_error_changed(self, _text):
        try:
            value = float((self.e_target_error.text() or "").strip())
        except (TypeError, ValueError):
            return
        if value <= 0:
            return
        self._target_err_pct = value
        if self._body_results:
            self._render_body_results_table()

    def _target_error_value(self):
        try:
            value = float((getattr(self, "e_target_error", None).text() or "").strip())
        except Exception:
            value = self._target_err_pct
        if value <= 0:
            value = self.TARGET_ERR_PCT
        self._target_err_pct = value
        return value

    def _parse_penelope_number(self, value):
        try:
            return float(str(value).replace("D", "E").replace("d", "e"))
        except (TypeError, ValueError):
            return None

    def _matching_in_token(self, keyword, result_value, fallback):
        if not self._workspace:
            return fallback or ""
        for in_path in sorted(Path(self._workspace).glob("*.in")):
            try:
                text = _decode_text_bytes(in_path.read_bytes())
            except Exception:
                continue
            match = re.search(rf"^\s*{re.escape(keyword)}\s+(\S+)", text, re.IGNORECASE | re.MULTILINE)
            if not match:
                continue
            token = match.group(1).strip()
            token_value = self._parse_penelope_number(token)
            if token_value is None or result_value in (None, ""):
                return token
            try:
                ref = float(result_value)
            except (TypeError, ValueError):
                return token
            if abs(token_value - ref) <= max(1.0, abs(ref)) * 1e-6:
                return token
        return fallback or ""

    def _reference_display_values(self):
        return (
            self._sim_showers_text or (f"{self._sim_showers:g}" if self._sim_showers else ""),
            self._sim_time_text or (f"{self._sim_time_sec:g}" if self._sim_time_sec else ""),
        )

    def _prediction_values(self, error_ref, edep_ref):
        target_err = self._target_error_value()
        n_target = ""
        t_target = ""
        if (
            error_ref not in ("", None)
            and self._sim_showers not in ("", None)
            and self._sim_time_sec not in ("", None)
            and self._sim_showers
            and self._sim_time_sec
            and abs(float(edep_ref or 0.0)) > 1e-20
        ):
            scale = (float(error_ref) / target_err) ** 2
            n_target = float(self._sim_showers) * scale
            t_target = float(self._sim_time_sec) * scale
        return target_err, n_target, t_target

    def _refresh_dose_columns(self):
        for result in self._body_results:
            mass = self._body_masses.get(int(result.get("geo_body_id", result["body_id"])))
            if mass is None:
                mass = ""
            result["mass"] = mass
            dose, ddose = self._dose_values(result["edep"], result["dedep"], mass)
            dose_ev_g, ddose_ev_g = self._dose_values_ev_per_g(result["edep"], result["dedep"], mass)
            result["dose"] = dose
            result["ddose"] = ddose
            result["dose_ev_g"] = dose_ev_g
            result["ddose_ev_g"] = ddose_ev_g
        self._render_body_results_table()

    def _parse_penmain_results(self, path):
        self.summary.clear()
        self.tbl_bodies.setRowCount(0)
        self._body_results = []
        self._sim_time_sec = None
        self._sim_showers = None
        self._sim_time_text = ""
        self._sim_showers_text = ""
        if hasattr(self, "lbl_reference_values"):
            self.lbl_reference_values.setText("N ref: -    Time ref: -")
        if not path.exists():
            self.summary.setPlainText("No penmain-res.dat found in this case.")
            return
        text = _decode_text_bytes(path.read_bytes())
        src_info = self._extract_source_info_from_in(path.parent)
        summary_bits = _analysis_summary_lines(text, src_info)
        health = _penmain_result_health(path.parent)
        if health.get("incomplete"):
            summary_bits.insert(0, f"Incomplete run: {health.get('reason')}")
            self._log_analysis(f"Incomplete penmain-res detected in {path.parent.name}: {health.get('reason')}", "warn")
        mt = re.search(r"Simulation time\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)\s*sec", text, re.IGNORECASE)
        ms = re.search(r"Simulated primary showers\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)", text, re.IGNORECASE)
        if mt:
            try:
                self._sim_time_sec = float(mt.group(1))
                self._sim_time_text = mt.group(1)
            except ValueError:
                self._sim_time_sec = None
        if ms:
            try:
                self._sim_showers = float(ms.group(1))
                self._sim_showers_text = ms.group(1)
            except ValueError:
                self._sim_showers = None
        self._sim_showers_text = self._matching_in_token("NSIMSH", self._sim_showers, self._sim_showers_text)
        self._sim_time_text = self._matching_in_token("TIME", self._sim_time_sec, self._sim_time_text)
        if hasattr(self, "lbl_reference_values"):
            n_txt, t_txt = self._reference_display_values()
            self.lbl_reference_values.setText(f"N ref: {n_txt or '-'}    Time ref: {t_txt or '-'}")
        self._current_source_col = src_info.get("source_col", "")
        self._resolve_analysis_body_cache(path.parent, log=True)
        self.summary.setPlainText("\n".join(summary_bits) or path.name)

        body_re = re.compile(
            r"^\s*Body\s+(\d+)\s+\.+\s+([+\-]?\d+\.\d+E[+\-]\d+)\s+\+-\s+([+\-]?\d+\.\d+E[+\-]\d+)\s+eV\s+\(effic\.\s*=\s*([+\-]?\d+\.\d+E[+\-]\d+)\)",
            re.IGNORECASE | re.MULTILINE,
        )
        for match in body_re.finditer(text):
            body_id = int(match.group(1))
            geo_body = self._geo_body_for_result_id(body_id)
            geo_body_id = int(geo_body["id"]) if geo_body else body_id
            label = (geo_body.get("label", "").strip() if geo_body else "") or f"Body {body_id}"
            energy = float(match.group(2))
            stu = float(match.group(3))
            effic = match.group(4)
            error = abs(stu / energy * 100.0) if energy else ""
            geometry = self._body_geometry.get(geo_body_id, "coords not available from .geo")
            geometry_type = self._body_geometry_type(geo_body, self._geo_surfaces) if geo_body else "Unknown"
            if geo_body and geo_body_id != body_id:
                geometry = f"geo BODY({geo_body_id}) {label}; {geometry}"
            self._body_results.append({
                "body_id": body_id,
                "geo_body_id": geo_body_id,
                "component": label,
                "edep": energy,
                "dedep": stu,
                "error": error,
                "effic": effic,
                "geometry": geometry,
                "geometry_type": geometry_type,
                "mass": "",
                "dose": "",
                "ddose": "",
            })
        self._refresh_dose_columns()

    def _fmt_num(self, value):
        if value in ("", None):
            return ""
        try:
            return f"{float(value):.6E}"
        except (TypeError, ValueError):
            return str(value)

    def _render_body_results_table(self):
        self.tbl_bodies.setRowCount(0)
        n_ref, t_ref = self._reference_display_values()
        target_err = self._target_error_value()
        for result in self._body_results:
            row = self.tbl_bodies.rowCount()
            self.tbl_bodies.insertRow(row)
            _target_err, n_target, t_target = self._prediction_values(result.get("error", ""), result.get("edep", 0.0))
            mass_note = "mass from geo volume x material density"
            if result.get("mass") in ("", None):
                mass_note = "mass unavailable: geometry volume or material density could not be inferred"
            row_tip = (
                f"Body {result['body_id']}: {result['component']}\n"
                f"Geometry type: {result.get('geometry_type') or 'Unknown'}\n"
                f"Geometry: {result['geometry']}\n"
                f"{mass_note}"
            )
            values = (
                str(result["body_id"]),
                result["component"],
                self._fmt_num(result["edep"]),
                self._fmt_num(result["dedep"]),
                self._fmt_num(result["edep"] * self.EV_TO_J),
                self._fmt_num(result["dedep"] * self.EV_TO_J),
                f"{result['error']:.3g}" if result["error"] != "" else "",
                self._fmt_num(result["mass"]),
                self._fmt_num(result["dose"]),
                self._fmt_num(result["ddose"]),
                self._fmt_num(result.get("dose_ev_g", "")),
                self._fmt_num(result.get("ddose_ev_g", "")),
                n_ref,
                t_ref,
                f"{target_err:g}",
                self._fmt_num(n_target),
                self._fmt_num(t_target),
            )
            for col, value in enumerate(values):
                item = QTableWidgetItem(value)
                item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                if col in (0, 1):
                    item.setToolTip(row_tip)
                else:
                    item.setToolTip(value or row_tip)
                self.tbl_bodies.setItem(row, col, item)
        if self._body_results:
            self._append_total_results_row()

    def _append_total_results_row(self):
        total_edep = sum(float(result["edep"]) for result in self._body_results)
        total_dedep = sum(float(result["dedep"]) ** 2 for result in self._body_results) ** 0.5
        total_error = abs(total_dedep / total_edep * 100.0) if total_edep else ""
        masses = [result.get("mass", "") for result in self._body_results]
        total_mass = ""
        if all(mass not in ("", None) for mass in masses):
            total_mass = sum(float(mass) for mass in masses)
        total_dose, total_ddose = self._dose_values(total_edep, total_dedep, total_mass)
        total_dose_ev_g, total_ddose_ev_g = self._dose_values_ev_per_g(total_edep, total_dedep, total_mass)
        n_ref, t_ref = self._reference_display_values()
        target_err, n_target, t_target = self._prediction_values(total_error, total_edep)
        total_edep_j = total_edep * self.EV_TO_J
        total_dedep_j = total_dedep * self.EV_TO_J
        row = self.tbl_bodies.rowCount()
        self.tbl_bodies.insertRow(row)
        values = (
            "TOTAL",
            "Total Dosage",
            self._fmt_num(total_edep),
            self._fmt_num(total_dedep),
            self._fmt_num(total_edep_j),
            self._fmt_num(total_dedep_j),
            f"{total_error:.3g}" if total_error != "" else "",
            self._fmt_num(total_mass),
            self._fmt_num(total_dose),
            self._fmt_num(total_ddose),
            self._fmt_num(total_dose_ev_g),
            self._fmt_num(total_ddose_ev_g),
            n_ref,
            t_ref,
            f"{target_err:g}",
            self._fmt_num(n_target),
            self._fmt_num(t_target),
        )
        for col, value in enumerate(values):
            item = QTableWidgetItem(value)
            item.setBackground(QColor("#12241A"))
            item.setForeground(QColor("#D6F5DD"))
            font = item.font()
            font.setBold(True)
            item.setFont(font)
            item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
            item.setToolTip(value)
            self.tbl_bodies.setItem(row, col, item)

    def _risk_quality_label(self, error_pct, near_zero=False):
        if near_zero:
            return "Unreliable"
        try:
            e = float(error_pct)
        except (TypeError, ValueError):
            return ""
        if e > 50.0:
            return "Unreliable"
        if e > 20.0:
            return "Uncertain"
        return "Accepted"

    def _fmt_duration(self, seconds):
        try:
            s = float(seconds)
        except (TypeError, ValueError):
            return ""
        if s < 60:
            return f"{s:.1f} s"
        if s < 3600:
            return f"{s / 60.0:.1f} min"
        return f"{s / 3600.0:.2f} h"

    def _extract_run_stats_from_res(self, res_path):
        try:
            text = _decode_text_bytes(Path(res_path).read_bytes())
        except Exception:
            return None, None
        mt = re.search(r"Simulation time\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)\s*sec", text, re.IGNORECASE)
        ms = re.search(r"Simulated primary showers\s*\.{2,}\s*([+\-]?\d+(?:\.\d+)?E[+\-]?\d+)", text, re.IGNORECASE)
        if not mt or not ms:
            return None, None
        try:
            return float(mt.group(1)), float(ms.group(1))
        except ValueError:
            return None, None

    def _case_stats_map(self):
        stats = {}
        root = self._multi_root or (self._workspace.parent if self._workspace else None)
        if not root:
            return stats
        for folder in self._analysis_candidate_folders(root):
            t_ref, n_ref = self._extract_run_stats_from_res(folder / "penmain-res.dat")
            if t_ref and n_ref and t_ref > 0 and n_ref > 0:
                stats[folder.name] = {"time_ref": t_ref, "n_ref": n_ref}
        return stats

    def _risk_baselines(self):
        baselines = []
        case_name = self._workspace.name if self._workspace else ""
        if self._body_results and self._sim_time_sec and self._sim_showers and self._sim_time_sec > 0 and self._sim_showers > 0:
            for result in self._body_results:
                if result.get("error", "") in ("", None):
                    continue
                baselines.append({
                    "source": "Current case",
                    "case": case_name,
                    "body": f"Body {result['body_id']}",
                    "component": result.get("component", ""),
                    "error_ref": float(result["error"]),
                    "n_ref": float(self._sim_showers),
                    "time_ref": float(self._sim_time_sec),
                    "near_zero": abs(float(result.get("edep", 0.0))) <= 1e-20,
                })

        if self._dose_xlsx and self._dose_xlsx.exists():
            openpyxl = self._load_openpyxl()
            if openpyxl is not None:
                try:
                    wb = openpyxl.load_workbook(self._dose_xlsx, data_only=True)
                    ws = wb.active
                    headers = self._dose_header_map(ws)
                    c_case = headers.get("Case")
                    c_body = headers.get("Body")
                    c_comp = headers.get("Component")
                    c_err = headers.get("Error (%)")
                    c_edep = headers.get("Edep (eV)")
                    if c_case and c_body and c_err:
                        stats_map = self._case_stats_map()
                        for row in range(2, ws.max_row + 1):
                            case = str(ws.cell(row, c_case).value or "").strip()
                            body = str(ws.cell(row, c_body).value or "").strip()
                            if not case or not body or body.upper() == "TOTAL":
                                continue
                            if case not in stats_map:
                                continue
                            try:
                                error_ref = float(ws.cell(row, c_err).value)
                            except (TypeError, ValueError):
                                continue
                            comp = str(ws.cell(row, c_comp).value or "").strip() if c_comp else ""
                            near_zero = False
                            if c_edep:
                                try:
                                    near_zero = abs(float(ws.cell(row, c_edep).value)) <= 1e-20
                                except (TypeError, ValueError):
                                    near_zero = False
                            baselines.append({
                                "source": "Workbook",
                                "case": case,
                                "body": body,
                                "component": comp,
                                "error_ref": error_ref,
                                "n_ref": float(stats_map[case]["n_ref"]),
                                "time_ref": float(stats_map[case]["time_ref"]),
                                "near_zero": near_zero,
                            })
                except Exception as exc:
                    self._log_analysis(f"Risk baseline load failed from workbook: {exc}", "warn")

        # Keep unique-ish entries by core identity.
        dedup = {}
        for b in baselines:
            key = (b["source"], b["case"], b["body"], b["component"], round(b["error_ref"], 6))
            dedup[key] = b
        return sorted(dedup.values(), key=lambda x: (x["source"], x["case"], x["body"], x["component"]))

    def _parse_candidate_nsimsh(self, text):
        out = []
        seen = set()
        for tok in re.split(r"[,\s;]+", (text or "").strip()):
            if not tok:
                continue
            try:
                val = float(tok)
            except ValueError:
                continue
            if val <= 0:
                continue
            key = int(round(val))
            if key in seen:
                continue
            seen.add(key)
            out.append(float(key))
        return out

    def _parse_positive_float(self, text):
        try:
            value = float(str(text).strip())
        except Exception:
            return None
        if not math.isfinite(value) or value <= 0:
            return None
        return float(value)

    def _workspace_in_baseline(self):
        if not self._workspace or not Path(self._workspace).exists():
            return None
        in_files = sorted(Path(self._workspace).glob("*.in"))
        if not in_files:
            return None
        target = in_files[0]
        try:
            text = _decode_text_bytes(target.read_bytes())
        except Exception:
            return None
        m_n = re.search(r"^\s*NSIMSH\s+([^\s\[]+)", text, re.IGNORECASE | re.MULTILINE)
        m_t = re.search(r"^\s*TIME\s+([^\s\[]+)", text, re.IGNORECASE | re.MULTILINE)
        if not m_n or not m_t:
            return None
        n_ref = self._parse_positive_float(m_n.group(1))
        t_ref = self._parse_positive_float(m_t.group(1))
        if n_ref is None or t_ref is None:
            return None
        return {"n_ref": n_ref, "time_ref": t_ref, "source": f"{target.name} in {Path(self._workspace).name}"}

    def _open_risk_assessment(self, seed_n_ref=None, seed_time_ref=None, seed_source=""):
        # Pre-run target threshold required by project: 5% or below.
        self._risk_default_error_ref = self.TARGET_ERR_PCT
        n_seed = self._parse_positive_float(seed_n_ref)
        t_seed = self._parse_positive_float(seed_time_ref)
        baseline_source = seed_source or ""
        if n_seed is None or t_seed is None:
            ws_base = self._workspace_in_baseline()
            if ws_base:
                n_seed = ws_base["n_ref"]
                t_seed = ws_base["time_ref"]
                baseline_source = ws_base["source"]
        if n_seed is None or t_seed is None:
            QMessageBox.warning(
                self,
                "Risk Assessment",
                "No valid baseline found.\n\nOpen an .in file with NSIMSH and TIME (Simulation tab), or load an active case with a valid .in file.",
            )
            return
        self._risk_default_nref = float(n_seed)
        self._risk_default_time_ref = float(t_seed)

        baselines = self._risk_baselines()
        dlg = QDialog(self)
        dlg.setWindowTitle("Risk Assessment (Pre-run estimate)")
        dlg.setModal(True)
        dlg.setMinimumWidth(860)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)

        form = QFormLayout()
        form.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        cmb_base = QComboBox()
        cmb_base.setStyleSheet(combo_dropdown_css())
        if baselines:
            for idx, b in enumerate(baselines):
                label = (
                    f"[{b['source']}] {b['case']} | {b['body']} {b['component']} | "
                    f"Err={b['error_ref']:.2f}% @ N={b['n_ref']:.3g}, T={self._fmt_duration(b['time_ref'])}"
                )
                cmb_base.addItem(label, idx)
        else:
            cmb_base.addItem("No automatic baseline available", None)
            cmb_base.setEnabled(False)
        e_candidates = QLineEdit("3e6, 1e7, 3e7, 1e8")
        e_candidates.setStyleSheet(entry_css())
        e_candidates.setToolTip("Comma/space separated NSIMSH candidates.")
        form.addRow("Baseline:", cmb_base)
        form.addRow("NSIMSH:", e_candidates)
        lay.addLayout(form)

        if baseline_source:
            src_lbl = QLabel(f"Pre-run baseline source: {baseline_source}")
            src_lbl.setStyleSheet(label_css(P["fg2"]))
            src_lbl.setWordWrap(True)
            lay.addWidget(src_lbl)

        manual_box = QFrame()
        manual_box.setStyleSheet(f"QFrame {{ background:{P['bg2']}; border:1px solid {P['border']}; border-radius:6px; }}")
        manual_lay = QFormLayout(manual_box)
        manual_lay.setContentsMargins(8, 8, 8, 8)
        manual_lay.setLabelAlignment(Qt.AlignmentFlag.AlignRight)
        chk_manual = QCheckBox("Use manual baseline (works without penmain-res.dat)")
        chk_manual.setStyleSheet(label_css(P["fg"]))
        chk_manual.setChecked(True)
        chk_manual.setEnabled(False)
        e_err_ref = QLineEdit(f"{self._risk_default_error_ref:g}")
        e_err_ref.setStyleSheet(entry_css())
        e_err_ref.setReadOnly(True)
        e_err_ref.setToolTip("Fixed project threshold target.")
        e_n_ref = QLineEdit(f"{self._risk_default_nref:g}")
        e_n_ref.setStyleSheet(entry_css())
        e_n_ref.setReadOnly(True)
        e_t_ref = QLineEdit(f"{self._risk_default_time_ref:g}")
        e_t_ref.setStyleSheet(entry_css())
        e_t_ref.setReadOnly(True)
        manual_lay.addRow(chk_manual)
        manual_lay.addRow("Err ref (%):", e_err_ref)
        manual_lay.addRow("N ref:", e_n_ref)
        manual_lay.addRow("Time ref (s):", e_t_ref)
        lay.addWidget(manual_box)

        hint = QLabel("Model: Error(N)=Error_ref*sqrt(N_ref/N), Time(N)=Time_ref*(N/N_ref).")
        hint.setStyleSheet(label_css(P["fg2"]))
        lay.addWidget(hint)
        lbl_info = QLabel("")
        lbl_info.setStyleSheet(label_css(P["fg2"]))
        lbl_info.setWordWrap(True)
        lay.addWidget(lbl_info)

        tbl = QTableWidget(0, 4)
        tbl.setHorizontalHeaderLabels(["NSIMSH", "Pred Error (%)", "Pred Time", "Quality"])
        tbl.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(1, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(2, QHeaderView.ResizeMode.ResizeToContents)
        tbl.horizontalHeader().setSectionResizeMode(3, QHeaderView.ResizeMode.Stretch)
        tbl.verticalHeader().setVisible(False)
        tbl.setStyleSheet(
            f"QTableWidget {{ background:{P['bg']}; color:{P['fg']}; border:1px solid {P['border']}; border-radius:4px; }}"
            f"QTableWidget::item:selected {{ background:{P['sel']}; }}"
            f"QHeaderView::section {{ background:{P['bg2']}; color:{P['fg2']}; border:0; padding:4px; }}"
        )
        lay.addWidget(tbl, stretch=1)

        btns = QDialogButtonBox(QDialogButtonBox.StandardButton.Close)
        btns.rejected.connect(dlg.reject)
        btns.accepted.connect(dlg.accept)
        btns.button(QDialogButtonBox.StandardButton.Close).setStyleSheet(btn_css(width=90))
        lay.addWidget(btns)

        def paint_quality_item(item, quality):
            if quality == "Accepted":
                item.setBackground(QColor("#13301D"))
                item.setForeground(QColor("#CFF6D7"))
            elif quality == "Uncertain":
                item.setBackground(QColor("#3A2E10"))
                item.setForeground(QColor("#FFE7A6"))
            elif quality == "Unreliable":
                item.setBackground(QColor("#3A1414"))
                item.setForeground(QColor("#FFD0D0"))

        def current_baseline():
            if chk_manual.isChecked():
                err_ref = self._parse_positive_float(e_err_ref.text())
                n_ref = self._parse_positive_float(e_n_ref.text())
                t_ref = self._parse_positive_float(e_t_ref.text())
                if err_ref is None or n_ref is None or t_ref is None:
                    return None, "Manual baseline values must be positive numbers."
                return {
                    "source": "Manual",
                    "case": "manual",
                    "body": "-",
                    "component": "-",
                    "error_ref": err_ref,
                    "n_ref": n_ref,
                    "time_ref": t_ref,
                    "near_zero": False,
                }, "Manual baseline active."
            idx = cmb_base.currentData()
            if idx is None:
                return None, "No automatic baseline available; enable Manual baseline."
            return baselines[int(idx)], "Automatic baseline active."

        def refresh_table():
            base, info = current_baseline()
            lbl_info.setText(info)
            if base is None:
                tbl.setRowCount(0)
                return
            n_vals = self._parse_candidate_nsimsh(e_candidates.text())
            if not n_vals:
                n_vals = [3e6, 1e7, 3e7, 1e8]
            tbl.setRowCount(0)
            for n in n_vals:
                pred_err = float(base["error_ref"]) * math.sqrt(float(base["n_ref"]) / float(n))
                pred_time = float(base["time_ref"]) * (float(n) / float(base["n_ref"]))
                quality = self._risk_quality_label(pred_err, near_zero=bool(base.get("near_zero")))
                row = tbl.rowCount()
                tbl.insertRow(row)
                values = (
                    f"{int(n):,}",
                    f"{pred_err:.2f}",
                    self._fmt_duration(pred_time),
                    quality,
                )
                for col, val in enumerate(values):
                    item = QTableWidgetItem(val)
                    item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                    if col == 3:
                        paint_quality_item(item, quality)
                    tbl.setItem(row, col, item)
            if chk_manual.isChecked():
                self._risk_default_error_ref = float(base["error_ref"])
                self._risk_default_nref = float(base["n_ref"])
                self._risk_default_time_ref = float(base["time_ref"])

        cmb_base.currentIndexChanged.connect(lambda _i: refresh_table())
        e_candidates.textChanged.connect(lambda _t: refresh_table())
        refresh_table()
        dlg.exec()

    def _append_dose_rows_to_xlsx(self):
        if not self._workspace:
            self._log_analysis("Append canceled: no case selected.", "warn")
            QMessageBox.warning(self, "No case", "Select an analysis case first.")
            return
        self._log_analysis(f"Append started for case: {self._workspace}", "info")
        if not self._body_results:
            self._log_analysis("No cached body results; parsing penmain-res.dat.", "info")
            self._parse_penmain_results(self._workspace / "penmain-res.dat")
        if not self._body_results:
            self._log_analysis("Append canceled: no deposited-energy body results found.", "warn")
            QMessageBox.warning(self, "No results", "No deposited-energy body results were found.")
            return
        wb, ws = self._ensure_dose_workbook()
        if wb is None:
            self._log_analysis("Append canceled: workbook is unavailable.", "err")
            return
        self._refresh_dose_columns()
        case, rows = self._dose_rows_for_current_results()
        self._log_analysis(
            f"Prepared case '{case}' with {len(self._body_results)} body row(s) + total.",
            "info",
        )
        body_rows = self._body_rows_only(rows)
        start_row = ws.max_row + 1
        self._remove_case_rows(ws, case)
        self._remove_total_rows_from_sheet(ws)
        self._append_rows_to_sheet(ws, body_rows)
        self._sync_totals_sheet(wb, rows)
        self._set_dose_column_widths(ws)
        self._apply_dose_quality_and_formatting(ws)
        try:
            wb.save(self._dose_xlsx)
        except PermissionError:
            self._log_analysis(f"Append failed: workbook is open -> {self._dose_xlsx}", "err")
            QMessageBox.warning(self, "Workbook open", "Close the Excel workbook before appending rows.")
            return
        self._update_dose_xlsx_label("existing")
        self.status_message.emit(f"Appended dose rows {start_row}-{ws.max_row}")
        self._log_analysis(
            f"Append complete: {len(body_rows)} body row(s) saved to main sheet; total row synced to TOTALS in {self._dose_xlsx}",
            "ok",
        )
        QMessageBox.information(
            self,
            "Dosage exported",
            f"Appended {len(body_rows)} body row(s) to the main sheet.\nTotal Dosage was written to the TOTALS sheet:\n{self._dose_xlsx}",
        )


    #  Combined split-run analysis

    def _auto_group_splits_by_signature(self, root_folder):
        """Recursively scan root_folder and group subfolders by .in compatibility signature.

        Returns a list of groups, each group being a list of (folder, res_file) tuples.
        Only folders that have a penmain-res.dat and a parseable .in are included.
        Grouping keys: SKPAR, SPECTR, SPOSIT, SCONE, MFNAME file names, GEOMFN file name.
        """
        root = Path(root_folder)
        groups = {}
        for folder in sorted(root.rglob("*")):
            if not folder.is_dir():
                continue
            res = folder / "penmain-res.dat"
            if not res.exists():
                continue
            sig, _ = self._compatibility_signature_from_in(folder)
            if not sig:
                continue
            key = (
                sig.get("SKPAR", ()),
                sig.get("SPECTR", ()),
                sig.get("SPOSIT", ()),
                sig.get("SCONE", ()),
                tuple(sorted(sig.get("MFNAME", ()))),
                sig.get("GEOMFN", ()),
            )
            groups.setdefault(key, []).append((folder, res))
        return [v for v in groups.values() if len(v) >= 1]

    def _select_signature_group_for_combination(self, groups):
        """Let the user pick which signature group to combine when multiple exist."""
        if not groups:
            return None
        if len(groups) == 1:
            return groups[0]
        dlg = QDialog(self)
        dlg.setWindowTitle("Select split group by .in signature")
        dlg.setModal(True)
        dlg.setMinimumWidth(820)
        dlg.setStyleSheet(f"QDialog {{ background:{P['bg']}; }} QLabel {{ color:{P['fg']}; }}")
        lay = QVBoxLayout(dlg)
        hint = QLabel(
            f"Found {len(groups)} distinct simulation signatures. "
            "Select the group of sibling split-runs to combine."
        )
        hint.setStyleSheet(label_css(P["fg2"]))
        hint.setWordWrap(True)
        lay.addWidget(hint)
        lst = QListWidget()
        lst.setSelectionMode(QAbstractItemView.SelectionMode.SingleSelection)
        lst.setStyleSheet(
            f"QListWidget {{ background:{P['bg2']}; color:{P['fg']}; border:1px solid {P['border']}; border-radius:4px; }}"
            f"QListWidget::item {{ padding:4px; }}"
        )
        for i, group in enumerate(groups):
            sample_folder, _ = group[0]
            sig, _ = self._compatibility_signature_from_in(sample_folder)
            skpar = " ".join(sig.get("SKPAR", ())) or "?"
            geomfn = " ".join(sig.get("GEOMFN", ())) or "?"
            label = f"Group {i+1}  ({len(group)} run(s))  SKPAR={skpar}  GEO={geomfn}  sample: {sample_folder.name}"
            item = QListWidgetItem(label)
            item.setData(Qt.ItemDataRole.UserRole, i)
            lst.addItem(item)
        if lst.count():
            lst.setCurrentRow(0)
        lay.addWidget(lst)
        btn_row = QHBoxLayout()
        ok_btn = QPushButton("Combine selected group")
        ok_btn.setStyleSheet(btn_css(P["bg3"], 180))
        cancel_btn = QPushButton("Cancel")
        cancel_btn.setStyleSheet(btn_css(P["bg2"], 80))
        ok_btn.clicked.connect(dlg.accept)
        cancel_btn.clicked.connect(dlg.reject)
        btn_row.addStretch()
        btn_row.addWidget(ok_btn)
        btn_row.addWidget(cancel_btn)
        lay.addLayout(btn_row)
        if dlg.exec() != QDialog.DialogCode.Accepted:
            return None
        cur = lst.currentItem()
        if cur is None:
            return None
        idx = cur.data(Qt.ItemDataRole.UserRole)
        return groups[idx]

