        panel.setMinimumWidth(160)
        panel.setMaximumWidth(360)
        panel.setStyleSheet(
            f"QFrame {{ background:{P['bg2']}; border-right:1px solid {P['border']}; }}"
        )
        lay = QVBoxLayout(panel)
        lay.setContentsMargins(8, 8, 8, 8)
        lay.setSpacing(6)

        lbl = QLabel("Project Explorer")
        lbl.setStyleSheet(label_css(P["accent"], bold=True))
        lay.addWidget(lbl)

        self.lbl_project_root = QLabel("Project: none")
        self.lbl_project_root.setStyleSheet(label_css(P["fg2"], size=9))
        self.lbl_project_root.setWordWrap(True)
        lay.addWidget(self.lbl_project_root)

        self.project_empty_state = QFrame()
        self.project_empty_state.setStyleSheet(
            f"QFrame {{ background:{P['bg']}; border:1px dashed {P['border']}; border-radius:6px; }}"
        )
        empty_lay = QVBoxLayout(self.project_empty_state)
        empty_lay.setContentsMargins(12, 12, 12, 12)
        empty_lay.setSpacing(8)
        empty_title = QLabel("No project opened")
        empty_title.setStyleSheet(label_css(P["fg"], bold=True))
        empty_lay.addWidget(empty_title)
        empty_hint = QLabel(
            "Open an existing project or create a new one to populate the explorer with cases, geometry, materials, instructions, and analysis files."
        )
        empty_hint.setStyleSheet(label_css(P["fg2"], size=9))
        empty_hint.setWordWrap(True)
        empty_lay.addWidget(empty_hint)
        empty_btn_row = QHBoxLayout()
        empty_btn_row.setContentsMargins(0, 0, 0, 0)
        empty_btn_row.setSpacing(6)
        self.btn_project_empty_new = QPushButton("NEW")
        self.btn_project_empty_new.setStyleSheet(btn_css(width=90))
        self.btn_project_empty_new.clicked.connect(self._new_project)
        self.btn_project_empty_open = QPushButton("OPEN")
        self.btn_project_empty_open.setStyleSheet(btn_css(width=90))
        self.btn_project_empty_open.clicked.connect(self._open_project)
        empty_btn_row.addWidget(self.btn_project_empty_new)
        empty_btn_row.addWidget(self.btn_project_empty_open)
        empty_btn_row.addStretch(1)
