        self.lbl_project_hint = QLabel("Use the top Project menu to create/open a project, edit settings, organize case groups, and import/export files. Double-click .geo/.in/.dat/.xlsx files here to open linked views.")
        self.lbl_project_hint.setStyleSheet(label_css(P["fg2"], size=9))
        self.lbl_project_hint.setWordWrap(True)
