    def _restore_saved_ui_state(self):
        if hasattr(self, "_main_splitter"):
            sizes = list(self._saved_main_splitter_sizes or [])
            if len(sizes) >= 2 and sum(max(0, int(v)) for v in sizes[:2]) > 0:
                self._main_splitter.setSizes([max(0, int(sizes[0])), max(1, int(sizes[1]))])
        self._set_project_sidebar_visible(bool(self._saved_project_sidebar_visible))
        geo_splitter = getattr(getattr(self, "geo_tab", None), "_workspace_splitter", None)
        geo_sizes = list(self._saved_geo_workspace_splitter_sizes or [])
        if geo_splitter is not None and len(geo_sizes) >= 2 and sum(max(0, int(v)) for v in geo_sizes[:2]) > 0:
            try:
                self.geo_tab._workspace_splitter_adjusting = True
                geo_splitter.setSizes([max(0, int(geo_sizes[0])), max(1, int(geo_sizes[1]))])
            finally:
                QTimer.singleShot(0, lambda: setattr(self.geo_tab, "_workspace_splitter_adjusting", False))
        if hasattr(self, "geo_tab"):
            self.geo_tab.restore_workspace_layout_state(
                editor_sizes=getattr(self, "_saved_geo_editor_splitter_sizes", None),
                layout_mode=getattr(self, "_saved_geo_layout_mode", "render"),
            )

    def _set_project_sidebar_visible(self, visible):
        self._project_sidebar_visible = bool(visible)
        if hasattr(self, "_project_sidebar"):
            self._project_sidebar.setVisible(self._project_sidebar_visible)
        if hasattr(self, "_main_splitter"):
            if self._project_sidebar_visible:
                sizes = self._main_splitter.sizes()
                if not sizes or (sizes[0] == 0):
                    saved = list(self._saved_main_splitter_sizes or [])
                    if len(saved) >= 2 and sum(max(0, int(v)) for v in saved[:2]) > 0:
                        self._main_splitter.setSizes([max(0, int(saved[0])), max(1, int(saved[1]))])
                    else:
                        self._main_splitter.setSizes([240, 1160])
            else:
                self._main_splitter.setSizes([0, max(1, self.width())])
        self._update_project_sidebar_buttons()

    def _rebalance_workspace_for_geo_left_delta(self, delta):
        delta = max(0, int(delta or 0))
        if delta <= 0 or not getattr(self, "_project_sidebar_visible", True):
            return
        splitter = getattr(self, "_main_splitter", None)
        sidebar = getattr(self, "_project_sidebar", None)
        if splitter is None or sidebar is None:
            return
        sizes = splitter.sizes()
        if len(sizes) < 2:
            return
        sidebar_size, tabs_size = int(sizes[0] or 0), int(sizes[1] or 0)
        min_sidebar = max(120, int(sidebar.minimumWidth() or 0))
        reclaim = min(delta, max(0, sidebar_size - min_sidebar))
        if reclaim <= 0:
            return
        geo_splitter = None
        try:
            geo_splitter = getattr(self.geo_tab, "_workspace_splitter", None)
            if geo_splitter is not None:
                self.geo_tab._workspace_splitter_adjusting = True
            splitter.setSizes([sidebar_size - reclaim, tabs_size + reclaim])
        finally:
            if geo_splitter is not None:
                QTimer.singleShot(0, lambda: setattr(self.geo_tab, "_workspace_splitter_adjusting", False))

    def _update_project_sidebar_buttons(self):
        visible = bool(getattr(self, "_project_sidebar_visible", True))
        if hasattr(self, "btn_project_sidebar_header"):
            self.btn_project_sidebar_header.setText("Collapse" if visible else "Expand")
        if hasattr(self, "btn_project_sidebar_corner"):
            self.btn_project_sidebar_corner.setText("<" if visible else ">")
            self.btn_project_sidebar_corner.setToolTip("Hide Project Explorer" if visible else "Show Project Explorer")

    def _toggle_project_sidebar(self):
        self._set_project_sidebar_visible(not bool(getattr(self, "_project_sidebar_visible", True)))
        if hasattr(self, "_act_toggle_sidebar"):
            self._act_toggle_sidebar.setChecked(self._project_sidebar_visible)

    def _update_project_sidebar_empty_state(self):
        has_project = bool(self._project_root)
        if hasattr(self, "project_empty_state"):
            self.project_empty_state.setVisible(not has_project)
        if hasattr(self, "project_tree"):
            self.project_tree.setVisible(has_project)
        if hasattr(self, "lbl_project_hint"):
            self.lbl_project_hint.setVisible(has_project)

    def _project_children(self, folder):
        folder = Path(folder)
        children = []
        try:
            for child in folder.iterdir():
                if child.name in PROJECT_TREE_IGNORES:
                    continue
                children.append(child)
        except OSError:
            return []
        return sorted(children, key=lambda p: (not p.is_dir(), p.name.lower()))

    def _project_item_has_placeholder(self, item):
        if item.childCount() != 1:
            return False
        child = item.child(0)
        return bool(child and child.data(0, Qt.ItemDataRole.UserRole + 1) == "placeholder")

    def _make_project_tree_item(self, path):
        path = Path(path)
        label = path.name or str(path)
        item = QTreeWidgetItem([label])
        item.setData(0, Qt.ItemDataRole.UserRole, str(path))
        item.setToolTip(0, str(path))
        if path.is_dir():
            item.setForeground(0, QColor(P["accent"]))
            if self._project_children(path):
                placeholder = QTreeWidgetItem(["..."])
                placeholder.setData(0, Qt.ItemDataRole.UserRole + 1, "placeholder")
                item.addChild(placeholder)
        return item

    def _populate_project_tree_children(self, item, folder):
        while item.childCount():
            item.takeChild(0)
        for child in self._project_children(folder):
            item.addChild(self._make_project_tree_item(child))

    def _on_project_tree_item_expanded(self, item):
        if not item:
            return
        raw = item.data(0, Qt.ItemDataRole.UserRole)
        if not raw:
            return
        path = Path(raw)
        if not path.is_dir():
            return
        if self._project_item_has_placeholder(item):
            self._populate_project_tree_children(item, path)

    def _on_project_tree_item_activated(self, item, _column=0):
        if not item:
            return
        raw = item.data(0, Qt.ItemDataRole.UserRole)
        if not raw:
            return
        path = Path(raw)
        if path.is_dir():
            item.setExpanded(not item.isExpanded())
            return
        suffix = path.suffix.lower()
        try:
            if suffix == ".geo":
                self.geo_tab._open_geo(str(path))
                self.tabs.setCurrentIndex(0)
                self._sync_project_from_current_files()
                return
            if suffix == ".in":
                self.sim_tab._open_in(str(path))
                self.tabs.setCurrentIndex(1)
                self._sync_project_from_current_files()
                return
            if suffix == ".dat":
                folder = path.parent
                if (folder / "penmain-res.dat").exists():
                    self.analysis_tab._load_workspace(folder)
                    self.tabs.setCurrentIndex(2)
                return
            if suffix == ".xlsx":
                self.analysis_tab._dose_xlsx = path
                self.analysis_tab._dose_xlsx_user_selected = True
                self.analysis_tab._dose_workbook_config = None
                if hasattr(self.analysis_tab, "lbl_dose_xlsx"):
                    self.analysis_tab._update_dose_xlsx_label("project")
                self.tabs.setCurrentIndex(2)
                return
        except Exception as exc:
            QMessageBox.warning(self, "Project Explorer", f"Could not open:\n{path}\n\n{exc}")

    def _refresh_project_tree(self):
        if not hasattr(self, "project_tree"):
            return
        self._project_tree_refresh_pending = False
        self.project_tree.clear()
        if not self._project_root:
            if hasattr(self, "lbl_project_root"):
                self.lbl_project_root.setText("Project: none")
            self._update_project_sidebar_empty_state()
            return
        root = Path(self._project_root)
        if hasattr(self, "lbl_project_root"):
            self.lbl_project_root.setText(f"Project: {root}")
        root_item = self._make_project_tree_item(root)
        root_item.setText(0, root.name or str(root))
        self.project_tree.addTopLevelItem(root_item)
        self._populate_project_tree_children(root_item, root)
        root_item.setExpanded(True)
        self._update_project_sidebar_empty_state()

    def _schedule_project_tree_refresh(self, delay_ms=0):
        if self._project_tree_refresh_pending:
            return
        self._project_tree_refresh_pending = True
        QTimer.singleShot(max(0, int(delay_ms or 0)), self._refresh_project_tree)

    def _project_folder_for_suffix(self, suffix):
        suffix = str(suffix or "").lower()
        folders = dict((self._project_meta or {}).get("folders") or {})
        if suffix == ".geo":
            rel = folders.get("geometry", PROJECT_DIR_GEOMETRY)
        elif suffix == ".mat":
            rel = folders.get("materials", PROJECT_DIR_MATERIALS)
        elif suffix in {".in", ".txt", ".md", ".pdf"}:
            rel = folders.get("instructions", PROJECT_DIR_INSTRUCTIONS)
        else:
            rel = folders.get("instructions", PROJECT_DIR_INSTRUCTIONS)
        return Path(self._project_root) / rel

    def _safe_copy_file(self, src, dst, overwrite=False):
        src = Path(src)
        dst = Path(dst)
        try:
            if dst.exists():
                try:
                    if src.resolve() == dst.resolve():
                        return False
                except OSError:
                    pass
                if not overwrite:
                    return False
            dst.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(src, dst)
            return True
        except OSError as exc:
            if getattr(exc, "winerror", None) == 32 and dst.exists():
                self._project_log(f"[PROJECT] Skipped locked file: {dst.name}\n", "warn")
                return False
            raise

    def _import_files_into_project(self):
        if not self._project_root:
            QMessageBox.information(self, "Import Files", "Open or create a project first.")
            return
        start = str(Path(self._project_root))
        paths, _ = QFileDialog.getOpenFileNames(
            self,
            "Import files into project",
            start,
            "Supported files (*.in *.geo *.mat *.txt *.md *.pdf);;All files (*.*)",
        )
        if not paths:
            return
        copied = []
        unchanged = []
        skipped = []
        failed = []
        for raw in paths:
            src = Path(raw)
            if not src.exists() or not src.is_file():
                skipped.append(str(src))
                continue
            target_dir = self._project_folder_for_suffix(src.suffix)
            target = target_dir / src.name
            try:
                target_dir.mkdir(parents=True, exist_ok=True)
                changed = self._safe_copy_file(src, target, overwrite=True)
                if changed:
                    copied.append(f"{src.name} -> {target_dir.name}")
                else:
                    unchanged.append(f"{src.name} -> {target_dir.name}")
            except Exception as exc:
                self._project_log(f"[PROJECT] Import failed {src} -> {target}: {exc}\n", "err")
                failed.append(f"{src.name}: {exc}")
        self._refresh_project_tree()
        if copied:
            app_log(f"Project import: {len(copied)} file(s) into {self._project_root}", "PROJECT")
        msg = []
        if copied:
            msg.append(f"Imported: {len(copied)}")
        if unchanged:
            msg.append(f"Unchanged: {len(unchanged)}")
        if skipped:
            msg.append(f"Skipped: {len(skipped)}")
        if failed:
            msg.append(f"Failed: {len(failed)}")
            msg.append("")
            msg.append("Details:")
            msg.extend(failed[:5])
        QMessageBox.information(self, "Import Files", "\n".join(msg) if msg else "No files were imported.")

    def _export_selected_project_files(self):
        if not self._project_root:
            QMessageBox.information(self, "Export Files", "Open or create a project first.")
            return
        items = list(getattr(self, "project_tree", QTreeWidget()).selectedItems()) if hasattr(self, "project_tree") else []
        files = []
        project_root = Path(self._project_root)
        for item in items:
            raw = item.data(0, Qt.ItemDataRole.UserRole)
            if not raw:
                continue
            path = Path(raw)
            if not path.exists() or not path.is_file():
                continue
            try:
                path.relative_to(project_root)
            except Exception:
                continue
            files.append(path)
        if not files:
            QMessageBox.information(self, "Export Files", "Select one or more project files in Project Explorer first.")
            return
        target_dir = QFileDialog.getExistingDirectory(self, "Choose export folder", str(project_root))
        if not target_dir:
            return
        target_dir = Path(target_dir)
        copied = []
        unchanged = []
        failed = []
        for src in files:
            try:
                target = target_dir / src.name
                changed = self._safe_copy_file(src, target, overwrite=True)
                if changed:
                    copied.append(src.name)
                else:
                    unchanged.append(src.name)
            except Exception as exc:
                self._project_log(f"[PROJECT] Export failed {src} -> {target}: {exc}\n", "err")
                failed.append(f"{src.name}: {exc}")
        if copied:
            app_log(f"Project export: {len(copied)} file(s) from {self._project_root} to {target_dir}", "PROJECT")
        msg = []
        if copied:
            msg.append(f"Exported: {len(copied)}")
        if unchanged:
            msg.append(f"Unchanged: {len(unchanged)}")
        if failed:
            msg.append(f"Failed: {len(failed)}")
            msg.append("")
            msg.append("Details:")
            msg.extend(failed[:5])
        QMessageBox.information(self, "Export Files", "\n".join(msg) if msg else "No files were exported.")

